window.SAT = {"cats":[{"id":"algebra","section":"math","name":{"en":"Algebra","es":"Álgebra","ru":"Алгебра","tr":"Cebir","hi":"बीजगणित","ar":"الجبر"},"blurb":{"en":"Linear equations, inequalities, systems and linear functions.","es":"Ecuaciones lineales, desigualdades, sistemas y funciones lineales.","ru":"Линейные уравнения, неравенства, системы и линейные функции.","tr":"Doğrusal denklemler, eşitsizlikler, sistemler ve doğrusal fonksiyonlar.","hi":"रैखिक समीकरण, असमिकाएँ, निकाय और रैखिक फलन।","ar":"المعادلات الخطية والمتباينات والأنظمة والدوال الخطية."}},{"id":"advanced","section":"math","name":{"en":"Advanced Math","es":"Matemáticas avanzadas","ru":"Высшая математика","tr":"İleri Matematik","hi":"उन्नत गणित","ar":"الرياضيات المتقدمة"},"blurb":{"en":"Quadratics, polynomials, exponents and nonlinear functions.","es":"Cuadráticas, polinomios, exponentes y funciones no lineales.","ru":"Квадратичные, многочлены, степени и нелинейные функции.","tr":"İkinci dereceden, polinomlar, üsler ve doğrusal olmayan fonksiyonlar.","hi":"द्विघात, बहुपद, घातांक और अरैखिक फलन।","ar":"المعادلات التربيعية وكثيرات الحدود والأسس والدوال غير الخطية."}},{"id":"data","section":"math","name":{"en":"Problem-Solving & Data Analysis","es":"Resolución de problemas y datos","ru":"Решение задач и анализ данных","tr":"Problem Çözme ve Veri Analizi","hi":"समस्या-समाधान और डेटा विश्लेषण","ar":"حل المشكلات وتحليل البيانات"},"blurb":{"en":"Ratios, percentages, statistics and data interpretation.","es":"Razones, porcentajes, estadística e interpretación de datos.","ru":"Отношения, проценты, статистика и анализ данных.","tr":"Oranlar, yüzdeler, istatistik ve veri yorumlama.","hi":"अनुपात, प्रतिशत, सांख्यिकी और डेटा व्याख्या।","ar":"النِّسَب والنِّسَب المئوية والإحصاء وتفسير البيانات."}},{"id":"geometry","section":"math","name":{"en":"Geometry & Trigonometry","es":"Geometría y trigonometría","ru":"Геометрия и тригонометрия","tr":"Geometri ve Trigonometri","hi":"ज्यामिति और त्रिकोणमिति","ar":"الهندسة وحساب المثلثات"},"blurb":{"en":"Area, volume, triangles, circles and right-triangle trig.","es":"Área, volumen, triángulos, círculos y trigonometría.","ru":"Площадь, объём, треугольники, окружности и тригонометрия.","tr":"Alan, hacim, üçgenler, çemberler ve dik üçgen trigonometrisi.","hi":"क्षेत्रफल, आयतन, त्रिभुज, वृत्त और समकोण त्रिकोणमिति।","ar":"المساحة والحجم والمثلثات والدوائر وحساب مثلثات المثلث القائم."}},{"id":"information","section":"rw","name":{"en":"Information & Ideas","es":"Información e ideas","ru":"Информация и идеи","tr":"Bilgi ve Fikirler","hi":"जानकारी और विचार","ar":"المعلومات والأفكار"},"blurb":{"en":"Central ideas, evidence and inferences from short passages.","es":"Ideas centrales, evidencia e inferencias de textos cortos.","ru":"Главные идеи, доказательства и выводы из коротких текстов.","tr":"Kısa metinlerden ana fikirler, kanıt ve çıkarımlar.","hi":"छोटे गद्यांशों से मुख्य विचार, प्रमाण और अनुमान।","ar":"الأفكار الرئيسية والأدلة والاستنتاجات من نصوص قصيرة."}},{"id":"craft","section":"rw","name":{"en":"Craft & Structure","es":"Arte y estructura","ru":"Стиль и структура","tr":"Üslup ve Yapı","hi":"शिल्प और संरचना","ar":"الصياغة والبنية"},"blurb":{"en":"Vocabulary in context, text structure and purpose.","es":"Vocabulario en contexto, estructura y propósito del texto.","ru":"Лексика в контексте, структура и цель текста.","tr":"Bağlamda kelime, metnin yapısı ve amacı.","hi":"संदर्भ में शब्दावली, पाठ की संरचना और उद्देश्य।","ar":"المفردات في السياق، بنية النص والغرض منه."}},{"id":"expression","section":"rw","name":{"en":"Expression of Ideas","es":"Expresión de ideas","ru":"Выражение идей","tr":"Fikirlerin İfadesi","hi":"विचारों की अभिव्यक्ति","ar":"التعبير عن الأفكار"},"blurb":{"en":"Transitions and rhetorical synthesis.","es":"Transiciones y síntesis retórica.","ru":"Переходы и риторический синтез.","tr":"Geçiş ifadeleri ve retorik sentez.","hi":"संक्रमण और अलंकारिक संश्लेषण।","ar":"أدوات الربط والتركيب البلاغي."}},{"id":"conventions","section":"rw","name":{"en":"Standard English Conventions","es":"Convenciones del inglés","ru":"Нормы английского","tr":"Standart İngilizce Kuralları","hi":"मानक अंग्रेज़ी नियम","ar":"قواعد الإنجليزية القياسية"},"blurb":{"en":"Grammar, punctuation and sentence structure.","es":"Gramática, puntuación y estructura de oraciones.","ru":"Грамматика, пунктуация и структура предложений.","tr":"Dil bilgisi, noktalama ve cümle yapısı.","hi":"व्याकरण, विराम-चिह्न और वाक्य-संरचना।","ar":"القواعد وعلامات الترقيم وبنية الجملة."}}],"q":[{"cat":"algebra","a":1,"q":"If 5x - 3 = 17, what is the value of x?","options":["3","4","5","7"],"explanation":"Add 3 to both sides: 5x = 20. Divide by 5: x = 4.","skill":"linear equations in one variable"},{"cat":"algebra","a":2,"q":"A function is defined by f(x) = 2x + 7. What is the value of f(6)?","options":["13","15","19","20"],"explanation":"Substitute x = 6: f(6) = 2(6) + 7 = 12 + 7 = 19.","skill":"linear functions"},{"cat":"algebra","a":0,"q":"What value of x satisfies the equation 3(x + 4) = 27?","options":["5","7","9","11"],"explanation":"Divide both sides by 3: x + 4 = 9. Subtract 4: x = 5.","skill":"linear equations in one variable"},{"cat":"algebra","a":1,"q":"A taxi charges a flat fee of $3 plus $2 for each mile driven. Which equation gives the total cost C, in dollars, for a ride of m miles?","options":["C = 3m + 2","C = 2m + 3","C = 5m","C = 2m - 3"],"explanation":"The flat fee $3 is the constant and $2 per mile multiplies m, so C = 2m + 3.","skill":"interpreting linear models"},{"cat":"algebra","a":1,"q":"If x - 8 = -3, what is the value of 2x?","options":["5","10","-10","-5"],"explanation":"Add 8 to both sides: x = 5. Then 2x = 2(5) = 10.","skill":"linear equations in one variable"},{"cat":"algebra","a":2,"q":"Which of the following is a solution to the inequality 4x + 1 > 13?","options":["2","3","4","1"],"explanation":"Subtract 1: 4x > 12, so x > 3. Among the choices, only 4 is greater than 3.","skill":"linear inequalities"},{"cat":"algebra","a":1,"q":"The graph of a line passes through the points (0, 4) and (2, 10). What is the slope of the line?","options":["2","3","6","4"],"explanation":"Slope = (10 - 4)/(2 - 0) = 6/2 = 3.","skill":"linear functions"},{"cat":"algebra","a":1,"q":"For the system y = 2x and y = x + 5, what is the value of x at the solution?","options":["3","5","10","2"],"explanation":"Set 2x = x + 5, so x = 5. (Then y = 10.)","skill":"systems of two linear equations"},{"cat":"algebra","a":1,"q":"A plant is 12 cm tall and grows 3 cm each week. Which equation gives its height h, in cm, after w weeks?","options":["h = 12w + 3","h = 3w + 12","h = 15w","h = 3w - 12"],"explanation":"Starting height 12 is the constant, growth 3 cm per week multiplies w: h = 3w + 12.","skill":"interpreting linear models"},{"cat":"algebra","a":0,"q":"If 6 - 2x = 14, what is the value of x?","options":["-4","4","-10","10"],"explanation":"Subtract 6: -2x = 8. Divide by -2: x = -4.","skill":"linear equations in one variable"},{"cat":"algebra","a":1,"q":"A line has equation 2x + 3y = 12. What is the y-intercept of the line?","options":["6","4","3","2"],"explanation":"Set x = 0: 3y = 12, so y = 4. The y-intercept is 4.","skill":"linear equations in two variables"},{"cat":"algebra","a":1,"q":"The cost to print booklets is modeled by C = 0.5n + 40, where n is the number of booklets and C is the cost in dollars. What does the number 40 represent?","options":["The cost per booklet","The fixed setup cost in dollars","The number of booklets","The cost of 40 booklets"],"explanation":"In C = 0.5n + 40, the constant 40 is the cost when n = 0, the fixed setup cost.","skill":"interpreting linear models"},{"cat":"algebra","a":0,"q":"If 3x + 2y = 18 and y = 3, what is the value of x?","options":["4","6","3","8"],"explanation":"Substitute y = 3: 3x + 6 = 18, so 3x = 12 and x = 4.","skill":"linear equations in two variables"},{"cat":"algebra","a":1,"q":"What is the solution set of the inequality -3x + 5 <= 14?","options":["x <= -3","x >= -3","x <= 3","x >= 3"],"explanation":"Subtract 5: -3x <= 9. Divide by -3 and flip the inequality: x >= -3.","skill":"linear inequalities"},{"cat":"algebra","a":0,"q":"A line passes through (1, 5) and has slope 2. What is its equation in slope-intercept form?","options":["y = 2x + 3","y = 2x + 5","y = 2x - 3","y = 5x + 2"],"explanation":"Using y = 2x + b with point (1,5): 5 = 2(1) + b, so b = 3. The equation is y = 2x + 3.","skill":"linear functions"},{"cat":"algebra","a":1,"q":"At a fair, ride tickets cost $4 each and a wristband costs $10. Maria spends exactly $38 on a wristband and ride tickets. How many ride tickets did she buy?","options":["6","7","8","9"],"explanation":"Let t be tickets: 4t + 10 = 38, so 4t = 28 and t = 7.","skill":"linear equations in one variable"},{"cat":"algebra","a":0,"q":"The solution to the system 2x + y = 7 and x - y = 2 is (x, y). What is the value of y?","options":["1","2","3","4"],"explanation":"Add the equations: 3x = 9, so x = 3. Then from x - y = 2: 3 - y = 2, so y = 1.","skill":"systems of two linear equations"},{"cat":"algebra","a":2,"q":"A linear function g satisfies g(0) = 5 and g(4) = 17. What is the value of g(10)?","options":["29","32","35","38"],"explanation":"Slope = (17 - 5)/(4 - 0) = 12/4 = 3, so g(x) = 3x + 5. Then g(10) = 30 + 5 = 35.","skill":"linear functions"},{"cat":"algebra","a":1,"q":"A car's fuel tank starts with 16 gallons and the car uses 0.04 gallon per mile. How many miles can the car travel before the tank is empty?","options":["320","400","440","640"],"explanation":"Set 16 - 0.04m = 0, so 0.04m = 16 and m = 16/0.04 = 400 miles.","skill":"interpreting linear models"},{"cat":"algebra","a":1,"q":"A scientist models the temperature T, in degrees, of a cooling liquid as T = 80 - 5t, where t is time in minutes. By how many degrees does the temperature change every 3 minutes?","options":["Increases by 15","Decreases by 15","Decreases by 5","Increases by 5"],"explanation":"The rate of change is -5 degrees per minute, so over 3 minutes the change is -5(3) = -15, a decrease of 15 degrees.","skill":"interpreting linear models"},{"cat":"algebra","a":3,"q":"The system 3x + 4y = 24 and 3x + 4y = 18 has how many solutions?","options":["Exactly one","Exactly two","Infinitely many","No solution"],"explanation":"Both expressions equal 3x + 4y but are set equal to different values (24 and 18), which is impossible, so there is no solution.","skill":"systems of two linear equations"},{"cat":"algebra","a":1,"q":"A vendor sells small bags for $3 and large bags for $5. On one day the vendor sells 40 bags total for $160. How many large bags were sold?","options":["15","20","25","30"],"explanation":"Let L be large bags and S small: S + L = 40 and 3S + 5L = 160. Substitute S = 40 - L: 3(40 - L) + 5L = 160, so 120 + 2L = 160, 2L = 40, L = 20.","skill":"systems of two linear equations"},{"cat":"algebra","a":2,"q":"For what value of k does the system y = 4x + 1 and y = kx - 5 have no solution?","options":["-4","1","4","5"],"explanation":"Two lines have no solution when they are parallel (equal slopes) but different intercepts. The slope of the first line is 4, so k = 4 makes them parallel; the intercepts differ, so there is no solution.","skill":"systems of two linear equations"},{"cat":"algebra","a":1,"q":"A gym membership plan A costs $25 per month plus a $40 sign-up fee. Plan B costs $35 per month with no sign-up fee. After how many months do the two plans cost the same total amount?","options":["3","4","5","8"],"explanation":"Set 25m + 40 = 35m. So 40 = 10m and m = 4 months.","skill":"systems of two linear equations"},{"cat":"algebra","a":0,"q":"The number of liters L of water in a tank after t minutes is L = 200 - 8t. A valve must close before the tank drops below 40 liters. For which values of t does L stay at or above 40 liters?","options":["t <= 20","t <= 30","t >= 20","t <= 15"],"explanation":"Set 200 - 8t >= 40, so -8t >= -160. Divide by -8 and flip: t <= 20.","skill":"linear inequalities"},{"cat":"algebra","a":1,"q":"If 4x + 5 = 21, what is the value of x?","options":["3","4","5","6"],"explanation":"Subtract 5 from both sides: 4x = 16. Divide by 4: x = 4.","skill":"linear equations in one variable"},{"cat":"algebra","a":1,"q":"A function is defined by f(x) = 3x - 4. What is the value of f(5)?","options":["8","11","15","19"],"explanation":"Substitute x = 5: f(5) = 3(5) - 4 = 15 - 4 = 11.","skill":"linear functions"},{"cat":"algebra","a":0,"q":"If x + 9 = 2, what is the value of 3x?","options":["-21","-7","7","21"],"explanation":"Solve x = 2 - 9 = -7. Then 3x = 3(-7) = -21.","skill":"linear equations in one variable"},{"cat":"algebra","a":2,"q":"What value of x satisfies the equation 2(x - 3) = 14?","options":["7","8","10","11"],"explanation":"Divide both sides by 2: x - 3 = 7. Add 3: x = 10.","skill":"linear equations in one variable"},{"cat":"algebra","a":1,"q":"A bike rental charges a flat fee of $5 plus $2 for each hour. Which equation gives the total cost C, in dollars, for h hours?","options":["C = 5h + 2","C = 2h + 5","C = 7h","C = 2h - 5"],"explanation":"The hourly cost is 2h and the flat fee is 5, so C = 2h + 5.","skill":"linear equations in two variables"},{"cat":"algebra","a":3,"q":"Which of the following is a solution to the inequality 3x - 2 > 10?","options":["x = 2","x = 3","x = 4","x = 5"],"explanation":"Add 2: 3x > 12, so x > 4. Only x = 5 satisfies x > 4; the others give values at or below the bound.","skill":"linear inequalities in one variable"},{"cat":"algebra","a":1,"q":"The graph of a line passes through the points (0, -1) and (3, 8). What is the slope of the line?","options":["2","3","9","-3"],"explanation":"Slope = (8 - (-1)) / (3 - 0) = 9 / 3 = 3.","skill":"linear functions"},{"cat":"algebra","a":1,"q":"For the system y = 3x and y = x + 8, what is the value of x at the solution?","options":["2","4","6","8"],"explanation":"Set 3x = x + 8, so 2x = 8 and x = 4.","skill":"systems of linear equations"},{"cat":"algebra","a":2,"q":"A candle is 20 cm tall and burns down 4 cm each hour. Which equation gives its height h, in cm, after t hours?","options":["h = 20 + 4t","h = 4t - 20","h = 20 - 4t","h = 4 - 20t"],"explanation":"It starts at 20 and decreases by 4 each hour, so h = 20 - 4t.","skill":"linear equations in two variables"},{"cat":"algebra","a":0,"q":"If 7 - 3x = 19, what is the value of x?","options":["-4","-2","2","4"],"explanation":"Subtract 7: -3x = 12. Divide by -3: x = -4.","skill":"linear equations in one variable"},{"cat":"algebra","a":1,"q":"A line has equation 3x + 5y = 30. What is the y-intercept of the line?","options":["5","6","10","30"],"explanation":"Set x = 0: 5y = 30, so y = 6. The y-intercept is 6.","skill":"linear equations in two variables"},{"cat":"algebra","a":1,"q":"The cost to ship packages is modeled by C = 1.5n + 12, where n is the number of packages. What does the number 12 represent?","options":["The cost per package","A fixed base cost regardless of n","The number of packages shipped","The total cost for 1 package"],"explanation":"When n = 0, C = 12, so 12 is the fixed base cost independent of the number of packages.","skill":"linear functions"},{"cat":"algebra","a":1,"q":"If 4x - 3y = 25 and y = -1, what is the value of x?","options":["4","5.5","7","22"],"explanation":"Substitute y = -1: 4x - 3(-1) = 25, so 4x + 3 = 25, 4x = 22, x = 5.5.","skill":"systems of linear equations"},{"cat":"algebra","a":1,"q":"What is the solution set of the inequality -2x + 7 >= 1?","options":["x >= 3","x <= 3","x >= 4","x <= 4"],"explanation":"Subtract 7: -2x >= -6. Divide by -2 and flip the sign: x <= 3.","skill":"linear inequalities in one variable"},{"cat":"algebra","a":0,"q":"A line passes through (2, 3) and has slope 4. What is its equation in slope-intercept form?","options":["y = 4x - 5","y = 4x + 5","y = 4x - 3","y = 4x + 3"],"explanation":"Using y = 4x + b with (2,3): 3 = 8 + b, so b = -5. Thus y = 4x - 5.","skill":"linear functions"},{"cat":"algebra","a":2,"q":"At a concert, snacks cost $3 each and a souvenir program costs $8. Jordan spends exactly $29 on snacks and one program. How many snacks did Jordan buy?","options":["5","6","7","8"],"explanation":"Let s be snacks: 3s + 8 = 29, so 3s = 21 and s = 7.","skill":"linear equations in one variable"},{"cat":"algebra","a":1,"q":"The solution to the system 3x + y = 11 and x - y = 1 is (x, y). What is the value of x?","options":["2","3","4","5"],"explanation":"Add the equations: 4x = 12, so x = 3.","skill":"systems of linear equations"},{"cat":"algebra","a":1,"q":"A linear function g satisfies g(0) = 3 and g(5) = 23. What is the value of g(8)?","options":["31","35","39","43"],"explanation":"Slope = (23 - 3)/(5 - 0) = 4, so g(x) = 4x + 3. Then g(8) = 32 + 3 = 35.","skill":"linear functions"},{"cat":"algebra","a":2,"q":"A water heater starts with 50 liters and drains 0.5 liter per minute. After how many minutes will it contain 20 liters?","options":["40","50","60","70"],"explanation":"Solve 50 - 0.5t = 20, so 0.5t = 30 and t = 60 minutes.","skill":"linear equations in two variables"},{"cat":"algebra","a":1,"q":"A scientist models the height H, in meters, of a draining tank as H = 12 - 0.8t, where t is in minutes. What is the height after 5 minutes?","options":["7 meters","8 meters","8.4 meters","9 meters"],"explanation":"Substitute t = 5: H = 12 - 0.8(5) = 12 - 4 = 8 meters.","skill":"linear functions"},{"cat":"algebra","a":3,"q":"The system 2x + 5y = 20 and 2x + 5y = 35 has how many solutions?","options":["Exactly one","Exactly two","Infinitely many","Zero"],"explanation":"The two lines have the same left side but different constants, so they are parallel and never intersect: zero solutions.","skill":"systems of linear equations"},{"cat":"algebra","a":1,"q":"A vendor sells small drinks for $2 and large drinks for $5. On one day the vendor sells 30 drinks for a total of $96. How many large drinks were sold?","options":["10","12","18","20"],"explanation":"Let L be large drinks: 5L + 2(30 - L) = 96, so 3L + 60 = 96, 3L = 36, L = 12.","skill":"systems of linear equations"},{"cat":"algebra","a":2,"q":"For what value of k does the system y = 5x + 2 and y = kx - 7 have no solution?","options":["-5","2","5","7"],"explanation":"Parallel lines with different intercepts have no solution. They need equal slopes, so k = 5.","skill":"systems of linear equations"},{"cat":"algebra","a":2,"q":"Gym plan A costs $20 per month plus a $50 sign-up fee. Plan B costs $30 per month with no sign-up fee. After how many months do the two plans cost the same?","options":["3","4","5","6"],"explanation":"Set 20m + 50 = 30m, so 50 = 10m and m = 5 months.","skill":"systems of linear equations"},{"cat":"algebra","a":2,"q":"A delivery van can carry at most 1,200 kg. It already holds 480 kg of equipment and will load boxes weighing 24 kg each. What is the greatest number of boxes b it can add without exceeding the limit?","options":["28","29","30","31"],"explanation":"Solve 480 + 24b <= 1200, so 24b <= 720 and b <= 30. The greatest whole number is 30.","skill":"linear inequalities in one variable"},{"cat":"algebra","a":0,"q":"A line passes through (-4, 9) and (2, -3). Which equation represents this line in slope-intercept form?","options":["y = -2x + 1","y = -2x + 9","y = 2x + 1","y = -3x + 1"],"explanation":"Slope = (-3 - 9)/(2 - (-4)) = -12/6 = -2. Using (2, -3): -3 = -2(2) + b, so b = 1. Thus y = -2x + 1.","skill":"linear functions"},{"cat":"advanced","a":1,"q":"If f(x) = 3x^2 - 5, what is the value of f(2)?","options":["1","7","13","31"],"explanation":"Substitute x = 2: f(2) = 3(2)^2 - 5 = 3(4) - 5 = 12 - 5 = 7. The correct answer is 7.","skill":"function notation and nonlinear relationships"},{"cat":"advanced","a":0,"q":"What is the product of (x + 4)(x - 4)?","options":["x^2 - 16","x^2 + 16","x^2 - 8x - 16","x^2 - 8"],"explanation":"This is a difference of squares: (x + 4)(x - 4) = x^2 - 4^2 = x^2 - 16. The correct answer is x^2 - 16.","skill":"polynomial expressions"},{"cat":"advanced","a":0,"q":"Simplify the expression x^7 / x^3, where x is not equal to 0.","options":["x^4","x^10","x^21","x^(7/3)"],"explanation":"When dividing powers with the same base, subtract exponents: x^7 / x^3 = x^(7-3) = x^4. The correct answer is x^4.","skill":"exponents and radicals"},{"cat":"advanced","a":1,"q":"What are the solutions to the equation x^2 - 9x + 20 = 0?","options":["x = -4 and x = -5","x = 4 and x = 5","x = 2 and x = 10","x = -2 and x = -10"],"explanation":"Factor: x^2 - 9x + 20 = (x - 4)(x - 5) = 0, since (-4)(-5) = 20 and -4 + -5 = -9. So x = 4 or x = 5. The correct answer is x = 4 and x = 5.","skill":"quadratic equations and functions"},{"cat":"advanced","a":1,"q":"A population of bacteria starts at 200 cells and doubles every hour. Which function gives the number of cells P after t hours?","options":["P = 200 + 2t","P = 200(2)^t","P = 2(200)^t","P = 200t^2"],"explanation":"Exponential growth with an initial value of 200 and a growth factor of 2 per hour gives P = 200(2)^t. The correct answer is P = 200(2)^t.","skill":"exponential functions and growth/decay"},{"cat":"advanced","a":0,"q":"Simplify the rational expression (6x^2) / (3x), where x is not equal to 0.","options":["2x","2x^2","3x","18x^3"],"explanation":"Divide coefficients: 6/3 = 2. Divide powers: x^2 / x = x. So (6x^2)/(3x) = 2x. The correct answer is 2x.","skill":"rational expressions"},{"cat":"advanced","a":0,"q":"What is the value of 16^(1/2)?","options":["4","8","32","256"],"explanation":"A fractional exponent of 1/2 means the square root: 16^(1/2) = sqrt(16) = 4. The correct answer is 4.","skill":"exponents and radicals"},{"cat":"advanced","a":1,"q":"Expand and simplify (x + 3)^2.","options":["x^2 + 9","x^2 + 6x + 9","x^2 + 3x + 9","x^2 + 6x + 6"],"explanation":"(x + 3)^2 = x^2 + 2(3)x + 3^2 = x^2 + 6x + 9. The correct answer is x^2 + 6x + 9.","skill":"polynomial expressions"},{"cat":"advanced","a":0,"q":"If g(x) = x^2 + 2x, for what value of x does g(x) = 0 besides x = 0?","options":["x = -2","x = 2","x = -1","x = 1"],"explanation":"Set g(x) = 0: x^2 + 2x = x(x + 2) = 0. So x = 0 or x + 2 = 0, giving x = -2. The correct answer is x = -2.","skill":"function notation and nonlinear relationships"},{"cat":"advanced","a":0,"q":"The value of a car is $24,000 and decreases by 10% each year. Which expression gives the value V after t years?","options":["V = 24000(0.90)^t","V = 24000(1.10)^t","V = 24000(0.10)^t","V = 24000 - 0.10t"],"explanation":"A 10% annual decrease means each year the value is multiplied by 1 - 0.10 = 0.90. So V = 24000(0.90)^t. The correct answer is V = 24000(0.90)^t.","skill":"exponential functions and growth/decay"},{"cat":"advanced","a":0,"q":"Simplify sqrt(50).","options":["5 sqrt(2)","2 sqrt(5)","25 sqrt(2)","5 sqrt(10)"],"explanation":"Factor out a perfect square: sqrt(50) = sqrt(25 * 2) = sqrt(25) * sqrt(2) = 5 sqrt(2). The correct answer is 5 sqrt(2).","skill":"exponents and radicals"},{"cat":"advanced","a":0,"q":"What is the sum of the polynomials (2x^2 + 3x - 1) and (x^2 - 5x + 4)?","options":["3x^2 - 2x + 3","3x^2 + 8x + 3","x^2 - 2x + 3","3x^2 - 2x - 5"],"explanation":"Combine like terms: (2x^2 + x^2) + (3x - 5x) + (-1 + 4) = 3x^2 - 2x + 3. The correct answer is 3x^2 - 2x + 3.","skill":"polynomial expressions"},{"cat":"advanced","a":0,"q":"The function h(x) = 2x^2 - 8 has its minimum value at x = 0. What is that minimum value?","options":["-8","0","8","-4"],"explanation":"Since the squared term is smallest (equal to 0) when x = 0, the minimum of h is h(0) = 2(0)^2 - 8 = -8. The correct answer is -8.","skill":"quadratic equations and functions"},{"cat":"advanced","a":0,"q":"For x not equal to 3, simplify (x^2 - 9) / (x - 3).","options":["x + 3","x - 3","x + 9","x^2 - 6"],"explanation":"Factor the numerator as a difference of squares: x^2 - 9 = (x - 3)(x + 3). Cancel (x - 3): the result is x + 3. The correct answer is x + 3.","skill":"rational expressions"},{"cat":"advanced","a":0,"q":"An investment of $5,000 earns 4% interest compounded annually. Which expression gives its value after 3 years?","options":["5000(1.04)^3","5000(0.04)^3","5000(4)^3","5000 + 3(0.04)"],"explanation":"Compound growth multiplies by (1 + 0.04) = 1.04 each year for 3 years: 5000(1.04)^3. The correct answer is 5000(1.04)^3.","skill":"exponential functions and growth/decay"},{"cat":"advanced","a":0,"q":"If f(x) = x^2 - 4x + 7, what is f(x + 1) - f(x) in simplest form?","options":["2x - 3","2x + 3","-2x + 3","2x - 11"],"explanation":"f(x+1) = (x+1)^2 - 4(x+1) + 7 = x^2 + 2x + 1 - 4x - 4 + 7 = x^2 - 2x + 4. Subtract f(x) = x^2 - 4x + 7: (x^2 - 2x + 4) - (x^2 - 4x + 7) = 2x - 3. The correct answer is 2x - 3.","skill":"function notation and nonlinear relationships"},{"cat":"advanced","a":0,"q":"What is the quotient when 2x^3 - 3x^2 + 4x - 6 is divided by (x - 1) plus the remainder, expressed as the remainder only?","options":["-3","3","-6","0"],"explanation":"By the Remainder Theorem, the remainder equals the polynomial evaluated at x = 1: 2(1)^3 - 3(1)^2 + 4(1) - 6 = 2 - 3 + 4 - 6 = -3. The correct answer is -3.","skill":"polynomial expressions"},{"cat":"advanced","a":0,"q":"The quadratic equation x^2 + kx + 16 = 0 has exactly one real solution. What is a possible value of k?","options":["8","4","16","2"],"explanation":"One real solution requires the discriminant to equal 0: k^2 - 4(1)(16) = 0, so k^2 = 64 and k = 8 or k = -8. Of the choices, 8 works. The correct answer is 8.","skill":"quadratic equations and functions"},{"cat":"advanced","a":0,"q":"Simplify the expression (2x^2 y)^3.","options":["8x^6 y^3","6x^5 y^3","8x^5 y^3","2x^6 y^3"],"explanation":"Raise each factor to the 3rd power: 2^3 = 8, (x^2)^3 = x^6, y^3 = y^3. So (2x^2 y)^3 = 8x^6 y^3. The correct answer is 8x^6 y^3.","skill":"exponents and radicals"},{"cat":"advanced","a":0,"q":"Add the rational expressions 1/x + 2/(x+1), where x is not 0 or -1. What is the result as a single fraction?","options":["(3x + 1) / (x(x+1))","3 / (2x + 1)","(x + 1) / (x(x+1))","(2x + 1) / (x(x+1))"],"explanation":"Common denominator x(x+1): 1/x = (x+1)/(x(x+1)) and 2/(x+1) = 2x/(x(x+1)). Sum of numerators: (x + 1) + 2x = 3x + 1. Result: (3x + 1)/(x(x+1)). The correct answer is (3x + 1)/(x(x+1)).","skill":"rational expressions"},{"cat":"advanced","a":0,"q":"A radioactive sample has a half-life of 5 years. If 80 grams remain now, how many grams will remain after 15 years?","options":["10","20","40","5"],"explanation":"15 years is 15/5 = 3 half-lives. Each half-life halves the amount: 80 -> 40 -> 20 -> 10. After 3 half-lives, 10 grams remain. The correct answer is 10.","skill":"exponential functions and growth/decay"},{"cat":"advanced","a":0,"q":"The function f is defined by f(x) = a(x - 2)(x + 6). The graph of y = f(x) in the xy-plane has its vertex at x = h. What is the value of h?","options":["-2","2","4","-6"],"explanation":"The x-coordinate of the vertex is halfway between the zeros x = 2 and x = -6: h = (2 + (-6))/2 = -4/2 = -2. The correct answer is -2.","skill":"quadratic equations and functions"},{"cat":"advanced","a":0,"q":"If x^(2/3) = 9, what is the value of x, assuming x is positive?","options":["27","3","729","18"],"explanation":"Raise both sides to the 3/2 power: x = 9^(3/2) = (sqrt(9))^3 = 3^3 = 27. The correct answer is 27.","skill":"exponents and radicals"},{"cat":"advanced","a":0,"q":"The expression (x^2 - 5x + 6) / (x^2 - 4) is equivalent to which of the following, for x not equal to 2 or -2?","options":["(x - 3) / (x + 2)","(x - 3) / (x - 2)","(x + 3) / (x + 2)","(x - 2) / (x + 2)"],"explanation":"Factor: numerator x^2 - 5x + 6 = (x - 2)(x - 3); denominator x^2 - 4 = (x - 2)(x + 2). Cancel (x - 2): (x - 3)/(x + 2). The correct answer is (x - 3)/(x + 2).","skill":"rational expressions"},{"cat":"advanced","a":0,"q":"The quadratic function f(x) = x^2 - 6x + 11 can be written in vertex form. What is the minimum value of f(x)?","options":["2","11","-3","3"],"explanation":"Complete the square: x^2 - 6x + 11 = (x^2 - 6x + 9) + 2 = (x - 3)^2 + 2. The minimum occurs at x = 3, giving a value of 2. The correct answer is 2.","skill":"quadratic equations and functions"},{"cat":"advanced","a":0,"q":"A culture of bacteria triples every 4 hours. If there are 50 bacteria initially, which expression gives the number after t hours?","options":["50(3)^(t/4)","50(3)^(4t)","50(3)^t * 4","50(3/4)^t"],"explanation":"The number of tripling periods in t hours is t/4, so the count is 50(3)^(t/4). For example, at t = 4 this gives 50(3)^1 = 150, which is triple. The correct answer is 50(3)^(t/4).","skill":"exponential functions and growth/decay"},{"cat":"advanced","a":2,"q":"If f(x) = 2x^2 + 1, what is the value of f(3)?","options":["7","13","19","37"],"explanation":"f(3) = 2(3)^2 + 1 = 2(9) + 1 = 18 + 1 = 19.","skill":"function notation"},{"cat":"advanced","a":0,"q":"What is the value of 27^(1/3)?","options":["3","6","9","13.5"],"explanation":"27^(1/3) is the cube root of 27, which is 3 because 3^3 = 27.","skill":"exponents and radicals"},{"cat":"advanced","a":0,"q":"What is the product of the expression (x + 5)(x + 2)?","options":["x^2 + 7x + 10","x^2 + 10x + 7","x^2 + 3x + 10","x^2 + 7x + 7"],"explanation":"Using FOIL: x*x + x*2 + 5*x + 5*2 = x^2 + 2x + 5x + 10 = x^2 + 7x + 10.","skill":"polynomials"},{"cat":"advanced","a":0,"q":"Simplify the rational expression (10x^3) / (5x^2), where x is not equal to 0.","options":["2x","2x^5","5x","2"],"explanation":"Divide coefficients: 10/5 = 2. Subtract exponents: x^(3-2) = x^1. The result is 2x.","skill":"rational expressions"},{"cat":"advanced","a":1,"q":"What are the solutions to the equation x^2 - 7x + 12 = 0?","options":["x = 2 and x = 6","x = 3 and x = 4","x = 1 and x = 12","x = -3 and x = -4"],"explanation":"Factor: (x - 3)(x - 4) = 0, since 3 and 4 multiply to 12 and add to 7. So x = 3 or x = 4.","skill":"quadratics"},{"cat":"advanced","a":1,"q":"A sample of 500 cells of a microorganism triples every hour. Which function gives the number of cells N after t hours?","options":["N = 500 + 3t","N = 500 * 3^t","N = 500 * t^3","N = 3 * 500^t"],"explanation":"Tripling every hour means multiplying by 3 each hour, so N = 500 * 3^t. This is exponential growth with base 3.","skill":"exponential growth/decay"},{"cat":"advanced","a":0,"q":"Simplify the expression sqrt(72).","options":["6 sqrt(2)","8 sqrt(3)","2 sqrt(18)","36 sqrt(2)"],"explanation":"72 = 36 * 2, so sqrt(72) = sqrt(36) * sqrt(2) = 6 sqrt(2).","skill":"exponents and radicals"},{"cat":"advanced","a":0,"q":"What is the result of subtracting (x^2 - 4x + 5) from (3x^2 + 2x - 1)?","options":["2x^2 + 6x - 6","2x^2 - 2x + 4","4x^2 - 2x + 4","2x^2 - 6x + 6"],"explanation":"(3x^2 + 2x - 1) - (x^2 - 4x + 5) = 3x^2 - x^2 + 2x + 4x - 1 - 5 = 2x^2 + 6x - 6.","skill":"polynomials"},{"cat":"advanced","a":2,"q":"Expand and simplify (x - 4)^2.","options":["x^2 - 16","x^2 + 16","x^2 - 8x + 16","x^2 - 8x - 16"],"explanation":"(x - 4)^2 = x^2 - 2(4)(x) + 16 = x^2 - 8x + 16.","skill":"polynomials"},{"cat":"advanced","a":1,"q":"If g(x) = x^2 - 5x, for what positive value of x does g(x) = 0?","options":["2","5","-5","10"],"explanation":"Factor: x(x - 5) = 0, so x = 0 or x = 5. The positive value is 5.","skill":"quadratics"},{"cat":"advanced","a":0,"q":"The price of a laptop is $800 and increases by 5% each year. Which expression gives its price after t years?","options":["800(1.05)^t","800(0.95)^t","800(1 + 5)^t","800 + 1.05t"],"explanation":"A 5% annual increase multiplies by 1.05 each year, so the price after t years is 800(1.05)^t.","skill":"exponential growth/decay"},{"cat":"advanced","a":0,"q":"Simplify the expression (3x^4 y^2)^2.","options":["9x^8 y^4","6x^8 y^4","9x^6 y^4","3x^8 y^4"],"explanation":"Raise each factor to the power 2: 3^2 = 9, (x^4)^2 = x^8, (y^2)^2 = y^4. The result is 9x^8 y^4.","skill":"exponents and radicals"},{"cat":"advanced","a":0,"q":"For x not equal to 5, simplify (x^2 - 25) / (x + 5).","options":["x - 5","x + 5","x - 25","x^2 - 5"],"explanation":"x^2 - 25 = (x + 5)(x - 5). Cancel (x + 5): the result is x - 5.","skill":"rational expressions"},{"cat":"advanced","a":0,"q":"If f(x) = 4x - 3, what is the value of f(2a) in terms of a?","options":["8a - 3","8a - 6","4a - 3","2a - 3"],"explanation":"Substitute 2a for x: f(2a) = 4(2a) - 3 = 8a - 3.","skill":"function notation"},{"cat":"advanced","a":2,"q":"The function h(x) = -2x^2 + 8 has its maximum value at x = 0. What is that maximum value?","options":["0","2","8","-8"],"explanation":"At x = 0, h(0) = -2(0)^2 + 8 = 8. Since the leading coefficient is negative, this vertex value is the maximum.","skill":"quadratics"},{"cat":"advanced","a":0,"q":"What is the sum of the rational expressions 3/x + 1/(2x), where x is not equal to 0?","options":["7/(2x)","4/(3x)","4/(2x)","3/(2x^2)"],"explanation":"Common denominator 2x: 3/x = 6/(2x). Then 6/(2x) + 1/(2x) = 7/(2x).","skill":"rational expressions"},{"cat":"advanced","a":2,"q":"If x^(3/2) = 27, what is the value of x, assuming x is positive?","options":["3","6","9","81"],"explanation":"Raise both sides to the 2/3 power: x = 27^(2/3) = (27^(1/3))^2 = 3^2 = 9.","skill":"exponents and radicals"},{"cat":"advanced","a":2,"q":"A radioactive isotope has a half-life of 3 days. If 64 grams are present now, how many grams remain after 9 days?","options":["32","16","8","4"],"explanation":"9 days is three half-lives. 64 -> 32 -> 16 -> 8 grams. After three halvings, 8 grams remain.","skill":"exponential growth/decay"},{"cat":"advanced","a":2,"q":"The quadratic equation x^2 + 6x + c = 0 has exactly one real solution. What is the value of c?","options":["3","6","9","36"],"explanation":"One real solution means the discriminant is 0: 6^2 - 4c = 0, so 36 = 4c and c = 9.","skill":"quadratics"},{"cat":"advanced","a":0,"q":"If f(x) = x^2 + 3x, what is f(x - 2) in simplest form?","options":["x^2 - x - 2","x^2 - x + 2","x^2 + 3x - 2","x^2 - 4x + 2"],"explanation":"f(x - 2) = (x - 2)^2 + 3(x - 2) = x^2 - 4x + 4 + 3x - 6 = x^2 - x - 2.","skill":"function notation"},{"cat":"advanced","a":1,"q":"The function f is defined by f(x) = a(x - 1)(x + 5). The graph of y = f(x) in the xy-plane passes through (0, -10). What is the value of a?","options":["1","2","-2","5"],"explanation":"At x = 0: f(0) = a(-1)(5) = -5a. Set -5a = -10, so a = 2.","skill":"quadratics"},{"cat":"advanced","a":0,"q":"The expression (x^2 + 2x - 8) / (x^2 - 4) is equivalent to which of the following, for x not equal to 2 or -2?","options":["(x + 4)/(x + 2)","(x - 4)/(x - 2)","(x + 4)/(x - 2)","(x - 2)/(x + 2)"],"explanation":"Factor: x^2 + 2x - 8 = (x + 4)(x - 2) and x^2 - 4 = (x + 2)(x - 2). Cancel (x - 2): (x + 4)/(x + 2).","skill":"rational expressions"},{"cat":"advanced","a":0,"q":"The quadratic function f(x) = x^2 + 8x + 19 is written in vertex form. What is the minimum value of f?","options":["3","-4","19","8"],"explanation":"Complete the square: x^2 + 8x + 19 = (x + 4)^2 - 16 + 19 = (x + 4)^2 + 3. The minimum value is 3.","skill":"quadratics"},{"cat":"advanced","a":1,"q":"If 2^(x+3) = 64, what is the value of x?","options":["2","3","5","6"],"explanation":"64 = 2^6, so x + 3 = 6 and x = 3.","skill":"exponents and radicals"},{"cat":"advanced","a":0,"q":"What is the remainder when the polynomial p(x) = x^3 - 2x^2 + 4x - 5 is divided by (x - 2)?","options":["3","-5","8","11"],"explanation":"By the Remainder Theorem, the remainder equals p(2) = 8 - 8 + 8 - 5 = 3.","skill":"polynomials"},{"cat":"advanced","a":0,"q":"For x not equal to 0 or 3, simplify the complex fraction (1/x - 1/3) / (x - 3).","options":["-1/(3x)","1/(3x)","-1/(x - 3)","1/(x^2 - 3x)"],"explanation":"The numerator 1/x - 1/3 = (3 - x)/(3x). Dividing by (x - 3): (3 - x)/(3x(x - 3)) = -(x - 3)/(3x(x - 3)) = -1/(3x).","skill":"rational expressions"},{"cat":"data","a":2,"q":"In a class, the ratio of boys to girls is 3 to 5. If there are 24 boys, how many girls are in the class?","options":["8","14","40","64"],"explanation":"The ratio boys:girls is 3:5. With 24 boys, each part equals 24/3 = 8. Girls = 5 parts = 5 x 8 = 40.","skill":"ratios"},{"cat":"data","a":1,"q":"A car travels at a constant speed of 180 miles in 3 hours. At this rate, how many miles will it travel in 5 hours?","options":["240","300","360","540"],"explanation":"The rate is 180/3 = 60 miles per hour. In 5 hours it travels 60 x 5 = 300 miles.","skill":"rates"},{"cat":"data","a":1,"q":"A jacket originally priced at $80 is increased in price by 15%. What is the new price?","options":["$88","$92","$95","$120"],"explanation":"A 15% increase adds 0.15 x 80 = 12 dollars. New price = 80 + 12 = 92 dollars.","skill":"percentages"},{"cat":"data","a":2,"q":"A hiking trail is 2.5 kilometers long. How many meters long is the trail? (1 kilometer = 1000 meters)","options":["25 meters","250 meters","2,500 meters","25,000 meters"],"explanation":"Multiply by 1000: 2.5 x 1000 = 2,500 meters.","skill":"unit conversion"},{"cat":"data","a":1,"q":"The five quiz scores recorded for a student are 4, 8, 10, 6, and 12. What is the mean of these scores?","options":["6","8","10","40"],"explanation":"Sum = 4 + 8 + 10 + 6 + 12 = 40. Mean = 40/5 = 8.","skill":"mean/median/mode/range"},{"cat":"data","a":1,"q":"If 4 identical pens cost $6.00, what is the cost of 10 of these pens at the same unit price?","options":["$12.00","$15.00","$18.00","$24.00"],"explanation":"Unit cost = 6/4 = 1.5 dollars per pen. Ten pens cost 1.5 x 10 = 15 dollars.","skill":"proportions"},{"cat":"data","a":1,"q":"What is 30% of 250?","options":["55","75","83","750"],"explanation":"30% = 0.30, and 0.30 x 250 = 75.","skill":"percentages"},{"cat":"data","a":1,"q":"A data set consists of the values 7, 3, 9, 5, and 11. What is the median of this data set?","options":["5","7","9","11"],"explanation":"Ordered: 3, 5, 7, 9, 11. The middle value of five numbers is the third one, 7.","skill":"mean/median/mode/range"},{"cat":"data","a":1,"q":"A typist types 240 words in 4 minutes at a constant rate. At this rate, how many words can the typist type in 7 minutes?","options":["360","420","480","960"],"explanation":"Rate = 240/4 = 60 words per minute. In 7 minutes: 60 x 7 = 420 words.","skill":"rates"},{"cat":"data","a":2,"q":"A backpack is marked at $60. During a sale it is discounted 25%. What is the sale price?","options":["$15","$35","$45","$48"],"explanation":"A 25% discount means paying 75% of the price: 0.75 x 60 = 45 dollars.","skill":"percentages"},{"cat":"data","a":2,"q":"A package weighs 3 pounds. How many ounces does it weigh? (1 pound = 16 ounces)","options":["19 ounces","32 ounces","48 ounces","64 ounces"],"explanation":"Multiply by 16: 3 x 16 = 48 ounces.","skill":"unit conversion"},{"cat":"data","a":2,"q":"The high temperatures over five days were 12, 18, 7, 25, and 15 degrees. What is the range of these temperatures?","options":["13","15","18","25"],"explanation":"Range = maximum - minimum = 25 - 7 = 18 degrees.","skill":"mean/median/mode/range"},{"cat":"data","a":2,"q":"A recipe uses flour and sugar in a ratio of 2 to 3. If a baker uses 8 cups of flour, how many cups of sugar are needed to keep the same ratio?","options":["5 cups","10 cups","12 cups","16 cups"],"explanation":"Each part equals 8/2 = 4 cups. Sugar = 3 parts = 3 x 4 = 12 cups.","skill":"ratios"},{"cat":"data","a":2,"q":"A bag contains 5 red, 3 blue, and 2 green marbles. If one marble is drawn at random, what is the probability that it is red?","options":["1/5","3/10","1/2","5/8"],"explanation":"Total marbles = 5 + 3 + 2 = 10. P(red) = 5/10 = 1/2.","skill":"probability"},{"cat":"data","a":2,"q":"The number of members in a club grew from 40 to 50 over one year. What was the percent increase in membership?","options":["10%","20%","25%","50%"],"explanation":"Increase = 50 - 40 = 10. Percent increase = 10/40 x 100 = 25%.","skill":"percentages"},{"cat":"data","a":1,"q":"A teacher records the following test scores: 4, 7, 7, 9, 2, 7, and 5. What is the mode of this data set?","options":["5","7","9","41"],"explanation":"The mode is the value that appears most often. The value 7 appears three times, more than any other.","skill":"mean/median/mode/range"},{"cat":"data","a":2,"q":"On a map, 1 inch represents 25 actual miles. Two cities are 4.5 inches apart on the map. What is the actual distance between them?","options":["29.5 miles","100 miles","112.5 miles","125 miles"],"explanation":"Multiply the map distance by the scale: 4.5 x 25 = 112.5 miles.","skill":"proportions"},{"cat":"data","a":2,"q":"The mean of 5 numbers is 12. A sixth number is added so that the mean of all 6 numbers becomes 14. What is the value of the sixth number?","options":["14","20","24","26"],"explanation":"Original sum = 12 x 5 = 60. New sum = 14 x 6 = 84. The sixth number = 84 - 60 = 24.","skill":"mean/median/mode/range"},{"cat":"data","a":1,"q":"28 is what percent of 80?","options":["28%","35%","52%","45%"],"explanation":"Percent = 28/80 x 100 = 35%.","skill":"percentages"},{"cat":"data","a":2,"q":"Three identical machines together produce 600 parts in 2 hours. Working at the same rate, how many parts can 5 of these machines produce in 2 hours?","options":["360","720","1,000","1,200"],"explanation":"Each machine makes 600/3 = 200 parts in 2 hours. Five machines make 5 x 200 = 1,000 parts in 2 hours.","skill":"rates"},{"cat":"data","a":2,"q":"A jar contains 12 marbles, of which 4 are red. If one marble is drawn at random, what is the probability that it is NOT red?","options":["1/3","1/2","2/3","3/4"],"explanation":"Not-red marbles = 12 - 4 = 8. P(not red) = 8/12 = 2/3.","skill":"probability"},{"cat":"data","a":2,"q":"A scatterplot relating study hours x to test score y has a line of best fit modeled by y = 2.5x + 10. Based on this model, what score is predicted for a student who studies 8 hours?","options":["20","26","30","45"],"explanation":"Substitute x = 8: y = 2.5(8) + 10 = 20 + 10 = 30.","skill":"scatterplots and line of best fit"},{"cat":"data","a":1,"q":"A town has 2,000 residents. 60% of them are adults, and 40% of the adults are employed full time. How many residents are employed full-time adults?","options":["320","480","800","1,200"],"explanation":"Adults = 0.60 x 2000 = 1,200. Employed adults = 0.40 x 1200 = 480.","skill":"percentages"},{"cat":"data","a":1,"q":"In a survey, 52% of respondents supported a measure, with a margin of error of 3 percentage points. Which interval is most likely to contain the true percentage of all voters who support the measure?","options":["49% to 52%","49% to 55%","52% to 55%","46% to 58%"],"explanation":"The interval is the estimate plus or minus the margin of error: 52% - 3% = 49% and 52% + 3% = 55%, giving 49% to 55%.","skill":"sample statistics and margin of error"},{"cat":"data","a":1,"q":"Class A has 20 students with an average score of 80, and Class B has 30 students with an average score of 90. What is the average score of all 50 students combined?","options":["85","86","87","88"],"explanation":"Total points = 20 x 80 + 30 x 90 = 1600 + 2700 = 4300. Combined average = 4300/50 = 86.","skill":"interpreting graphs and tables"},{"cat":"data","a":1,"q":"An investment of $500 increases by 20% in the first year and then decreases by 20% in the second year. What is its value at the end of the second year?","options":["$460","$480","$500","$520"],"explanation":"After year 1: 500 x 1.20 = 600. After year 2: 600 x 0.80 = 480. The successive percent changes do not cancel.","skill":"percentages"},{"cat":"data","a":1,"q":"A paint mixture uses blue paint and yellow paint in a ratio of 7 to 4. If the mixture contains 28 ounces of blue paint, how many ounces of yellow paint does it contain?","options":["11","16","18","49"],"explanation":"The ratio of blue to yellow is 7 to 4. Since 28 ounces of blue is 4 times 7, multiply 4 by 4 to get 16 ounces of yellow.","skill":"ratios"},{"cat":"data","a":2,"q":"What is 45% of 60?","options":["15","21","27","105"],"explanation":"45% of 60 equals 0.45 times 60, which is 27.","skill":"percentages"},{"cat":"data","a":2,"q":"A bottle holds 4.2 liters of water. How many milliliters does it hold? (1 liter = 1,000 milliliters)","options":["42","420","4,200","42,000"],"explanation":"Multiply 4.2 liters by 1,000 milliliters per liter to get 4,200 milliliters.","skill":"unit conversion"},{"cat":"data","a":0,"q":"The five values in a data set are 9, 14, 11, 6, and 10. What is the mean of these values?","options":["10","11","12","50"],"explanation":"The sum is 9 + 14 + 11 + 6 + 10 = 50. Dividing by 5 gives a mean of 10.","skill":"mean/median/mode/range"},{"cat":"data","a":2,"q":"A package weighs 3.5 pounds. How many ounces does it weigh? (1 pound = 16 ounces)","options":["19.5","48","56","64"],"explanation":"Multiply 3.5 pounds by 16 ounces per pound to get 56 ounces.","skill":"unit conversion"},{"cat":"data","a":1,"q":"A car travels 150 miles in 2.5 hours at a constant speed. At this rate, how many miles will it travel in 6 hours?","options":["300","360","375","450"],"explanation":"The speed is 150 divided by 2.5 = 60 miles per hour. In 6 hours the car travels 60 times 6 = 360 miles.","skill":"rates"},{"cat":"data","a":1,"q":"If 6 identical notebooks cost $9.00, what is the cost of 15 of these notebooks at the same unit price?","options":["$18.00","$22.50","$24.00","$27.00"],"explanation":"Each notebook costs 9.00 divided by 6 = $1.50. Then 15 notebooks cost 15 times 1.50 = $22.50.","skill":"proportions"},{"cat":"data","a":1,"q":"18 is what percent of 72?","options":["20%","25%","30%","40%"],"explanation":"Divide 18 by 72 to get 0.25, which equals 25%.","skill":"percentages"},{"cat":"data","a":1,"q":"The high temperatures recorded over six days were 23, 8, 15, 31, 19, and 11 degrees. What is the range of these temperatures?","options":["19","23","31","39"],"explanation":"The range is the maximum minus the minimum: 31 - 8 = 23 degrees.","skill":"mean/median/mode/range"},{"cat":"data","a":3,"q":"A sweater is priced at $120. The store increases the price by 30%. What is the new price?","options":["$36","$90","$150","$156"],"explanation":"A 30% increase adds 0.30 times 120 = $36. The new price is 120 + 36 = $156.","skill":"percentages"},{"cat":"data","a":1,"q":"A data set consists of the values 14, 9, 21, 6, 17, and 11. What is the median of this data set?","options":["11","12.5","13","14"],"explanation":"Sorted, the values are 6, 9, 11, 14, 17, 21. With six values, the median is the average of the third and fourth: (11 + 14) divided by 2 = 12.5.","skill":"mean/median/mode/range"},{"cat":"data","a":2,"q":"On a map, 1 centimeter represents 8 actual kilometers. Two towns are 7.5 centimeters apart on the map. What is the actual distance between them?","options":["15 km","56 km","60 km","75 km"],"explanation":"Multiply 7.5 centimeters by 8 kilometers per centimeter to get 60 kilometers.","skill":"proportions"},{"cat":"data","a":2,"q":"A bag contains 6 red marbles, 4 blue marbles, and 5 green marbles. If one marble is drawn at random, what is the probability that it is not blue?","options":["4/15","6/15","11/15","4/11"],"explanation":"There are 15 marbles total, and 6 + 5 = 11 are not blue. The probability is 11/15.","skill":"probability"},{"cat":"data","a":2,"q":"A scatterplot relating advertising spending x (in thousands of dollars) to sales y (in thousands of units) has a line of best fit modeled by y = 2.5x + 40. Based on this model, what is the predicted value of y when x = 12?","options":["52","64","70","82"],"explanation":"Substitute x = 12: y = 2.5(12) + 40 = 30 + 40 = 70.","skill":"scatterplots"},{"cat":"data","a":2,"q":"The mean of 6 numbers is 15. When one of the numbers is removed, the mean of the remaining 5 numbers is 13. What is the value of the number that was removed?","options":["13","15","25","28"],"explanation":"The sum of the 6 numbers is 6 times 15 = 90. The sum of the 5 remaining numbers is 5 times 13 = 65. The removed number is 90 - 65 = 25.","skill":"mean/median/mode/range"},{"cat":"data","a":1,"q":"In a survey, 48% of respondents preferred the new design, with a margin of error of 4 percentage points. Which of the following gives the most plausible range for the true percent of all people who prefer the new design?","options":["Between 44% and 48%","Between 44% and 52%","Between 46% and 50%","Between 48% and 52%"],"explanation":"The margin of error extends 4 points in each direction from 48%, giving a range from 44% to 52%.","skill":"sample statistics"},{"cat":"data","a":2,"q":"Five identical machines together produce 400 bottles in 8 minutes, all working at the same constant rate. At this rate, how many bottles can 8 such machines produce in 5 minutes?","options":["320","360","400","500"],"explanation":"Each machine produces 400 divided by (5 machines times 8 minutes) = 10 bottles per minute. Then 8 machines in 5 minutes produce 8 times 10 times 5 = 400 bottles.","skill":"rates"},{"cat":"data","a":0,"q":"A town has 3,000 residents. 55% of them are adults, and 20% of the adults own their home. How many residents are adults who own their home?","options":["330","600","1,100","1,650"],"explanation":"The number of adults is 0.55 times 3,000 = 1,650. Of these, 0.20 times 1,650 = 330 own their home.","skill":"percentages"},{"cat":"data","a":1,"q":"Class A has 25 students with an average test score of 88, and Class B has 15 students with an average test score of 72. What is the average score of all 40 students combined?","options":["80","82","84","160"],"explanation":"Total points = 25(88) + 15(72) = 2,200 + 1,080 = 3,280. Dividing by 40 students gives an average of 82.","skill":"mean/median/mode/range"},{"cat":"data","a":1,"q":"A store sells a 12-ounce box of cereal for $3.60 and a 20-ounce box of the same cereal for $5.40. Which box has the lower price per ounce, and what is that price per ounce?","options":["The 12-ounce box, at $0.27 per ounce","The 20-ounce box, at $0.27 per ounce","The 12-ounce box, at $0.30 per ounce","The 20-ounce box, at $0.30 per ounce"],"explanation":"The 12-ounce box costs 3.60/12 = $0.30 per ounce; the 20-ounce box costs 5.40/20 = $0.27 per ounce. The 20-ounce box is cheaper per ounce at $0.27.","skill":"rates"},{"cat":"data","a":1,"q":"A frequency table records the following data: the value 2 appears 3 times, the value 3 appears 5 times, the value 4 appears 4 times, and the value 5 appears 2 times. What is the median of this data set?","options":["2.5","3","3.5","4"],"explanation":"There are 14 values total, so the median is the average of the 7th and 8th values. Counting in order (three 2s, then five 3s), both the 7th and 8th values are 3, so the median is 3.","skill":"graphs/tables"},{"cat":"data","a":1,"q":"The price of a stock decreased from $250 to $190 over one month. What was the percent decrease in the price?","options":["18%","24%","30%","32%"],"explanation":"The decrease is 250 - 190 = 60. The percent decrease is 60/250 = 0.24, which is 24%.","skill":"percentages"},{"cat":"data","a":1,"q":"A jar contains 20 marbles, of which 8 are red. Two marbles are drawn at random, one after the other, without replacement. What is the probability that both marbles drawn are red?","options":["4/25","14/95","2/5","56/95"],"explanation":"The probability the first is red is 8/20. After removing one red, the probability the second is red is 7/19. Multiplying gives (8/20)(7/19) = 56/380 = 14/95.","skill":"probability"},{"cat":"data","a":2,"q":"An investment of $2,000 decreases in value by 15% during the first year and then increases by 40% during the second year. What is the value of the investment at the end of the second year?","options":["$2,250","$2,300","$2,380","$2,500"],"explanation":"After a 15% decrease: 2,000 times 0.85 = 1,700. After a 40% increase: 1,700 times 1.40 = 2,380.","skill":"percentages"},{"cat":"data","a":1,"q":"One pump can fill a tank in 6 hours, and a second pump can fill the same tank in 3 hours. Working together at their constant rates, how long will it take the two pumps to fill the tank?","options":["1.5 hours","2 hours","4.5 hours","9 hours"],"explanation":"The combined rate is 1/6 + 1/3 = 1/6 + 2/6 = 3/6 = 1/2 tank per hour. The time to fill one tank is the reciprocal, 2 hours.","skill":"rates"},{"cat":"data","a":2,"q":"A chemist has 40 liters of a solution that is 30% acid. How many liters of pure acid must be added so that the resulting mixture is 50% acid?","options":["8","12","16","20"],"explanation":"The original solution contains 0.30 times 40 = 12 liters of acid. Adding x liters of pure acid gives (12 + x)/(40 + x) = 0.50. Solving: 12 + x = 20 + 0.5x, so 0.5x = 8 and x = 16 liters.","skill":"proportions"},{"cat":"geometry","a":1,"q":"A rectangle has a length of 12 centimeters and a width of 4 centimeters. What is the perimeter of the rectangle, in centimeters?","options":["16","32","48","64"],"explanation":"Perimeter = 2(length + width) = 2(12 + 4) = 2(16) = 32 cm. (The distractor 48 is the area; 64 doubles incorrectly.)","skill":"area and volume"},{"cat":"geometry","a":1,"q":"A rectangular box has dimensions 2 inches by 3 inches by 5 inches. What is the volume of the box, in cubic inches?","options":["10","30","31","62"],"explanation":"Volume = length x width x height = 2 x 3 x 5 = 30 cubic inches. (10 multiplies only two dimensions; 31 is the surface-area-style miscount.)","skill":"area and volume"},{"cat":"geometry","a":2,"q":"Two angles are supplementary. One angle measures 65 degrees. What is the measure of the other angle, in degrees?","options":["25","35","115","125"],"explanation":"Supplementary angles sum to 180 degrees, so the other angle is 180 - 65 = 115 degrees. (25 treats them as complementary.)","skill":"lines and angles"},{"cat":"geometry","a":1,"q":"In a right triangle, the two legs have lengths 9 and 12. What is the length of the hypotenuse?","options":["13","15","21","225"],"explanation":"By the Pythagorean theorem, hypotenuse = sqrt(9^2 + 12^2) = sqrt(81 + 144) = sqrt(225) = 15. (21 adds the legs; 225 forgets the square root.)","skill":"triangles and the Pythagorean theorem"},{"cat":"geometry","a":2,"q":"A cube has an edge length of 5 units. What is the total surface area of the cube, in square units?","options":["25","125","150","750"],"explanation":"A cube has 6 square faces, each of area 5^2 = 25. Surface area = 6 x 25 = 150 square units. (125 is the volume; 25 is one face.)","skill":"area and volume"},{"cat":"geometry","a":0,"q":"A triangle has two interior angles measuring 50 degrees and 60 degrees. What is the measure of the third interior angle, in degrees?","options":["70","110","120","250"],"explanation":"The interior angles of a triangle sum to 180 degrees, so the third angle is 180 - 50 - 60 = 70 degrees. (110 is the exterior angle at that vertex.)","skill":"lines and angles"},{"cat":"geometry","a":2,"q":"A circle has a circumference of 12pi units. What is the area of the circle, in square units?","options":["6pi","12pi","36pi","144pi"],"explanation":"Circumference = 2(pi)r = 12pi gives r = 6. Area = (pi)r^2 = (pi)(6^2) = 36pi. (144pi squares the diameter; 12pi reuses the circumference.)","skill":"circles (arcs, sectors, equations)"},{"cat":"geometry","a":2,"q":"In an isosceles triangle, the vertex (apex) angle measures 40 degrees. What is the measure of each base angle, in degrees?","options":["40","50","70","140"],"explanation":"The two base angles are equal and together with the vertex angle sum to 180. Each base angle = (180 - 40)/2 = 140/2 = 70 degrees.","skill":"triangles and the Pythagorean theorem"},{"cat":"geometry","a":1,"q":"A ladder leans against a vertical wall. The foot of the ladder is 5 feet from the wall, and the ladder is 13 feet long. How high up the wall does the top of the ladder reach, in feet?","options":["8","12","12.5","18"],"explanation":"The wall height h satisfies 5^2 + h^2 = 13^2, so h^2 = 169 - 25 = 144 and h = 12 feet. (8 subtracts lengths; 18 adds them.)","skill":"triangles and the Pythagorean theorem"},{"cat":"geometry","a":2,"q":"A right cylinder has a radius of 5 units and a height of 10 units. What is the volume of the cylinder, in cubic units? (Use the formula V = (pi)r^2 h.)","options":["50pi","100pi","250pi","500pi"],"explanation":"V = (pi)r^2 h = (pi)(5^2)(10) = (pi)(25)(10) = 250pi cubic units. (50pi multiplies r by h only; 500pi doubles the radius.)","skill":"area and volume"},{"cat":"geometry","a":2,"q":"Two parallel lines are cut by a transversal. One of the eight angles formed measures 65 degrees. What is the measure of a co-interior (same-side interior) angle paired with it, in degrees?","options":["25","65","115","130"],"explanation":"Co-interior angles between parallel lines are supplementary, so the angle is 180 - 65 = 115 degrees. (65 is a corresponding/alternate angle, not co-interior.)","skill":"lines and angles"},{"cat":"geometry","a":0,"q":"A right triangle has an acute angle A with the side opposite A of length 3 and the hypotenuse of length 5. What is the value of sin A?","options":["3/5","4/5","3/4","5/3"],"explanation":"By definition, sin A = (opposite)/(hypotenuse) = 3/5. (4/5 is cos A, 3/4 is tan A, and 5/3 inverts the ratio.)","skill":"right-triangle trigonometry (sin/cos/tan)"},{"cat":"geometry","a":1,"q":"A trapezoid has parallel sides (bases) of length 6 and 10 and a height of 4. What is the area of the trapezoid, in square units?","options":["20","32","40","60"],"explanation":"Area = (1/2)(b1 + b2)(h) = (1/2)(6 + 10)(4) = (1/2)(16)(4) = 32 square units. (60 multiplies all three; 40 forgets the one-half on the wrong base.)","skill":"area and volume"},{"cat":"geometry","a":0,"q":"A 6-foot-tall person casts a shadow 8 feet long at the same time a nearby building casts a shadow 40 feet long. Using similar triangles, what is the height of the building, in feet?","options":["30","32","48","53"],"explanation":"The triangles are similar, so height/shadow is constant: 6/8 = h/40. Then h = (6 x 40)/8 = 240/8 = 30 feet. (53 adds 40 + something; 48 misuses the ratio.)","skill":"similar triangles"},{"cat":"geometry","a":1,"q":"A right circular cone has a radius of 3 units and a height of 4 units. What is the volume of the cone, in cubic units? (Use V = (1/3)(pi)r^2 h.)","options":["4pi","12pi","36pi","48pi"],"explanation":"V = (1/3)(pi)(3^2)(4) = (1/3)(pi)(9)(4) = (1/3)(36pi) = 12pi cubic units. (36pi omits the one-third factor.)","skill":"area and volume"},{"cat":"geometry","a":2,"q":"In a 30-60-90 right triangle, the hypotenuse has length 10. What is the length of the side opposite the 60-degree angle?","options":["5","5*sqrt(2)","5*sqrt(3)","10*sqrt(3)"],"explanation":"In a 30-60-90 triangle the sides are in ratio 1 : sqrt(3) : 2 (short leg : long leg : hypotenuse). The hypotenuse 10 makes the short leg 5, so the long leg (opposite 60 degrees) is 5*sqrt(3). (5 is the short leg opposite 30 degrees.)","skill":"right-triangle trigonometry (sin/cos/tan)"},{"cat":"geometry","a":1,"q":"A circle has radius 10 units. A sector of the circle has a central angle of 72 degrees. What is the length of the arc that bounds this sector, in units?","options":["2pi","4pi","20pi","72pi"],"explanation":"Arc length = (central angle/360)(2(pi)r) = (72/360)(2(pi)(10)) = (1/5)(20pi) = 4pi units. (20pi is the full circumference.)","skill":"circles (arcs, sectors, equations)"},{"cat":"geometry","a":2,"q":"The equation of a circle is x^2 + y^2 - 6x + 8y = 0. What is the radius of this circle?","options":["3","4","5","25"],"explanation":"Complete the square: (x^2 - 6x + 9) + (y^2 + 8y + 16) = 0 + 9 + 16, giving (x - 3)^2 + (y + 4)^2 = 25. So r = sqrt(25) = 5. (25 is r^2; 3 and 4 are center-coordinate values.)","skill":"circles (arcs, sectors, equations)"},{"cat":"geometry","a":2,"q":"A right triangle has acute angle B with the side adjacent to B of length 12 and the hypotenuse of length 13. The side opposite B has length 5. What is the value of tan B?","options":["5/13","12/13","5/12","12/5"],"explanation":"tan B = (opposite)/(adjacent) = 5/12. (5/13 is sin B, 12/13 is cos B, and 12/5 inverts tan B.)","skill":"right-triangle trigonometry (sin/cos/tan)"},{"cat":"geometry","a":0,"q":"Two similar triangles have areas of 16 square units and 25 square units. A side of the smaller triangle has length 8. What is the length of the corresponding side of the larger triangle?","options":["10","12.5","16","20"],"explanation":"For similar figures, area ratio = (linear ratio)^2. So (linear ratio)^2 = 25/16, giving linear ratio = 5/4. The corresponding side = 8 x (5/4) = 10. (12.5 applies the area ratio directly to the length.)","skill":"similar triangles"},{"cat":"geometry","a":1,"q":"A circle has radius 6 units. A sector has a central angle of 120 degrees. What is the area of the sector, in square units?","options":["6pi","12pi","18pi","36pi"],"explanation":"Sector area = (central angle/360)((pi)r^2) = (120/360)((pi)(36)) = (1/3)(36pi) = 12pi square units. (36pi is the whole circle.)","skill":"circles (arcs, sectors, equations)"},{"cat":"geometry","a":2,"q":"An equilateral triangle has a side length of 6 units. What is its area, in square units?","options":["9","9*sqrt(2)","9*sqrt(3)","18*sqrt(3)"],"explanation":"Area of an equilateral triangle = (sqrt(3)/4)(side^2) = (sqrt(3)/4)(36) = 9*sqrt(3) square units. (18*sqrt(3) uses base x height without the one-half.)","skill":"area and volume"},{"cat":"geometry","a":2,"q":"From a point on level ground, the angle of elevation to the top of a flagpole is 30 degrees. The point is 100 feet from the base of the pole. What is the height of the flagpole, in feet? (Note: tan 30 = 1/sqrt(3).)","options":["50","50*sqrt(3)","100/sqrt(3)","100*sqrt(3)"],"explanation":"tan 30 = height/distance, so height = 100 x tan 30 = 100 x (1/sqrt(3)) = 100/sqrt(3) feet. (100*sqrt(3) would use the cotangent instead.)","skill":"right-triangle trigonometry (sin/cos/tan)"},{"cat":"geometry","a":0,"q":"The endpoints of a diameter of a circle are (1, 2) and (7, 10). What is the equation of this circle?","options":["(x - 4)^2 + (y - 6)^2 = 25","(x - 4)^2 + (y - 6)^2 = 100","(x - 8)^2 + (y - 12)^2 = 25","(x + 4)^2 + (y + 6)^2 = 25"],"explanation":"The center is the midpoint: ((1+7)/2, (2+10)/2) = (4, 6). The diameter length is sqrt((7-1)^2 + (10-2)^2) = sqrt(36 + 64) = 10, so the radius is 5 and r^2 = 25. Equation: (x - 4)^2 + (y - 6)^2 = 25. (The 100 version uses the diameter as the radius; the (8,12) version uses the sum instead of the midpoint.)","skill":"circles (arcs, sectors, equations)"},{"cat":"geometry","a":0,"q":"In a circle, a central angle and an inscribed angle both intercept the same arc. The central angle measures 80 degrees. What is the measure of the inscribed angle, in degrees?","options":["40","80","100","160"],"explanation":"An inscribed angle is half the central angle that intercepts the same arc, so the inscribed angle = 80/2 = 40 degrees. (160 doubles instead of halves; 100 is the supplement.)","skill":"circles (arcs, sectors, equations)"},{"cat":"geometry","a":0,"q":"A right triangle has legs in the ratio 3 : 4, and its hypotenuse measures 25 units. The longer leg lies along the ground, and an acute angle theta is formed at the top of the hypotenuse, opposite the shorter leg. What is the length of the shorter leg, and what is sin(theta)?","options":["15 units; 3/5","20 units; 4/5","15 units; 4/5","20 units; 3/5"],"explanation":"A 3-4-5 right triangle scaled so the hypotenuse is 25 has legs 15 and 20 (since 15-20-25 = 5(3-4-5)). The shorter leg is 15. Angle theta is opposite the shorter leg (15), so sin(theta) = opposite/hypotenuse = 15/25 = 3/5.","skill":"right-triangle trigonometry (sin/cos/tan)"},{"cat":"geometry","a":2,"q":"A triangle has a base of 14 centimeters and a height of 9 centimeters. What is the area of the triangle, in square centimeters?","options":["23","46","63","126"],"explanation":"Area of a triangle = (1/2) x base x height = (1/2)(14)(9) = 63 square centimeters.","skill":"area/volume"},{"cat":"geometry","a":0,"q":"Two angles are complementary. One angle measures 28 degrees. What is the measure of the other angle?","options":["62 degrees","72 degrees","152 degrees","332 degrees"],"explanation":"Complementary angles sum to 90 degrees, so the other angle is 90 - 28 = 62 degrees.","skill":"lines/angles"},{"cat":"geometry","a":2,"q":"A rectangular prism has dimensions 4 inches by 5 inches by 6 inches. What is its volume, in cubic inches?","options":["15","74","120","148"],"explanation":"Volume of a rectangular prism = length x width x height = 4 x 5 x 6 = 120 cubic inches.","skill":"area/volume"},{"cat":"geometry","a":2,"q":"A circle has a radius of 7 units. What is the area of the circle, in square units?","options":["7pi","14pi","49pi","196pi"],"explanation":"Area of a circle = pi x r^2 = pi x 7^2 = 49pi square units.","skill":"circles"},{"cat":"geometry","a":0,"q":"A right triangle has legs of length 8 and 15. What is the length of the hypotenuse?","options":["17","19","21","23"],"explanation":"By the Pythagorean theorem, hypotenuse = sqrt(8^2 + 15^2) = sqrt(64 + 225) = sqrt(289) = 17.","skill":"triangles & Pythagorean theorem"},{"cat":"geometry","a":1,"q":"A triangle has two interior angles measuring 70 degrees and 45 degrees. What is the measure of the third angle?","options":["55 degrees","65 degrees","75 degrees","115 degrees"],"explanation":"The interior angles of a triangle sum to 180 degrees, so the third angle is 180 - 70 - 45 = 65 degrees.","skill":"triangles & Pythagorean theorem"},{"cat":"geometry","a":2,"q":"In an isosceles triangle, the vertex (apex) angle measures 70 degrees. What is the measure of each base angle?","options":["35 degrees","45 degrees","55 degrees","70 degrees"],"explanation":"The two base angles are equal and sum with the apex to 180 degrees: (180 - 70)/2 = 55 degrees each.","skill":"triangles & Pythagorean theorem"},{"cat":"geometry","a":2,"q":"A circle has a diameter of 14 units. What is the area of the circle, in square units?","options":["14pi","28pi","49pi","196pi"],"explanation":"The radius is half the diameter: r = 7. Area = pi x r^2 = pi x 7^2 = 49pi square units.","skill":"circles"},{"cat":"geometry","a":1,"q":"In a 45-45-90 right triangle, each leg has length 7. What is the length of the hypotenuse?","options":["7","7sqrt(2)","7sqrt(3)","14"],"explanation":"In a 45-45-90 triangle the hypotenuse equals a leg times sqrt(2), so the hypotenuse is 7sqrt(2).","skill":"triangles & Pythagorean theorem"},{"cat":"geometry","a":1,"q":"Two parallel lines are cut by a transversal. A pair of co-interior (same-side interior) angles is formed. If one of these angles measures 110 degrees, what is the measure of the other?","options":["55 degrees","70 degrees","110 degrees","250 degrees"],"explanation":"Co-interior angles between parallel lines are supplementary, so the other angle is 180 - 110 = 70 degrees.","skill":"lines/angles"},{"cat":"geometry","a":1,"q":"In a right triangle, acute angle A has the side adjacent to A of length 4 and the hypotenuse of length 8. What is cos(A)?","options":["1/4","1/2","sqrt(3)/2","2"],"explanation":"Cosine = adjacent/hypotenuse = 4/8 = 1/2.","skill":"right-triangle trig"},{"cat":"geometry","a":2,"q":"A sphere has a radius of 6 units. What is its surface area, in square units?","options":["36pi","72pi","144pi","288pi"],"explanation":"Surface area of a sphere = 4 pi r^2 = 4 pi (6^2) = 144pi square units.","skill":"area/volume"},{"cat":"geometry","a":1,"q":"In a circle, an inscribed angle intercepts an arc of measure 140 degrees. What is the measure of the inscribed angle?","options":["40 degrees","70 degrees","140 degrees","280 degrees"],"explanation":"An inscribed angle is half the measure of its intercepted arc: 140/2 = 70 degrees.","skill":"circles"},{"cat":"geometry","a":2,"q":"In a 30-60-90 right triangle, the side opposite the 30-degree angle has length 5. What is the length of the side opposite the 60-degree angle?","options":["5","5sqrt(2)","5sqrt(3)","10"],"explanation":"In a 30-60-90 triangle the side opposite 60 degrees is the short side times sqrt(3), so it is 5sqrt(3).","skill":"triangles & Pythagorean theorem"},{"cat":"geometry","a":1,"q":"A circle has a radius of 9 units. A sector has a central angle of 80 degrees. What is the length of the arc of this sector, in units?","options":["2pi","4pi","8pi","9pi"],"explanation":"Arc length = (central angle/360) x 2 pi r = (80/360)(2 pi)(9) = (2/9)(18pi) = 4pi units.","skill":"circles"},{"cat":"geometry","a":1,"q":"A right circular cone has a radius of 6 units and a height of 8 units. What is the length of its slant height, in units?","options":["7","10","12","14"],"explanation":"The slant height is sqrt(r^2 + h^2) = sqrt(6^2 + 8^2) = sqrt(36 + 64) = sqrt(100) = 10 units.","skill":"area/volume"},{"cat":"geometry","a":1,"q":"From a point on level ground, the angle of elevation to the top of a tower is 45 degrees, and the point is 30 feet from the base of the tower. What is the height of the tower, in feet?","options":["15","30","30sqrt(2)","60"],"explanation":"With a 45-degree elevation, tan(45) = height/distance = 1, so the height equals the distance: 30 feet.","skill":"right-triangle trig"},{"cat":"geometry","a":1,"q":"In a triangle, one exterior angle measures 115 degrees. One of the two remote interior angles measures 70 degrees. What is the measure of the other remote interior angle?","options":["35 degrees","45 degrees","55 degrees","65 degrees"],"explanation":"An exterior angle equals the sum of its two remote interior angles, so the other one is 115 - 70 = 45 degrees.","skill":"lines/angles"},{"cat":"geometry","a":2,"q":"Two similar triangles have a scale factor (ratio of corresponding sides) of 2 to 3. A side of the smaller triangle measures 6. What is the length of the corresponding side of the larger triangle?","options":["4","8","9","12"],"explanation":"Corresponding sides are proportional: 2/3 = 6/x, so x = 6 x 3/2 = 9.","skill":"similar triangles"},{"cat":"geometry","a":2,"q":"A circle has a radius of 13 units. A chord lies 5 units from the center of the circle. What is the length of the chord, in units?","options":["12","18","24","26"],"explanation":"The perpendicular from the center bisects the chord, forming a right triangle: half-chord = sqrt(13^2 - 5^2) = sqrt(144) = 12, so the full chord is 24 units.","skill":"circles"},{"cat":"geometry","a":0,"q":"The equation of a circle is x^2 + y^2 - 10x + 4y - 7 = 0. What is the radius of this circle?","options":["6","7","8","36"],"explanation":"Completing the square: (x-5)^2 + (y+2)^2 = 7 + 25 + 4 = 36, so the radius is sqrt(36) = 6.","skill":"circles"},{"cat":"geometry","a":0,"q":"A triangle has two sides of length 10 and 8 with an included angle of 30 degrees between them. What is the area of the triangle, in square units?","options":["20","40","20sqrt(3)","80"],"explanation":"Area = (1/2)(a)(b)sin(C) = (1/2)(10)(8)sin(30) = 40 x (1/2) = 20 square units.","skill":"right-triangle trig"},{"cat":"geometry","a":1,"q":"A larger circle has a radius of 8 units, and a smaller circle with radius 5 units is removed from its center. What is the area of the remaining ring (annulus), in square units?","options":["13pi","39pi","49pi","89pi"],"explanation":"Annulus area = pi(8^2) - pi(5^2) = 64pi - 25pi = 39pi square units.","skill":"circles"},{"cat":"geometry","a":1,"q":"A cube has an edge length of 4 units. What is the length of the space diagonal connecting two opposite corners of the cube, in units?","options":["4sqrt(2)","4sqrt(3)","8","12"],"explanation":"The space diagonal of a cube with edge s is s x sqrt(3) = 4sqrt(3) units.","skill":"area/volume"},{"cat":"geometry","a":2,"q":"Two similar solids have a linear scale factor of 2 to 1. If the smaller solid has a volume of 9 cubic units, what is the volume of the larger solid, in cubic units?","options":["18","36","72","81"],"explanation":"Volumes of similar solids scale by the cube of the linear ratio: (2/1)^3 = 8, so the larger volume is 9 x 8 = 72 cubic units.","skill":"similar triangles"},{"cat":"geometry","a":1,"q":"In a right triangle, the legs are in the ratio 5 to 12, and the hypotenuse measures 26 units. What is the length of the shorter leg, in units?","options":["8","10","12","13"],"explanation":"A 5-12-13 right triangle scaled so the hypotenuse is 26 uses factor 2 (since 13 x 2 = 26). The shorter leg is 5 x 2 = 10 units.","skill":"triangles & Pythagorean theorem"},{"cat":"information","a":1,"q":"The axolotl is a type of salamander that lives in lakes near Mexico City. Unlike most amphibians, the axolotl does not undergo a full metamorphosis. Instead, it keeps many features of its larval stage, such as feathery external gills, even as an adult. This unusual trait is one reason scientists are so interested in studying the animal.\n\nWhich choice best states the main idea of the text?","options":["The axolotl is endangered because it lives only near Mexico City.","The axolotl retains larval features into adulthood, making it of interest to scientists.","Most amphibians undergo a full metamorphosis during their lives.","The axolotl's gills are the only feature scientists wish to study."],"explanation":"The passage centers on the axolotl keeping larval features as an adult, which interests scientists. The endangerment and gills-only claims overstate details not supported, and the metamorphosis statement is only background contrast, not the main idea.","skill":"central ideas and details"},{"cat":"information","a":1,"q":"Honeybees communicate the location of food through a behavior called the \"waggle dance.\" A returning forager moves in a figure-eight pattern, and the angle and duration of its central run encode the direction and distance of a food source. Other bees follow the dancer closely, then leave the hive to search in the indicated area.\n\nAccording to the text, what does the waggle dance allow honeybees to do?","options":["Build new sections of the honeycomb more quickly.","Share information about where food can be found.","Defend the hive from approaching predators.","Determine which flowers produce the most nectar."],"explanation":"The text states the dance encodes direction and distance of a food source so other bees can find it. The other choices describe activities the passage never connects to the dance.","skill":"central ideas and details"},{"cat":"information","a":2,"q":"The painter Hilma af Klint created large, colorful abstract works years before artists like Wassily Kandinsky, who are often credited with inventing abstract art. Yet af Klint asked that her paintings not be shown publicly until decades after her death. As a result, her pioneering role went largely unrecognized during her lifetime.\n\nWhich choice best states the main idea of the text?","options":["Af Klint's paintings were more colorful than Kandinsky's works.","Kandinsky borrowed many ideas directly from af Klint's paintings.","Af Klint produced early abstract art but remained little known because her work was hidden.","Af Klint regretted asking that her paintings be kept private."],"explanation":"The text emphasizes af Klint's early abstraction and how concealment kept her unrecognized. The other choices make claims about color, borrowing, or regret that the passage does not support.","skill":"central ideas and details"},{"cat":"information","a":1,"q":"Many people assume that deserts are always hot, but this is not true. The Gobi Desert in Asia experiences bitterly cold winters, with temperatures sometimes dropping well below freezing. What truly defines a desert is not its temperature but its lack of precipitation: a desert is simply a region that receives very little rain or snow.\n\nAccording to the text, what defines a region as a desert?","options":["Its consistently high temperatures throughout the year.","Its very low amount of precipitation.","Its location on the continent of Asia.","Its dramatic shifts between hot and cold seasons."],"explanation":"The passage directly states that lack of precipitation, not temperature, defines a desert. High temperature is the misconception being corrected, and location and seasonal shifts are not given as definitions.","skill":"central ideas and details"},{"cat":"information","a":1,"q":"Author Zora Neale Hurston spent years collecting folklore in the rural American South, recording stories, songs, and sayings that might otherwise have been lost. She drew on this material in her novels, weaving authentic folk speech and traditions into her fiction. In this way, her work as a researcher directly enriched her work as a novelist.\n\nWhich choice best states the main idea of the text?","options":["Hurston preferred collecting folklore to writing novels.","Hurston's folklore research informed and strengthened her fiction.","Hurston's novels were criticized for their use of folk speech.","Hurston traveled widely outside the American South for her research."],"explanation":"The text shows how Hurston's research fed into and enriched her fiction. The other choices introduce preferences, criticism, or travel that the passage does not state.","skill":"central ideas and details"},{"cat":"information","a":1,"q":"A team of geologists studied layers of rock in a canyon wall, noting that the lowest layers are the oldest and the highest are the youngest. By examining fossils trapped within each layer, they could estimate which species lived during which time period. The arrangement of the rock thus served as a kind of timeline of ancient life.\n\nAccording to the text, the rock layers were useful to the geologists because they","options":["contained valuable minerals that could be mined.","recorded the relative ages of different species.","were easier to study than fossils alone.","formed unusually colorful patterns in the canyon."],"explanation":"The text explains that ordered layers let geologists estimate when species lived, serving as a timeline. Minerals, ease of study, and color are not supported by the passage.","skill":"central ideas and details"},{"cat":"information","a":1,"q":"Researcher Lin Maria studied two groups of students preparing for an exam. One group reviewed their notes repeatedly, while the other quizzed themselves on the material. On the final test, the self-quizzing group scored noticeably higher. Maria concluded that actively retrieving information strengthens memory more than passively rereading it does.\n\nWhich finding, if true, would most directly support Maria's conclusion?","options":["Students in both groups reported enjoying their study methods equally.","In a follow-up study, students who tested themselves again outperformed those who reread.","The rereading group spent more total minutes studying than the self-quizzing group.","Both groups had similar scores on a practice test taken before studying."],"explanation":"A repeated result showing self-testers outperform rereaders directly supports the claim that retrieval beats rereading. Enjoyment is irrelevant, study time alone does not address performance, and a baseline only establishes equal starting points.","skill":"command of textual evidence"},{"cat":"information","a":1,"q":"Some biologists argue that octopuses are highly intelligent. They point out that octopuses can solve puzzles, open jars to reach food, and even recognize individual human caretakers. These behaviors, the biologists claim, require a level of cognition unusual among invertebrates.\n\nWhich finding, if true, would most strongly support the biologists' argument?","options":["Octopuses have three hearts and blue-colored blood.","In experiments, octopuses remembered the solution to a maze weeks after first solving it.","Octopuses typically live for only one to two years.","Many invertebrates, like jellyfish, lack a centralized brain."],"explanation":"Long-term memory of a solved maze demonstrates advanced cognition, supporting the intelligence claim. Hearts, lifespan, and facts about other invertebrates do not bear on octopus intelligence.","skill":"command of textual evidence"},{"cat":"information","a":1,"q":"A historian claims that the printing press dramatically increased literacy in Europe. She notes that before its invention, books were copied by hand and were too expensive for most people to own. After printing spread, books became far cheaper and more plentiful.\n\nWhich finding, if true, would most directly support the historian's claim?","options":["The earliest printing presses were located mainly in large cities.","Records show that the percentage of people who could read rose sharply in the decades after printing spread.","Many early printed books were copies of religious texts.","Hand-copied books were often decorated with elaborate illustrations."],"explanation":"A documented rise in reading ability after printing spread directly supports the literacy claim. Press locations, book topics, and decoration describe features of printing or books but not changes in literacy.","skill":"command of textual evidence"},{"cat":"information","a":1,"q":"In a study of urban gardens, ecologist Param noticed that gardens with a wide variety of plant species attracted more types of pollinating insects than gardens dominated by a single species. He proposed that increasing plant diversity could help support struggling pollinator populations in cities.\n\nWhich finding, if true, would most strongly support Param's proposal?","options":["City gardens are generally smaller than rural gardens.","When gardeners added several new plant species to single-species plots, the number of pollinator species increased.","Pollinating insects are most active during the warmest months of the year.","Some single-species gardens were located near busy roads."],"explanation":"An increase in pollinator species after adding plant diversity directly supports the proposal. Garden size, seasonal activity, and road proximity are unrelated to the link between plant diversity and pollinators.","skill":"command of textual evidence"},{"cat":"information","a":0,"q":"An economist argues that remote work has reduced traffic congestion in major cities. She observes that since many companies adopted work-from-home policies, fewer commuters travel during traditional rush hours.\n\nWhich finding, if true, would most directly weaken the economist's argument?","options":["Traffic data show that overall congestion in major cities has remained unchanged since remote work expanded.","Some employees say they enjoy working from home more than commuting.","A few large companies have required workers to return to offices full-time.","Public transit ridership has declined in several cities."],"explanation":"If congestion is unchanged despite remote work, the claimed reduction does not hold, weakening the argument. Employee preferences and a few return-to-office cases are tangential, and transit ridership does not address overall road congestion.","skill":"command of textual evidence"},{"cat":"information","a":1,"q":"Marine biologist Okonkwo studied coral reefs recovering from a heat wave. He found that reefs located near deep, cool ocean currents regained their color and health faster than reefs in warmer, shallow waters. Okonkwo suggested that access to cooler water helps corals recover from heat stress.\n\nWhich finding, if true, would most strongly support Okonkwo's suggestion?","options":["Corals in shallow waters are home to a greater variety of fish.","In a controlled experiment, corals exposed to periodic cool water recovered faster than identical corals kept in warm water.","Heat waves have become more frequent in recent decades.","Some corals can survive temporary exposure to high temperatures."],"explanation":"A controlled experiment isolating cool-water exposure as the cause of faster recovery directly supports the suggestion. Fish variety, heat-wave frequency, and heat tolerance do not test the cooling-recovery link.","skill":"command of textual evidence"},{"cat":"information","a":0,"q":"The ancient city of Catalhoyuk in present-day Turkey had no streets between its houses. Instead, the homes were packed tightly together, and residents entered through openings in their roofs, walking across the rooftops to reach their own ladders. This unusual layout suggests that movement through the settlement was very different from movement through a modern town.\n\nBased on the text, which statement about daily life in Catalhoyuk can most reasonably be inferred?","options":["Residents likely traveled on the rooftops rather than at ground level.","Residents preferred living in homes without windows.","The city was abandoned because it lacked proper streets.","Most residents owned ladders made of imported wood."],"explanation":"Since homes were entered from the roof and people walked across rooftops, rooftop travel is the reasonable inference. The other choices add details about windows, abandonment, or imported wood the text neither states nor implies.","skill":"logical inferences from a short passage"},{"cat":"information","a":0,"q":"A new species of frog discovered in a remote rainforest is active only at night and has unusually large eyes compared with related daytime species. Many nocturnal animals have larger eyes, which gather more of the limited light available after dark.\n\nWhich choice most logically completes the text?","options":["the frog's large eyes likely help it see in low-light conditions.","the frog is probably more colorful than its relatives.","the frog must be larger overall than daytime frogs.","the frog likely avoids all contact with other frog species."],"explanation":"The passage links large eyes to gathering light in darkness, so the eyes likely aid low-light vision. Color, overall size, and avoiding other frogs are not supported by any information given.","skill":"logical inferences from a short passage"},{"cat":"information","a":0,"q":"Researchers found that a certain bird sings more complex songs in quiet rural areas than in noisy cities. In the cities, the constant hum of traffic seems to drown out the higher notes of the bird's song, so urban birds tend to sing simpler, lower tunes that carry better through the noise.\n\nWhich choice most logically completes the text?","options":["the birds' song complexity appears to be influenced by their surrounding noise levels.","rural birds are healthier than city birds.","the birds prefer living in cities despite the noise.","city noise has no effect on bird behavior."],"explanation":"The text shows song complexity differs with noise, so noise levels appear to influence it. Health and preference are unsupported, and the no-effect claim directly contradicts the passage.","skill":"logical inferences from a short passage"},{"cat":"information","a":1,"q":"A museum displayed two paintings believed to be by the same artist. Chemical analysis revealed that one painting used a blue pigment that was not invented until fifty years after the artist's death. The museum announced it would re-examine the painting's origins.\n\nWhich statement can most reasonably be inferred from the text?","options":["The artist secretly developed the blue pigment before anyone else.","The painting with the newer pigment may not have been made by the original artist.","Both paintings are forgeries created at the same time.","The museum plans to remove both paintings from display."],"explanation":"A pigment invented after the artist's death implies that painting may not be the artist's, prompting re-examination. The secret-development claim contradicts the timeline, and the forgery and removal claims overstate what the evidence shows.","skill":"logical inferences from a short passage"},{"cat":"information","a":0,"q":"Some plants release chemicals into the soil that prevent other plants from growing nearby. The black walnut tree, for example, produces a substance that is toxic to many garden vegetables. Gardeners who plant tomatoes too close to a black walnut often find that the tomatoes wither and die.\n\nWhich choice most logically completes the text?","options":["gardeners hoping to grow healthy tomatoes should avoid planting them near black walnut trees.","black walnut trees grow faster than tomato plants.","tomatoes release the same toxic substance as black walnut trees.","all garden vegetables are immune to the black walnut's chemicals."],"explanation":"Since the walnut's chemical kills nearby tomatoes, avoiding planting them close follows logically. Growth rate is unsupported, and the claims about tomatoes releasing the toxin or vegetables being immune contradict the passage.","skill":"logical inferences from a short passage"},{"cat":"information","a":1,"q":"During a long sea voyage in the 1700s, sailors often developed scurvy, a disease causing weakness and bleeding gums. A naval physician noticed that sailors who were given citrus fruits recovered, while those who were not continued to suffer. Citrus fruits, it was later understood, are rich in vitamin C.\n\nWhich statement can most reasonably be inferred from the text?","options":["Scurvy was caused by spending too much time at sea.","A lack of vitamin C likely contributed to the sailors' scurvy.","Citrus fruits were the only food available on long voyages.","All diseases among sailors could be cured with citrus fruits."],"explanation":"Citrus, which is rich in vitamin C, cured scurvy, implying a vitamin C deficiency contributed to it. The time-at-sea choice confuses setting with cause, and the other choices overgeneralize beyond the text.","skill":"logical inferences from a short passage"},{"cat":"information","a":0,"q":"Archaeologists studying an ancient settlement uncovered storage pits filled with the remains of grains that do not grow naturally in the region. The nearest place where these grains grew wild was hundreds of miles away. The researchers believe the find reveals something important about the settlement's connections to distant communities.\n\nWhich choice most logically completes the text?","options":["the settlement's residents likely traded with or traveled to faraway regions to obtain the grains.","the residents preferred grains to all other types of food.","the grains were probably grown in secret within the settlement.","the settlement was the largest in its region."],"explanation":"Grains from hundreds of miles away imply long-distance trade or travel. Food preference and settlement size are unsupported, and the secret-growing claim contradicts the statement that the grains did not grow in the region.","skill":"logical inferences from a short passage"},{"cat":"information","a":1,"q":"A study tracked how quickly people forget newly learned vocabulary words. Participants who reviewed the words at gradually increasing intervals, such as after one day, then three days, then a week, remembered far more words a month later than participants who crammed all their reviews into a single session.\n\nBased on the text, which approach to reviewing material is most likely to improve long-term memory?","options":["Reviewing material only once, immediately after learning it.","Spacing reviews out over increasing intervals of time.","Avoiding any review until just before it is needed.","Reviewing all material in one long session."],"explanation":"The spaced-review group remembered far more, so spacing reviews over increasing intervals improves long-term memory. The other choices describe single, delayed, or crammed approaches the study found less effective.","skill":"logical inferences from a short passage"},{"cat":"information","a":1,"q":"Sociologist Adeyemi studied volunteer organizations in several towns. She found that groups whose members met regularly in person tended to retain volunteers longer than groups that communicated only online. Adeyemi proposed that face-to-face interaction helps build the personal bonds that keep volunteers committed.\n\nWhich finding, if true, would most directly support Adeyemi's proposal?","options":["Online groups were often larger than in-person groups.","When several online-only groups began holding regular in-person meetings, their volunteer retention improved.","Most volunteers reported joining their group to help their community.","In-person meetings were usually held in the evenings."],"explanation":"Improved retention after adding in-person meetings directly supports the claim that face-to-face contact builds commitment. Group size, joining motivation, and meeting times do not connect in-person interaction to retention.","skill":"command of textual evidence"},{"cat":"information","a":0,"q":"The tardigrade, often called a \"water bear,\" is a tiny animal less than a millimeter long. It can survive extreme conditions that would kill most living things, including freezing temperatures, the vacuum of space, and years without water.\n\nWhich choice best states the main idea of the text?","options":["Tardigrades are remarkably tough animals that can endure harsh conditions.","Tardigrades are too small for most people to see without a microscope.","Tardigrades prefer to live in cold environments rather than warm ones.","Tardigrades have been studied by scientists for many decades."],"explanation":"The text emphasizes that the tardigrade can survive extreme conditions that would kill most living things, making toughness the main idea. The other choices mention details not central to the passage.","skill":"central ideas/details"},{"cat":"information","a":1,"q":"Maria Tallchief was one of the first Native American ballerinas to achieve international fame. Born in Oklahoma, she became the lead dancer of the New York City Ballet and performed in leading roles across Europe and the United States during the 1940s and 1950s.\n\nAccording to the text, what is true about Maria Tallchief?","options":["She preferred performing in Europe over the United States.","She danced as a lead performer for the New York City Ballet.","She began her career as a choreographer rather than a dancer.","She trained other ballerinas after retiring from the stage."],"explanation":"The text directly states she became the lead dancer of the New York City Ballet. The other options are not supported by the passage.","skill":"central ideas/details"},{"cat":"information","a":2,"q":"Bamboo is one of the fastest-growing plants on Earth. Certain species can grow nearly a meter in a single day under ideal conditions. Because it grows so quickly and can be harvested without killing the plant, bamboo is increasingly used as a renewable material for furniture and flooring.\n\nWhich choice best states the main idea of the text?","options":["Bamboo furniture is more durable than furniture made from other woods.","Bamboo grows only in regions with warm, humid climates.","Bamboo's rapid growth makes it a useful renewable material.","Bamboo is harvested mainly for use in flooring."],"explanation":"The text connects bamboo's fast growth and ability to be harvested without killing the plant to its use as a renewable material. The other choices are details or claims not supported as the central point.","skill":"central ideas/details"},{"cat":"information","a":1,"q":"The Sahara Desert was not always dry. Around 10,000 years ago, the region received far more rainfall than it does today and was covered with grasslands, lakes, and rivers. Ancient rock paintings found in the desert depict people herding cattle and swimming, activities impossible in the dry landscape that exists now.\n\nWhich choice is best supported by the text?","options":["The Sahara has always been the driest place on Earth.","The Sahara once had a much wetter climate than it does today.","The rock paintings in the Sahara were created within the last century.","Cattle herding is still common in the Sahara today."],"explanation":"The text states the region received far more rainfall and had grasslands, lakes, and rivers, supporting that it was once much wetter. The other choices contradict the passage.","skill":"inferences from a short passage"},{"cat":"information","a":1,"q":"Octavia Butler was a pioneering science fiction author who often featured Black protagonists in her novels at a time when such characters were rare in the genre. Her work explored themes of power, survival, and social change, and she became the first science fiction writer to receive a MacArthur \"Genius\" Grant.\n\nAccording to the text, Octavia Butler was notable in part because she","options":["wrote exclusively about historical events in the United States.","featured Black protagonists when they were uncommon in science fiction.","refused to accept literary awards for her novels.","founded a magazine dedicated to science fiction writing."],"explanation":"The text states she often featured Black protagonists at a time when such characters were rare in the genre. The other options are not supported.","skill":"central ideas/details"},{"cat":"information","a":2,"q":"A gardener wanted to know whether adding crushed eggshells to soil would help tomato plants grow. She planted two groups of seedlings in identical conditions, adding eggshells only to the first group. After eight weeks, the plants grown with eggshells were noticeably taller and produced more fruit than those grown without them.\n\nWhich choice best states the result of the gardener's experiment?","options":["Eggshells prevented insects from damaging the tomato plants.","Both groups of plants grew to the same height after eight weeks.","Plants grown with eggshells grew taller and produced more fruit.","Tomato plants grow best when planted close together."],"explanation":"The final sentence states that plants grown with eggshells were taller and produced more fruit. The other choices misstate or go beyond the results.","skill":"central ideas/details"},{"cat":"information","a":2,"q":"The Inca built a vast network of roads stretching thousands of miles through the Andes Mountains, connecting distant parts of their empire. Remarkably, they did this without the use of wheeled vehicles or iron tools. Messengers traveled these roads on foot, relaying information across the empire in a system of relay runners.\n\nWhich choice is best supported by the text?","options":["The Inca relied on wheeled carts to transport goods across their roads.","The Inca road network was built using advanced iron tools.","The Inca were able to construct extensive roads without wheeled vehicles.","The Inca roads connected only the capital city to nearby villages."],"explanation":"The text states the Inca built the roads without the use of wheeled vehicles or iron tools, supporting that they constructed extensive roads without wheeled vehicles. The other choices contradict the passage.","skill":"inferences from a short passage"},{"cat":"information","a":1,"q":"In 1815, the volcano Mount Tambora erupted in Indonesia, releasing enormous amounts of ash and gas into the atmosphere. The following year, regions as far away as North America and Europe experienced unusually cold weather, crop failures, and summer snowfall. Historians now refer to 1816 as \"the year without a summer.\"\n\nWhich choice best explains why 1816 was called \"the year without a summer\"?","options":["A series of wars disrupted farming across Europe and North America.","Ash and gas from Mount Tambora's eruption affected the global climate.","Scientists in 1816 had not yet developed accurate calendars.","A second volcano erupted in North America during the summer of 1816."],"explanation":"The text links Tambora's release of ash and gas to the cold weather and crop failures of the following year, making this the explanation. The other options are not mentioned.","skill":"inferences from a short passage"},{"cat":"information","a":1,"q":"Some researchers studying memory have found that people recall information better when they study in short sessions spread over several days rather than in one long session. They suggest that the brain strengthens memories during the breaks between study sessions, particularly during sleep.\n\nWhich finding, if true, would most directly support the researchers' suggestion?","options":["Students who studied in a single long session reported feeling more confident.","People who slept between study sessions remembered more than those who did not.","Longer study sessions are generally more enjoyable than shorter ones.","Most students prefer to study late at night rather than in the morning."],"explanation":"The suggestion is that breaks, particularly sleep, strengthen memory. A finding that those who slept between sessions remembered more directly supports this. The other options are unrelated to the role of sleep in memory.","skill":"command of textual evidence"},{"cat":"information","a":0,"q":"A biologist studying a population of lizards on an island noticed that lizards with longer legs could run faster and escape predators more easily. Over several generations, the average leg length of the lizard population increased. The biologist concluded that natural selection favored longer-legged lizards on the island.\n\nWhich observation, if true, would most strongly support the biologist's conclusion?","options":["Longer-legged lizards survived to reproduce more often than shorter-legged ones.","The island had fewer predators than nearby islands.","All lizards on the island ate the same kinds of insects.","Lizards on the island were larger than lizards on the mainland."],"explanation":"Natural selection favoring longer legs would be supported by evidence that longer-legged lizards reproduced more often, passing on the trait. The other observations do not directly link leg length to reproductive success.","skill":"command of textual evidence"},{"cat":"information","a":2,"q":"The writer James Baldwin spent many years living in France, far from his native United States. He once explained that the physical distance gave him a clearer perspective on American society. By stepping outside the country, he felt better able to observe and write about the tensions and injustices he had experienced at home.\n\nWhich choice best describes how distance affected Baldwin's writing, according to the text?","options":["It caused him to stop writing about the United States entirely.","It made him forget the details of his earlier life in America.","It gave him a clearer perspective on American society.","It led him to write primarily about life in France."],"explanation":"The text states the physical distance gave him a clearer perspective on American society. The other choices contradict the passage.","skill":"central ideas/details"},{"cat":"information","a":3,"q":"Researchers compared two groups of office workers. One group sat at standing desks for part of the workday, while the other sat in traditional chairs all day. After six months, the standing-desk group reported less back pain and higher energy levels, though both groups completed the same amount of work.\n\nWhich choice best summarizes the results of the study?","options":["The standing-desk group completed more work than the seated group.","The seated group reported less back pain than the standing-desk group.","Both groups reported identical levels of energy after six months.","The standing-desk group reported less back pain and more energy, with no difference in work output."],"explanation":"The text states the standing-desk group reported less back pain and higher energy, while both groups completed the same amount of work. The other choices misstate the findings.","skill":"central ideas/details"},{"cat":"information","a":1,"q":"Certain species of fig trees depend entirely on a single species of tiny wasp to pollinate their flowers, and those wasps can reproduce only inside the figs of that tree. Neither the tree nor the wasp can survive and reproduce without the other.\n\nWhich choice is best supported by the text?","options":["The fig tree and the wasp are in competition for the same resources.","The fig tree and the wasp depend on each other for reproduction.","The wasp harms the fig tree by feeding on its flowers.","The fig tree can be pollinated by many different insect species."],"explanation":"The text states neither can survive and reproduce without the other, supporting mutual dependence. The other choices contradict the passage.","skill":"inferences from a short passage"},{"cat":"information","a":2,"q":"An archaeologist excavating a 3,000-year-old settlement found that nearly every house contained a small clay oven and storage jars for grain. However, only a few of the largest houses contained decorative pottery, imported beads, and metal tools. The archaeologist suspected that the settlement may have had differences in wealth among its residents.\n\nWhich finding would most directly support the archaeologist's suspicion?","options":["All houses in the settlement were built using the same materials.","The largest houses were located near a central well.","The decorative items were found only in the largest houses, while ordinary items appeared in all houses.","The clay ovens in every house were of similar size and design."],"explanation":"Differences in wealth would be supported by valuable items concentrating in the largest houses while ordinary items appeared everywhere. The other options do not indicate wealth differences.","skill":"command of textual evidence"},{"cat":"information","a":2,"q":"A common belief is that bats are blind, but this is incorrect. All bat species can see, and some have excellent vision. Many bats also use echolocation, sending out sound waves and listening for echoes, which allows them to navigate and hunt in complete darkness in addition to using their eyes.\n\nWhich choice is best supported by the text?","options":["Bats rely only on echolocation and never use their eyes.","Bats are unable to see and must depend entirely on sound.","Bats can see and may also use echolocation to navigate.","Only a few bat species are able to see at all."],"explanation":"The text states all bats can see and many also use echolocation, supporting that bats can both see and use echolocation. The other choices contradict the passage.","skill":"inferences from a short passage"},{"cat":"information","a":1,"q":"A team of scientists studied whether playing classical music to dairy cows would increase their milk production. They played music to one herd and kept another herd in silence under otherwise identical conditions. Over three weeks, the herd exposed to music produced slightly more milk, but the difference was so small that the scientists could not rule out chance.\n\nWhich choice best describes the scientists' conclusion?","options":["Music clearly caused a large increase in milk production.","The slight difference may have been due to chance rather than the music.","The herd in silence produced more milk than the herd with music.","Classical music reduced milk production in dairy cows."],"explanation":"The text says the difference was so small that chance could not be ruled out, meaning the slight difference may have been due to chance. The other choices overstate or misstate the conclusion.","skill":"central ideas/details"},{"cat":"information","a":1,"q":"The poet Emily Dickinson published fewer than a dozen poems during her lifetime, and most of those appeared without her name. After her death, her sister discovered nearly 1,800 poems she had written and kept private. Today Dickinson is regarded as one of the most important poets in American literature.\n\nWhich choice is best supported by the text?","options":["Dickinson was widely celebrated as a poet during her lifetime.","Most of Dickinson's poems became known only after her death.","Dickinson refused to write poetry until late in her life.","Dickinson published nearly all of her poems under her own name."],"explanation":"Since she published fewer than a dozen poems while alive and her sister discovered nearly 1,800 after her death, most became known only afterward. The other choices contradict the passage.","skill":"inferences from a short passage"},{"cat":"information","a":0,"q":"An economist studied two neighborhoods that received new public libraries. In the first neighborhood, the library offered free job-training classes; in the second, it did not. Over two years, residents of the first neighborhood found new jobs at a higher rate than residents of the second, even though the two neighborhoods had similar employment rates before the libraries opened.\n\nWhich choice best supports the conclusion that the job-training classes contributed to the higher employment in the first neighborhood?","options":["The two neighborhoods had similar employment rates before the libraries opened.","Both libraries were the same size and had the same hours.","Residents in both neighborhoods borrowed the same number of books.","The second neighborhood had more residents than the first."],"explanation":"Because the neighborhoods had similar employment before, the difference afterward can more plausibly be attributed to the classes offered in the first. The other options do not isolate the effect of the classes.","skill":"command of textual evidence"},{"cat":"information","a":2,"q":"Glass frogs, found in Central and South American rainforests, have translucent skin on their undersides through which their internal organs are visible. Scientists have found that when these frogs sleep, they pull most of their red blood cells into their liver, making their bodies even more transparent and harder for predators to spot.\n\nWhich choice best states the function of the glass frog's behavior described in the text?","options":["Pulling blood cells into the liver helps the frog digest food more quickly.","Storing blood cells in the liver makes the frog more visible to mates.","Concentrating blood cells in the liver helps the frog avoid being seen by predators.","Removing blood cells from circulation allows the frog to swim faster."],"explanation":"The text states that pulling red blood cells into the liver makes the frog more transparent and harder for predators to spot. The other choices describe functions not mentioned.","skill":"central ideas/details"},{"cat":"information","a":1,"q":"A psychologist proposed that people are more likely to keep a promise when they write it down rather than simply stating it aloud. She reasoned that the act of writing forces a person to think more carefully about the commitment, increasing their sense of accountability.\n\nWhich finding, if true, would most strongly support the psychologist's proposal?","options":["People who enjoy writing tend to make more promises than others.","Participants who wrote down their goals fulfilled them more often than those who spoke them aloud.","Most participants found it easier to speak their goals than to write them.","Writing down a goal took participants longer than saying it aloud."],"explanation":"The proposal predicts that writing down a commitment increases follow-through. Evidence that those who wrote goals fulfilled them more often directly supports this. The other findings do not address whether writing improves promise-keeping.","skill":"command of textual evidence"},{"cat":"information","a":0,"q":"Researchers studying a remote alpine meadow observed that a certain wildflower bloomed about two weeks earlier than it had decades ago, based on historical records. They also noted that the bees that normally pollinate the flower did not become active any earlier. The researchers worried that the flower and its pollinators were becoming out of sync.\n\nWhich choice best explains the researchers' concern?","options":["The flowers might bloom before their pollinators are active, reducing pollination.","The bees might begin to feed on a different species of flower entirely.","The flowers might produce too much nectar for the bees to collect.","The historical records might contain errors about past bloom times."],"explanation":"The flower now blooms earlier while the bees' activity has not shifted, so the bloom may occur before pollinators are active, reducing pollination. The other choices are not supported by the text.","skill":"inferences from a short passage"},{"cat":"information","a":1,"q":"A historian studying medieval trade examined records from a port city. She found that the city's wealthiest merchants were almost all involved in the spice trade, and that the volume of spices passing through the port grew steadily over a century. From this, she argued that the spice trade was central to the city's prosperity.\n\nWhich finding would most directly weaken the historian's argument?","options":["Spice prices remained stable throughout the century she studied.","The city's wealth came mostly from textile production, not the spice trade.","Several wealthy merchants owned ships used to transport spices.","The port was located along a major sea route used by spice traders."],"explanation":"The historian argues the spice trade was central to prosperity. Evidence that the city's wealth came mostly from textiles, not spices, directly weakens this. The other options are consistent with or support her argument.","skill":"command of textual evidence"},{"cat":"information","a":3,"q":"An ecologist reintroduced wolves to a national park where they had been absent for decades. Within several years, the population of elk, which the wolves hunt, declined. As elk numbers fell, young willow and aspen trees, which elk had heavily grazed, began to grow back along riverbanks, and beavers returned to build dams.\n\nWhich choice best describes the chain of effects suggested by the text?","options":["Reintroducing wolves had no measurable effect on other species in the park.","The return of beavers caused the wolves to hunt more elk.","Fewer wolves led to more elk, which allowed trees to recover.","Wolves reduced elk numbers, allowing trees to recover and beavers to return."],"explanation":"The text describes wolves reducing elk, which let trees recover and beavers return. Choice C reverses the wolf-elk relationship, and the others contradict the passage.","skill":"inferences from a short passage"},{"cat":"information","a":1,"q":"A linguist studying an endangered language noticed that it was spoken fluently only by people over the age of sixty in the community. Younger residents understood some words but spoke primarily the regional majority language. The linguist concluded that without intervention, the endangered language was likely to disappear within a generation or two.\n\nWhich choice best supports the linguist's conclusion?","options":["The endangered language has a rich vocabulary for describing local plants.","Only older community members speak the language fluently, and younger ones do not.","The majority language is spoken across a wide geographic region.","The endangered language was once written using a unique alphabet."],"explanation":"If only older members speak the language fluently while younger ones do not, the language is likely to die out as elders pass away, supporting the conclusion. The other options do not bear on the language's survival.","skill":"command of textual evidence"},{"cat":"information","a":0,"q":"Two researchers debated why a species of migratory bird had begun spending winters farther north than it once did. One argued that warmer winter temperatures allowed the birds to find food in northern areas year-round. The other argued that bird feeders placed by humans now provided a reliable food source in the north.\n\nWhich finding, if true, would best support the second researcher's explanation over the first?","options":["The birds wintered farther north only in areas where many feeders were present, regardless of temperature.","Winter temperatures in the northern areas had risen over the past few decades.","The birds traveled in larger flocks than they had in the past.","The birds returned south earlier in the spring than they once did."],"explanation":"The second researcher credits feeders, not warmth. Evidence that the birds wintered north only where feeders were present, regardless of temperature, favors the feeder explanation over the temperature one. The other findings do not distinguish the two explanations.","skill":"command of textual evidence"},{"cat":"information","a":1,"q":"A team analyzing ancient pottery found that pots made in one village contained tiny mineral fragments matching clay deposits located more than 200 miles away. The same distinctive pots appeared at sites across a wide region. The researchers proposed that the village had been a major center of pottery production and trade.\n\nWhich finding would most strongly support the researchers' proposal?","options":["The pots from the village were more fragile than pots made elsewhere.","The distinctive pots were found in large quantities at many distant settlements but were produced only in the village.","The clay deposits near the village were smaller than deposits elsewhere.","The village contained fewer houses than neighboring settlements."],"explanation":"If the distinctive pots were made only in the village yet found widely at distant sites, this supports the village being a center of production and trade. The other options do not support widespread trade from the village.","skill":"command of textual evidence"},{"cat":"craft","a":0,"q":"Marine biologist Dr. Lena Okafor argues that coral reefs are remarkably ______ ecosystems: even after a severe bleaching event, many reefs can regrow and rebuild their populations of fish and invertebrates within a decade if water conditions improve.\n\nWhich choice completes the text with the most logical and precise word or phrase?","options":["resilient","decorative","ancient","isolated"],"explanation":"\"Resilient\" means able to recover from difficulty, which fits the reefs' ability to regrow after bleaching. \"Decorative\" and \"ancient\" describe other qualities not supported by the recovery context, and \"isolated\" contradicts the idea of bustling populations rebuilding.","skill":"words in context (academic vocabulary)"},{"cat":"craft","a":0,"q":"When the city council first proposed building a network of bike lanes, the plan seemed ______ to many drivers, who worried that removing car lanes would worsen traffic. Within a year, however, commute times had actually dropped as more people chose to cycle.\n\nWhich choice completes the text with the most logical and precise word or phrase?","options":["impractical","affordable","temporary","popular"],"explanation":"Drivers \"worried\" the plan would worsen traffic, so they viewed it as \"impractical\" (not workable). \"Affordable\" and \"temporary\" address cost and duration, which are not at issue, and \"popular\" contradicts the drivers' negative reaction.","skill":"words in context (academic vocabulary)"},{"cat":"craft","a":0,"q":"In her memoir, the pianist describes her early performances as ______ affairs, full of mistakes she now finds embarrassing. Yet she insists those flawed recitals taught her more than any flawless one could have.\n\nWhich choice completes the text with the most logical and precise word or phrase?","options":["clumsy","private","lengthy","expensive"],"explanation":"The performances were \"full of mistakes\" she finds embarrassing, so \"clumsy\" (awkward, error-filled) fits best. \"Private,\" \"lengthy,\" and \"expensive\" describe other traits not connected to the mistakes she emphasizes.","skill":"words in context (academic vocabulary)"},{"cat":"craft","a":0,"q":"The novelist was famous for her ______ descriptions: a single paragraph might list the color of a character's coat, the smell of the rain, the sound of distant traffic, and the precise angle of afternoon light through a window.\n\nWhich choice completes the text with the most logical and precise word or phrase?","options":["detailed","brief","humorous","fictional"],"explanation":"The example lists many specific sensory items, illustrating \"detailed\" descriptions. \"Brief\" contradicts the abundance of detail, while \"humorous\" and \"fictional\" describe qualities the example does not demonstrate.","skill":"words in context (academic vocabulary)"},{"cat":"craft","a":0,"q":"Although the two researchers reached the same conclusion, their methods could not have been more ______: one relied entirely on computer simulations, while the other spent three years gathering measurements in the field.\n\nWhich choice completes the text with the most logical and precise word or phrase?","options":["divergent","outdated","expensive","cautious"],"explanation":"The sentence contrasts simulations with fieldwork, so \"divergent\" (sharply different) captures how the methods differ. \"Outdated,\" \"expensive,\" and \"cautious\" describe other attributes not supported by the comparison.","skill":"words in context (academic vocabulary)"},{"cat":"craft","a":0,"q":"Some critics dismissed the architect's design as merely ______, claiming its bold curves served no function and existed only to attract attention. The architect responded that the curves also improved the building's airflow and reduced energy costs.\n\nWhich choice completes the text with the most logical and precise word or phrase?","options":["ornamental","structural","affordable","historic"],"explanation":"Critics said the curves \"served no function\" and existed \"only to attract attention,\" matching \"ornamental\" (decorative without purpose). \"Structural\" is the opposite of the critics' claim, and \"affordable\" and \"historic\" are unrelated to the function debate.","skill":"words in context (academic vocabulary)"},{"cat":"craft","a":0,"q":"The committee's report was praised for its ______ tone: rather than taking sides in the heated dispute, it carefully laid out the evidence supporting each position and left readers to draw their own conclusions.\n\nWhich choice completes the text with the most logical and precise word or phrase?","options":["impartial","enthusiastic","apologetic","mysterious"],"explanation":"The report avoided \"taking sides\" and presented evidence for each position, so \"impartial\" (neutral, unbiased) fits. \"Enthusiastic,\" \"apologetic,\" and \"mysterious\" describe tones not supported by the balanced approach described.","skill":"words in context (academic vocabulary)"},{"cat":"craft","a":0,"q":"Early evidence for the new drug was promising but far from ______: the trial involved only thirty patients, and researchers cautioned that much larger studies would be needed before any firm claims could be made.\n\nWhich choice completes the text with the most logical and precise word or phrase?","options":["conclusive","expensive","recent","voluntary"],"explanation":"The small trial and the call for larger studies show the evidence was not yet \"conclusive\" (decisive enough to settle the matter). \"Expensive,\" \"recent,\" and \"voluntary\" address cost, timing, and participation, none of which the passage emphasizes.","skill":"words in context (academic vocabulary)"},{"cat":"craft","a":0,"q":"The following passage describes a discovery about octopus behavior.\n\nResearchers studying octopuses in a controlled tank noticed something unexpected. When a particular caretaker who had once handled the animals roughly approached, the octopuses changed color and squirted water at him. A different caretaker, who had always been gentle, was met calmly. The team concluded that the octopuses could recognize and remember individual humans.\n\nWhich choice best states the main purpose of the text?","options":["To present an observation and the conclusion researchers drew from it","To argue that octopuses should not be kept in tanks","To compare octopuses with other intelligent sea creatures","To explain how octopuses change color to blend into their surroundings"],"explanation":"The text describes what researchers observed (different reactions to two caretakers) and the conclusion they reached (octopuses recognize individuals). It does not argue for ethics, compare species, or explain camouflage in general.","skill":"text structure and purpose"},{"cat":"craft","a":0,"q":"The following text is adapted from a student essay about urban design.\n\nMany cities once paved over their rivers to make room for highways. In recent years, though, a number of these cities have torn out the concrete and let the water flow freely again. Seoul, for example, removed an elevated freeway in 2005 to restore a buried stream. The project cooled the surrounding area, attracted wildlife, and quickly became a popular gathering place.\n\nWhich choice best describes the overall structure of the text?","options":["It introduces a general trend and then illustrates it with a specific example.","It poses a question and then offers several competing answers.","It describes a problem and then warns against a proposed solution.","It lists events in the order a tourist would encounter them."],"explanation":"The text first states a general trend (cities restoring buried rivers) and then gives Seoul as a specific illustration. It does not pose a question, warn against a solution, or follow a tourist's itinerary.","skill":"text structure and purpose"},{"cat":"craft","a":0,"q":"The following text is from a passage about scientific instruments.\n\nThe telescope and the microscope are often mentioned together, but they solve opposite problems. The telescope gathers light from objects so distant that the eye cannot detect them, bringing galaxies into view. The microscope magnifies objects so small that they would otherwise go unseen, revealing cells and bacteria. In each case, the instrument extends the limits of human sight, just in opposite directions.\n\nWhich choice best describes the main purpose of the text?","options":["To explain how two instruments address opposite limits of human vision","To argue that the microscope is more useful than the telescope","To trace the historical development of optical lenses","To describe how galaxies and cells were first discovered"],"explanation":"The passage's main point is that both instruments extend human sight \"in opposite directions.\" It does not rank the instruments, give their history, or recount specific discoveries.","skill":"text structure and purpose"},{"cat":"craft","a":0,"q":"The following text is adapted from a magazine article about food science.\n\nWhy does bread go stale? Many people assume staling is simply the bread drying out, but that explanation is incomplete. Even bread sealed in an airtight bag eventually turns firm and crumbly. The real cause is a process called retrogradation, in which starch molecules that had loosened during baking gradually rearrange themselves into a more rigid structure.\n\nWhich choice best describes the function of the second sentence in the text as a whole?","options":["It introduces a common belief that the text then corrects.","It restates the question posed in the first sentence.","It provides evidence supporting the final claim about starch.","It offers a practical tip for keeping bread fresh."],"explanation":"The second sentence names a common assumption (\"drying out\") and labels it \"incomplete,\" setting up the correction that follows. It does not merely restate the question, supply supporting evidence, or give a storage tip.","skill":"text structure and purpose"},{"cat":"craft","a":0,"q":"The following text is from an essay about a painter.\n\nFor most of his career, the painter Anton Reyes worked in near-total obscurity, selling only a handful of canvases. He took a job as a sign painter to pay rent and painted his own work late at night. Today his paintings hang in major museums, and a single one recently sold for more than he earned in his entire lifetime.\n\nWhich choice best describes the function of the last sentence in the text?","options":["It underscores the contrast between Reyes's earlier obscurity and his later fame.","It explains why Reyes chose to work as a sign painter.","It questions whether the museums valued Reyes's work fairly.","It introduces a new painter for comparison with Reyes."],"explanation":"The final sentence highlights how a single painting now exceeds his lifetime earnings, sharpening the contrast between his early obscurity and present fame. It does not explain his day job, question the museums, or introduce a new artist.","skill":"text structure and purpose"},{"cat":"craft","a":0,"q":"The following text is adapted from a report on language learning.\n\nIt is widely believed that children learn new languages effortlessly while adults struggle. Research complicates this picture. In controlled studies, adults often acquire vocabulary and grammar rules faster than children do, at least at first. Children's advantage appears mainly in pronunciation, where they more reliably achieve a native-sounding accent. The popular belief, then, captures one real difference while ignoring several others.\n\nWhich choice best describes the overall structure of the text?","options":["It states a popular belief, qualifies it with research, and assesses what the belief gets right and wrong.","It defines a scientific term and then gives examples of its use.","It presents two studies that reach contradictory conclusions.","It recommends a specific method for adults learning languages."],"explanation":"The text opens with a common belief, complicates it with research findings, and concludes by judging what the belief captures and misses. It does not define a term, pit two studies against each other, or recommend a method.","skill":"text structure and purpose"},{"cat":"craft","a":0,"q":"The following text is from a passage about the history of a public park.\n\nWhen the park first opened in 1871, it was little more than a muddy field with a few benches. Over the next decade, gardeners planted hundreds of trees, and a pond was dug at its center. By the 1890s, the once-bare ground had become a shaded retreat where families gathered on weekends, and the park had earned a place in guidebooks of the city.\n\nWhich choice best describes the overall structure of the text?","options":["It traces the gradual transformation of the park over time.","It compares the park with other parks built in the same era.","It argues that the park should be expanded further.","It describes a single memorable day in the park's history."],"explanation":"The passage moves chronologically from 1871 to the 1890s, charting how a muddy field became a celebrated retreat. It does not compare parks, argue for expansion, or focus on one specific day.","skill":"text structure and purpose"},{"cat":"craft","a":0,"q":"Text 1\nThe spread of streaming services has been a boon for music listeners. For a small monthly fee, anyone can access millions of songs from across the world, discovering artists they would never have found in a local record store.\n\nText 2\nStreaming may benefit listeners, but for many musicians it is a poor deal. A single stream pays only a tiny fraction of a cent, so an artist may need hundreds of thousands of plays to earn what one album sale once provided. Lesser-known performers, in particular, struggle to make a living.\n\nBased on the texts, how would the author of Text 2 most likely respond to the view expressed in Text 1?","options":["By acknowledging the benefit to listeners but stressing the cost to musicians","By denying that streaming has increased access to music","By arguing that record stores were better for listeners","By claiming that streaming services lose money each year"],"explanation":"Text 2 begins \"Streaming may benefit listeners, but,\" granting Text 1's point while emphasizing harm to musicians. It does not deny increased access, praise record stores for listeners, or discuss the services' profitability.","skill":"connections between two short texts"},{"cat":"craft","a":0,"q":"Text 1\nUrban planner Dana Cho argues that wide, fast roads make cities more dangerous. When drivers feel safe speeding, she notes, pedestrians and cyclists pay the price, and accident rates climb.\n\nText 2\nIn a recent study, engineers narrowed several city streets and added trees and parked cars along the edges. Drivers slowed down noticeably, even without new speed-limit signs, and the number of crashes fell over the following year.\n\nWhich choice best describes the relationship between the two texts?","options":["Text 2 provides empirical support for the claim made in Text 1.","Text 2 disputes the central argument of Text 1.","Text 2 restates Text 1's argument without adding information.","Text 2 raises a question that Text 1 fails to answer."],"explanation":"Text 1 claims fast roads endanger people; Text 2's study shows that narrowing streets slowed drivers and cut crashes, offering evidence for that claim. It neither disputes nor merely restates Text 1, and it does not pose an unanswered question.","skill":"connections between two short texts"},{"cat":"craft","a":0,"q":"Text 1\nHistorian Marcus Vell contends that the printing press was the single most important cause of the rapid spread of new ideas in sixteenth-century Europe. Before the press, he notes, copying a book by hand could take months.\n\nText 2\nThe printing press certainly mattered, but it could not have spread ideas without a literate public to read the books. Rising literacy, improved roads, and growing networks of merchants all worked together. Singling out one cause oversimplifies a process driven by many forces at once.\n\nBased on the texts, the author of Text 2 would most likely characterize Vell's argument as","options":["too narrow in attributing the spread of ideas to a single cause","incorrect in claiming that the printing press mattered at all","overly focused on the role of merchants and roads","convincing because it accounts for rising literacy"],"explanation":"Text 2 says \"singling out one cause oversimplifies\" a multi-factor process, so the author would see Vell's single-cause claim as too narrow. Text 2 agrees the press \"certainly mattered,\" does not focus on merchants as Vell's emphasis, and faults rather than praises his account of literacy.","skill":"connections between two short texts"},{"cat":"craft","a":0,"q":"Text 1\nBiologist Reza Amin claims that wolves reintroduced to a national park improved the health of the entire ecosystem. By thinning herds of elk, the wolves allowed young trees along riverbanks to grow, which in turn stabilized the soil and attracted beavers and songbirds.\n\nText 2\nThe changes credited to wolves may have other explanations. During the same years, the region experienced unusually wet weather and a decline in human hunting nearby. Without ruling out these factors, it is difficult to be sure how much of the recovery the wolves alone caused.\n\nWhich choice best describes how Text 2 relates to Text 1?","options":["It cautions that factors other than wolves could explain the changes Text 1 attributes to them.","It provides additional examples of species that benefited from the wolves.","It denies that the ecosystem recovered at all during this period.","It argues that wolves harmed the ecosystem rather than helped it."],"explanation":"Text 2 points to wet weather and reduced hunting as alternative explanations, urging caution about crediting wolves alone. It does not add examples, deny the recovery, or claim wolves caused harm.","skill":"connections between two short texts"},{"cat":"craft","a":0,"q":"Text 1\nMany educators praise open-plan classrooms, where movable furniture and shared spaces let students collaborate freely. Supporters say the flexible layout sparks creativity and keeps lessons from feeling rigid.\n\nText 2\nResearcher Priya Nandakumar surveyed teachers in newly built open-plan schools. While some welcomed the freedom, a majority reported that noise from neighboring groups made it hard for students to concentrate, and several said they had begun rearranging furniture to recreate the walls the design had removed.\n\nBased on the texts, Nandakumar's findings in Text 2 most directly complicate which assumption underlying Text 1?","options":["That the flexibility of open-plan classrooms is mainly an advantage for learning","That students prefer collaborating in groups over working alone","That movable furniture is more expensive than fixed furniture","That creativity can be measured through teacher surveys"],"explanation":"Text 1 assumes open-plan flexibility benefits learning; Nandakumar's finding that noise hindered concentration and teachers rebuilt walls complicates that assumption. The findings do not address student preferences, furniture cost, or how creativity is measured.","skill":"connections between two short texts"},{"cat":"craft","a":0,"q":"Text 1\nScience writer Tomas Belling celebrates citizen-science projects, in which volunteers with no formal training help gather data—counting birds, photographing plants, or logging weather. He argues that millions of amateur observers can collect data on a scale no team of professionals could match.\n\nText 2\nVolunteer-gathered data has real value, yet it must be handled with care. Untrained observers may misidentify species or record measurements inconsistently. The best projects succeed not by ignoring these problems but by building in checks—training modules, expert review, and software that flags unlikely entries.\n\nBased on the texts, how do the two authors differ in their treatment of citizen science?","options":["Text 1 emphasizes its scale, while Text 2 focuses on safeguarding the quality of its data.","Text 1 supports citizen science, while Text 2 rejects it entirely.","Text 1 discusses birds, while Text 2 discusses only weather data.","Text 1 relies on data, while Text 2 relies only on personal opinion."],"explanation":"Text 1 stresses the unmatched scale of volunteer data, whereas Text 2 accepts its value but concentrates on quality controls. Text 2 does not reject citizen science, the difference is not about specific subjects, and both engage with data rather than mere opinion.","skill":"connections between two short texts"},{"cat":"craft","a":0,"q":"After weeks of rain, the hikers were relieved to finally see a ______ sky, with no clouds in any direction.\n\nWhich choice completes the text with the most logical and precise word or phrase?","options":["clear","crowded","narrow","fragile"],"explanation":"The phrase \"no clouds in any direction\" signals an open, cloudless sky, which \"clear\" describes precisely. The other options do not fit a description of weather without clouds.","skill":"words in context"},{"cat":"craft","a":1,"q":"The new intern was so ______ that she completed every task on the first day without being asked twice and even volunteered for extra assignments.\n\nWhich choice completes the text with the most logical and precise word or phrase?","options":["reluctant","eager","confused","absent"],"explanation":"Completing tasks promptly and volunteering for more shows enthusiasm, which \"eager\" captures. \"Reluctant\" is the opposite, and \"confused\" and \"absent\" contradict her productivity.","skill":"words in context"},{"cat":"craft","a":1,"q":"Although the recipe looked complicated, the chef insisted it was actually quite ______: it required only three ingredients and a single pan.\n\nWhich choice completes the text with the most logical and precise word or phrase?","options":["expensive","simple","dangerous","famous"],"explanation":"The contrast word \"although\" sets up an opposition to \"complicated,\" and the detail of three ingredients and one pan supports \"simple.\" The other choices are unrelated to ease of preparation.","skill":"words in context"},{"cat":"craft","a":1,"q":"The following text is from a guide about houseplants.\n\nSucculents are popular among beginning gardeners because they need very little attention. Unlike many leafy plants, they store water in their thick leaves, so they can survive for weeks between waterings. This makes them ideal for people who often forget to tend to their plants.\n\nWhat is the main purpose of the text?","options":["To warn readers that succulents are difficult to grow","To explain why succulents suit forgetful or busy people","To compare the cost of succulents and leafy plants","To describe the appearance of a succulent's leaves"],"explanation":"The text emphasizes that succulents need little attention and survive long periods without water, making them ideal for forgetful caretakers. The other choices misstate or only touch on minor details.","skill":"text structure and purpose"},{"cat":"craft","a":0,"q":"Critics initially called the young director's films ______, dismissing his slow pacing and minimal dialogue as boring; years later, the same restraint was praised as masterful.\n\nWhich choice completes the text with the most logical and precise word or phrase?","options":["tedious","thrilling","expensive","colorful"],"explanation":"The words \"dismissing\" and \"boring\" signal a negative judgment, so \"tedious\" fits. The later reversal to praise confirms the earlier word was critical, ruling out the positive or neutral options.","skill":"words in context"},{"cat":"craft","a":1,"q":"The following text is adapted from a short article about bees.\n\nWhen a honeybee finds a rich source of nectar, it returns to the hive and performs a series of movements known as the \"waggle dance.\" The angle and duration of the dance tell other bees the direction and distance of the food. In this way, a single bee can guide hundreds of others to a meal.\n\nWhich choice best describes the function of the second sentence in the overall structure of the text?","options":["It questions whether the waggle dance is real.","It explains how the waggle dance communicates specific information.","It compares the waggle dance to human language.","It lists the dangers bees face when gathering nectar."],"explanation":"The second sentence specifies that the dance's angle and duration convey direction and distance, explaining how the dance works. It neither questions, compares to language, nor lists dangers.","skill":"text structure and purpose"},{"cat":"craft","a":1,"q":"The senator's speech was admired for its ______ wording: every sentence was carefully chosen to avoid offending any group while still conveying her position.\n\nWhich choice completes the text with the most logical and precise word or phrase?","options":["careless","diplomatic","rushed","hostile"],"explanation":"Wording crafted to avoid offending anyone while still making a point is \"diplomatic.\" \"Careless\" and \"rushed\" contradict the careful choosing, and \"hostile\" contradicts avoiding offense.","skill":"words in context"},{"cat":"craft","a":1,"q":"The following text is from a passage about a mountain village.\n\nFor centuries, the village of Aldwick was reachable only by a steep mule path, and few outsiders ever made the climb. When a paved road finally connected it to the valley in 1962, the change was swift. Within a decade, the population had tripled, and the quiet streets filled with shops, cafes, and visitors.\n\nWhich choice best states the main idea of the text?","options":["Mule paths are safer than paved roads in mountainous areas.","A new road transformed a once-isolated village.","The village of Aldwick was founded in 1962.","Tourists prefer villages that are hard to reach."],"explanation":"The text contrasts the village's former isolation with the rapid growth that followed the new road, making transformation the main idea. The other choices distort details or are unsupported.","skill":"text structure and purpose"},{"cat":"craft","a":1,"q":"Far from being ______, the ancient manuscript was in surprisingly good condition, its ink still dark and its pages intact after a thousand years.\n\nWhich choice completes the text with the most logical and precise word or phrase?","options":["valuable","deteriorated","readable","modern"],"explanation":"\"Far from being\" sets up a contrast with the good condition described, so the blank needs a word meaning damaged or decayed: \"deteriorated.\" The good condition rules out the other options as the intended contrast.","skill":"words in context"},{"cat":"craft","a":0,"q":"The professor's lectures were notably ______; she could distill an entire week of complicated readings into a few clear, memorable sentences.\n\nWhich choice completes the text with the most logical and precise word or phrase?","options":["concise","lengthy","confusing","irrelevant"],"explanation":"Reducing a week of reading to a few clear sentences describes brevity, which \"concise\" captures. \"Lengthy\" is the opposite, and \"confusing\" and \"irrelevant\" contradict \"clear\" and \"memorable.\"","skill":"words in context"},{"cat":"craft","a":0,"q":"The following text is from a science writer's essay.\n\nMany people assume that a desert is simply a place with great heat. In fact, deserts are defined not by temperature but by dryness: any region that receives very little precipitation qualifies. By this measure, the frozen expanse of Antarctica, which gets almost no rain or snow inland, is among the largest deserts on Earth.\n\nWhich choice best describes the overall structure of the text?","options":["It presents a common belief and then corrects it with a clarifying definition and example.","It lists several deserts in order of their size.","It argues that Antarctica should not be called a desert.","It describes a personal journey through a desert region."],"explanation":"The text opens with a misconception (deserts equal heat), corrects it with the real definition (dryness), and illustrates with Antarctica. The other options misrepresent its movement from belief to correction.","skill":"text structure and purpose"},{"cat":"craft","a":0,"q":"Rather than condemning the new policy outright, the editorial took a ______ stance, acknowledging its potential benefits while raising serious questions about its costs.\n\nWhich choice completes the text with the most logical and precise word or phrase?","options":["measured","furious","indifferent","enthusiastic"],"explanation":"Weighing both benefits and costs rather than condemning describes a balanced, \"measured\" position. \"Furious\" and \"enthusiastic\" are one-sided extremes, and \"indifferent\" contradicts raising serious questions.","skill":"words in context"},{"cat":"craft","a":1,"q":"The following text is adapted from a report on sleep research.\n\nFor years, scientists believed that the brain shut down during sleep to conserve energy. Recent studies suggest the opposite. During certain sleep stages, the brain becomes highly active, replaying the day's events and strengthening memories. In other words, sleep may be less a period of rest than a period of essential work.\n\nWhat is the main purpose of the text?","options":["To describe the different stages of human sleep in detail","To revise an earlier view of sleep in light of new findings","To argue that people need more hours of sleep than they get","To explain how to fall asleep more quickly"],"explanation":"The text contrasts the old belief that the brain shuts down with new evidence that it is active during sleep, revising the earlier view. The other options address topics the text does not pursue.","skill":"text structure and purpose"},{"cat":"craft","a":1,"q":"The witness's account was so ______ that the jury found it hard to trust: she contradicted herself repeatedly and could not keep her timeline straight.\n\nWhich choice completes the text with the most logical and precise word or phrase?","options":["consistent","inconsistent","lengthy","polite"],"explanation":"Contradicting herself and confusing the timeline make the account \"inconsistent,\" explaining why the jury distrusted it. \"Consistent\" is the opposite, and the other options do not explain the distrust.","skill":"words in context"},{"cat":"craft","a":1,"q":"Once dismissed as a ______ pursuit suited only to idle dreamers, amateur astronomy now contributes real data to professional research, as backyard observers track comets and report supernovae.\n\nWhich choice completes the text with the most logical and precise word or phrase?","options":["serious","frivolous","expensive","dangerous"],"explanation":"\"Idle dreamers\" and the contrast with real scientific contribution signal a dismissive label meaning unserious: \"frivolous.\" \"Serious\" contradicts \"dismissed,\" and cost and danger are not at issue.","skill":"words in context"},{"cat":"craft","a":1,"q":"The following text is from an essay about a sculptor.\n\nThe sculptor rarely planned her works in advance. She preferred to let the stone guide her, chipping away tentatively until a form began to emerge from within the block. Only then, she said, did she discover what the sculpture was meant to be. To her, carving was an act of listening rather than commanding.\n\nWhich choice best describes the function of the last sentence in the text?","options":["It introduces a new sculptor for comparison.","It summarizes the sculptor's approach with a contrasting metaphor.","It lists the tools the sculptor used most often.","It questions whether the sculptor's method was effective."],"explanation":"The final sentence captures her method through the metaphor of \"listening rather than commanding,\" summing up the responsive approach described earlier. It does not introduce a new artist, list tools, or doubt her.","skill":"text structure and purpose"},{"cat":"craft","a":1,"q":"Text 1\nA growing number of restaurants now print only a QR code instead of a paper menu. Supporters say the change saves paper, lets owners update prices instantly, and reduces the spread of germs from shared menus.\n\nText 2\nFor diners without smartphones or strong eyesight, scanning a tiny code can turn an ordinary meal into a frustrating ordeal. A printed menu, by contrast, asks nothing of the customer but the ability to read.\n\nBased on the texts, how would the author of Text 2 most likely respond to the supporters mentioned in Text 1?","options":["By agreeing that QR menus benefit every type of diner equally","By pointing out that the benefits overlook diners who find the codes hard to use","By arguing that paper menus spread more germs than QR codes","By proposing that restaurants abandon menus altogether"],"explanation":"Text 2 stresses that some diners struggle with QR codes, so its author would note that Text 1's praise ignores those customers' difficulties. The other options misstate Text 2's accessibility concern.","skill":"connections between two short texts"},{"cat":"craft","a":0,"q":"The committee praised the proposal's ______ logic, noting that each recommendation followed inevitably from the one before, leaving no gaps for opponents to exploit.\n\nWhich choice completes the text with the most logical and precise word or phrase?","options":["airtight","shaky","vague","borrowed"],"explanation":"Recommendations following inevitably with \"no gaps\" describe flawless reasoning, which \"airtight\" conveys. \"Shaky\" and \"vague\" suggest weakness, and \"borrowed\" does not relate to logical soundness.","skill":"words in context"},{"cat":"craft","a":1,"q":"The following text is from a passage about translation.\n\nA translator faces a constant tension. To stay faithful to a poem's literal meaning, she may have to sacrifice its music, the rhythm and rhyme that give it life. But to preserve that music, she must often depart from the exact words. Every translated poem is therefore a negotiation, a series of small surrenders in pursuit of a larger loyalty.\n\nWhich choice best describes the overall structure of the text?","options":["It traces the history of a single famous translation.","It frames a dilemma and characterizes translation as a trade-off between two goals.","It argues that poems should never be translated at all.","It provides step-by-step instructions for translating poetry."],"explanation":"The text sets up the tension between literal meaning and musicality, then defines translation as a negotiation between these competing aims. It is neither a history, a ban, nor a how-to guide.","skill":"text structure and purpose"},{"cat":"craft","a":0,"q":"Text 1\nEconomist Paula Reyes maintains that raising the minimum wage helps low-income workers. When wages rise, she notes, families can afford more, and that extra spending circulates through local businesses, strengthening the whole community.\n\nText 2\nBusiness analyst Greg Tan does not dispute that higher wages aid those who keep their jobs. His worry lies elsewhere: faced with steeper payrolls, some small employers may cut hours or hire fewer people, so the very workers the policy aims to help could find fewer opportunities.\n\nBased on the texts, which choice best describes a difference in how the two authors view raising the minimum wage?","options":["Reyes focuses on benefits to spending and community, while Tan focuses on possible reductions in employment.","Reyes thinks wages should fall, while Tan thinks they should rise.","Reyes denies that workers benefit, while Tan insists they do.","Both authors agree the policy has no drawbacks whatsoever."],"explanation":"Reyes emphasizes increased spending circulating through the community, whereas Tan emphasizes that higher payrolls may reduce hours and hiring. The other options reverse or misstate their positions.","skill":"connections between two short texts"},{"cat":"craft","a":0,"q":"What once seemed a ______ distinction between living and nonliving matter has grown blurrier as scientists study viruses, entities that reproduce like organisms yet remain inert outside a host.\n\nWhich choice completes the text with the most logical and precise word or phrase?","options":["clear-cut","imaginary","recent","trivial"],"explanation":"The contrast \"has grown blurrier\" implies the distinction was formerly sharp, which \"clear-cut\" expresses. \"Imaginary\" and \"trivial\" contradict the idea of a meaningful boundary, and \"recent\" misreads the timeline.","skill":"words in context"},{"cat":"craft","a":1,"q":"The following text is adapted from a literary critic's essay.\n\nThe novel's narrator never tells us how to feel about the events he describes. He reports a betrayal in the same flat tone he uses for the weather, declines to judge the characters, and withholds any tidy moral. This refusal is not a flaw but a strategy: by staying silent, the author forces readers to render the verdict themselves.\n\nWhich choice best describes the function of the final sentence in the text?","options":["It concedes that the narrator's flatness weakens the novel.","It reinterprets the narrator's neutrality as a deliberate device with an effect on readers.","It introduces a second novel with a different kind of narrator.","It summarizes the plot of the novel for readers unfamiliar with it."],"explanation":"The last sentence recasts the narrator's silence as a purposeful \"strategy\" that compels readers to judge, reinterpreting what might seem a flaw. It does not concede weakness, add a novel, or recap plot.","skill":"text structure and purpose"},{"cat":"craft","a":1,"q":"Text 1\nArchaeologist Nadia Cole argues that the abandonment of the ancient city was caused chiefly by drought. Layers of dried lakebed sediment beneath the ruins, she says, show that water vanished just as the population began to leave.\n\nText 2\nResearcher Ivo Petrov accepts that drought struck the region but considers it only part of the story. The city's own records, he notes, describe bitter conflicts among rival rulers in the same period. A weakened, divided leadership, he argues, may have left the city unable to respond to the crisis the drought created.\n\nBased on the texts, how does Petrov's explanation in Text 2 relate to Cole's in Text 1?","options":["It rejects the idea that drought played any role in the abandonment.","It accepts drought as a factor but adds political conflict as a contributing cause.","It claims the city was never actually abandoned.","It offers identical evidence to support the same single cause."],"explanation":"Petrov \"accepts that drought struck\" but treats it as only part of the story, adding political conflict as a further cause. He neither denies the drought, disputes the abandonment, nor merely repeats Cole.","skill":"connections between two short texts"},{"cat":"craft","a":1,"q":"The biographer resisted the ______ portrait that admirers had long preferred, refusing to smooth over the inventor's cruelty toward rivals or his habit of claiming others' ideas as his own.\n\nWhich choice completes the text with the most logical and precise word or phrase?","options":["unflattering","flattering","accurate","detailed"],"explanation":"Admirers prefer a favorable image, and the biographer's refusal to hide flaws contrasts with it, so the blank means overly positive: \"flattering.\" \"Unflattering\" reverses the logic, and \"accurate\" and \"detailed\" do not capture the bias being resisted.","skill":"words in context"},{"cat":"craft","a":1,"q":"The following text is from an essay about scientific progress.\n\nWe tend to picture discovery as a sudden flash, a lone genius crying out in triumph. Yet most breakthroughs arrive slowly and collectively. A finding is questioned, repeated, refined, and revised by many hands over many years before it hardens into accepted fact. The dramatic moment we celebrate is usually just the visible peak of a long, crowded climb.\n\nWhich choice best states the main purpose of the text?","options":["To celebrate the lone geniuses behind major discoveries","To challenge a popular image of discovery by emphasizing its gradual, collective nature","To explain the specific steps required to publish a scientific paper","To argue that scientific facts can never be fully trusted"],"explanation":"The text contrasts the myth of the sudden lone genius with the reality of slow, collective work, using the \"crowded climb\" image to drive home that revision. It does not celebrate geniuses, give publishing steps, or attack the reliability of facts.","skill":"text structure and purpose"},{"cat":"craft","a":0,"q":"Text 1\nMedia scholar Lin Hartley warns that recommendation algorithms narrow what we encounter online. By feeding us more of what we already like, she argues, these systems quietly wall us off inside \"filter bubbles,\" shrinking our exposure to unfamiliar ideas.\n\nText 2\nData scientist Omar Veil counters that the bubble is often self-made. In his studies, users who actively searched and followed diverse sources saw a wide range of views, regardless of the algorithm. The tool, he suggests, mostly reflects choices the user has already made.\n\nBased on the texts, which choice best describes the relationship between the two authors' explanations for limited online exposure?","options":["Hartley blames the algorithm's design, while Veil emphasizes the user's own choices.","Both authors agree the algorithm alone determines what users see.","Veil argues that filter bubbles do not exist in any form.","Hartley claims users deliberately seek out diverse sources."],"explanation":"Hartley attributes narrowing to the algorithm walling users off, while Veil locates the cause in users' active choices, calling the bubble \"self-made.\" The other options misrepresent one or both positions.","skill":"connections between two short texts"},{"cat":"expression","a":0,"q":"Many city parks were originally designed for quiet activities like walking and picnicking. Today, however, these same parks must accommodate cyclists, skateboarders, and dog walkers as well. ______ planners are now redesigning paths to keep different users safe and separated.\n\nWhich choice completes the text with the most logical transition?","options":["As a result,","Nevertheless,","For example,","In contrast,"],"explanation":"The increased variety of park users (cause) leads planners to redesign paths (effect), so a cause-and-effect transition like 'As a result' is correct. 'Nevertheless' and 'In contrast' signal opposition, and 'For example' signals an illustration, none of which fit.","skill":"transitions"},{"cat":"expression","a":1,"q":"The honeybee communicates the location of food through a movement called the waggle dance. The angle of the dance indicates direction, and its duration signals distance. ______ a longer waggle tells other bees that the flowers are farther away.\n\nWhich choice completes the text with the most logical transition?","options":["However,","For instance,","In conclusion,","On the other hand,"],"explanation":"The sentence gives a specific illustration of how duration signals distance, so 'For instance' is correct. 'However' and 'On the other hand' signal contrast, and 'In conclusion' signals a summary, none of which fit an example.","skill":"transitions"},{"cat":"expression","a":1,"q":"Solar panels generate the most electricity when sunlight is strong and direct. ______ they still produce some power on cloudy days, because diffuse light reaches the panels even when the sky is overcast.\n\nWhich choice completes the text with the most logical transition?","options":["Therefore,","Nonetheless,","Likewise,","Specifically,"],"explanation":"The text contrasts peak production in strong sun with continued production on cloudy days, so a contrast transition like 'Nonetheless' is correct. 'Therefore' signals a result, 'Likewise' signals similarity, and 'Specifically' signals elaboration, none of which fit.","skill":"transitions"},{"cat":"expression","a":0,"q":"Archaeologists studying an ancient settlement found pottery shards scattered across the site. The shards were decorated with patterns identical to those found two hundred miles away. ______ the researchers concluded that the two communities had likely traded goods with each other.\n\nWhich choice completes the text with the most logical transition?","options":["Consequently,","However,","Similarly,","In the meantime,"],"explanation":"The matching patterns (evidence) lead to the conclusion about trade (result), so 'Consequently' is correct. 'However' signals contrast, 'Similarly' signals comparison, and 'In the meantime' signals simultaneous time, none of which fit a conclusion.","skill":"transitions"},{"cat":"expression","a":1,"q":"The novelist spent years researching the historical period before writing her book. She visited archives, interviewed historians, and read hundreds of letters from the era. ______ critics praised the novel for its remarkable authenticity and rich detail.\n\nWhich choice completes the text with the most logical transition?","options":["Nevertheless,","Unsurprisingly,","In contrast,","For example,"],"explanation":"The thorough research naturally results in an authentic novel, so 'Unsurprisingly' fits the expected outcome. 'Nevertheless' and 'In contrast' signal opposition, and 'For example' signals an illustration, none of which fit.","skill":"transitions"},{"cat":"expression","a":0,"q":"Coral reefs support an enormous variety of marine life. They occupy less than one percent of the ocean floor. ______ they are home to roughly a quarter of all known ocean species.\n\nWhich choice completes the text with the most logical transition?","options":["Yet","Thus","Likewise","Furthermore"],"explanation":"There is a striking contrast between the tiny area reefs occupy and the huge share of species they host, so the contrast transition 'Yet' is correct. 'Thus' signals result, while 'Likewise' and 'Furthermore' signal addition or similarity, none of which capture the contrast.","skill":"transitions"},{"cat":"expression","a":2,"q":"The factory installed sensors to monitor energy use on every machine. Managers reviewed the data each week and adjusted schedules to avoid peak-rate hours. ______ the company reduced its electricity costs by nearly thirty percent within a year.\n\nWhich choice completes the text with the most logical transition?","options":["Instead,","In short,","As a result,","By contrast,"],"explanation":"The monitoring and scheduling changes (cause) produced the cost reduction (effect), so 'As a result' is correct. 'Instead' and 'By contrast' signal opposition, and 'In short' signals a summary rather than a causal result.","skill":"transitions"},{"cat":"expression","a":1,"q":"Volunteers planted native grasses along the eroding riverbank last spring. The deep roots of these grasses hold soil in place far better than the shallow-rooted weeds that grew there before. ______ sections of the bank that were once washing away after every storm now remain stable.\n\nWhich choice completes the text with the most logical transition?","options":["Otherwise,","Consequently,","Conversely,","Meanwhile,"],"explanation":"The deep roots holding soil (cause) result in stable banks (effect), so 'Consequently' is correct. 'Otherwise' implies an alternative condition, 'Conversely' signals contrast, and 'Meanwhile' signals simultaneous time, none of which fit.","skill":"transitions"},{"cat":"expression","a":0,"q":"The new bridge was designed to expand and contract with temperature changes. Engineers built gaps into the roadway to allow this movement. ______ they fitted the structure with sensors that alert crews if stress on the joints becomes dangerous.\n\nWhich choice completes the text with the most logical transition?","options":["Additionally,","However,","Therefore,","In other words,"],"explanation":"The sentence adds a second design feature to the first, so the additive transition 'Additionally' is correct. 'However' signals contrast, 'Therefore' signals result, and 'In other words' signals restatement, none of which fit a second item.","skill":"transitions"},{"cat":"expression","a":1,"q":"Most migratory birds rely on the Earth's magnetic field to navigate vast distances. Bright artificial lights in cities can disorient them, causing them to circle buildings until exhausted. ______ several cities have begun dimming downtown lights during peak migration seasons.\n\nWhich choice completes the text with the most logical transition?","options":["Regardless,","In response,","Similarly,","For example,"],"explanation":"The cities act in reaction to the problem of disorientation, so 'In response' is correct. 'Regardless' dismisses the prior point, 'Similarly' signals comparison, and 'For example' signals illustration, none of which fit a reaction.","skill":"transitions"},{"cat":"expression","a":1,"q":"Economists once assumed that people always make purely rational financial decisions. Recent studies, ______ have shown that emotions and mental shortcuts strongly influence choices about spending and saving.\n\nWhich choice completes the text with the most logical transition?","options":["therefore,","however,","likewise,","in fact,"],"explanation":"The recent studies contradict the old assumption of pure rationality, so the contrast transition 'however' is correct. 'Therefore' signals result, 'likewise' signals similarity, and 'in fact' signals emphasis or confirmation, none of which capture the contradiction.","skill":"transitions"},{"cat":"expression","a":2,"q":"A student is writing about a community garden project. She has taken these notes:\n- The garden was started in 2019 on a vacant lot.\n- Residents grow vegetables in shared plots.\n- Surplus produce is donated to a local food bank.\n- In 2023, the garden donated over 1,500 pounds of food.\n\nThe student wants to emphasize the garden's contribution to fighting local hunger. Which choice most effectively uses the notes to accomplish this goal?","options":["The community garden, started in 2019 on a vacant lot, lets residents grow vegetables in shared plots.","Residents who grow vegetables in the garden's shared plots have been doing so since 2019.","The community garden donated over 1,500 pounds of surplus produce to a local food bank in 2023.","Started on a vacant lot in 2019, the garden contains shared plots for growing vegetables."],"explanation":"The goal is to emphasize fighting local hunger, and only the option highlighting the 1,500 pounds donated to the food bank addresses that. The other choices focus on the garden's origin or structure, not its contribution to fighting hunger.","skill":"rhetorical synthesis"},{"cat":"expression","a":1,"q":"A student is writing about the inventor Garrett Morgan. She has taken these notes:\n- Garrett Morgan was an American inventor born in 1877.\n- He invented an early traffic signal in 1923.\n- His signal added a warning position between stop and go.\n- This warning position made intersections safer.\n\nThe student wants to explain how Morgan's traffic signal improved safety. Which choice most effectively uses the notes to accomplish this goal?","options":["Garrett Morgan, an American inventor, was born in 1877 and created many devices.","Morgan's 1923 traffic signal made intersections safer by adding a warning position between stop and go.","In 1923, Garrett Morgan invented a traffic signal, one of his many notable inventions.","Garrett Morgan was an American inventor who is known for his 1923 traffic signal."],"explanation":"The goal is to explain how the signal improved safety, and only the option linking the warning position to safer intersections does so. The other choices give biographical facts or merely mention the invention without explaining the safety improvement.","skill":"rhetorical synthesis"},{"cat":"expression","a":1,"q":"A student is writing about a species of frog. He has taken these notes:\n- The glass frog lives in Central and South American rainforests.\n- Its belly skin is transparent.\n- Through this skin, its internal organs are visible.\n- Scientists study the frog to understand how it hides its blood while sleeping.\n\nThe student wants to introduce the glass frog to an audience unfamiliar with it. Which choice most effectively accomplishes this goal?","options":["Scientists study the glass frog to learn how it hides its blood while it sleeps.","The glass frog, found in Central and South American rainforests, has transparent belly skin that reveals its internal organs.","The internal organs of the glass frog are visible through the transparent skin on its belly.","Hiding its blood while sleeping is one behavior that scientists find fascinating about the frog."],"explanation":"To introduce the frog to an unfamiliar audience, the best choice names the animal, says where it lives, and describes its defining trait. The other options assume familiarity by diving into a specific detail or behavior without introducing the frog itself.","skill":"rhetorical synthesis"},{"cat":"expression","a":2,"q":"A student is writing an article about two painting techniques. She has taken these notes:\n- Fresco involves painting on wet plaster.\n- In fresco, the colors bond with the wall as the plaster dries.\n- Tempera involves mixing pigment with egg yolk.\n- Tempera is applied to wood panels or dry surfaces.\n\nThe student wants to highlight a difference between the two techniques. Which choice most effectively uses the notes to accomplish this goal?","options":["Both fresco and tempera are painting techniques that artists have used for centuries.","Fresco and tempera each require the artist to prepare materials before painting begins.","Whereas fresco is painted on wet plaster, tempera mixes pigment with egg yolk for use on dry surfaces.","Tempera, which mixes pigment with egg yolk, is applied to wood panels or other dry surfaces."],"explanation":"The goal is to highlight a difference, and only the option contrasting wet plaster with dry surfaces and egg-yolk mixing does so. One option stresses similarity, another describes only tempera, and the first is too vague to show a difference.","skill":"rhetorical synthesis"},{"cat":"expression","a":1,"q":"A student is writing about a marine biologist's research. He has taken these notes:\n- Dr. Reyes studies bioluminescent plankton.\n- These plankton glow blue when disturbed by waves or boats.\n- Dr. Reyes measured glow intensity at twelve coastal sites.\n- Sites with cleaner water showed brighter glows.\n\nThe student wants to present the main finding of Dr. Reyes's study. Which choice most effectively uses the notes to accomplish this goal?","options":["Dr. Reyes studies bioluminescent plankton, which glow blue when disturbed by waves or boats.","Across twelve coastal sites, Dr. Reyes found that plankton glowed more brightly in cleaner water.","Bioluminescent plankton glow blue whenever they are disturbed by passing waves or boats.","Dr. Reyes measured the intensity of plankton glow at twelve different coastal sites."],"explanation":"The main finding is the relationship between water cleanliness and glow brightness, which only the second option states. The others describe the subject, the glowing behavior, or the method without reporting the result.","skill":"rhetorical synthesis"},{"cat":"expression","a":2,"q":"A student is writing about an architectural innovation. She has taken these notes:\n- The Pantheon in Rome was completed around 126 CE.\n- Its dome is made of concrete.\n- The concrete is lighter near the top and heavier near the base.\n- This varied density helps the dome support its own weight.\n\nThe student wants to explain how the Pantheon's dome stays standing. Which choice most effectively uses the notes to accomplish this goal?","options":["The Pantheon in Rome, completed around 126 CE, features a famous concrete dome.","The dome of the Pantheon, finished around 126 CE, has impressed visitors for centuries.","The Pantheon's concrete dome supports its own weight because the concrete is lighter at the top and heavier at the base.","Made of concrete, the Pantheon's dome was completed in Rome around the year 126 CE."],"explanation":"The goal is to explain how the dome stays standing, and only the option connecting the varied density to weight support does so. The others state the dome's date or material without explaining its structural stability.","skill":"rhetorical synthesis"},{"cat":"expression","a":1,"q":"A student is writing about a study on urban trees. He has taken these notes:\n- Researchers compared streets with many trees to streets with few trees.\n- Tree-lined streets were on average several degrees cooler in summer.\n- Cooler streets reduced residents' use of air conditioning.\n- Lower air-conditioning use led to lower energy bills.\n\nThe student wants to emphasize a practical financial benefit of street trees. Which choice most effectively uses the notes to accomplish this goal?","options":["Researchers compared streets that had many trees with streets that had only a few.","On tree-lined streets, reduced air-conditioning use lowered residents' energy bills.","Streets lined with trees were, on average, several degrees cooler during the summer months.","Cooler streets in summer caused residents to rely less on their air conditioning."],"explanation":"The practical financial benefit is the lower energy bills, which only the second option names. The others describe the comparison, the cooling effect, or reduced AC use without reaching the financial outcome.","skill":"rhetorical synthesis"},{"cat":"expression","a":2,"q":"A student is writing about a composer. She has taken these notes:\n- Florence Price was an American composer born in 1887.\n- In 1933, the Chicago Symphony Orchestra performed her Symphony No. 1.\n- This made her the first African American woman to have a symphony played by a major U.S. orchestra.\n- Her music blended classical forms with African American spirituals.\n\nThe student wants to emphasize the historical significance of the 1933 performance. Which choice most effectively uses the notes to accomplish this goal?","options":["Florence Price, born in 1887, was an American composer whose music blended several traditions.","Florence Price's music combined classical forms with the melodies of African American spirituals.","The 1933 performance of Price's Symphony No. 1 made her the first African American woman to have a symphony played by a major U.S. orchestra.","In 1933, the Chicago Symphony Orchestra performed Florence Price's Symphony No. 1."],"explanation":"The historical significance is the 'first' milestone, which only the third option states. The first two describe her background or style, and the fourth notes the performance without explaining why it mattered historically.","skill":"rhetorical synthesis"},{"cat":"expression","a":1,"q":"A student is writing about a conservation effort. He has taken these notes:\n- The California condor nearly went extinct in the 1980s.\n- By 1987, only 27 individuals remained.\n- Scientists captured the remaining birds for a breeding program.\n- By 2020, the wild and captive population had grown to over 500.\n\nThe student wants to emphasize the success of the breeding program. Which choice most effectively uses the notes to accomplish this goal?","options":["By 1987, only 27 California condors remained alive in the world.","After a breeding program began, the condor population grew from just 27 birds in 1987 to over 500 by 2020.","Scientists captured the last wild California condors for a breeding program in the 1980s.","The California condor nearly went extinct during the 1980s, alarming many scientists."],"explanation":"The success is best shown by the growth from 27 to over 500, which only the second option presents. The others emphasize the low point, the capture, or the near-extinction without conveying the program's success.","skill":"rhetorical synthesis"},{"cat":"expression","a":2,"q":"A student is writing about a type of bridge. She has taken these notes:\n- A suspension bridge hangs its roadway from large cables.\n- The cables are anchored to tall towers and to the ground at each end.\n- This design allows suspension bridges to span very long distances.\n- The Golden Gate Bridge is a famous suspension bridge.\n\nThe student wants to explain why suspension bridges can cross long distances. Which choice most effectively uses the notes to accomplish this goal?","options":["The Golden Gate Bridge is one famous example of a suspension bridge.","A suspension bridge hangs its roadway from large cables anchored to tall towers.","Because a suspension bridge hangs its roadway from cables anchored to towers and the ground, it can span very long distances.","Suspension bridges, such as the Golden Gate Bridge, are admired for their graceful appearance."],"explanation":"The goal is to explain why such bridges can cross long distances, and only the option linking the cable-and-tower design to long spans does so. The others name an example or describe the design without explaining the long-span capability.","skill":"rhetorical synthesis"},{"cat":"expression","a":0,"q":"The library extended its weekend hours to give students more time to study. ______ many students who work weekday jobs were finally able to use the building during the day.\n\nWhich choice completes the text with the most logical transition?","options":["As a result,","However,","For example,","In contrast,"],"explanation":"The second sentence states an effect of the extended hours, so the cause-and-effect transition 'As a result' is logical. The other options signal contrast or illustration, which do not fit.","skill":"transitions"},{"cat":"expression","a":2,"q":"The bakery sells fresh bread every morning. ______ it offers a selection of cakes, pastries, and cookies throughout the day.\n\nWhich choice completes the text with the most logical transition?","options":["Nevertheless,","Therefore,","Additionally,","Instead,"],"explanation":"The second sentence adds another category of products the bakery sells, so the additive transition 'Additionally' fits. The other options signal contrast or consequence, which are illogical here.","skill":"transitions"},{"cat":"expression","a":0,"q":"Maria practiced the piano for two hours every day for months. ______ she performed flawlessly at the spring recital.\n\nWhich choice completes the text with the most logical transition?","options":["Consequently,","By contrast,","Meanwhile,","However,"],"explanation":"Her flawless performance is a result of months of practice, so 'Consequently' signals the correct cause-and-effect relationship. The others indicate contrast or simultaneity.","skill":"transitions"},{"cat":"expression","a":2,"q":"The hiking trail was marked as easy on the map. ______ several sections were steep and covered in loose rock.\n\nWhich choice completes the text with the most logical transition?","options":["Similarly,","In fact,","However,","Furthermore,"],"explanation":"The actual condition of the trail contradicts the 'easy' label, so the contrast transition 'However' is correct. The other options signal addition or emphasis without contrast.","skill":"transitions"},{"cat":"expression","a":1,"q":"A student is writing about a public art installation. She has taken these notes:\n- The mural covers an entire wall on Fifth Street.\n- It was painted by local artist Dev Patel.\n- It depicts scenes from the neighborhood's history.\n- It was completed in 2024.\n\nThe student wants to introduce the mural and its creator. Which choice most effectively uses relevant information from the notes to accomplish this goal?","options":["The mural depicts scenes from the neighborhood's history.","In 2024, local artist Dev Patel completed a mural on Fifth Street.","The mural covers an entire wall.","Local artist Dev Patel works in the neighborhood."],"explanation":"This option names both the mural and its creator, Dev Patel, fulfilling the goal of introducing the installation and the artist. The other options omit either the creator or the mural itself.","skill":"rhetorical synthesis from notes"},{"cat":"expression","a":2,"q":"Most reptiles cannot regulate their own body temperature internally. ______ they bask in the sun to warm up and seek shade to cool down.\n\nWhich choice completes the text with the most logical transition?","options":["Nonetheless,","Instead,","For this reason,","On the other hand,"],"explanation":"Because reptiles cannot regulate temperature internally, they rely on behavior to do so, making 'For this reason' the logical cause-and-effect transition. The others imply contrast.","skill":"transitions"},{"cat":"expression","a":0,"q":"The committee reviewed dozens of proposals over several weeks. ______ they selected only three projects to receive funding.\n\nWhich choice completes the text with the most logical transition?","options":["Ultimately,","Similarly,","Conversely,","For instance,"],"explanation":"'Ultimately' signals the final outcome of the lengthy review process, which fits the sequence. The other options indicate comparison, contrast, or example, none of which fit.","skill":"transitions"},{"cat":"expression","a":2,"q":"A student is writing about a scientist's discovery. He has taken these notes:\n- Barbara McClintock studied corn genetics.\n- She discovered that genes can move within a genome.\n- These mobile genes are called transposons.\n- She won the Nobel Prize in 1983.\n\nThe student wants to explain what McClintock discovered. Which choice most effectively uses relevant information from the notes to accomplish this goal?","options":["Barbara McClintock won the Nobel Prize in 1983.","Barbara McClintock studied corn genetics for many years.","McClintock discovered that genes can move within a genome, a phenomenon involving mobile genes called transposons.","Transposons are an important topic in genetics today."],"explanation":"This option directly explains the discovery: that genes can move within a genome, and that these are called transposons. The other choices focus on her award, her field, or general relevance rather than the discovery itself.","skill":"rhetorical synthesis from notes"},{"cat":"expression","a":1,"q":"Electric vehicles produce no tailpipe emissions while driving. ______ the electricity that charges them may come from power plants that burn fossil fuels.\n\nWhich choice completes the text with the most logical transition?","options":["Likewise,","However,","As a result,","In addition,"],"explanation":"The second sentence qualifies the clean image of electric vehicles by noting a hidden emissions source, so the contrast transition 'However' is correct. The others signal similarity, consequence, or addition.","skill":"transitions"},{"cat":"expression","a":3,"q":"The orchestra rehearsed the symphony many times before the concert. The conductor, ______ wanted to ensure that every musician knew the piece perfectly.\n\nWhich choice completes the text with the most logical transition?","options":["for example,","in contrast,","meanwhile,","after all,"],"explanation":"'After all' introduces the underlying reason for the repeated rehearsals, explaining the conductor's motivation. The other options signal illustration, contrast, or simultaneity, which are illogical here.","skill":"transitions"},{"cat":"expression","a":2,"q":"A student is writing about a historic building. She has taken these notes:\n- The Carter House was built in 1850.\n- It served as a hospital during a major war.\n- It is now a museum.\n- Visitors can tour its restored rooms.\n\nThe student wants to emphasize the building's current use. Which choice most effectively uses relevant information from the notes to accomplish this goal?","options":["The Carter House was built in 1850.","During a major war, the Carter House served as a hospital.","Now a museum, the Carter House lets visitors tour its restored rooms.","The Carter House has a long and varied history."],"explanation":"This option highlights the building's present use as a museum where visitors can tour restored rooms, matching the goal. The other choices focus on its construction date, wartime role, or general history.","skill":"rhetorical synthesis from notes"},{"cat":"expression","a":1,"q":"Deep-sea creatures live where almost no sunlight reaches. Many of them produce their own light through chemical reactions; ______ they can attract prey, find mates, or confuse predators in the darkness.\n\nWhich choice completes the text with the most logical transition?","options":["nevertheless,","in this way,","by comparison,","regardless,"],"explanation":"'In this way' connects the ability to produce light to the purposes that light serves, showing method and result. The other options imply contrast or dismissal, which do not fit.","skill":"transitions"},{"cat":"expression","a":1,"q":"Early telephones could only connect two specific locations with a single dedicated wire. The invention of the switchboard changed this; ______ a single line could now be connected to many different destinations.\n\nWhich choice completes the text with the most logical transition?","options":["nonetheless,","consequently,","for instance,","in contrast,"],"explanation":"The switchboard's effect was that one line could reach many destinations, so the cause-and-effect transition 'consequently' is correct. 'In contrast' and 'nonetheless' wrongly imply opposition, and 'for instance' signals an example.","skill":"transitions"},{"cat":"expression","a":1,"q":"A student is writing about a method of farming. He has taken these notes:\n- Crop rotation means planting different crops in a field each season.\n- Continuous planting of one crop drains specific nutrients from the soil.\n- Different crops use and replenish different nutrients.\n- Rotation helps keep soil fertile over time.\n\nThe student wants to explain why crop rotation helps soil. Which choice most effectively uses relevant information from the notes to accomplish this goal?","options":["Crop rotation means planting different crops in a field each season.","Because different crops use and replenish different nutrients, rotating them helps keep soil fertile over time.","Continuous planting of one crop drains nutrients from the soil.","Crop rotation has been practiced by farmers for centuries."],"explanation":"This option explains the mechanism: because different crops use and replenish different nutrients, rotation maintains fertility. The other choices define rotation, describe only the problem, or add unrelated history.","skill":"rhetorical synthesis from notes"},{"cat":"expression","a":2,"q":"The research team expected the chemical reaction to slow down at lower temperatures, and most of their trials confirmed this. In one trial, ______ the reaction unexpectedly sped up, prompting the team to repeat the experiment.\n\nWhich choice completes the text with the most logical transition?","options":["therefore,","similarly,","however,","indeed,"],"explanation":"The one trial contradicts the expected pattern, so the contrast transition 'however' is logical. 'Similarly' and 'indeed' imply agreement, and 'therefore' implies consequence.","skill":"transitions"},{"cat":"expression","a":1,"q":"A student is writing about two methods of preserving food. She has taken these notes:\n- Freezing slows the growth of bacteria by keeping food very cold.\n- Canning seals food in airtight containers and heats it to kill bacteria.\n- Freezing keeps food's texture closer to fresh.\n- Canned food can be stored at room temperature for years.\n\nThe student wants to contrast a benefit of each method. Which choice most effectively uses relevant information from the notes to accomplish this goal?","options":["Freezing and canning both protect food from bacteria.","While freezing keeps food's texture closer to fresh, canning allows food to be stored at room temperature for years.","Freezing slows bacterial growth by keeping food cold.","Canning seals food in airtight containers and heats it."],"explanation":"This option states a distinct benefit of each method and contrasts them, fulfilling the goal. The other choices describe a shared trait or only one method's process.","skill":"rhetorical synthesis from notes"},{"cat":"expression","a":1,"q":"Lighthouses once required keepers to maintain the lamps and warn ships through every storm. Today, most lighthouses operate automatically; ______ the lonely profession of lighthouse keeper has nearly vanished.\n\nWhich choice completes the text with the most logical transition?","options":["even so,","as a result,","for example,","on the contrary,"],"explanation":"Automation caused the disappearance of the keeper profession, so the cause-and-effect transition 'as a result' is correct. The other options signal contrast or illustration.","skill":"transitions"},{"cat":"expression","a":2,"q":"The town's recycling program initially accepted only paper and glass. Over the following decade, the list of accepted materials grew steadily. ______ residents can now recycle plastics, metals, and electronics as well.\n\nWhich choice completes the text with the most logical transition?","options":["Nevertheless,","By contrast,","Today,","Otherwise,"],"explanation":"'Today' fits the sequence by marking the present result of a decade of expansion. The other options signal contrast or alternatives, which do not match the steady growth described.","skill":"transitions"},{"cat":"expression","a":1,"q":"A student is writing about an astronomer's work. He has taken these notes:\n- Annie Jump Cannon worked at the Harvard Observatory.\n- She developed a system for classifying stars by temperature.\n- Her classification system is still used by astronomers today.\n- She cataloged hundreds of thousands of stars.\n\nThe student wants to emphasize the lasting importance of Cannon's classification system. Which choice most effectively uses relevant information from the notes to accomplish this goal?","options":["Annie Jump Cannon cataloged hundreds of thousands of stars.","Cannon developed a system for classifying stars by temperature that astronomers still use today.","Cannon worked at the Harvard Observatory.","Cannon classified stars during her long career."],"explanation":"This option names the classification system and stresses that it is still used today, matching the goal of emphasizing lasting importance. The other choices focus on her workplace or the quantity of stars without noting the system's endurance.","skill":"rhetorical synthesis from notes"},{"cat":"expression","a":1,"q":"Many people assume that all deserts are hot, sandy places. The largest desert on Earth, ______ is Antarctica, a frozen continent that receives very little precipitation.\n\nWhich choice completes the text with the most logical transition?","options":["likewise,","in fact,","as a result,","for this reason,"],"explanation":"'In fact' introduces a surprising correction to the common assumption about deserts. The other options imply similarity or consequence, which do not fit the contradiction being presented.","skill":"transitions"},{"cat":"expression","a":2,"q":"A student is writing about a wetland restoration project. She has taken these notes:\n- The wetland had been drained for farmland decades ago.\n- Workers reflooded the area and replanted native species.\n- Within five years, migratory birds returned to nest.\n- Water quality in the nearby river also improved.\n\nThe student wants to present two positive outcomes of the restoration. Which choice most effectively uses relevant information from the notes to accomplish this goal?","options":["The wetland had been drained for farmland decades ago.","Workers reflooded the area and replanted native species.","After the restoration, migratory birds returned to nest and water quality in the nearby river improved.","The wetland project took many years to complete."],"explanation":"This option presents two distinct positive outcomes, the return of birds and improved water quality, fulfilling the goal. The other choices describe the prior problem, the process, or an unrelated detail.","skill":"rhetorical synthesis from notes"},{"cat":"expression","a":1,"q":"Researchers had long believed that octopuses were solitary animals that avoided one another. Recent observations of a dense colony off the coast of Australia, ______ revealed octopuses living in close groups and even communicating through color changes.\n\nWhich choice completes the text with the most logical transition?","options":["consequently,","however,","for example,","in the same way,"],"explanation":"The new observations contradict the long-held belief that octopuses are solitary, so the contrast transition 'however' is correct. The other options signal consequence, illustration, or similarity, none of which captures the contradiction.","skill":"transitions"},{"cat":"expression","a":2,"q":"A student is writing about a textile tradition. He has taken these notes:\n- Kente cloth originated among the Akan people of Ghana.\n- Each color and pattern carries a specific meaning.\n- The cloth is woven in narrow strips that are sewn together.\n- It is traditionally worn during important ceremonies.\n\nThe student wants to explain the cultural significance of Kente cloth's design. Which choice most effectively uses relevant information from the notes to accomplish this goal?","options":["Kente cloth is woven in narrow strips that are sewn together.","Kente cloth originated among the Akan people of Ghana.","In Kente cloth, each color and pattern carries a specific meaning, reflecting its role in important ceremonies.","Kente cloth is admired for its bright appearance."],"explanation":"This option connects the meaningful colors and patterns to the cloth's ceremonial role, addressing its cultural significance. The other choices describe the weaving method, origin, or general appearance without explaining meaning.","skill":"rhetorical synthesis from notes"},{"cat":"expression","a":1,"q":"The engineers designing the dam needed it to withstand both extreme floods and prolonged droughts. Building for one scenario often weakened the design against the other; ______ the team had to develop a flexible structure capable of adapting to widely varying water levels.\n\nWhich choice completes the text with the most logical transition?","options":["nevertheless,","thus,","in contrast,","for instance,"],"explanation":"The need for a flexible structure follows logically from the conflicting design demands, so the consequence transition 'thus' is correct. 'Nevertheless' and 'in contrast' imply opposition, and 'for instance' signals an example.","skill":"transitions"},{"cat":"expression","a":2,"q":"A student is writing about a linguist's fieldwork. She has taken these notes:\n- Dr. Lin documented an endangered language spoken by fewer than 200 people.\n- She recorded hundreds of hours of native speakers.\n- She compiled the first written dictionary of the language.\n- Community members now use the dictionary to teach children.\n\nThe student wants to emphasize how Dr. Lin's work benefits the language community. Which choice most effectively uses relevant information from the notes to accomplish this goal?","options":["Dr. Lin recorded hundreds of hours of native speakers.","Dr. Lin documented an endangered language spoken by fewer than 200 people.","Dr. Lin compiled the first written dictionary of the language, which community members now use to teach children.","Dr. Lin spent considerable time conducting her fieldwork."],"explanation":"This option links the dictionary Dr. Lin created to its use by the community to teach children, directly showing the benefit. The other choices describe her methods or the language's status without indicating community benefit.","skill":"rhetorical synthesis from notes"},{"cat":"expression","a":1,"q":"Astronomers detecting distant exoplanets rarely see the planets directly. A planet passing in front of its star dims the star's light by a tiny, measurable amount; ______ careful measurement of these dips allows scientists to infer a planet's size and orbit without ever observing it.\n\nWhich choice completes the text with the most logical transition?","options":["nonetheless,","in other words,","by contrast,","even so,"],"explanation":"The second clause restates and clarifies how the dimming is used to deduce planetary details, so 'in other words' fits as a clarifying transition. The other options signal contrast or concession, which do not match.","skill":"transitions"},{"cat":"conventions","a":2,"q":"The community garden on Maple Street ______ a popular gathering place for residents who want fresh vegetables and a bit of quiet.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?","options":["have become","are becoming","has become","were becoming"],"explanation":"The singular subject \"garden\" requires a singular verb. \"Has become\" agrees in number; \"have become,\" \"are becoming,\" and \"were becoming\" are all plural and do not agree with the singular subject.","skill":"subject-verb agreement"},{"cat":"conventions","a":2,"q":"When Maria finished painting the mural, ______ stepped back to admire the bright colors she had chosen.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?","options":["they","it","she","we"],"explanation":"The pronoun must agree with its antecedent, \"Maria,\" a single female individual. \"She\" agrees in number and gender; \"they,\" \"it,\" and \"we\" do not match the singular feminine antecedent.","skill":"pronoun-antecedent agreement"},{"cat":"conventions","a":3,"q":"Last summer, the museum ______ a rare collection of ancient coins that had been discovered in a nearby riverbed.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?","options":["displays","will display","displaying","displayed"],"explanation":"The phrase \"Last summer\" signals a completed past action, so the simple past \"displayed\" is correct. \"Displays\" is present, \"will display\" is future, and \"displaying\" is not a finite verb.","skill":"verb tense and form"},{"cat":"conventions","a":0,"q":"The chef added a pinch of saffron to the rice; ______ gave the dish a golden color and a delicate aroma.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?","options":["this spice","these spices","they","their spice"],"explanation":"The antecedent is the singular \"saffron,\" so a singular reference is needed. \"This spice\" is singular and clear; \"these spices\" and \"they\" are plural, and \"their spice\" introduces an illogical possessive.","skill":"pronoun-antecedent agreement"},{"cat":"conventions","a":0,"q":"The hikers reached the summit just before noon ______ they ate lunch while taking in the panoramic view of the valley below.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?","options":[", and","; where","where, and","; there"],"explanation":"Two independent clauses joined by a coordinating conjunction require a comma before the conjunction: \", and\" correctly joins them. \"; where\" and \"; there\" create faulty constructions, and \"where, and\" is ungrammatical.","skill":"sentence boundaries (run-ons/fragments)"},{"cat":"conventions","a":2,"q":"Each of the volunteers who arrived early ______ assigned a station to staff during the charity marathon.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?","options":["were","have been","was","are"],"explanation":"The subject is \"Each,\" which is singular, so a singular verb is required: \"was.\" The intervening phrase \"of the volunteers\" does not change the number; \"were,\" \"have been,\" and \"are\" are plural.","skill":"subject-verb agreement"},{"cat":"conventions","a":1,"q":"The novelist's most famous ______ a sweeping family saga that spans three generations and two continents.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?","options":["book, is","book is","book; is","book: is"],"explanation":"The subject \"book\" should connect directly to its verb \"is\" with no punctuation. A comma, semicolon, or colon between a subject and its verb is incorrect.","skill":"punctuation (commas, semicolons, colons, dashes, apostrophes)"},{"cat":"conventions","a":0,"q":"Walking quietly through the forest at dawn, ______ noticed by the photographer hiding behind a fallen log.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?","options":["a family of deer was","the camera was","there was a herd","it was the deer that were"],"explanation":"The introductory modifier \"Walking quietly through the forest\" must describe the noun that follows. Only \"a family of deer\" can logically be walking; a camera, \"there,\" and the awkward \"it was the deer that were\" create dangling or illogical modifiers.","skill":"modifier placement"},{"cat":"conventions","a":1,"q":"By the time the rescue team arrived, the stranded climbers ______ a small shelter from rocks and branches to protect themselves from the wind.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?","options":["build","had built","have built","builds"],"explanation":"The past perfect \"had built\" is needed to show that the climbers completed the shelter before the team arrived. \"Build\" and \"builds\" are present tense, and \"have built\" is present perfect, none of which fit the sequence of past events.","skill":"verb tense and form"},{"cat":"conventions","a":2,"q":"The professor explained that the experiment's ______ could be measured only after the solution had been heated for several hours.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?","options":["results, which were surprising","results which, were surprising","results—which were surprising—","results; which were surprising"],"explanation":"A nonrestrictive clause set off mid-sentence can be enclosed by a matched pair of dashes: \"results—which were surprising—.\" The other options misplace the comma, use a semicolon before a dependent clause, or break the pairing.","skill":"punctuation (commas, semicolons, colons, dashes, apostrophes)"},{"cat":"conventions","a":2,"q":"Neither the manager nor the employees ______ aware that the store's hours had changed for the holiday weekend.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?","options":["was","is","were","has been"],"explanation":"In a \"neither...nor\" construction, the verb agrees with the nearer subject, \"employees,\" which is plural, so \"were\" is correct. \"Was,\" \"is,\" and \"has been\" are singular and do not agree with the closer plural noun.","skill":"subject-verb agreement"},{"cat":"conventions","a":0,"q":"The architect presented three designs to the committee, and ______ favored the one with the curved glass facade.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?","options":["its members","it's members","their member","its' members"],"explanation":"The possessive form \"its\" correctly shows ownership by \"the committee.\" \"It's\" means \"it is,\" \"its'\" is not a word, and \"their member\" disagrees in number with the singular committee.","skill":"punctuation (commas, semicolons, colons, dashes, apostrophes)"},{"cat":"conventions","a":0,"q":"The scientist wanted to test one variable at a ______ she ran each trial separately, changing only the temperature.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?","options":["time, so","time so,","time; so","time, so,"],"explanation":"Two independent clauses joined by the coordinating conjunction \"so\" require a comma before it: \"time, so.\" The other options misplace the comma, use an incorrect semicolon before a coordinating conjunction, or add an unnecessary second comma.","skill":"sentence boundaries (run-ons/fragments)"},{"cat":"conventions","a":1,"q":"Having studied the migration patterns for over a decade, ______ that the birds were returning earlier each spring.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?","options":["the data suggested to the researchers","the researchers concluded","it was concluded","the conclusion was reached"],"explanation":"The introductory phrase \"Having studied the migration patterns\" must modify the people who studied, namely \"the researchers.\" The other choices place data, \"it,\" or \"the conclusion\" as the studier, creating dangling modifiers.","skill":"modifier placement"},{"cat":"conventions","a":0,"q":"The committee will review the ______ proposals: a new bike lane, a community pool, and an expanded library.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?","options":["following three","following three,","following, three","following: three"],"explanation":"\"The following three proposals\" is a complete noun phrase that flows directly into the colon already present in the sentence. Inserting a comma or another colon after \"following\" or \"three\" disrupts the phrase.","skill":"punctuation (commas, semicolons, colons, dashes, apostrophes)"},{"cat":"conventions","a":3,"q":"The results of the recent survey, which polled thousands of commuters across five cities, ______ that most prefer flexible working hours.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?","options":["suggests","suggesting","has suggested","suggest"],"explanation":"The subject is the plural \"results,\" so the plural verb \"suggest\" is required. The long intervening clause does not change the subject; \"suggests\" and \"has suggested\" are singular, and \"suggesting\" is not a finite verb.","skill":"subject-verb agreement"},{"cat":"conventions","a":0,"q":"The famous bridge, completed in 1937 after years of dangerous ______ remains an enduring symbol of engineering ingenuity to this day.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?","options":["construction,","construction;","construction","construction:"],"explanation":"A comma is needed to close the nonrestrictive modifier \"completed in 1937...construction\" that began after \"bridge.\" A semicolon or colon would incorrectly separate the subject from its verb \"remains,\" and omitting punctuation leaves the modifier unclosed.","skill":"punctuation (commas, semicolons, colons, dashes, apostrophes)"},{"cat":"conventions","a":1,"q":"If the city council had approved the funding sooner, the new transit line ______ by next year, easing congestion for thousands of daily commuters.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?","options":["will be completed","would have been completed","is completed","completes"],"explanation":"The conditional \"If...had approved\" requires the conditional perfect \"would have been completed\" in the main clause. \"Will be completed,\" \"is completed,\" and \"completes\" fail to match the past-counterfactual condition.","skill":"verb tense and form"},{"cat":"conventions","a":1,"q":"The young inventor, along with her two mentors, ______ presenting a prototype at the national science fair next month, hoping to attract investors.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?","options":["are","is","were","have been"],"explanation":"The subject is the singular \"inventor\"; the phrase \"along with her two mentors\" is parenthetical and does not affect the verb. The singular \"is\" agrees; \"are,\" \"were,\" and \"have been\" are plural.","skill":"subject-verb agreement"},{"cat":"conventions","a":1,"q":"The editor returned the manuscript with detailed notes, the author revised three chapters, and the publisher approved the final ______ the book reached stores ahead of schedule.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?","options":["draft, and","draft; consequently,","draft,","draft and,"],"explanation":"The final clause \"the book reached stores\" is independent and must be properly joined to the preceding independent clause; \"; consequently,\" correctly links two independent clauses with a conjunctive adverb. The comma options create comma splices, and \"draft and,\" is ungrammatical.","skill":"sentence boundaries (run-ons/fragments)"},{"cat":"conventions","a":1,"q":"Carefully balanced on a single thin wire, ______ amazed the audience with its graceful, seemingly impossible movements.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?","options":["the crowd watched as the acrobat","the acrobat","everyone saw that the performance","there was an acrobat who"],"explanation":"The opening modifier \"Carefully balanced on a single thin wire\" must describe the one doing the balancing, which is \"the acrobat.\" The crowd, \"everyone,\" and \"there\" cannot logically be balanced on the wire, producing dangling modifiers.","skill":"modifier placement"},{"cat":"conventions","a":1,"q":"The library near the train station ______ free workshops on coding every Saturday morning.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?","options":["offer","offers","are offering","have offered"],"explanation":"The subject \"library\" is singular, so it requires the singular present-tense verb \"offers.\" The phrase \"near the train station\" is a prepositional phrase that does not change the number of the subject.","skill":"subject-verb & pronoun agreement"},{"cat":"conventions","a":0,"q":"Diego packed his suitcase the night before his flight ______ he did not want to feel rushed in the morning.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?","options":["because","because,","; because","because;"],"explanation":"The subordinating conjunction \"because\" correctly joins the dependent clause to the independent clause with no punctuation needed before it. A semicolon cannot precede a subordinating conjunction joining a dependent clause.","skill":"sentence boundaries"},{"cat":"conventions","a":1,"q":"The two scientists shared a laboratory, and ______ often compared notes at the end of each day.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?","options":["it","they","he","she"],"explanation":"The antecedent \"two scientists\" is plural, so the plural pronoun \"they\" is required for pronoun-antecedent agreement.","skill":"subject-verb & pronoun agreement"},{"cat":"conventions","a":0,"q":"After the rain stopped, the children ran outside to splash in the ______ that had formed along the sidewalk.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?","options":["puddles","puddle's","puddles'","puddles's"],"explanation":"The plural noun \"puddles\" is needed, not a possessive form. No apostrophe is required because nothing is being possessed.","skill":"punctuation"},{"cat":"conventions","a":2,"q":"Every morning, the baker ______ dozens of loaves before the shop opens to the public at seven.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?","options":["bake","baking","bakes","to bake"],"explanation":"The singular subject \"baker\" requires the singular present-tense verb \"bakes.\" The non-finite forms \"baking\" and \"to bake\" cannot serve as the main verb here.","skill":"verb tense/form"},{"cat":"conventions","a":1,"q":"The new bridge connects two neighborhoods that ______ separated by the river for over a century.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?","options":["has been","had been","is being","being"],"explanation":"The plural relative pronoun \"that\" refers to \"neighborhoods,\" and the past-perfect \"had been\" correctly describes a state completed before the bridge connected them.","skill":"verb tense/form"},{"cat":"conventions","a":0,"q":"My grandmother grew up in a small coastal town ______ she learned to sail before she could ride a bicycle.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?","options":["where","which","and","but"],"explanation":"The relative adverb \"where\" correctly introduces a clause describing the location \"town\" and links it to the rest of the sentence without creating a comma splice.","skill":"sentence boundaries"},{"cat":"conventions","a":2,"q":"The teacher reminded the students that the deadline for the science fair ______ moved to Friday.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?","options":["have been","were","has been","are"],"explanation":"The singular subject \"deadline\" requires the singular verb form \"has been.\" The phrase \"for the science fair\" does not change the number of the subject.","skill":"subject-verb & pronoun agreement"},{"cat":"conventions","a":1,"q":"Marcus enjoys three outdoor ______ kayaking, rock climbing, and trail running.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?","options":["activities","activities:","activities;","activities,"],"explanation":"A colon correctly introduces the list that explains the \"three outdoor activities,\" and it follows a complete independent clause.","skill":"punctuation"},{"cat":"conventions","a":2,"q":"Excited about the upcoming concert, ______ bought tickets the moment they went on sale.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?","options":["the tickets were","it was","the fans","there were many who"],"explanation":"The introductory modifier \"Excited about the upcoming concert\" must describe the people who felt excited; \"the fans\" is the only logical subject that the modifier can sensibly describe.","skill":"modifiers"},{"cat":"conventions","a":3,"q":"The orchestra rehearsed for weeks, and on opening night ______ performance earned a standing ovation from the audience.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?","options":["their","they're","there","its"],"explanation":"The antecedent \"orchestra\" is a singular collective noun acting as a unit, so the singular possessive pronoun \"its\" is correct.","skill":"subject-verb & pronoun agreement"},{"cat":"conventions","a":2,"q":"The documentary about deep-sea creatures, narrated by a renowned biologist, ______ widely praised for its stunning underwater footage.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?","options":["were","have been","was","are"],"explanation":"The singular subject \"documentary\" requires the singular verb \"was.\" The intervening phrases do not change the subject's number.","skill":"subject-verb & pronoun agreement"},{"cat":"conventions","a":1,"q":"By the time the train finally departed, the passengers ______ in the station for nearly two hours.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?","options":["wait","had waited","have waited","are waiting"],"explanation":"The past-perfect \"had waited\" correctly shows that the waiting was completed before the past event of the train departing.","skill":"verb tense/form"},{"cat":"conventions","a":0,"q":"The store offers a generous return ______ customers may exchange any item within thirty days of purchase.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?","options":["policy, and","policy and","policy,","policy"],"explanation":"Two independent clauses must be joined by a comma plus a coordinating conjunction; \"policy, and\" correctly prevents a run-on and a comma splice.","skill":"sentence boundaries"},{"cat":"conventions","a":2,"q":"The hikers, who had set out before dawn, ______ surprised to find the trail covered in fresh snow.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?","options":["was","is","were","has been"],"explanation":"The plural subject \"hikers\" requires the plural verb \"were.\" The nonrestrictive clause set off by commas does not affect the subject's number.","skill":"subject-verb & pronoun agreement"},{"cat":"conventions","a":0,"q":"Founded in 1885, the ______ collection of rare manuscripts attracts scholars from around the world.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?","options":["museum's","museums","museums'","museum"],"explanation":"The singular possessive \"museum's\" correctly shows that the collection belongs to the museum. The introductory phrase logically modifies the museum.","skill":"punctuation"},{"cat":"conventions","a":2,"q":"Neither the coach nor the players ______ certain whether the championship game would be postponed.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?","options":["was","is","were","has been"],"explanation":"In a \"neither/nor\" construction, the verb agrees with the nearer subject, \"players,\" which is plural, so \"were\" is correct.","skill":"subject-verb & pronoun agreement"},{"cat":"conventions","a":1,"q":"The committee postponed the vote ______ several members requested more time to study the proposal.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?","options":[", however","; however,","however","however;"],"explanation":"When the conjunctive adverb \"however\" joins two independent clauses, it requires a semicolon before it and a comma after it.","skill":"sentence boundaries"},{"cat":"conventions","a":1,"q":"Engineers tested the prototype repeatedly ______ they wanted to ensure it could withstand extreme temperatures.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?","options":["; because","because",", because","because,"],"explanation":"The subordinating conjunction \"because\" joins the dependent clause to the independent clause and needs no punctuation when the dependent clause follows the main clause.","skill":"punctuation"},{"cat":"conventions","a":0,"q":"Renowned for her vivid imagery, ______ poems have been translated into more than twenty languages.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?","options":["the poet's","the poems","many readers admire her","translators value the"],"explanation":"The introductory modifier describes the poet, so the noun immediately following must logically be modified by it; \"the poet's poems\" places the poet in the modified position correctly.","skill":"modifiers"},{"cat":"conventions","a":2,"q":"The report concluded that pollution levels ______ significantly since the new regulations took effect last spring.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?","options":["dropped","had dropped","have dropped","drop"],"explanation":"The present-perfect \"have dropped\" correctly conveys an action that began in the past and continues to have relevance in the present, consistent with the ongoing effect of the regulations marked by \"since.\"","skill":"verb tense/form"},{"cat":"conventions","a":2,"q":"The festival featured musicians from across the ______ dancers, painters, and storytellers also contributed to the lively atmosphere.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?","options":["region,","region","region;","region and"],"explanation":"Two independent clauses must be separated by a semicolon (or a period); a semicolon after \"region\" correctly avoids a comma splice and run-on.","skill":"sentence boundaries"},{"cat":"conventions","a":1,"q":"Each of the paintings displayed in the east ______ been carefully restored by a team of conservators.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?","options":["wing have","wing has","wings have","wing, has"],"explanation":"The subject is \"Each,\" which is singular and takes the singular verb \"has.\" No comma should separate the subject from its verb.","skill":"subject-verb & pronoun agreement"},{"cat":"conventions","a":2,"q":"The astronomer explained that, had the telescope been calibrated correctly, the team ______ the distant comet weeks earlier.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?","options":["would detect","will have detected","would have detected","detected"],"explanation":"This is a past contrary-to-fact conditional; the main clause requires \"would have detected\" to match the past-perfect condition \"had the telescope been calibrated.\"","skill":"verb tense/form"},{"cat":"conventions","a":2,"q":"The annual report, along with its detailed financial appendices and supplementary charts, ______ distributed to every shareholder before the meeting.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?","options":["were","have been","was","are being"],"explanation":"The singular subject \"report\" governs the verb; phrases beginning with \"along with\" are parenthetical and do not make the subject plural, so the singular \"was\" is correct.","skill":"subject-verb & pronoun agreement"},{"cat":"conventions","a":2,"q":"Drifting silently above the canyon at sunrise, ______ captured photographs that would later win international awards.\n\nWhich choice completes the text so that it conforms to the conventions of Standard English?","options":["the photographs were","the hot-air balloon allowed the journalist to be","the journalist","it was the journalist who"],"explanation":"The introductory participial phrase \"Drifting silently above the canyon\" must modify the noun that was drifting; \"the journalist\" is the logical subject that performed the action and can be modified without creating a dangling modifier.","skill":"modifiers"},{"cat":"algebra","a":0,"q":"If 5x - 7 = 23, what is the value of x?","options":["6","5","8","16/5"],"explanation":"Add 7 to both sides: 5x = 30, then divide by 5 to get x = 6. The distractor 16/5 comes from subtracting 7 instead of adding it (5x = 16).","skill":"Linear equations in one variable"},{"cat":"algebra","a":0,"q":"A line passes through the points (2, 5) and (6, 13). What is the slope of the line?","options":["2","1/2","-2","4"],"explanation":"Slope = (13 - 5)/(6 - 2) = 8/4 = 2. The distractor 1/2 comes from inverting the slope formula by dividing run by rise.","skill":"Slope of a line"},{"cat":"algebra","a":0,"q":"If 3(x + 4) = 2x + 19, what is the value of x?","options":["7","-7","31/5","5"],"explanation":"Distribute: 3x + 12 = 2x + 19, so x + 12 = 19 and x = 7. The distractor -7 results from a sign error when moving terms across the equals sign.","skill":"Linear equations in one variable"},{"cat":"algebra","a":0,"q":"What is the y-intercept of the line 4x + 2y = 10?","options":["5","10","2","-5"],"explanation":"Set x = 0: 2y = 10, so y = 5. The distractor 10 comes from reading the constant directly without dividing by the coefficient of y.","skill":"Linear functions"},{"cat":"algebra","a":0,"q":"Solve the inequality 2x + 9 ≤ 21.","options":["x ≤ 6","x ≥ 6","x ≤ 15","x ≤ 12"],"explanation":"Subtract 9: 2x ≤ 12, then divide by 2 to get x ≤ 6. The distractor x ≥ 6 reverses the inequality sign, which is only required when dividing by a negative.","skill":"Linear inequalities"},{"cat":"algebra","a":0,"q":"If |x - 3| = 8, what are the possible values of x?","options":["11 and -5","11 and 5","-11 and 5","5 and -5"],"explanation":"Either x - 3 = 8 giving x = 11, or x - 3 = -8 giving x = -5. The distractor 11 and 5 forgets to apply the sign change in the second case.","skill":"Absolute-value equations"},{"cat":"algebra","a":0,"q":"A taxi charges a flat fee of $3.00 plus $2.50 per mile. Which equation gives the total cost C, in dollars, for a ride of m miles?","options":["C = 2.50m + 3.00","C = 3.00m + 2.50","C = 5.50m","C = 2.50m - 3.00"],"explanation":"The per-mile rate 2.50 multiplies the miles m, and the flat fee 3.00 is added once. The distractor swaps which value is the rate and which is the constant.","skill":"Building linear models"},{"cat":"algebra","a":0,"q":"The system below has how many solutions?\n2x + y = 5\n4x + 2y = 7","options":["No solution","Exactly one solution","Infinitely many solutions","Exactly two solutions"],"explanation":"Doubling the first equation gives 4x + 2y = 10, which contradicts 4x + 2y = 7. Parallel lines never intersect, so there is no solution. Infinitely many would require identical equations.","skill":"Systems of linear equations"},{"cat":"algebra","a":0,"q":"If y = -3x + 7, what is the value of y when x = -2?","options":["13","1","-13","5"],"explanation":"Substitute: y = -3(-2) + 7 = 6 + 7 = 13. The distractor 1 comes from treating -3(-2) as -6 instead of +6.","skill":"Linear functions"},{"cat":"algebra","a":0,"q":"Solve the system:\nx + y = 10\nx - y = 4","options":["x = 7, y = 3","x = 3, y = 7","x = 6, y = 4","x = 7, y = -3"],"explanation":"Adding the equations gives 2x = 14, so x = 7 and y = 3. The distractor x = 3, y = 7 swaps the two solved values.","skill":"Systems of linear equations"},{"cat":"algebra","a":0,"q":"A line has slope -4 and passes through the point (1, 2). What is the equation of the line in slope-intercept form?","options":["y = -4x + 6","y = -4x + 2","y = -4x - 2","y = 4x - 2"],"explanation":"Using y = mx + b: 2 = -4(1) + b gives b = 6, so y = -4x + 6. The distractor y = -4x + 2 mistakenly uses the y-coordinate as the intercept.","skill":"Linear functions"},{"cat":"algebra","a":0,"q":"If 7 - 2x > 1, which of the following describes all values of x?","options":["x < 3","x > 3","x < -3","x > -3"],"explanation":"Subtract 7: -2x > -6, then divide by -2 and flip the sign: x < 3. The distractor x > 3 forgets to reverse the inequality when dividing by a negative.","skill":"Linear inequalities"},{"cat":"algebra","a":0,"q":"A plumber's total charge is modeled by C = 45h + 60, where h is hours worked. What does the number 45 represent?","options":["The hourly labor rate in dollars","The flat service fee in dollars","The total cost for one hour","The number of hours worked"],"explanation":"Because 45 multiplies the variable h (hours), it is the rate of change per hour. The constant 60 is the flat fee; the total for one hour would be 45 + 60 = 105.","skill":"Interpreting linear models"},{"cat":"algebra","a":0,"q":"For what value of k does the system below have infinitely many solutions?\n3x - y = 6\n6x - 2y = k","options":["12","6","3","-12"],"explanation":"Multiplying the first equation by 2 gives 6x - 2y = 12, so k must equal 12 for the equations to be identical. k = 6 would make the lines parallel with no solution.","skill":"Systems of linear equations"},{"cat":"algebra","a":0,"q":"If 2/3 x - 4 = 6, what is the value of x?","options":["15","10","3","20/3"],"explanation":"Add 4: 2/3 x = 10, then multiply by 3/2 to get x = 15. The distractor 10 stops after isolating 2/3 x without multiplying by the reciprocal.","skill":"Linear equations in one variable"},{"cat":"algebra","a":0,"q":"The cost to rent a kayak is $15 plus $9 for each hour. If Maria paid $69, for how many hours did she rent the kayak?","options":["6","7","8","4"],"explanation":"Solve 15 + 9h = 69: subtract 15 to get 9h = 54, so h = 6. The distractor 7 comes from forgetting to subtract the flat fee (63/9 = 7).","skill":"Building linear models"},{"cat":"algebra","a":0,"q":"Lines p and q are perpendicular. If line p has a slope of 2/5, what is the slope of line q?","options":["-5/2","5/2","-2/5","2/5"],"explanation":"Perpendicular slopes are negative reciprocals, so the slope of q is -5/2. The distractor 5/2 takes the reciprocal but omits the negative sign.","skill":"Slope of a line"},{"cat":"algebra","a":0,"q":"If 4x + 3y = 24 and x = 3, what is the value of y?","options":["4","12","8","-4"],"explanation":"Substitute x = 3: 12 + 3y = 24, so 3y = 12 and y = 4. The distractor 12 stops at 3y = 12 without dividing by 3.","skill":"Linear equations in two variables"},{"cat":"algebra","a":0,"q":"A car's fuel tank starts with 12 gallons and the car uses 0.04 gallon per mile. Which equation gives the gallons G remaining after driving d miles?","options":["G = 12 - 0.04d","G = 12 + 0.04d","G = 0.04d - 12","G = 0.04(12 - d)"],"explanation":"Fuel decreases as miles increase, so the rate 0.04 is subtracted from the starting 12 gallons. The distractor adds the fuel used, which would increase the tank's contents.","skill":"Building linear models"},{"cat":"algebra","a":0,"q":"If |2x + 1| = 9, what is the sum of all possible values of x?","options":["-1","4","8","-5"],"explanation":"From 2x + 1 = 9, x = 4; from 2x + 1 = -9, x = -5. Their sum is 4 + (-5) = -1. The distractor 4 reports only the positive solution.","skill":"Absolute-value equations"},{"cat":"algebra","a":0,"q":"A line is graphed so that it passes through (0, -2) and has slope 3. At what x-value does the line cross the x-axis?","options":["2/3","-2/3","3/2","-2"],"explanation":"The line is y = 3x - 2; set y = 0 to get 3x = 2, so x = 2/3. The distractor -2/3 comes from a sign error when solving 3x = 2.","skill":"Linear functions"},{"cat":"algebra","a":0,"q":"At a bookstore, hardcover books cost $20 each and paperbacks cost $12 each. Tom bought 9 books total and spent $148. How many hardcover books did he buy?","options":["5","4","6","3"],"explanation":"Let h be hardcovers: 20h + 12(9 - h) = 148 gives 8h + 108 = 148, so h = 5. The distractor 4 is the number of paperbacks, not hardcovers.","skill":"Systems of linear equations"},{"cat":"algebra","a":0,"q":"The line y = mx - 8 passes through the point (4, 4). What is the value of m?","options":["3","-3","1","-1"],"explanation":"Substitute: 4 = 4m - 8, so 4m = 12 and m = 3. The distractor -3 results from a sign error when adding 8 to both sides.","skill":"Linear functions"},{"cat":"algebra","a":0,"q":"A membership plan costs $40 to join plus a monthly fee. After 6 months the total paid is $148. What is the monthly fee, in dollars?","options":["18","24.67","30.80","108"],"explanation":"Solve 40 + 6f = 148: subtract 40 to get 6f = 108, so f = 18. The distractor 24.67 comes from dividing the full 148 by 6 without removing the join fee.","skill":"Interpreting linear models"},{"cat":"algebra","a":0,"q":"If 3x - 2y = 12 and 3x + y = 3, what is the value of y?","options":["-3","3","-1","1"],"explanation":"Subtracting the first equation from the second gives 3y = -9, so y = -3. The distractor 3 drops the negative sign when dividing -9 by 3.","skill":"Systems of linear equations"},{"cat":"advanced","a":0,"q":"If f(x) = 3x^2 - 5x + 2, what is the value of f(-2)?","options":["24","4","0","-4"],"explanation":"f(-2) = 3(-2)^2 - 5(-2) + 2 = 3(4) + 10 + 2 = 12 + 10 + 2 = 24. The distractor 4 comes from mishandling the sign of -5(-2) as -10 (giving 12 - 10 + 2 = 4).","skill":"Function evaluation"},{"cat":"advanced","a":0,"q":"Which of the following is equivalent to (2x^3)(4x^5)?","options":["8x^8","6x^8","8x^15","6x^15"],"explanation":"Multiply coefficients (2*4 = 8) and add exponents (3 + 5 = 8), giving 8x^8. The distractor 8x^15 wrongly multiplies the exponents instead of adding them.","skill":"Exponent rules"},{"cat":"advanced","a":0,"q":"The expression √(50) can be written in the form a√b, where a and b are positive integers and b has no perfect-square factor greater than 1. What is the value of a?","options":["5","25","2","10"],"explanation":"√50 = √(25*2) = √25 * √2 = 5√2, so a = 5. The distractor 25 leaves the perfect square un-simplified inside the radical.","skill":"Radicals"},{"cat":"advanced","a":0,"q":"If g(x) = x^2 + 1 and h(x) = 2x - 3, what is g(h(2))?","options":["2","5","1","10"],"explanation":"h(2) = 2(2) - 3 = 1, then g(1) = 1^2 + 1 = 2. The distractor 5 comes from computing g(2) = 5 first and ignoring h.","skill":"Composite functions"},{"cat":"advanced","a":0,"q":"What is the sum of the polynomials (3x^2 - 2x + 5) and (x^2 + 4x - 9)?","options":["4x^2 + 2x - 4","4x^2 - 2x - 4","2x^2 + 2x - 4","4x^2 + 2x + 14"],"explanation":"Combine like terms: (3+1)x^2 + (-2+4)x + (5-9) = 4x^2 + 2x - 4. The distractor 4x^2 - 2x - 4 fails to combine the x-terms correctly (-2 + 4 = 2, not -2).","skill":"Polynomial operations"},{"cat":"advanced","a":0,"q":"A population of bacteria doubles every 3 hours. If there are initially 500 bacteria, which function P models the number of bacteria after t hours?","options":["P = 500(2)^(t/3)","P = 500(2)^(3t)","P = 500(3)^(t/2)","P = 500 + 2t/3"],"explanation":"Doubling (base 2) every 3 hours means the exponent is t/3, giving P = 500(2)^(t/3). The distractor 500(2)^(3t) doubles every 1/3 hour instead, growing far too fast.","skill":"Exponential growth"},{"cat":"advanced","a":0,"q":"What is the vertex of the parabola y = (x - 4)^2 + 7?","options":["(4, 7)","(-4, 7)","(4, -7)","(7, 4)"],"explanation":"In vertex form y = (x - h)^2 + k, the vertex is (h, k) = (4, 7). The distractor (-4, 7) misreads the sign of h inside the squared term.","skill":"Quadratic functions"},{"cat":"advanced","a":0,"q":"If x ≠ 0, which expression is equivalent to (x^6 * x^(-2)) / x^3?","options":["x","x^5","x^11","x^(-1)"],"explanation":"x^6 * x^(-2) = x^4, then x^4 / x^3 = x^(4-3) = x^1 = x. The distractor x^5 incorrectly adds the -2 as +2 in the numerator.","skill":"Exponent rules"},{"cat":"advanced","a":0,"q":"For what value of c does the equation x^2 + 6x + c = 0 have exactly one real solution?","options":["9","6","3","36"],"explanation":"One real solution means discriminant b^2 - 4ac = 0: 36 - 4c = 0, so c = 9. The distractor 6 mistakenly sets c equal to b instead of using the discriminant.","skill":"Discriminant"},{"cat":"advanced","a":0,"q":"Which of the following is the factored form of x^2 - 49?","options":["(x - 7)(x + 7)","(x - 7)^2","(x - 49)(x + 1)","(x + 7)^2"],"explanation":"This is a difference of squares: x^2 - 49 = (x - 7)(x + 7). The distractor (x - 7)^2 expands to x^2 - 14x + 49, which has a middle term.","skill":"Factoring"},{"cat":"advanced","a":0,"q":"If (x + 3)/(x - 2) = 5, what is the value of x?","options":["13/4","7/4","5/2","8"],"explanation":"Cross-multiply: x + 3 = 5(x - 2) = 5x - 10, so 13 = 4x and x = 13/4. The distractor 7/4 comes from writing 5(x-2) = 5x - 2 (forgetting to distribute over 2).","skill":"Rational equations"},{"cat":"advanced","a":0,"q":"The function f is defined by f(x) = 2x^2 - 12x + 5. What is the minimum value of f(x)?","options":["-13","3","5","-7"],"explanation":"The minimum occurs at x = -b/(2a) = 12/4 = 3; f(3) = 2(9) - 36 + 5 = 18 - 36 + 5 = -13. The distractor 3 gives the x-value of the vertex, not the minimum value.","skill":"Quadratic max/min"},{"cat":"advanced","a":0,"q":"Which expression is equivalent to (4x^2 - 9)/(2x - 3) for x ≠ 3/2?","options":["2x + 3","2x - 3","4x + 3","2x + 9"],"explanation":"Factor the numerator as a difference of squares: (2x-3)(2x+3)/(2x-3) = 2x + 3. The distractor 2x - 3 cancels the wrong factor.","skill":"Rational expressions"},{"cat":"advanced","a":0,"q":"The graph of y = x^2 is shifted 3 units to the left and 2 units down. Which equation represents the new graph?","options":["y = (x + 3)^2 - 2","y = (x - 3)^2 - 2","y = (x + 3)^2 + 2","y = (x - 2)^2 - 3"],"explanation":"A shift left by 3 gives (x + 3), and down by 2 subtracts 2: y = (x + 3)^2 - 2. The distractor (x - 3)^2 - 2 shifts right instead of left.","skill":"Function transformations"},{"cat":"advanced","a":0,"q":"If 9^(x) = 27, what is the value of x?","options":["3/2","3","2/3","9/27"],"explanation":"Write both sides as powers of 3: (3^2)^x = 3^3, so 2x = 3 and x = 3/2. The distractor 3 ignores that the base 9 is itself 3^2.","skill":"Exponential equations"},{"cat":"advanced","a":0,"q":"What is the product (x - 4)(x^2 + 2x - 1)?","options":["x^3 - 2x^2 - 9x + 4","x^3 + 2x^2 - 9x + 4","x^3 - 2x^2 - x - 4","x^3 - 6x^2 - 9x + 4"],"explanation":"Distribute: x^3 + 2x^2 - x - 4x^2 - 8x + 4 = x^3 - 2x^2 - 9x + 4. The distractor x^3 + 2x^2 - 9x + 4 fails to combine 2x^2 - 4x^2 = -2x^2.","skill":"Polynomial multiplication"},{"cat":"advanced","a":0,"q":"The solutions to the system y = x^2 - 4 and y = 3x are given by which pair of x-values?","options":["x = -1 and x = 4","x = 1 and x = -4","x = 2 and x = -2","x = -1 and x = -4"],"explanation":"Set x^2 - 4 = 3x, so x^2 - 3x - 4 = 0, (x - 4)(x + 1) = 0, giving x = 4 or x = -1. The distractor x = 1 and x = -4 reverses the signs of the roots.","skill":"Nonlinear systems"},{"cat":"advanced","a":0,"q":"If f(x) = ax^2 + bx + c has roots x = 2 and x = 5, which of the following could be f(x)?","options":["x^2 - 7x + 10","x^2 + 7x + 10","x^2 - 7x - 10","x^2 - 3x + 10"],"explanation":"With roots 2 and 5, f(x) = (x - 2)(x - 5) = x^2 - 7x + 10. The distractor x^2 + 7x + 10 would have roots -2 and -5.","skill":"Quadratic functions"},{"cat":"advanced","a":0,"q":"A car loses 15% of its value each year. If its current value is $20,000, which expression gives its value after 4 years?","options":["20000(0.85)^4","20000(1.15)^4","20000(0.15)^4","20000(0.85)(4)"],"explanation":"Losing 15% leaves 85% each year, so the value is 20000(0.85)^4. The distractor 20000(1.15)^4 models 15% growth instead of decay.","skill":"Exponential decay"},{"cat":"advanced","a":0,"q":"Which value of x satisfies √(2x + 7) = x - 4?","options":["9","1","3","9 and 1"],"explanation":"Square both sides: 2x + 7 = x^2 - 8x + 16, so x^2 - 10x + 9 = 0, (x - 9)(x - 1) = 0, giving x = 9 or x = 1. Checking, x = 1 gives √9 = 3 ≠ -3, so it is extraneous; only x = 9 works. The distractor '9 and 1' keeps the extraneous root.","skill":"Radical equations"},{"cat":"advanced","a":0,"q":"If x^2 + y^2 = 25 and y = x + 1, which point is a solution to the system?","options":["(3, 4)","(4, 3)","(3, -4)","(-4, 3)"],"explanation":"Substitute: x^2 + (x+1)^2 = 25, so 2x^2 + 2x - 24 = 0, x^2 + x - 12 = 0, (x+4)(x-3) = 0; x = 3 gives y = 4. The point (4,3) satisfies the circle but not y = x + 1.","skill":"Nonlinear systems"},{"cat":"advanced","a":0,"q":"The expression (x^(1/2) * x^(1/3)) is equivalent to which of the following?","options":["x^(5/6)","x^(1/6)","x^(2/5)","x^(1/5)"],"explanation":"Add the exponents: 1/2 + 1/3 = 3/6 + 2/6 = 5/6, so the result is x^(5/6). The distractor x^(1/6) subtracts the exponents instead of adding.","skill":"Radicals"},{"cat":"advanced","a":0,"q":"If 1/(x) + 1/(x + 2) = 1/2 and x > 0, what is the value of x?","options":["1 + √5","1 + √3","2 + √5","1 - √5"],"explanation":"Combine: (2x + 2)/(x(x+2)) = 1/2, so 2(2x + 2) = x^2 + 2x, giving x^2 - 2x - 4 = 0; x = (2 ± √20)/2 = 1 ± √5. Since x > 0, x = 1 + √5. The distractor 1 - √5 is negative and rejected.","skill":"Rational equations"},{"cat":"advanced","a":0,"q":"The function f(x) = x^2 - 6x + 11 is written in vertex form. What is the vertex form of f(x)?","options":["(x - 3)^2 + 2","(x - 3)^2 - 2","(x + 3)^2 + 2","(x - 6)^2 + 11"],"explanation":"Complete the square: x^2 - 6x + 9 - 9 + 11 = (x - 3)^2 + 2. The distractor (x - 3)^2 - 2 subtracts instead of adding the leftover constant (11 - 9 = +2).","skill":"Completing the square"},{"cat":"advanced","a":0,"q":"For the quadratic f(x) = -2x^2 + 8x - 3, over which interval is f increasing?","options":["x < 2","x > 2","x < -2","x > -2"],"explanation":"The vertex is at x = -b/(2a) = -8/(-4) = 2; since a = -2 < 0 the parabola opens downward, so f increases for x < 2 and decreases after. The distractor x > 2 gives the decreasing interval.","skill":"Quadratic functions"},{"cat":"data","a":1,"q":"A recipe that serves 4 people requires 6 cups of flour. If the same recipe is scaled proportionally to serve 10 people, how many cups of flour are needed?","options":["12 cups","15 cups","16 cups","24 cups"],"explanation":"The ratio is 6 cups per 4 people = 1.5 cups per person. For 10 people: 10 x 1.5 = 15 cups. The distractor 12 comes from adding 6 to scale incorrectly (4+6=10 people, +6 cups), ignoring proportionality.","skill":"Proportions"},{"cat":"data","a":2,"q":"A car travels 180 miles using 6 gallons of gasoline. At this rate, how many gallons are needed to travel 300 miles?","options":["8 gallons","9 gallons","10 gallons","12 gallons"],"explanation":"The rate is 180/6 = 30 miles per gallon. For 300 miles: 300/30 = 10 gallons. The distractor 9 results from incorrectly using a 20 mpg rate.","skill":"Rates"},{"cat":"data","a":2,"q":"A jacket originally priced at $80 is on sale for 25% off. What is the sale price of the jacket?","options":["$20","$55","$60","$65"],"explanation":"25% of $80 is $20, so the sale price is $80 - $20 = $60. The distractor $20 is the amount of the discount, not the final price.","skill":"Percent change"},{"cat":"data","a":2,"q":"A quantity increases from 50 to 65. What is the percent increase?","options":["15%","23%","30%","65%"],"explanation":"Percent increase = (65 - 50)/50 = 15/50 = 0.30 = 30%. The distractor 15% mistakes the raw increase amount (15) for the percent.","skill":"Percent change"},{"cat":"data","a":1,"q":"The data set consists of the values 4, 7, 7, 9, and 13. What is the mean of this data set?","options":["7","8","9","13"],"explanation":"Mean = (4 + 7 + 7 + 9 + 13)/5 = 40/5 = 8. The distractor 7 is the mode and median, not the mean.","skill":"Mean"},{"cat":"data","a":1,"q":"A data set has the values 3, 8, 8, 10, 12, and 15. What is the median of this data set?","options":["8","9","9.5","10"],"explanation":"With six values in order, the median is the average of the 3rd and 4th values: (8 + 10)/2 = 9. The distractor 8 is the mode and is the lower middle value alone.","skill":"Median"},{"cat":"data","a":1,"q":"In a survey, the recorded ages were 12, 15, 15, 18, and 22 years. What is the range of these ages?","options":["7","10","15","18"],"explanation":"Range = maximum - minimum = 22 - 12 = 10. The distractor 15 is the mode, not the range.","skill":"Range"},{"cat":"data","a":2,"q":"A map uses a scale where 2 centimeters represents 15 kilometers. Two cities are 8 centimeters apart on the map. What is the actual distance between the cities?","options":["30 km","45 km","60 km","120 km"],"explanation":"Each cm represents 7.5 km, so 8 cm represents 8 x 7.5 = 60 km. The distractor 120 incorrectly multiplies 8 by 15 without dividing by 2.","skill":"Unit conversion"},{"cat":"data","a":1,"q":"A runner completes a race at a constant pace, covering 400 meters every 90 seconds. How many minutes will it take the runner to cover 2,000 meters at this pace?","options":["6.5 minutes","7.5 minutes","8 minutes","9 minutes"],"explanation":"2,000/400 = 5 segments, each 90 seconds, so 450 seconds total = 450/60 = 7.5 minutes. The distractor 9 minutes wrongly uses 540 seconds (6 segments).","skill":"Rates and unit conversion"},{"cat":"data","a":1,"q":"A solution is made by mixing salt and water in a ratio of 3 to 17 by mass. If the total mixture has a mass of 500 grams, how many grams of salt does it contain?","options":["60 grams","75 grams","85 grams","150 grams"],"explanation":"Total parts = 3 + 17 = 20. Each part is 500/20 = 25 grams. Salt = 3 x 25 = 75 grams. The distractor 85 mistakenly uses the water ratio of 17 with a wrong part size.","skill":"Ratios"},{"cat":"data","a":3,"q":"A bag contains 5 red marbles, 3 blue marbles, and 2 green marbles. If one marble is drawn at random, what is the probability that it is NOT blue?","options":["3/10","1/2","3/5","7/10"],"explanation":"Non-blue marbles = 5 + 2 = 7 out of 10, so probability = 7/10. The distractor 3/10 gives the probability of drawing blue instead.","skill":"Probability"},{"cat":"data","a":1,"q":"A survey of 200 commuters records their primary transportation method by city zone. In the downtown zone, 40 use the bus and 25 use the train. In the suburban zone, 60 use the bus and 75 use the train. Given that a randomly selected commuter uses the train, what is the probability that the commuter is from the suburban zone?","options":["3/8","3/4","15/26","75/135"],"explanation":"Total train users = 25 + 75 = 100. Suburban train users = 75. Conditional probability = 75/100 = 3/4. The distractor 3/8 incorrectly divides 75 by the total of 200.","skill":"Conditional probability"},{"cat":"data","a":0,"q":"A two-way table classifies 150 people by whether they exercise regularly and whether they sleep at least 8 hours. Of those who exercise regularly, 54 sleep at least 8 hours and 16 do not. Of those who do not exercise regularly, 30 sleep at least 8 hours and 50 do not. Given that a randomly selected person sleeps at least 8 hours, what is the probability that the person exercises regularly?","options":["54/84","54/70","54/150","70/150"],"explanation":"People sleeping at least 8 hours = 54 + 30 = 84. Of those, 54 exercise regularly, so probability = 54/84. The distractor 54/70 wrongly uses the total who exercise (70) as the denominator.","skill":"Conditional probability"},{"cat":"data","a":1,"q":"Two data sets each contain five values. Data set X is {48, 49, 50, 51, 52} and data set Y is {30, 40, 50, 60, 70}. Both have a mean of 50. Which statement correctly compares their standard deviations?","options":["Data set X has the greater standard deviation","Data set Y has the greater standard deviation","The standard deviations are equal","The standard deviation cannot be compared without more data"],"explanation":"Data set Y's values are spread far from the mean of 50 (deviations up to 20), while X's values cluster close (deviations up to 2). Greater spread means greater standard deviation, so Y is larger. Choosing X reverses the relationship between spread and standard deviation.","skill":"Standard deviation comparison"},{"cat":"data","a":1,"q":"Two basketball players each took 10 free throws across several games. Player A's makes per game were 7, 7, 8, 7, 8, 7, 8, 7, 8, 7 and Player B's makes per game were 2, 10, 5, 9, 4, 10, 1, 9, 3, 10. Both players have similar average makes. Which statement about the standard deviation of makes per game is correct?","options":["Player A has the greater standard deviation","Player B has the greater standard deviation","Both have the same standard deviation","Standard deviation depends only on the mean, so they are equal"],"explanation":"Player A's values stay near 7-8 (small spread), while Player B's values swing widely from 1 to 10 (large spread). Greater variability means greater standard deviation, so Player B's is larger. The claim that equal means force equal standard deviations is false.","skill":"Standard deviation comparison"},{"cat":"data","a":2,"q":"A scatterplot shows hours studied (x) versus test score (y) for several students, and the line of best fit is y = 8x + 52. Based on this model, what is the predicted test score for a student who studies 5 hours?","options":["60","65","92","100"],"explanation":"Substitute x = 5: y = 8(5) + 52 = 40 + 52 = 92. The distractor 60 comes from computing 8 + 52 instead of multiplying by 5.","skill":"Line of best fit prediction"},{"cat":"data","a":1,"q":"A scatterplot relates the number of weeks a plant is grown (x) to its height in centimeters (y). The line of best fit is y = 2.5x + 4. What does the slope of 2.5 represent in this context?","options":["The plant's height when it is first planted","The predicted increase in height, in cm, for each additional week","The total height of the plant after all weeks","The number of weeks needed to reach 4 cm"],"explanation":"The slope of a line of best fit gives the predicted change in y per one-unit change in x, so 2.5 is the increase in height per additional week. The first option describes the y-intercept (4), not the slope.","skill":"Line of best fit interpretation"},{"cat":"data","a":2,"q":"A researcher wants to estimate the average daily screen time of all students at a large high school. Which sampling method is most likely to produce an unbiased estimate?","options":["Surveying students leaving the computer lab after school","Surveying members of the school's video game club","Selecting students at random from the full school roster","Surveying only students who volunteer to respond online"],"explanation":"A random selection from the full roster gives every student an equal chance of being chosen, minimizing bias. The other methods oversample heavy-screen-time or self-selected groups, producing biased estimates.","skill":"Sampling and inference"},{"cat":"data","a":2,"q":"In a random sample of 80 voters from a town, 52 said they support a new park proposal. If the town has 5,000 registered voters, approximately how many would be expected to support the proposal based on this sample?","options":["2,600","2,900","3,250","3,600"],"explanation":"Sample proportion = 52/80 = 0.65. Expected supporters = 0.65 x 5,000 = 3,250. The distractor 2,600 incorrectly uses a proportion of 0.52 (taking 52 as a percent).","skill":"Sampling inference"},{"cat":"data","a":1,"q":"A table lists monthly rainfall in inches for a city: January 3.2, February 2.8, March 4.5, April 3.5, and May 6.0. What is the average (arithmetic mean) monthly rainfall over these five months?","options":["3.5 inches","4.0 inches","4.5 inches","6.0 inches"],"explanation":"Sum = 3.2 + 2.8 + 4.5 + 3.5 + 6.0 = 20.0 inches; mean = 20.0/5 = 4.0 inches. The distractor 3.5 is one of the listed values (and the median-area value), not the mean.","skill":"Interpreting a table"},{"cat":"data","a":1,"q":"A frequency table shows the number of pets owned by households: 0 pets for 8 households, 1 pet for 12 households, 2 pets for 6 households, and 3 pets for 4 households. What is the mean number of pets per household?","options":["1.0 pet","1.2 pets","1.5 pets","2.0 pets"],"explanation":"Total pets = 0(8) + 1(12) + 2(6) + 3(4) = 0 + 12 + 12 + 12 = 36; total households = 8 + 12 + 6 + 4 = 30; mean = 36/30 = 1.2. The distractor 1.5 averages the four pet-count categories (0,1,2,3) without weighting by frequency.","skill":"Weighted mean from table"},{"cat":"data","a":1,"q":"The population of a town was 24,000 in 2020 and decreased by 8% by 2023. What was the town's population in 2023?","options":["16,000","22,080","23,920","25,920"],"explanation":"A decrease of 8% leaves 92% of the population: 0.92 x 24,000 = 22,080. The distractor 25,920 mistakenly adds 8% (0.92 should be used, not 1.08).","skill":"Percent change"},{"cat":"data","a":0,"q":"An item's price increased by 20% and then the new price decreased by 20%. If the original price was $50, what is the final price?","options":["$48","$50","$52","$60"],"explanation":"After +20%: 50 x 1.20 = $60. After -20%: 60 x 0.80 = $48. The distractor $50 assumes the two percent changes cancel, but the 20% decrease applies to the larger $60, not the original $50.","skill":"Successive percent change"},{"cat":"data","a":0,"q":"A scatterplot shows the relationship between a used car's age in years (x) and its value in thousands of dollars (y). The data points follow a clear downward trend, and the line of best fit is y = -1.5x + 18. Using this model, by approximately how much does the predicted value change for each additional year of age, and what is the predicted value of a 6-year-old car?","options":["Decreases by $1,500 per year; predicted value $9,000","Decreases by $1,500 per year; predicted value $27,000","Increases by $1,500 per year; predicted value $9,000","Decreases by $18,000 per year; predicted value $9,000"],"explanation":"The slope -1.5 (thousand dollars) means the value drops $1,500 per year. At x = 6: y = -1.5(6) + 18 = -9 + 18 = 9, or $9,000. The increasing-value option misreads the negative slope.","skill":"Line of best fit interpretation and prediction"},{"cat":"data","a":2,"q":"A factory produces 1,200 units in an 8-hour shift. If production continues at the same constant rate, how many units are produced in a 12-hour shift?","options":["1,500 units","1,600 units","1,800 units","2,400 units"],"explanation":"Rate = 1,200/8 = 150 units per hour. In 12 hours: 150 x 12 = 1,800 units. The distractor 1,600 comes from adding 400 (a 4-hour estimate at 100 units/hour) using the wrong rate.","skill":"Rates"},{"cat":"geometry","a":2,"q":"A rectangle has a length of 12 centimeters and a width of 5 centimeters. What is the area of the rectangle, in square centimeters?","options":["17","34","60","120"],"explanation":"Area of a rectangle = length × width = 12 × 5 = 60. Choice 34 is the perimeter (2(12+5)), not the area.","skill":"Area of rectangle"},{"cat":"geometry","a":1,"q":"A circle has a radius of 7 inches. What is the circumference of the circle, in inches? (Use the exact form in terms of π.)","options":["7π","14π","49π","98π"],"explanation":"Circumference = 2πr = 2π(7) = 14π. Choice 49π uses the area formula πr^2 instead of circumference.","skill":"Circumference of circle"},{"cat":"geometry","a":1,"q":"In a triangle, two of the interior angles measure 47° and 68°. What is the measure of the third interior angle?","options":["45°","65°","115°","135°"],"explanation":"Angles of a triangle sum to 180°, so the third angle = 180 − 47 − 68 = 65°. Choice 115° wrongly subtracts only one angle (180 − 47 − 18).","skill":"Triangle angle sum"},{"cat":"geometry","a":0,"q":"A right triangle has legs of length 6 and 8. What is the length of the hypotenuse?","options":["10","12","14","48"],"explanation":"By the Pythagorean theorem, hypotenuse = √(6^2 + 8^2) = √(36 + 64) = √100 = 10. Choice 14 incorrectly adds the legs (6 + 8).","skill":"Pythagorean theorem"},{"cat":"geometry","a":2,"q":"A square has a perimeter of 36 meters. What is the area of the square, in square meters?","options":["9","36","81","144"],"explanation":"Each side = 36 ÷ 4 = 9, so area = 9^2 = 81. Choice 144 uses side = 12 (mistakenly dividing perimeter by 3).","skill":"Square area and perimeter"},{"cat":"geometry","a":2,"q":"Lines m and n are parallel and are cut by a transversal. One of the angles formed measures 73°. What is the measure of its co-interior (same-side interior) angle on the same side of the transversal?","options":["17°","73°","107°","117°"],"explanation":"Same-side interior angles are supplementary, so the angle = 180 − 73 = 107°. Choice 73° treats them as equal (which is true only for corresponding or alternate interior angles).","skill":"Parallel line angles"},{"cat":"geometry","a":2,"q":"A rectangular box (rectangular prism) has dimensions 4 cm by 5 cm by 6 cm. What is the volume of the box, in cubic centimeters?","options":["60","74","120","148"],"explanation":"Volume of a rectangular prism = length × width × height = 4 × 5 × 6 = 120. Choice 148 is the surface area 2(4·5 + 5·6 + 4·6), not the volume.","skill":"Volume of prism"},{"cat":"geometry","a":0,"q":"In a right triangle, the angle θ has an opposite side of length 3 and a hypotenuse of length 5. What is the value of sin θ?","options":["3/5","4/5","3/4","5/3"],"explanation":"sin θ = opposite/hypotenuse = 3/5. Choice 4/5 is cos θ, using the adjacent side (length 4) instead of the opposite.","skill":"Right-triangle trig"},{"cat":"geometry","a":1,"q":"A 45-45-90 right triangle has each leg equal to 6 units. What is the length of the hypotenuse?","options":["6","6√2","12","6√3"],"explanation":"In a 45-45-90 triangle, the hypotenuse = leg × √2 = 6√2. Choice 6√3 incorrectly applies the 30-60-90 ratio.","skill":"Special right triangles"},{"cat":"geometry","a":0,"q":"The measure of an angle is 135°. What is the radian measure of this angle?","options":["3π/4","2π/3","5π/6","4π/3"],"explanation":"Radians = degrees × π/180 = 135 × π/180 = 3π/4. Choice 2π/3 corresponds to 120°, not 135°.","skill":"Degree to radian"},{"cat":"geometry","a":2,"q":"Two angles are supplementary. One angle measures 5x and the other measures 4x. What is the value of x?","options":["10","18","20","36"],"explanation":"Supplementary angles sum to 180°, so 5x + 4x = 9x = 180, giving x = 20. Choice 10 mistakenly uses 90° (complementary) instead of 180°.","skill":"Supplementary angles"},{"cat":"geometry","a":2,"q":"A right circular cylinder has a radius of 3 cm and a height of 10 cm. What is the volume of the cylinder, in cubic centimeters? (Express in terms of π.)","options":["30π","60π","90π","180π"],"explanation":"Volume of a cylinder = πr^2h = π(3^2)(10) = 90π. Choice 30π incorrectly uses πrh without squaring the radius.","skill":"Volume of cylinder"},{"cat":"geometry","a":1,"q":"Triangle ABC is similar to triangle DEF. In triangle ABC, side AB = 8 and BC = 12. In triangle DEF, the side corresponding to AB is DE = 20. What is the length of the side EF corresponding to BC?","options":["24","30","32","16"],"explanation":"The scale factor is DE/AB = 20/8 = 2.5, so EF = 12 × 2.5 = 30. Choice 24 wrongly adds 12 to the scale-factor difference instead of multiplying.","skill":"Similar triangles"},{"cat":"geometry","a":1,"q":"A circle has a radius of 12 cm. A sector of the circle has a central angle of 60°. What is the arc length of the sector, in centimeters? (Express in terms of π.)","options":["2π","4π","6π","24π"],"explanation":"Arc length = (central angle/360) × 2πr = (60/360) × 2π(12) = (1/6)(24π) = 4π. Choice 2π uses radius 6 or halves the result by mistake.","skill":"Arc length"},{"cat":"geometry","a":0,"q":"In the xy-plane, a circle has center (3, −2) and radius 5. Which of the following is the equation of the circle?","options":["(x − 3)^2 + (y + 2)^2 = 25","(x + 3)^2 + (y − 2)^2 = 25","(x − 3)^2 + (y + 2)^2 = 5","(x + 3)^2 + (y + 2)^2 = 25"],"explanation":"The standard form is (x − h)^2 + (y − k)^2 = r^2 with center (h, k) = (3, −2) and r^2 = 25, giving (x − 3)^2 + (y + 2)^2 = 25. Choice 3 uses r instead of r^2 on the right side.","skill":"Equation of circle"},{"cat":"geometry","a":2,"q":"In a 30-60-90 right triangle, the side opposite the 30° angle has length 7. What is the length of the side opposite the 60° angle?","options":["7","7√2","7√3","14"],"explanation":"In a 30-60-90 triangle, sides are in ratio 1 : √3 : 2, so the side opposite 60° = 7√3. Choice 14 is the hypotenuse (opposite the 90° angle), not the side opposite 60°.","skill":"Special right triangles"},{"cat":"geometry","a":1,"q":"In a right triangle, angle A and angle B are the two acute angles. If sin A = 0.6, what is the value of cos B?","options":["0.4","0.6","0.8","1.0"],"explanation":"In a right triangle the acute angles are complementary, so cos B = cos(90° − A) = sin A = 0.6. Choice 0.8 is cos A, not cos B.","skill":"Complementary angle trig"},{"cat":"geometry","a":2,"q":"A sphere has a radius of 3 cm. What is the volume of the sphere, in cubic centimeters? (Express in terms of π.)","options":["12π","27π","36π","108π"],"explanation":"Volume of a sphere = (4/3)πr^3 = (4/3)π(27) = 36π. Choice 27π forgets the factor 4/3 and just uses r^3.","skill":"Volume of sphere"},{"cat":"geometry","a":1,"q":"In a circle, an inscribed angle intercepts an arc whose central angle measures 80°. What is the measure of the inscribed angle?","options":["20°","40°","80°","160°"],"explanation":"An inscribed angle equals half the central angle that intercepts the same arc, so 80 ÷ 2 = 40°. Choice 160° doubles the central angle instead of halving it.","skill":"Inscribed angle"},{"cat":"geometry","a":1,"q":"A right circular cone has a radius of 4 cm and a height of 9 cm. What is the volume of the cone, in cubic centimeters? (Express in terms of π.)","options":["36π","48π","108π","144π"],"explanation":"Volume of a cone = (1/3)πr^2h = (1/3)π(16)(9) = 48π. Choice 144π omits the factor 1/3 (that is the cylinder volume).","skill":"Volume of cone"},{"cat":"geometry","a":2,"q":"A circle has a radius of 6 cm. A sector has a central angle of 120°. What is the area of the sector, in square centimeters? (Express in terms of π.)","options":["4π","9π","12π","36π"],"explanation":"Sector area = (central angle/360) × πr^2 = (120/360) × π(36) = (1/3)(36π) = 12π. Choice 4π divides by the wrong fraction (using arc-length thinking with radius).","skill":"Sector area"},{"cat":"geometry","a":0,"q":"A ramp forms a right triangle. The angle between the ramp and the horizontal ground is 25°, and the ramp itself (the hypotenuse) is 12 feet long. Which expression gives the vertical height the ramp rises, in feet?","options":["12 sin 25°","12 cos 25°","12 tan 25°","12 / sin 25°"],"explanation":"The height is opposite the 25° angle, so sin 25° = height/12, giving height = 12 sin 25°. Choice 12 cos 25° would give the horizontal base, not the vertical rise.","skill":"Right-triangle trig"},{"cat":"geometry","a":1,"q":"Two parallel lines are cut by a transversal. One interior angle measures (3x + 10)° and its alternate interior angle measures (5x − 30)°. What is the value of x?","options":["10","20","25","40"],"explanation":"Alternate interior angles are equal, so 3x + 10 = 5x − 30, giving 40 = 2x and x = 20. Choice 25 comes from treating the angles as supplementary instead of equal.","skill":"Parallel line angles"},{"cat":"geometry","a":1,"q":"In the xy-plane, the equation x^2 + y^2 − 6x + 8y − 11 = 0 represents a circle. What is the radius of the circle?","options":["5","6","11","36"],"explanation":"Completing the square: (x − 3)^2 + (y + 4)^2 = 11 + 9 + 16 = 36, so r = √36 = 6. Choice 36 mistakes r^2 for r.","skill":"Equation of circle"},{"cat":"geometry","a":0,"q":"A regular hexagon has a side length of 10 cm. (A regular hexagon can be divided into 6 equilateral triangles with side 10.) What is the area of the hexagon, in square centimeters?","options":["150√3","100√3","300√3","60√3"],"explanation":"Each equilateral triangle has area (√3/4)(10^2) = 25√3, and 6 of them give 150√3. Choice 100√3 forgets one factor by using only 4 triangles or an incorrect coefficient.","skill":"Area of polygon"},{"cat":"geometry","a":1,"q":"A right triangle has an acute angle θ for which tan θ = 8/15. What is the value of cos θ?","options":["8/17","15/17","17/15","15/8"],"explanation":"With opposite = 8 and adjacent = 15, the hypotenuse = √(8^2 + 15^2) = √289 = 17, so cos θ = adjacent/hypotenuse = 15/17. Choice 8/17 is sin θ, using the opposite side instead of the adjacent.","skill":"Right-triangle trig"},{"cat":"information","a":1,"q":"Marine biologist Dr. Ana Reyes studied the tiny crustaceans called copepods, which drift in ocean currents. She observed that during the day, copepods sink to darker, deeper waters, then rise toward the surface at night to feed. Reyes concluded that this daily vertical movement helps the copepods avoid predators that hunt by sight in sunlit waters.\n\nWhich choice best states the main idea of the text?","options":["Copepods are among the most numerous animals drifting in ocean currents worldwide.","Copepods move between deep and shallow water on a daily cycle that likely reduces predation.","Predators that rely on vision are unable to locate any prey in deep ocean waters.","Reyes spent most of her career investigating the feeding habits of ocean crustaceans."],"explanation":"The text centers on the daily up-and-down movement and Reyes's conclusion that it helps copepods avoid sight-hunting predators, which (B) captures. (A) names a detail not actually stated, and (C) overstates the claim into an absolute the text does not make.","skill":"Central ideas and details"},{"cat":"information","a":1,"q":"In her novel, the narrator describes her grandmother's kitchen: \"The room was never quiet. Even when no one spoke, the kettle hummed, the floorboards answered each footstep, and the old clock kept time with a stubborn, uneven tick.\" The narrator adds that she could find her way through that house in total darkness, guided by these sounds alone.\n\nWhat does the text most strongly suggest about the narrator's experience of her grandmother's house?","options":["She found the constant noises in the kitchen irritating and difficult to ignore.","She was familiar enough with the house's sounds to navigate it without sight.","She preferred visiting the kitchen only when her grandmother was cooking there.","She believed the old clock and kettle needed to be repaired or replaced."],"explanation":"The narrator says she could find her way through the house in total darkness guided by the sounds, supporting (B). (A) misreads her attentiveness as annoyance, which the text does not indicate.","skill":"Central ideas and details"},{"cat":"information","a":1,"q":"Historians once assumed that the medieval trading town of Halsford declined suddenly after a single devastating fire in 1340. However, recently uncovered tax records show that the town's population and the volume of goods passing through its market had already been shrinking steadily for nearly forty years before the fire. The records suggest that the fire struck a community whose prosperity was _______\n\nWhich choice most logically completes the text?","options":["increasing rapidly just before the disaster occurred.","already well into a long decline before the fire.","entirely dependent on the safety of its market buildings.","unaffected by changes in regional trade patterns."],"explanation":"The tax records show population and trade shrinking steadily for forty years before the fire, so the town's prosperity was already declining, supporting (B). (A) contradicts the evidence of a steady decline.","skill":"Inferences"},{"cat":"information","a":1,"q":"A research team measured how quickly two groups of office workers completed a sorting task. Workers in Group A worked in a room kept at a steady 21 degrees Celsius, while workers in Group B worked in a room that fluctuated between 17 and 26 degrees. On average, Group A completed the task in 8 minutes, while Group B averaged 11 minutes. The researchers concluded that a stable temperature supports faster task performance.\n\nWhich finding, if true, would most directly support the researchers' conclusion?","options":["Workers in Group B reported feeling slightly more tired at the end of the session.","When Group B later worked at a steady temperature, their average time fell to 8 minutes.","The sorting task was identical for both groups and required no special training.","Group A workers were on average two years older than Group B workers."],"explanation":"If Group B's time dropped to match Group A's once their temperature was stabilized, this directly ties the steady temperature to faster performance, supporting the conclusion (B). (C) controls a variable but does not show that temperature stability caused the speed difference.","skill":"Command of evidence"},{"cat":"information","a":1,"q":"Some plants release airborne chemicals when insects begin chewing on their leaves. Botanist Lia Okafor proposed that these chemicals act as warnings: nearby plants of the same species detect them and begin producing bitter compounds in their own leaves before any insect arrives. If Okafor's hypothesis is correct, then plants positioned downwind of a plant under attack should _______\n\nWhich choice most logically completes the text?","options":["show no change in the chemistry of their leaves.","begin producing bitter compounds sooner than plants placed upwind.","release more airborne chemicals than the plant being eaten.","attract a greater number of insects to their leaves."],"explanation":"If airborne warnings travel on the wind, downwind plants would receive the signal and start making bitter compounds before insects arrive, sooner than upwind plants that never get the signal, supporting (B). (A) contradicts the hypothesis that neighbors respond to the warning.","skill":"Inferences"},{"cat":"information","a":1,"q":"Text 1: Geologist Marcus Hale argues that the deep grooves in the valley's bedrock were carved by a massive glacier that advanced through the region thousands of years ago, smoothing and scratching the rock as it moved.\n\nText 2: Geologist Priya Nair agrees that ice shaped the valley but notes that the grooves run in two distinct directions that meet at sharp angles. She contends that a single advancing glacier could not produce such crossing patterns; instead, at least two separate ice flows, moving at different times, must have carved the rock.\n\nBased on the texts, how would Nair most likely respond to Hale's argument?","options":["By agreeing that a single glacier fully explains all of the grooves in the bedrock.","By arguing that the crossing grooves require more than one episode of ice flow.","By denying that ice played any role in shaping the valley's bedrock.","By proposing that flowing water, not ice, carved the grooves into the rock."],"explanation":"Nair accepts that ice shaped the valley but points to grooves running in two directions that cross at sharp angles, which she says a single glacier could not make, so she would argue for more than one ice flow (B). (D) contradicts her agreement that ice was responsible.","skill":"Cross-text connections"},{"cat":"information","a":1,"q":"When a star much larger than our Sun runs out of fuel, its core collapses and the outer layers are blasted away in an explosion called a supernova. Astronomers value these explosions because the debris they scatter contains heavy elements like iron and gold, which are forged in the extreme heat of the blast. Without supernovae, such elements would be far rarer in the universe, and the planets and living things that depend on them might never have formed.\n\nWhich choice best states the main idea of the text?","options":["Supernovae occur only when stars far smaller than the Sun exhaust their fuel.","Supernovae spread heavy elements that are important for forming planets and life.","Astronomers can predict exactly when a given star will explode as a supernova.","Iron and gold are the only two elements ever produced inside collapsing stars."],"explanation":"The text's central point is that supernovae forge and scatter heavy elements essential for planets and life, which (B) states. (A) reverses the text's statement that the stars are larger than the Sun.","skill":"Central ideas and details"},{"cat":"information","a":1,"q":"Anthropologist Dev Sharma studied a community of weavers who pass their craft from one generation to the next without written instructions. He noticed that apprentices spend their first year doing nothing but watching skilled weavers, never touching a loom. Sharma suggests that this long period of observation _______\n\nWhich choice most logically completes the text?","options":["prevents apprentices from ever mastering the craft of weaving.","lets apprentices absorb techniques before they attempt to weave themselves.","indicates that the community no longer values its traditional skills.","shows that written instructions would make the apprenticeship unnecessary."],"explanation":"A year of watching skilled weavers before touching a loom most plausibly lets apprentices absorb techniques first, supporting (B). (A) contradicts the idea that the watching period is part of how the craft is successfully passed down.","skill":"Inferences"},{"cat":"information","a":1,"q":"In the short story, Mr. Adler refuses to sell the small bookshop he has run for fifty years, even as developers offer him more money each month. \"A building can be rebuilt,\" he tells his daughter, \"but the people who meet here, who argue over poetry and lend one another umbrellas in the rain, cannot simply be relocated.\" He gestures at the worn chairs where regulars gather every afternoon.\n\nWhat does the text most strongly suggest about Mr. Adler's reason for keeping the shop?","options":["He believes the building itself is too valuable to be sold to developers.","He values the community that has formed around the shop more than money.","He expects the developers to eventually raise their offer to a fair amount.","He hopes his daughter will take over the business after he retires."],"explanation":"Adler contrasts a replaceable building with the irreplaceable community of people who gather there, showing he values that community over money, supporting (B). (A) is contradicted by his line that a building can be rebuilt.","skill":"Central ideas and details"},{"cat":"information","a":1,"q":"A team of economists examined whether offering small cash rewards would increase how often residents recycled. In one neighborhood, residents earned a small payment for each bag of recyclables; in a comparable neighborhood, residents received only printed reminders. Recycling rose sharply in the paid neighborhood at first but, after the payments ended, fell below the level seen in the reminder-only neighborhood. The economists concluded that cash rewards can undermine long-term recycling habits.\n\nWhich choice best describes data that would support the economists' conclusion?","options":["Data showing the paid neighborhood recycled more than the reminder neighborhood at every point.","Data showing that once payments stopped, the paid neighborhood recycled less than the reminder one.","Data showing both neighborhoods recycled at identical rates throughout the entire study.","Data showing the reminder neighborhood produced more total waste than the paid neighborhood."],"explanation":"The conclusion is that cash rewards undermine long-term habits, which is supported by data showing that after payments stopped the paid neighborhood fell below the reminder one (B). (A) would contradict the conclusion about long-term harm.","skill":"Command of evidence"},{"cat":"information","a":1,"q":"Engineers designing a new footbridge worried that crowds of pedestrians might unintentionally cause it to sway. They discovered that when many people walk across a slightly swaying bridge, they instinctively adjust their steps to match its motion, which makes the swaying grow stronger. To keep the bridge stable, the engineers concluded that they would need to _______\n\nWhich choice most logically completes the text?","options":["encourage as many pedestrians as possible to cross the bridge at once.","add devices that absorb motion so the bridge cannot begin to sway noticeably.","require all pedestrians to walk across the bridge in perfect unison.","make the bridge surface as smooth and slippery as they possibly could."],"explanation":"Since swaying grows when walkers sync to existing motion, preventing the bridge from swaying noticeably in the first place breaks that cycle, supporting (B). (C) would worsen the problem by increasing synchronized stepping.","skill":"Inferences"},{"cat":"information","a":1,"q":"Botanists have long known that some desert plants flower only after heavy rains. A recent study of one such plant found that seeds buried in the soil contain a chemical coating that dissolves only when soaked by a large amount of water, after which the seeds can sprout. The researchers suggested that this coating ensures the seeds germinate only when _______\n\nWhich choice most logically completes the text?","options":["the surrounding soil contains very little moisture.","enough rain has fallen to support the young plants' growth.","the seeds have been buried for less than a single day.","other plants of the same species have already died."],"explanation":"The coating dissolves only after a large soaking, so germination is delayed until substantial rain has fallen, which would support the seedlings, supporting (B). (A) contradicts the requirement that lots of water is needed.","skill":"Inferences"},{"cat":"information","a":0,"q":"A museum studied how long visitors lingered in front of paintings. It found that when a short, plainly written description was placed beside a work, visitors spent on average 40 seconds looking at it; when a longer, more technical description was used instead, the average dropped to 22 seconds. The museum concluded that brief, accessible descriptions encourage visitors to engage more closely with the art.\n\nWhich choice most effectively uses data from the text to support the museum's conclusion?","options":["Visitors spent about 18 seconds longer at works with short, plainly written descriptions.","Visitors read the longer technical descriptions more carefully than the brief ones.","The museum displayed roughly the same number of paintings in each part of the study.","Most visitors preferred paintings to sculptures during their time in the museum."],"explanation":"The 40-second versus 22-second figures show visitors lingered about 18 seconds longer with short descriptions, directly using the data to support the conclusion (A). (B) introduces a claim about reading that the data do not measure.","skill":"Command of evidence"},{"cat":"information","a":1,"q":"The poet writes of an abandoned orchard: \"No hand prunes these branches now, / yet the apples come, smaller each year, / sweet and unbidden, / falling where no basket waits.\" The lines describe trees that continue to bear fruit long after the people who planted them have gone.\n\nWhich choice best states the main idea of these lines?","options":["The orchard's trees have stopped producing any fruit since being abandoned.","The trees keep producing fruit despite no longer being cared for by people.","The poet plans to return and harvest the apples before they fall.","The apples have grown larger and sweeter without human interference."],"explanation":"The lines emphasize that the apples still come though no hand prunes the branches and no basket waits, so the trees bear fruit despite being uncared for (B). (D) contradicts the line noting the apples grow smaller each year.","skill":"Central ideas and details"},{"cat":"information","a":1,"q":"Sociologist Tomas Vega surveyed adults who had recently moved to a new city. He found that those who joined at least one local club or volunteer group within their first month reported feeling settled far sooner than those who did not. Vega argues that early participation in community groups speeds newcomers' sense of belonging.\n\nWhich finding, if true, would most strengthen Vega's argument?","options":["Newcomers who joined groups later than one month also eventually felt settled.","Among newcomers with similar backgrounds, only those who joined groups early felt settled quickly.","Many newcomers reported that finding affordable housing was their greatest challenge.","Some clubs in the city had been operating for more than several decades."],"explanation":"Showing that, among otherwise similar newcomers, only the early joiners felt settled quickly isolates early participation as the factor, strengthening Vega's claim (B). (A) is consistent but does not strengthen the point about early participation being faster.","skill":"Command of evidence"},{"cat":"information","a":0,"q":"Honeybees returning to the hive perform a looping \"waggle dance\" whose direction and duration tell other bees where to find flowers. Researchers noticed that when a food source was very close to the hive, returning bees skipped the directional part of the dance entirely and simply buzzed in tight circles. This suggests that the detailed directional dance is most useful when food is _______\n\nWhich choice most logically completes the text?","options":["located far enough away that other bees need guidance to find it.","so close to the hive that direction makes no difference to the bees.","of a kind that other bees in the hive have never encountered.","available in such small amounts that few bees can use it."],"explanation":"Bees drop the directional dance for nearby food and use it otherwise, so the directional dance is most useful when food is far enough that direction matters (A). (B) describes exactly the case where bees omit the directional dance.","skill":"Inferences"},{"cat":"information","a":1,"q":"A health clinic tested two ways of reminding patients about appointments. Patients who received a phone call the day before missed 12 percent of their appointments, while patients who received only a text message missed 19 percent. Patients who received both a call and a text missed just 7 percent. The clinic concluded that combining reminders is more effective than using either method alone.\n\nWhich choice most effectively uses data from the text to support the clinic's conclusion?","options":["Patients who received only a text message missed nearly one in five appointments.","Patients who received both reminders missed fewer appointments than those who received only one.","Patients who received a phone call missed more appointments than those who received a text.","The clinic offered three separate reminder methods to different groups of patients."],"explanation":"The 7 percent miss rate for both reminders is lower than either the 12 percent or 19 percent for single methods, so (B) uses the data to support that combining is most effective. (A) reports a true figure but does not address the comparison central to the conclusion.","skill":"Command of evidence"},{"cat":"information","a":1,"q":"When the Roman Empire built a network of paved roads across its territory, the roads were intended mainly to move soldiers quickly between provinces. Over time, however, merchants began using the same roads to carry goods, and travelers used them to spread news and ideas. Historians note that the roads ended up shaping commerce and culture far beyond their original military purpose.\n\nWhich choice best states the main idea of the text?","options":["Roman roads were poorly built and often failed to serve the army's needs.","Roman roads, built for the military, came to influence trade and culture as well.","Roman merchants opposed the army's use of the empire's paved roads.","Roman travelers preferred unpaved paths to the empire's official roads."],"explanation":"The text says the roads were built for soldiers but ended up shaping commerce and culture beyond that purpose, which (B) captures. (A) contradicts the text's emphasis on the roads' wide usefulness.","skill":"Central ideas and details"},{"cat":"information","a":0,"q":"Paleontologist Rosa Imani examined fossilized footprints left by a large plant-eating dinosaur. She measured the distance between successive prints and found it was unusually short relative to the animal's leg length. Comparing this with how living animals move, Imani inferred that this dinosaur was most likely _______\n\nWhich choice most logically completes the text?","options":["moving at a slow walk rather than running quickly.","swimming across a deep lake at the time.","considerably smaller than its footprints indicate.","hunting other dinosaurs for its food."],"explanation":"A short stride relative to leg length, as seen in living animals, indicates slow movement, so Imani would infer a slow walk (A). (D) is unsupported and also contradicts the description of the animal as a plant-eater.","skill":"Inferences"},{"cat":"information","a":1,"q":"Text 1: Education researcher Hana Kim found that students who handwrote their notes scored higher on later tests of conceptual understanding than students who typed their notes. She argued that the slower pace of handwriting forces students to summarize ideas in their own words.\n\nText 2: Researcher Leo Brandt replicated the study but allowed typing students extra time to review and rewrite their notes afterward. With this added step, the typing students scored just as well as the handwriting students. Brandt concluded that it is the act of summarizing, not the method of writing, that improves understanding.\n\nBased on the texts, Brandt's findings suggest that Kim's conclusion was","options":["entirely mistaken, since note-taking method has no effect on understanding at all.","partly right about summarizing but wrong to credit handwriting specifically.","fully confirmed, because handwriting students always outperform typing students.","irrelevant, because neither group of students actually improved their test scores."],"explanation":"Brandt agrees summarizing helps but shows typing students who summarize do just as well, so handwriting itself is not the key, making Kim partly right but wrong to credit handwriting (B). (A) overstates by denying any effect of summarizing, which Brandt actually endorses.","skill":"Cross-text connections"},{"cat":"information","a":1,"q":"A coastal town installed artificial reefs made of sunken concrete structures to see whether they would attract fish. Within two years, divers counted three times as many fish species around the artificial reefs as around nearby bare seafloor. Officials proposed expanding the program, claiming the reefs increase the total fish population in the area.\n\nWhich finding, if true, would most weaken the officials' claim?","options":["The artificial reefs cost less to build than the town had originally budgeted.","Fish simply relocated to the reefs from surrounding waters, leaving the area's total unchanged.","Divers found the artificial reefs easier to survey than the bare seafloor.","Some fish species near the reefs were more colorful than those on bare seafloor."],"explanation":"If fish merely moved to the reefs from nearby waters without any rise in the overall total, then the reefs did not increase the population, weakening the claim (B). (A) concerns cost, which is irrelevant to whether the population grew.","skill":"Command of evidence"},{"cat":"information","a":1,"q":"The essayist reflects on learning a second language as an adult: \"At first every sentence was a wall I climbed word by word. Then one morning I caught myself dreaming in the new tongue, the grammar arriving unbidden, and I understood that the language had stopped being something I did and become something I was.\"\n\nWhat does the text most strongly suggest about the essayist's relationship to the second language over time?","options":["The essayist gave up trying to learn the language after early struggles.","The language shifted from a conscious effort to a natural part of the self.","The essayist found the new language easier than their first language.","The essayist learned the language only in order to interpret dreams."],"explanation":"The essayist contrasts early effortful climbing with dreaming in the language and says it became something they were rather than did, showing a shift from effort to a natural part of self (B). (A) contradicts the description of eventual fluency.","skill":"Central ideas and details"},{"cat":"information","a":1,"q":"Researchers studied a species of ant that farms fungus for food inside its nest. They observed that when a harmful mold threatened the fungus, certain worker ants applied a substance from glands on their bodies that slowed the mold's growth. The researchers proposed that these ants protect their food supply by producing their own antifungal chemicals. If this proposal is correct, then removing those glands from the worker ants should _______\n\nWhich choice most logically completes the text?","options":["have no effect on how well the nest's fungus survives.","make the nest's fungus more vulnerable to harmful mold.","cause the ants to abandon farming fungus altogether.","increase the amount of food the colony is able to store."],"explanation":"If the gland substance protects the fungus from mold, removing the glands should leave the fungus more vulnerable, supporting (B). (A) contradicts the proposal that the chemicals provide protection.","skill":"Inferences"},{"cat":"information","a":0,"q":"A streaming service tested two layouts for its home screen. Users shown a layout that displayed only six recommended titles spent more time actually watching shows than users shown a layout displaying thirty titles at once. The company concluded that presenting fewer options helps users settle on something to watch more quickly.\n\nWhich finding, if true, would most strengthen the company's conclusion?","options":["Users shown thirty titles scrolled through the menu far longer before choosing anything.","Both layouts featured the same popular titles near the top of the screen.","Users shown six titles reported that the service's interface looked modern.","The company had spent considerable money developing both home-screen layouts."],"explanation":"If users with thirty titles spent much longer scrolling before choosing, that shows more options slowed their decision, strengthening the claim that fewer options help users settle faster (A). (B) controls a variable but does not show the number of options affected decision speed.","skill":"Command of evidence"},{"cat":"information","a":0,"q":"Volcanologists monitoring a remote volcano recorded a steady rise in the number of small earthquakes beneath it over several weeks, along with a slight swelling of the ground surface. Both signs, they noted, often appear when molten rock is moving upward inside a volcano. On the basis of these observations, the scientists warned that the volcano was _______\n\nWhich choice most logically completes the text?","options":["showing signs that an eruption could be approaching.","certain never to erupt again in the future.","slowly cooling and becoming completely inactive.","unaffected by any movement of molten rock below."],"explanation":"Rising earthquakes and ground swelling are described as signs of molten rock moving upward, so the scientists would warn that an eruption could be approaching (A). (C) contradicts the evidence of magma rising rather than the volcano cooling.","skill":"Inferences"},{"cat":"information","a":1,"q":"In a survey of small-business owners, 64 percent of those who had taken a basic accounting course said they felt confident managing their company's finances, compared with only 29 percent of those who had not taken such a course. A business advisor cited these figures to argue that accounting training boosts owners' financial confidence.\n\nWhich choice most effectively uses data from the text to support the advisor's argument?","options":["A majority of owners surveyed had at some point taken a basic accounting course.","Owners who had taken the course were more than twice as likely to feel confident.","About 29 percent of owners without the course still felt confident managing finances.","Most owners agreed that managing finances was an important part of running a business."],"explanation":"64 percent versus 29 percent means course-takers were more than twice as likely to feel confident, directly using the data to support the advisor (B). (C) reports a real figure but, taken alone, does not show the course made a difference.","skill":"Command of evidence"},{"cat":"information","a":1,"q":"In the novel, Captain Ruiz orders her crew to turn the ship back toward port despite being only a day from their destination. The storm clouds gathering ahead, she explains, are the kind that have swallowed better ships than hers. \"I would rather lose a week,\" she says quietly, \"than lose a single one of you to my pride.\"\n\nWhat does the text most strongly suggest about Captain Ruiz's decision?","options":["She turns back because she doubts the crew's ability to sail the ship.","She prioritizes her crew's safety over reaching the destination on time.","She is certain the gathering storm clouds pose no real danger.","She hopes to reach a different port that is closer than the original."],"explanation":"Ruiz turns back to avoid a dangerous storm, saying she would rather lose a week than lose a crew member to her pride, showing she values their safety over arriving on time (B). (C) contradicts her view that the clouds have swallowed better ships.","skill":"Central ideas and details"},{"cat":"information","a":1,"q":"Ecologists reintroduced beavers to a stretch of river where they had been absent for a century. Within a few years, the dams the beavers built created ponds that slowed the water, and the number of frog and fish species in the area rose noticeably. The ecologists concluded that beaver activity can increase the variety of life along a river.\n\nWhich finding, if true, would most strengthen the ecologists' conclusion?","options":["The beavers built more dams in their second year than in their first year.","Comparable river stretches without beavers showed no such rise in species variety.","Local residents found the new ponds pleasant places to walk beside.","The reintroduced beavers came from a population living in a distant region."],"explanation":"If similar river stretches lacking beavers showed no rise in species variety, the contrast ties the increase to beaver activity, strengthening the conclusion (B). (A) describes beaver behavior but does not link it to greater biodiversity.","skill":"Command of evidence"},{"cat":"information","a":0,"q":"Archaeologists excavating an ancient settlement found that its houses were built around a large central courtyard with a shared well, and that the smaller rooms used for storing grain opened onto this courtyard rather than into individual homes. From this layout, the researchers inferred that the settlement's residents most likely _______\n\nWhich choice most logically completes the text?","options":["stored and shared their food resources as a community rather than privately.","lived in constant conflict with their immediate neighbors.","abandoned the settlement shortly after the houses were built.","obtained all of their drinking water from a distant river."],"explanation":"Grain-storage rooms opening onto a shared courtyard with a common well point to communal storage and sharing of food, supporting (A). (D) contradicts the presence of a shared well at the center of the settlement.","skill":"Inferences"},{"cat":"information","a":0,"q":"A library compared book checkouts before and after it began displaying staff-written recommendation cards on certain shelves. Books with a recommendation card were checked out an average of 14 times over three months, while similar books without cards averaged 5 checkouts in the same period. The library concluded that the recommendation cards encouraged patrons to borrow the featured books.\n\nWhich choice most effectively uses data from the text to support the library's conclusion?","options":["Books with recommendation cards were checked out nearly three times as often as those without.","The library added recommendation cards to several shelves throughout the building.","Books without recommendation cards were still checked out at least a few times.","Patrons generally spent more time browsing shelves that had recommendation cards."],"explanation":"14 versus 5 checkouts means carded books were borrowed nearly three times as often, directly using the data to support that the cards encouraged borrowing (A). (C) cites a true detail that does not demonstrate the cards' effect.","skill":"Command of evidence"},{"cat":"craft","a":1,"q":"The new bridge was designed to be ______; engineers expected it to remain standing and fully functional for at least a century. Which choice completes the text with the most logical and precise word?","options":["temporary","durable","decorative","narrow"],"explanation":"\"Durable\" fits because the bridge is meant to last a century. \"Temporary\" is the opposite of lasting, and \"decorative\" and \"narrow\" do not address longevity.","skill":"Words in context"},{"cat":"craft","a":1,"q":"Although the report was lengthy, its central argument was remarkably ______, summarized clearly in a single sentence near the top of the first page. Which choice completes the text with the most logical and precise word?","options":["confusing","concise","verbose","hidden"],"explanation":"\"Concise\" matches an argument summarized clearly in one sentence. \"Verbose\" means wordy, the opposite of what a single-sentence summary implies.","skill":"Words in context"},{"cat":"craft","a":0,"q":"Critics praised the novelist's ______ prose, noting that she could convey complex emotions using only a handful of carefully chosen words. Which choice completes the text with the most logical and precise word?","options":["spare","ornate","careless","lengthy"],"explanation":"\"Spare\" means economical and stripped down, matching \"a handful of carefully chosen words.\" \"Ornate\" suggests elaborate decoration, contradicting the description.","skill":"Words in context"},{"cat":"craft","a":0,"q":"The committee's decision was not ______: members debated for weeks and several still disagreed even after the final vote. Which choice completes the text with the most logical and precise word?","options":["unanimous","expensive","temporary","public"],"explanation":"\"Unanimous\" means agreed by all, which the weeks of debate and lingering disagreement contradict. The other words do not relate to the lack of agreement described.","skill":"Words in context"},{"cat":"craft","a":1,"q":"As used in the following sentence, what does \"check\" most nearly mean? \"The dam was built to check the river's flow during the rainy season, preventing the floods that had once destroyed nearby farms.\"","options":["inspect","restrain","verify","mark"],"explanation":"Here \"check\" means to restrain or hold back, since the dam controls the river to prevent floods. \"Inspect\" and \"verify\" describe examination, which the context does not support.","skill":"Words in context"},{"cat":"craft","a":1,"q":"Many farmers resisted the new irrigation method at first, but as yields rose, even the most ______ skeptics began to adopt it. Which choice completes the text with the most logical and precise word?","options":["enthusiastic","obstinate","fleeting","generous"],"explanation":"\"Obstinate\" (stubborn) intensifies \"skeptics\" who resisted, fitting the contrast with eventual adoption. \"Enthusiastic\" contradicts the idea of skeptics resisting.","skill":"Words in context"},{"cat":"craft","a":1,"q":"The scientist's claim was met with ______ from her peers, who demanded far more evidence before they would even consider it plausible. Which choice completes the text with the most logical and precise word?","options":["acceptance","skepticism","indifference","celebration"],"explanation":"\"Skepticism\" matches peers demanding more evidence before believing the claim. \"Acceptance\" and \"celebration\" contradict their resistance, and \"indifference\" ignores their active demand for proof.","skill":"Words in context"},{"cat":"craft","a":0,"q":"Because the instructions were so ______, even the new employees, who had never used the software before, completed the setup without assistance. Which choice completes the text with the most logical and precise word?","options":["lucid","ambiguous","technical","lengthy"],"explanation":"\"Lucid\" means clear and easy to understand, explaining why inexperienced employees succeeded alone. \"Ambiguous\" means unclear, which would make independent success unlikely.","skill":"Words in context"},{"cat":"craft","a":1,"q":"As used in the following sentence, what does \"yields\" most nearly mean? \"Under heavy pressure, the soft metal yields, bending into whatever shape the press demands.\"","options":["produces","surrenders","profits","announces"],"explanation":"Here \"yields\" means gives way or surrenders to pressure, since the metal bends. \"Produces\" and \"profits\" are common meanings of \"yield\" but do not fit the physical bending described.","skill":"Words in context"},{"cat":"craft","a":1,"q":"The mayor's speech was deliberately ______, leaving room for multiple interpretations so that no single group of voters would feel excluded. Which choice completes the text with the most logical and precise word?","options":["blunt","vague","hostile","detailed"],"explanation":"\"Vague\" allows multiple interpretations, matching the goal of not excluding any group. \"Blunt\" and \"detailed\" imply precision, the opposite of leaving room for interpretation.","skill":"Words in context"},{"cat":"craft","a":1,"q":"Although she had every reason to be bitter, the retired teacher remained ______ about her years in an underfunded school, focusing on the students she had helped rather than on the hardships. Which choice completes the text with the most logical and precise word?","options":["resentful","sanguine","indifferent","evasive"],"explanation":"\"Sanguine\" means cheerfully optimistic, fitting the contrast with bitterness and her focus on the positive. \"Resentful\" contradicts the \"although\" structure signaling a positive attitude.","skill":"Words in context"},{"cat":"craft","a":1,"q":"The historian's account was praised for being ______: rather than favoring one side, it presented the strengths and weaknesses of every party in the conflict. Which choice completes the text with the most logical and precise word?","options":["partisan","evenhanded","superficial","outdated"],"explanation":"\"Evenhanded\" means fair and balanced, matching the account that favors no side. \"Partisan\" means biased toward one side, the opposite of the description.","skill":"Words in context"},{"cat":"craft","a":2,"q":"What is the main purpose of the following text? \"For centuries, sailors navigated using the stars, a method that demanded clear skies and years of training. Today, satellite systems can pinpoint a ship's location within meters, regardless of weather. Yet some maritime academies still teach celestial navigation, arguing that a captain should never depend entirely on technology that can fail.\"","options":["To argue that satellite navigation is unreliable in bad weather","To trace the complete history of maritime navigation methods","To explain a shift in navigation and a reason an older method persists","To criticize maritime academies for teaching outdated techniques"],"explanation":"The text describes the move from stars to satellites and explains why academies still teach the old method. It neither argues satellites are unreliable nor criticizes academies, so those purposes are too narrow or contrary.","skill":"Text structure and purpose"},{"cat":"craft","a":0,"q":"Which choice best describes the overall structure of the following text? \"The factory's emissions seemed to drop sharply after the new filters were installed. Closer analysis, however, revealed that production had simply slowed that month. Once output returned to normal levels, emissions climbed back to where they had been before.\"","options":["It presents an apparent result, then complicates it with further evidence.","It lists several unrelated facts about a factory's operations.","It describes a problem and proposes a detailed solution.","It compares two factories with different environmental records."],"explanation":"The text states an apparent improvement, then uses \"however\" to reveal the real cause, complicating the initial reading. There is no proposed solution or comparison of two factories.","skill":"Text structure and purpose"},{"cat":"craft","a":1,"q":"What is the function of the underlined sentence in the overall structure of the text? \"Coral reefs support roughly a quarter of all marine species. (underlined: This staggering diversity exists despite the fact that reefs occupy less than one percent of the ocean floor.) Such concentration makes their decline especially alarming to biologists.\"","options":["It offers a solution to the problem the text raises.","It emphasizes the reefs' importance by contrasting their tiny size with their huge biodiversity.","It questions whether reefs truly support so many species.","It introduces an unrelated fact about the ocean floor."],"explanation":"The sentence highlights significance by contrasting small area (under one percent) with large diversity. It does not offer a solution, cast doubt, or introduce an unrelated fact.","skill":"Text structure and purpose"},{"cat":"craft","a":0,"q":"Which choice best states the main purpose of the following text? \"When the painting was first displayed, critics dismissed its blurred edges as evidence of carelessness. Decades later, the same technique was hailed as a deliberate innovation that captured the fleeting quality of light. The artist's reputation, once tarnished, was entirely restored.\"","options":["To explain how a once-criticized technique came to be celebrated","To describe the proper way to paint the effects of light","To argue that critics should never judge new artwork","To compare two different painters of the same era"],"explanation":"The text traces how the blurred-edge technique moved from dismissal to praise, restoring the artist's reputation. It does not give painting instructions or compare two painters.","skill":"Text structure and purpose"},{"cat":"craft","a":1,"q":"What is the function of the quoted phrase in the following text? \"The startup's founders called their product 'a phone for people who hate phones.' This paradoxical slogan, far from confusing buyers, intrigued them, and preorders quickly exceeded expectations.\"","options":["It provides a technical specification of the product.","It captures the contradictory appeal that the next sentence explains drew customers in.","It criticizes customers who dislike their phones.","It summarizes the founders' financial projections."],"explanation":"The quoted slogan is paradoxical, and the following sentence explains it intrigued buyers, so it captures the product's contradictory appeal. It is neither a technical spec nor a financial projection.","skill":"Text structure and purpose"},{"cat":"craft","a":1,"q":"Which choice best describes the overall structure of the following text? \"At first glance, the abandoned lot looked worthless. The soil was poor, the fences were broken, and weeds had taken over. But to the urban gardeners who claimed it, each of these flaws was an opportunity: poor soil could be enriched, fences mended, and weeds cleared to make room for vegetables.\"","options":["It defines a term and then provides several examples of it.","It presents a negative impression and then reinterprets the same details positively.","It narrates events in the order they occurred over many years.","It weighs the costs and benefits of a financial decision."],"explanation":"The text lists flaws, then reframes each as an opportunity, reinterpreting the same details. It is not a definition with examples nor a chronological narrative.","skill":"Text structure and purpose"},{"cat":"craft","a":1,"q":"What is the main rhetorical purpose of the following text? \"You have surely felt it: that moment when a song you have not heard in years suddenly fills you with the emotions of your youth. Scientists are only beginning to map how memory and music intertwine, but the experience itself needs no scientific proof.\"","options":["To report the complete findings of a scientific study on memory","To draw readers in with a shared experience before noting the science is incomplete","To dismiss scientific research as unnecessary for understanding music","To instruct readers on how to improve their memory using music"],"explanation":"The text opens with a relatable experience to engage readers, then notes the science is still emerging. It does not report complete findings or give instructions.","skill":"Text structure and purpose"},{"cat":"craft","a":1,"q":"What is the function of the underlined sentence in the text? \"Many assume that bamboo is a kind of tree because of its height and woody stalks. (underlined: In fact, bamboo is a grass, more closely related to wheat than to oak.) This classification explains its astonishing growth rate, since grasses regrow far faster than trees.\"","options":["It restates the common assumption mentioned in the first sentence.","It corrects a common misconception and sets up the explanation that follows.","It provides statistics on how tall bamboo can grow.","It questions whether bamboo grows quickly at all."],"explanation":"The sentence corrects the misconception that bamboo is a tree and enables the next sentence's explanation of its growth rate. It does not restate the assumption or provide statistics.","skill":"Text structure and purpose"},{"cat":"craft","a":0,"q":"Which choice best describes the overall structure of the following text? \"The experiment produced a surprising result. To rule out error, the team repeated it three times under identical conditions. Each trial confirmed the original finding. Only then did the researchers feel confident enough to publish.\"","options":["It describes a result and the steps taken to confirm it before publication.","It argues that the experiment should never have been published.","It lists the equipment used in a laboratory procedure.","It contrasts the views of two competing research teams."],"explanation":"The text presents a surprising result and the verification steps leading to publication. It neither argues against publishing nor contrasts two teams.","skill":"Text structure and purpose"},{"cat":"craft","a":1,"q":"What is the function of the underlined sentence in the text? \"The committee had prepared for weeks, rehearsing answers to every question they could imagine. (underlined: Yet the one question that derailed them was the simplest of all.) When asked why the project mattered, no member could give a clear reply.\"","options":["It summarizes the committee's thorough preparation.","It introduces an ironic turn that the final sentence then illustrates.","It lists the questions the committee had rehearsed.","It praises the committee for its careful planning."],"explanation":"The sentence sets up irony (extensive prep undone by the simplest question), which the final sentence illustrates. It does not summarize preparation or list rehearsed questions.","skill":"Text structure and purpose"},{"cat":"craft","a":1,"q":"Text 1: Researchers studying productivity argue that frequent short breaks improve focus. Their data show that workers who paused briefly every hour completed tasks more accurately than those who worked straight through. Text 2: A separate team cautions that breaks can backfire when they involve switching to unrelated screens. Stepping away to scroll a phone, they found, often left workers more distracted than before. Based on the texts, how would the authors of Text 2 most likely respond to the finding described in Text 1?","options":["By denying that breaks have any effect on worker accuracy","By agreeing that breaks can help but noting that their content matters","By insisting that workers should never pause during tasks","By claiming that accuracy is unrelated to focus"],"explanation":"Text 2 does not reject breaks; it qualifies them, warning that screen-switching breaks distract. So its authors would accept that breaks can help while stressing what the break involves. They do not deny breaks entirely.","skill":"Cross-text connections"},{"cat":"craft","a":1,"q":"Text 1: Some economists maintain that raising the minimum wage inevitably reduces the number of available jobs, as employers cut positions to control costs. Text 2: Recent studies of cities that raised their minimum wage found little change in overall employment; some businesses absorbed costs through modestly higher prices instead of layoffs. Based on the texts, the authors of Text 2 would most likely argue that the claim in Text 1 is:","options":["fully confirmed by their findings","not supported by the evidence they gathered","irrelevant to the question of wages","too cautious in its predictions"],"explanation":"Text 2's studies found little employment change, undercutting Text 1's claim that higher wages inevitably cut jobs. The authors would therefore see Text 1 as unsupported, not confirmed.","skill":"Cross-text connections"},{"cat":"craft","a":2,"q":"Text 1: The author argues that solitude is essential for creativity, citing famous writers who produced their best work in isolation. Text 2: While acknowledging that quiet time aids concentration, this author emphasizes that many breakthroughs emerge from collaboration, when one person's idea sparks another's. Which choice best describes the relationship between the two texts?","options":["Text 2 completely rejects the premise of Text 1.","Text 2 restates Text 1's argument using different examples.","Text 2 accepts part of Text 1's view but stresses a factor Text 1 overlooks.","Text 2 provides evidence that directly proves Text 1 correct."],"explanation":"Text 2 grants that quiet time helps (partial agreement) but highlights collaboration, which Text 1 ignores. It neither fully rejects nor restates Text 1.","skill":"Cross-text connections"},{"cat":"craft","a":1,"q":"Text 1: A nutritionist claims that eating late at night causes weight gain because the body stores more fat when at rest. Text 2: Other researchers contend that total daily calories, not their timing, determine weight gain; in their trials, late eaters and early eaters who consumed the same amount gained identical weight. Based on the texts, how would the authors of Text 2 most likely characterize the explanation in Text 1?","options":["As correct but incomplete","As mistaken about the cause of weight gain","As supported by their own trials","As impossible to test scientifically"],"explanation":"Text 2's trials show timing did not matter when calories were equal, so its authors would view Text 1's timing-based cause as mistaken. They would not call it correct or supported.","skill":"Cross-text connections"},{"cat":"craft","a":1,"q":"Text 1: Defenders of standardized testing argue that the exams provide an objective measure that lets colleges compare applicants from very different schools fairly. Text 2: Critics respond that test scores correlate strongly with family income, meaning the exams may measure access to expensive preparation as much as genuine ability. Based on the texts, the authors of Text 2 would most likely respond to Text 1's claim of objectivity by:","options":["agreeing that the tests are entirely free of bias","questioning whether the scores reflect ability rather than wealth","proposing that colleges weigh the tests even more heavily","denying that schools differ from one another at all"],"explanation":"Text 2 links scores to income, challenging the idea that tests are objective measures of ability. Its authors would question what the scores actually reflect, not affirm the tests' fairness.","skill":"Cross-text connections"},{"cat":"craft","a":1,"q":"Text 1: One archaeologist asserts that the ancient settlement was abandoned suddenly, pointing to meals left half-eaten and tools dropped where they lay. Text 2: Another scholar notes that such scenes can also result from a gradual departure, since people leaving slowly often abandon worn tools and spoiled food they no longer value. Based on the texts, the author of Text 2 would most likely say that the evidence in Text 1:","options":["proves conclusively that the departure was sudden","could be explained by a slower departure as well","shows the settlement was never actually inhabited","is irrelevant to determining when the site was abandoned"],"explanation":"Text 2 offers an alternative reading of the same clues, suggesting a gradual departure could produce them too. So its author sees Text 1's evidence as not conclusive, not as irrelevant.","skill":"Cross-text connections"},{"cat":"craft","a":0,"q":"Text 1: A literary scholar praises the poem's irregular rhythm, arguing that its stumbling meter mirrors the speaker's emotional turmoil. Text 2: Another scholar suggests the irregular rhythm reflects nothing deliberate, attributing it instead to the conventions of the period, when strict meter was simply going out of fashion. Which choice best describes how Text 2 relates to Text 1?","options":["It offers a competing explanation for the same feature Text 1 discusses.","It denies that the poem has an irregular rhythm.","It praises the poem for entirely different reasons.","It provides additional support for Text 1's interpretation."],"explanation":"Both texts address the irregular rhythm, but Text 2 attributes it to period conventions rather than emotional meaning, an alternative explanation. It does not deny the rhythm or support Text 1.","skill":"Cross-text connections"},{"cat":"craft","a":1,"q":"Text 1: Advocates of remote work argue it boosts employee satisfaction by eliminating long commutes and granting workers control over their schedules. Text 2: Some managers warn that without in-person contact, newer employees miss the informal mentoring that happens in hallways and break rooms, slowing their professional growth. Based on the texts, the managers in Text 2 would most likely add which qualification to the argument in Text 1?","options":["Remote work harms experienced and new employees equally.","The benefits of remote work may come at a cost to newer workers' development.","Employee satisfaction is irrelevant to a company's success.","Long commutes are actually beneficial for professional growth."],"explanation":"Text 2 does not reject remote work's benefits but flags a downside for newer workers' growth, qualifying Text 1. It does not claim all employees are harmed equally or that commutes help.","skill":"Cross-text connections"},{"cat":"craft","a":0,"q":"Text 1: A psychologist contends that rewards are the most effective way to encourage children to read, since prizes motivate kids to pick up books they would otherwise ignore. Text 2: Another psychologist warns that once rewards stop, so does the reading; children come to value the prize rather than the book, and their interest fades without external incentives. Based on the texts, how would the author of Text 2 most likely evaluate the strategy endorsed in Text 1?","options":["As effective only in the short term, with a hidden long-term drawback","As the single best method for fostering lifelong reading","As completely ineffective at getting children to read","As irrelevant because children dislike all rewards"],"explanation":"Text 2 concedes rewards get kids reading initially but warns interest fades when rewards end, a long-term drawback. So its author sees the strategy as short-term effective but flawed, not wholly ineffective.","skill":"Cross-text connections"},{"cat":"craft","a":1,"q":"The diplomat was known for her ______ remarks, which managed to soothe tempers on both sides without conceding anything of substance. Which choice completes the text with the most logical and precise word?","options":["inflammatory","tactful","careless","boastful"],"explanation":"\"Tactful\" means sensitive and diplomatic, fitting remarks that soothe both sides. \"Inflammatory\" means provoking anger, the opposite of soothing tempers.","skill":"Words in context"},{"cat":"expression","a":0,"q":"While researching a topic, a student has taken the following notes:\n- Tardigrades are tiny aquatic animals, often less than a millimeter long.\n- They can survive extreme cold, extreme heat, and the vacuum of space.\n- To endure harsh conditions, they enter a dormant state called cryptobiosis.\n- In cryptobiosis, their metabolism slows to near zero.\n- Scientists study tardigrades to learn how cells can be preserved.\nThe student wants to introduce tardigrades to an audience unfamiliar with them. Which choice most effectively uses the notes to accomplish this goal?","options":["Tardigrades are tiny aquatic animals, often less than a millimeter long, that can survive extreme conditions.","In cryptobiosis, the metabolism of a tardigrade slows to near zero.","Scientists study tardigrades to learn how cells can be preserved.","Tardigrades enter a dormant state, called cryptobiosis, when conditions become harsh."],"explanation":"The key introduces the subject by naming what tardigrades are and giving their basic features, which suits an unfamiliar audience. The other choices dive into specialized details (cryptobiosis, research uses) that assume the reader already knows the basics.","skill":"Rhetorical synthesis"},{"cat":"expression","a":1,"q":"Many cities once relied on overhead trolley wires for public transit. Today, those wires have largely disappeared as buses switched to diesel and then electric batteries. ______ a few cities, such as San Francisco, still maintain trolleybus fleets that draw power from overhead lines.\nWhich choice completes the text with the most logical transition?","options":["Therefore,","However,","Likewise,","Consequently,"],"explanation":"The blank contrasts the general disappearance of trolley wires with the exception of cities that kept them, so the contrasting 'However' fits. 'Therefore' and 'Consequently' signal a result, and 'Likewise' signals similarity, none of which matches the contrast.","skill":"Transitions"},{"cat":"expression","a":2,"q":"While researching a topic, a student has taken the following notes:\n- The kora is a 21-string instrument from West Africa.\n- It has a large gourd body covered with cowhide.\n- Players pluck the strings with the thumb and index finger of each hand.\n- The kora produces a sound often compared to a harp.\n- It is central to the music of griots, who are oral historians.\nThe student wants to emphasize how the kora is played. Which choice most effectively uses the notes to accomplish this goal?","options":["The kora, a 21-string instrument from West Africa, has a large gourd body covered with cowhide.","The kora produces a sound that is often compared to that of a harp.","Players of the kora pluck the strings using the thumb and index finger of each hand.","The kora is central to the music of griots, who serve as oral historians."],"explanation":"The key focuses on the playing technique, matching the goal. The other choices describe the instrument's construction, sound, or cultural role rather than how it is played.","skill":"Rhetorical synthesis"},{"cat":"expression","a":2,"q":"The new park was designed with native plants that require little watering. The landscape architects expected the garden to need frequent attention during its first summer. ______ the plants thrived with almost no maintenance, surprising even the experts.\nWhich choice completes the text with the most logical transition?","options":["For instance,","In addition,","Instead,","Similarly,"],"explanation":"The outcome contradicts the expectation of frequent attention, so 'Instead' signals the reversal. 'For instance' introduces an example, 'In addition' adds information, and 'Similarly' draws a comparison, none of which captures the contrast.","skill":"Transitions"},{"cat":"expression","a":2,"q":"While researching a topic, a student has taken the following notes:\n- Solar panels convert sunlight directly into electricity.\n- Wind turbines convert moving air into electricity.\n- Solar output peaks at midday when the sun is highest.\n- Wind output often peaks at night and in winter.\n- Combining the two can provide steadier power throughout the day.\nThe student wants to emphasize a difference between solar and wind power. Which choice most effectively uses the notes to accomplish this goal?","options":["Both solar panels and wind turbines are used to generate electricity from natural sources.","Combining solar and wind power can provide steadier electricity throughout the day.","Solar output peaks at midday, whereas wind output often peaks at night and in winter.","Solar panels convert sunlight, and wind turbines convert moving air, into electricity."],"explanation":"The key contrasts the timing of peak output for the two sources, directly emphasizing a difference. The other choices stress similarities or the benefit of combining them rather than a difference.","skill":"Rhetorical synthesis"},{"cat":"expression","a":0,"q":"The factory installed sensors on every machine to track performance in real time. Managers worried that the flood of data would overwhelm their small analytics team. ______ the team built software that flagged only the most urgent problems, keeping the workload manageable.\nWhich choice completes the text with the most logical transition?","options":["As a result,","Nevertheless,","In contrast,","For example,"],"explanation":"Building filtering software is a response to the worry about too much data, so the cause-and-effect 'As a result' fits. 'Nevertheless' and 'In contrast' signal opposition, and 'For example' introduces an illustration, none of which matches.","skill":"Transitions"},{"cat":"expression","a":2,"q":"While researching a topic, a student has taken the following notes:\n- Lichens are organisms made of a fungus and an alga living together.\n- The fungus provides structure and absorbs water.\n- The alga produces food through photosynthesis.\n- Lichens can grow on bare rock where few other things survive.\n- They are sensitive to air pollution and are used to monitor air quality.\nThe student wants to explain how the two parts of a lichen work together. Which choice most effectively uses the notes to accomplish this goal?","options":["Lichens can grow on bare rock, a place where few other organisms are able to survive.","Because lichens are sensitive to air pollution, they are often used to monitor air quality.","In a lichen, the fungus provides structure and water while the alga produces food by photosynthesis.","A lichen is an organism made of a fungus and an alga that live closely together."],"explanation":"The key describes the complementary roles of the fungus and the alga, showing how they cooperate. The other choices state where lichens grow, their use as pollution monitors, or a general definition without the interaction.","skill":"Rhetorical synthesis"},{"cat":"expression","a":1,"q":"Early film projectors flickered noticeably because each frame was shown only once before the screen went dark. Engineers realized the eye perceived these gaps as an unsteady image. ______ they added a shutter that flashed each frame multiple times, smoothing out the flicker.\nWhich choice completes the text with the most logical transition?","options":["However,","To address this,","By comparison,","In fact,"],"explanation":"Adding the shutter solves the flicker problem just described, so 'To address this' signals the solution. 'However' and 'By comparison' signal contrast, and 'In fact' emphasizes a prior point rather than introducing a fix.","skill":"Transitions"},{"cat":"expression","a":1,"q":"While researching a topic, a student has taken the following notes:\n- The Antikythera mechanism is an ancient Greek device found in a shipwreck.\n- It dates to about 100 BCE.\n- It contained more than 30 bronze gears.\n- It could predict the positions of the sun and moon and the timing of eclipses.\n- It is often called the first known analog computer.\nThe student wants to emphasize the sophistication of the device. Which choice most effectively uses the notes to accomplish this goal?","options":["The Antikythera mechanism was discovered in an ancient shipwreck near a Greek island.","With more than 30 bronze gears, the mechanism could predict eclipses and the positions of the sun and moon.","The Antikythera mechanism dates to roughly 100 BCE, making it more than two thousand years old.","The Antikythera mechanism is an ancient Greek device recovered from a shipwreck."],"explanation":"The key highlights the device's complex engineering and impressive functions, emphasizing its sophistication. The other choices give only its discovery location or age, which do not stress how advanced it was.","skill":"Rhetorical synthesis"},{"cat":"expression","a":2,"q":"The town's recycling rate had stalled for years despite repeated awareness campaigns. Officials decided to try a different approach and gave each household a larger recycling bin. ______ participation jumped within a single quarter, suggesting that convenience mattered more than information.\nWhich choice completes the text with the most logical transition?","options":["Nonetheless,","On the other hand,","Remarkably,","Previously,"],"explanation":"The jump in participation is a striking positive result of the new bins, so 'Remarkably' fits the surprising success. 'Nonetheless' and 'On the other hand' signal contrast, and 'Previously' points backward in time, none of which suits the result.","skill":"Transitions"},{"cat":"expression","a":1,"q":"While researching a topic, a student has taken the following notes:\n- Coral reefs cover less than one percent of the ocean floor.\n- They support about a quarter of all marine species.\n- Reefs protect coastlines by absorbing wave energy.\n- Rising ocean temperatures cause coral bleaching.\n- Bleached coral can die if stressful conditions continue.\nThe student wants to emphasize the ecological importance of coral reefs. Which choice most effectively uses the notes to accomplish this goal?","options":["Rising ocean temperatures cause coral bleaching, which can kill reefs over time.","Although they cover less than one percent of the ocean floor, reefs support about a quarter of all marine species.","Coral reefs cover less than one percent of the total area of the ocean floor.","When ocean conditions remain stressful, bleached coral is likely to die."],"explanation":"The key contrasts the reefs' tiny area with the huge share of species they support, emphasizing their ecological importance. The other choices describe threats to reefs or a single fact rather than their importance.","skill":"Rhetorical synthesis"},{"cat":"expression","a":1,"q":"The author spent three years interviewing former factory workers for her book. She wanted readers to hear the events in the workers' own words. ______ she included long quoted passages rather than summarizing what each person said.\nWhich choice completes the text with the most logical transition?","options":["Even so,","Accordingly,","In contrast,","Meanwhile,"],"explanation":"Including direct quotes follows logically from wanting readers to hear the workers' own words, so 'Accordingly' signals the result. 'Even so' and 'In contrast' signal opposition, and 'Meanwhile' signals simultaneous events, none of which fits.","skill":"Transitions"},{"cat":"expression","a":2,"q":"While researching a topic, a student has taken the following notes:\n- Vincent van Gogh produced more than 2,000 artworks in about a decade.\n- He sold very few paintings during his lifetime.\n- His brother Theo supported him financially and emotionally.\n- After his death, his work became enormously influential.\n- His paintings now hang in major museums around the world.\nThe student wants to emphasize the contrast between van Gogh's success during his life and after his death. Which choice most effectively uses the notes to accomplish this goal?","options":["Van Gogh's brother Theo supported him both financially and emotionally throughout his career.","Van Gogh produced more than 2,000 artworks over a period of about ten years.","Though van Gogh sold very few paintings while alive, his work became enormously influential after his death.","Van Gogh's paintings now hang in major museums located around the world."],"explanation":"The key juxtaposes his lack of sales while living with his later influence, directly emphasizing the contrast. The other choices mention his brother, his productivity, or his current fame without contrasting the two periods.","skill":"Rhetorical synthesis"},{"cat":"expression","a":1,"q":"Most desert plants store water in thick stems or leaves to survive long droughts. The resurrection plant takes a different strategy entirely. ______ it dries out completely, appearing dead, and then revives within hours once rain returns.\nWhich choice completes the text with the most logical transition?","options":["Similarly,","Instead,","Therefore,","In addition,"],"explanation":"The plant's drying-out method is contrasted with the usual water-storing strategy, so 'Instead' signals the alternative. 'Similarly' and 'In addition' suggest agreement, and 'Therefore' suggests a result, none of which captures the contrast.","skill":"Transitions"},{"cat":"expression","a":1,"q":"While researching a topic, a student has taken the following notes:\n- A keystone species has a large effect on its ecosystem relative to its abundance.\n- Sea otters are a keystone species in kelp forests.\n- Sea otters eat sea urchins.\n- Without otters, urchins multiply and devour the kelp.\n- Healthy kelp forests shelter many other species.\nThe student wants to explain the role of sea otters in kelp forests. Which choice most effectively uses the notes to accomplish this goal?","options":["A keystone species has an effect on its ecosystem that is large relative to its abundance.","By eating sea urchins, sea otters keep urchin numbers low and allow kelp forests to flourish.","Healthy kelp forests provide shelter for a wide variety of marine species.","Sea otters are considered a keystone species within kelp forest ecosystems."],"explanation":"The key explains the mechanism by which otters protect kelp forests, fulfilling the goal. The other choices define keystone species generally, describe kelp's value, or label otters without explaining their role.","skill":"Rhetorical synthesis"},{"cat":"expression","a":1,"q":"Researchers gave one group of students written instructions and another group the same instructions in a short video. Both groups performed equally well on the immediate quiz. ______ when tested a week later, the video group remembered noticeably more.\nWhich choice completes the text with the most logical transition?","options":["Likewise,","However,","For instance,","Therefore,"],"explanation":"The delayed test reverses the earlier tie between the groups, so the contrasting 'However' fits. 'Likewise' signals similarity, 'For instance' introduces an example, and 'Therefore' signals a result, none of which matches the contrast.","skill":"Transitions"},{"cat":"expression","a":2,"q":"While researching a topic, a student has taken the following notes:\n- Esperanto is a constructed language created in 1887.\n- It was designed by L. L. Zamenhof to be easy to learn.\n- Its grammar has very few exceptions.\n- Words are built from a small set of regular roots and endings.\n- Today it has speakers in many countries but no official national status.\nThe student wants to emphasize why Esperanto is considered easy to learn. Which choice most effectively uses the notes to accomplish this goal?","options":["Esperanto is a constructed language that was created in the year 1887.","Today Esperanto has speakers in many countries but holds no official national status.","Esperanto's grammar has very few exceptions, and its words are built from regular roots and endings.","L. L. Zamenhof designed Esperanto with the intention of making it easy to learn."],"explanation":"The key gives the specific features (regular grammar and word-building) that make Esperanto easy, supporting the goal. The other choices state when it was made, its current status, or merely the designer's intention without the reasons.","skill":"Rhetorical synthesis"},{"cat":"expression","a":1,"q":"The startup's first app gained users quickly but crashed often under heavy traffic. The founders chose to rewrite the entire system before adding any new features. ______ they delayed several updates that loyal users had been requesting for months.\nWhich choice completes the text with the most logical transition?","options":["In other words,","In the meantime,","By contrast,","For example,"],"explanation":"Delaying updates happens during the rewrite period, so the time-based 'In the meantime' fits. 'In other words' restates an idea, 'By contrast' signals opposition, and 'For example' introduces an illustration, none of which captures the timing.","skill":"Transitions"},{"cat":"expression","a":1,"q":"While researching a topic, a student has taken the following notes:\n- The Great Pacific Garbage Patch is a large area of floating plastic debris.\n- Most of the plastic consists of tiny pieces called microplastics.\n- These pieces are spread out rather than forming a solid island.\n- Currents called gyres concentrate the debris in this region.\n- The patch is difficult to clean because the plastic is so dispersed.\nThe student wants to correct a common misconception about the garbage patch. Which choice most effectively uses the notes to accomplish this goal?","options":["Ocean currents known as gyres help concentrate floating debris in the region.","Rather than being a solid island, the patch is mostly tiny microplastics spread across the water.","The Great Pacific Garbage Patch is a large area of floating plastic debris.","The patch is hard to clean up because its plastic is so widely dispersed."],"explanation":"The key counters the common belief that the patch is a solid island, addressing the misconception. The other choices explain how debris gathers or why cleanup is hard but do not correct any false impression.","skill":"Rhetorical synthesis"},{"cat":"expression","a":1,"q":"Honeybees communicate the location of food through a movement known as the waggle dance. The angle of the dance indicates direction relative to the sun, and its duration indicates distance. ______ a dance lasting longer tells other bees that the food source is farther away.\nWhich choice completes the text with the most logical transition?","options":["Nevertheless,","For example,","In contrast,","Otherwise,"],"explanation":"The longer dance is a concrete illustration of how duration signals distance, so 'For example' fits. 'Nevertheless' and 'In contrast' signal opposition, and 'Otherwise' signals an alternative condition, none of which matches.","skill":"Transitions"},{"cat":"expression","a":1,"q":"While researching a topic, a student has taken the following notes:\n- Bioluminescence is the production of light by living organisms.\n- It is common in deep-sea creatures.\n- Some fish use it to lure prey toward their mouths.\n- Some squid use it to confuse predators.\n- Certain fireflies use it to attract mates.\nThe student wants to illustrate the variety of purposes bioluminescence serves. Which choice most effectively uses the notes to accomplish this goal?","options":["Bioluminescence is the production of light by living organisms and is common in the deep sea.","Organisms use bioluminescence in different ways: to lure prey, to confuse predators, and to attract mates.","Bioluminescence is especially common among creatures that live in the deep sea.","Some deep-sea fish use bioluminescence to lure prey toward their open mouths."],"explanation":"The key lists several distinct uses, directly illustrating the variety of purposes. The other choices define the phenomenon, note where it occurs, or give a single use, none of which conveys the range.","skill":"Rhetorical synthesis"},{"cat":"expression","a":1,"q":"The museum digitized its entire photo archive and posted the images online for free. Curators feared that fewer people would bother visiting in person. ______ attendance rose as online visitors became curious to see the originals.\nWhich choice completes the text with the most logical transition?","options":["Consequently,","Surprisingly,","Similarly,","Furthermore,"],"explanation":"Rising attendance defies the curators' fear of fewer visitors, so 'Surprisingly' fits the unexpected outcome. 'Consequently' and 'Furthermore' suggest a straightforward result or addition, and 'Similarly' suggests likeness, none of which captures the reversal.","skill":"Transitions"},{"cat":"expression","a":2,"q":"While researching a topic, a student has taken the following notes:\n- Two researchers measured how quickly different soils absorb rainwater.\n- Sandy soil absorbed water in about 2 minutes.\n- Clay soil took about 25 minutes to absorb the same amount.\n- Faster absorption reduces surface flooding.\n- The findings could guide where to build rain gardens.\nThe student wants to emphasize the difference between the two soils' absorption rates. Which choice most effectively uses the notes to accomplish this goal?","options":["The researchers' findings about soil could guide decisions about where to build rain gardens.","Two researchers measured how quickly several different soils absorbed rainwater.","Sandy soil absorbed the water in about 2 minutes, while clay soil took roughly 25 minutes.","Faster water absorption by soil helps reduce the amount of surface flooding."],"explanation":"The key states both absorption times side by side, emphasizing the large gap between the soils. The other choices describe the study's purpose, methods, or a general benefit without comparing the rates.","skill":"Rhetorical synthesis"},{"cat":"expression","a":0,"q":"Glassblowers must keep molten glass constantly rotating as they shape it. If the glass stops moving for even a moment, gravity pulls it out of shape. ______ a beginner's first pieces often sag noticeably to one side.\nWhich choice completes the text with the most logical transition?","options":["For this reason,","Nonetheless,","On the contrary,","Earlier,"],"explanation":"The sagging pieces are a consequence of stopping the rotation, so the causal 'For this reason' fits. 'Nonetheless' and 'On the contrary' signal opposition, and 'Earlier' signals time order, none of which matches the cause and effect.","skill":"Transitions"},{"cat":"expression","a":1,"q":"While researching a topic, a student has taken the following notes:\n- Octopuses have three hearts.\n- Two hearts pump blood to the gills; one pumps blood to the rest of the body.\n- Their blood is blue because it uses copper rather than iron to carry oxygen.\n- Copper-based blood works well in cold, low-oxygen water.\n- The central heart stops beating when an octopus swims.\nThe student wants to explain why octopus blood is blue. Which choice most effectively uses the notes to accomplish this goal?","options":["An octopus has three hearts: two that pump blood to the gills and one for the body.","Octopus blood is blue because it carries oxygen using copper instead of iron.","The central heart of an octopus stops beating whenever the animal swims.","Copper-based blood functions well in cold water that contains little oxygen."],"explanation":"The key directly states the cause of the blue color, fulfilling the goal. The other choices describe the hearts, the heart's behavior during swimming, or a benefit of copper blood without explaining the color.","skill":"Rhetorical synthesis"},{"cat":"expression","a":1,"q":"Astronomers had long assumed that planets could only form around single stars like our sun. Then telescopes detected planets orbiting pairs of stars. ______ the discovery forced scientists to revise their models of how planetary systems develop.\nWhich choice completes the text with the most logical transition?","options":["Regardless,","As a result,","In comparison,","Until then,"],"explanation":"Revising the models is the consequence of the unexpected discovery, so 'As a result' fits. 'Regardless' dismisses prior information, 'In comparison' draws a likeness, and 'Until then' marks a time boundary, none of which captures the result.","skill":"Transitions"},{"cat":"expression","a":2,"q":"While researching a topic, a student has taken the following notes:\n- The printing press was developed by Johannes Gutenberg around 1440.\n- Before it, books were copied by hand, a slow and costly process.\n- The press allowed many identical copies to be made quickly.\n- Books became cheaper and more widely available.\n- Literacy rates eventually began to rise across Europe.\nThe student wants to explain how the printing press changed the production of books. Which choice most effectively uses the notes to accomplish this goal?","options":["Johannes Gutenberg developed the printing press in Europe around the year 1440.","Across Europe, literacy rates eventually began to rise after the press appeared.","Whereas books had once been copied slowly by hand, the press could make many identical copies quickly.","Before the printing press, the copying of books was both a slow and a costly process."],"explanation":"The key contrasts the old hand-copying method with the press's fast duplication, explaining the change in production. The other choices give a date, a later effect on literacy, or only the old method without the contrast.","skill":"Rhetorical synthesis"},{"cat":"expression","a":1,"q":"The bridge's designers used a lightweight aluminum deck to reduce its overall weight. Aluminum, however, expands and contracts more than steel as temperatures change. ______ the engineers added flexible joints to absorb the daily shifts in length.\nWhich choice completes the text with the most logical transition?","options":["Even so,","To compensate,","Likewise,","Beforehand,"],"explanation":"The flexible joints offset the expansion problem, so 'To compensate' signals the corrective step. 'Even so' and 'Likewise' do not fit a cause-and-fix relationship, and 'Beforehand' wrongly implies the joints came first.","skill":"Transitions"},{"cat":"expression","a":3,"q":"While researching a topic, a student has taken the following notes:\n- Mycorrhizae are partnerships between fungi and plant roots.\n- The fungi extend the reach of the roots into the soil.\n- They help plants absorb water and nutrients like phosphorus.\n- In return, plants give the fungi sugars made by photosynthesis.\n- About 90 percent of land plants form these partnerships.\nThe student wants to emphasize that the relationship benefits both partners. Which choice most effectively uses the notes to accomplish this goal?","options":["About 90 percent of all land plants form partnerships with mycorrhizal fungi.","Mycorrhizal fungi extend the reach of plant roots farther into the surrounding soil.","The fungi help plants absorb water and nutrients such as phosphorus from the soil.","The fungi help plants take up nutrients, and in return the plants supply the fungi with sugars."],"explanation":"The key shows the exchange flowing in both directions, emphasizing mutual benefit. The other choices give the prevalence of the partnership or only the fungi's contribution, leaving out the reciprocity.","skill":"Rhetorical synthesis"},{"cat":"expression","a":2,"q":"Translators of poetry face a difficult choice on every line. They can preserve the literal meaning of the original words, or they can preserve its rhythm and rhyme. ______ capturing both at once is rarely possible.\nWhich choice completes the text with the most logical transition?","options":["In addition,","For instance,","Unfortunately,","Therefore,"],"explanation":"The impossibility of having both signals a regrettable limitation on the choice just described, which 'Unfortunately' conveys. 'In addition' merely adds a point, 'For instance' introduces an example, and 'Therefore' signals a conclusion, none of which fits as well.","skill":"Transitions"},{"cat":"expression","a":1,"q":"While researching a topic, a student has taken the following notes:\n- A research team compared two methods for desalinating seawater.\n- Reverse osmosis forces water through a fine membrane under high pressure.\n- Thermal distillation heats seawater and collects the evaporated vapor.\n- Reverse osmosis uses less energy per liter than thermal distillation.\n- Thermal distillation handles very salty water that clogs membranes.\nThe student wants to emphasize an advantage that thermal distillation has over reverse osmosis. Which choice most effectively uses the notes to accomplish this goal?","options":["Reverse osmosis forces seawater through a fine membrane under high pressure.","Unlike reverse osmosis, thermal distillation can handle very salty water that would clog membranes.","Reverse osmosis uses less energy per liter of fresh water than thermal distillation does.","Thermal distillation works by heating seawater and then collecting the vapor that evaporates."],"explanation":"The key names a specific strength of thermal distillation relative to reverse osmosis, matching the goal. Choice C names an advantage of reverse osmosis instead, and the other choices merely describe how each method works.","skill":"Rhetorical synthesis"},{"cat":"expression","a":0,"q":"The volunteers planted hundreds of young oak trees along the eroding riverbank. They knew it would take decades for the trees to mature. ______ they were planting a forest that their grandchildren, not they, would one day enjoy.\nWhich choice completes the text with the most logical transition?","options":["In effect,","However,","By contrast,","Previously,"],"explanation":"Planting for future generations is a restatement of what the slow-growing trees mean, so 'In effect' fits as a summary of the situation. 'However' and 'By contrast' signal opposition, and 'Previously' signals earlier time, none of which matches.","skill":"Transitions"},{"cat":"conventions","a":0,"q":"The committee reviewed the proposal for several weeks ______ its members finally voted to approve the new recycling program. Which choice completes the text so that it conforms to the conventions of Standard English?","options":["weeks, and","weeks","weeks,","weeks and,"],"explanation":"Two independent clauses joined by the coordinating conjunction 'and' require a comma before 'and.' Option B creates a run-on; C creates a comma splice; D misplaces the comma after the conjunction.","skill":"Sentence boundaries"},{"cat":"conventions","a":3,"q":"A row of ancient oak trees ______ the long gravel driveway leading up to the old farmhouse. Which choice completes the text so that it conforms to the conventions of Standard English?","options":["line","are lining","lining","lines"],"explanation":"The subject is the singular 'row,' not the plural object of the preposition 'trees,' so the singular verb 'lines' is needed. 'Line' and 'are lining' agree wrongly with 'trees'; 'lining' is not a finite verb.","skill":"Subject-verb agreement"},{"cat":"conventions","a":1,"q":"Each of the volunteers brought ______ own reusable bag to the community cleanup event. Which choice completes the text so that it conforms to the conventions of Standard English?","options":["their","his or her","they're","there"],"explanation":"'Each' is singular, so a singular pronoun 'his or her' is required. 'Their' is plural; 'they're' and 'there' are not possessive pronouns.","skill":"Pronoun-antecedent agreement"},{"cat":"conventions","a":1,"q":"By the time the rescuers arrived, the stranded hikers ______ for nearly six hours in the freezing cold. Which choice completes the text so that it conforms to the conventions of Standard English?","options":["wait","had waited","have waited","are waiting"],"explanation":"The past perfect 'had waited' shows action completed before another past event ('arrived'). 'Wait' and 'have waited' use wrong tenses; 'are waiting' is present.","skill":"Verb tense"},{"cat":"conventions","a":0,"q":"Marie Curie, ______ won two Nobel Prizes, conducted pioneering research on radioactivity. Which choice completes the text so that it conforms to the conventions of Standard English?","options":["who","which","she","whom"],"explanation":"The relative pronoun 'who' refers to a person and serves as the subject of the clause. 'Which' is for things; 'she' creates a comma splice; 'whom' is objective case.","skill":"Pronoun case"},{"cat":"conventions","a":2,"q":"The novel's protagonist, a quiet librarian named Elena, ______ to uncover a secret hidden in the archives. Which choice completes the text so that it conforms to the conventions of Standard English?","options":["determine","determining","is determined","are determined"],"explanation":"The singular subject 'protagonist' takes the singular verb 'is determined'; the appositive does not change agreement. 'Determine' and 'are determined' are plural; 'determining' is not finite.","skill":"Subject-verb agreement"},{"cat":"conventions","a":0,"q":"______ the symphony reached its dramatic climax, the audience sat in complete silence. Which choice completes the text so that it conforms to the conventions of Standard English?","options":["As","It was when","Then","During"],"explanation":"The subordinating conjunction 'As' correctly joins the dependent clause to the main clause. 'Then' creates a comma splice; 'It was when' is awkward and ungrammatical here; 'During' cannot introduce a clause.","skill":"Sentence boundaries"},{"cat":"conventions","a":1,"q":"The geologist examined the rock samples ______ she recorded each mineral's color, texture, and weight in her notebook. Which choice completes the text so that it conforms to the conventions of Standard English?","options":["samples,","samples;","samples, then","samples then"],"explanation":"A semicolon correctly joins two closely related independent clauses. The comma alone (A) is a comma splice; 'then' is an adverb, not a conjunction, so options C and D still leave a comma splice or run-on.","skill":"Semicolons"},{"cat":"conventions","a":1,"q":"The museum's collection of rare manuscripts ______ visitors from around the world each year. Which choice completes the text so that it conforms to the conventions of Standard English?","options":["attract","attracts","are attracting","have attracted"],"explanation":"The singular subject 'collection' requires the singular verb 'attracts.' 'Attract,' 'are attracting,' and 'have attracted' all incorrectly agree with the plural 'manuscripts.'","skill":"Subject-verb agreement"},{"cat":"conventions","a":2,"q":"Hoping to improve her chances of admission, ______ retook the standardized exam in the fall. Which choice completes the text so that it conforms to the conventions of Standard English?","options":["the application was revised when she","the decision was made that she","she","her scores"],"explanation":"The introductory modifier 'Hoping to improve her chances' must describe the person who hopes, so 'she' must follow. The other options create dangling modifiers by placing a thing as the subject.","skill":"Modifier placement"},{"cat":"conventions","a":1,"q":"The young architect presented her design to the board ______ everyone in the room was impressed by its bold simplicity. Which choice completes the text so that it conforms to the conventions of Standard English?","options":["board,","board, and","board and","board; and"],"explanation":"Two independent clauses are correctly joined by a comma plus 'and.' Option A is a comma splice; C is a run-on; D wrongly adds a semicolon with the conjunction.","skill":"Sentence boundaries"},{"cat":"conventions","a":0,"q":"The startup faced one major obstacle ______ it lacked the funding needed to launch its first product. Which choice completes the text so that it conforms to the conventions of Standard English?","options":["obstacle:","obstacle,","obstacle;,","obstacle, that"],"explanation":"A colon correctly introduces an explanation of the 'obstacle' after an independent clause. The comma creates a splice; ';,' is not valid punctuation; 'that' is unnecessary and ungrammatical.","skill":"Colons"},{"cat":"conventions","a":1,"q":"The astronomer pointed out that the planet's rings, ______ are made of ice and rock, reflect sunlight brilliantly. Which choice completes the text so that it conforms to the conventions of Standard English?","options":["that","which","they","and which"],"explanation":"A nonrestrictive clause set off by commas uses 'which,' not 'that.' 'They' creates a splice; 'and which' is redundant and ungrammatical.","skill":"Nonrestrictive elements"},{"cat":"conventions","a":2,"q":"Neither the coach nor the players ______ satisfied with the outcome of the championship game. Which choice completes the text so that it conforms to the conventions of Standard English?","options":["was","is","were","has been"],"explanation":"With 'neither...nor,' the verb agrees with the nearer subject, here the plural 'players,' requiring 'were.' The singular forms 'was,' 'is,' and 'has been' are incorrect.","skill":"Subject-verb agreement"},{"cat":"conventions","a":0,"q":"The bakery is famous for ______ cinnamon rolls, which sell out within an hour every morning. Which choice completes the text so that it conforms to the conventions of Standard English?","options":["its","it's","their","its'"],"explanation":"The singular possessive 'its' refers to the singular 'bakery.' 'It's' means 'it is'; 'their' is plural; 'its'' is not a word.","skill":"Apostrophes/possessives"},{"cat":"conventions","a":2,"q":"The professor explained that the experiment had failed ______ the results were nonetheless valuable for future research. Which choice completes the text so that it conforms to the conventions of Standard English?","options":["failed,","failed","failed, but","failed but"],"explanation":"Two independent clauses are correctly joined by a comma plus the coordinating conjunction 'but.' A comma alone (A) is a comma splice; no punctuation (B) is a run-on; 'but' without the comma (D) omits required punctuation.","skill":"Sentence boundaries"},{"cat":"conventions","a":0,"q":"The documentary explores how coral reefs, which support a quarter of all marine ______ are threatened by rising ocean temperatures. Which choice completes the text so that it conforms to the conventions of Standard English?","options":["species,","species","species;","species:"],"explanation":"The nonrestrictive clause beginning 'which support...' must be closed with a comma to pair with the opening comma. Omitting it (B), or using a semicolon (C) or colon (D), breaks the supplementary element.","skill":"Supplementary elements"},{"cat":"conventions","a":1,"q":"The director's latest film was praised for its stunning visuals, its haunting score, and ______ Which choice completes the text so that it conforms to the conventions of Standard English?","options":["it tells a gripping story.","its gripping story.","having a gripping story.","the story it tells grips you."],"explanation":"Parallel structure requires a noun phrase matching 'its stunning visuals' and 'its haunting score,' so 'its gripping story' is correct. The other options break the parallel series.","skill":"Parallel structure"},{"cat":"conventions","a":1,"q":"After the storm passed, the residents discovered that ______ homes had suffered surprisingly little damage. Which choice completes the text so that it conforms to the conventions of Standard English?","options":["there","their","they're","theirs"],"explanation":"The possessive 'their' is needed to show ownership of 'homes.' 'There' indicates place; 'they're' means 'they are'; 'theirs' is a standalone possessive.","skill":"Apostrophes/possessives"},{"cat":"conventions","a":2,"q":"The scientist who first proposed the theory ______ later awarded a prestigious medal for her contributions. Which choice completes the text so that it conforms to the conventions of Standard English?","options":["were","have been","was","are"],"explanation":"The singular subject 'scientist' takes the singular verb 'was.' The relative clause 'who first proposed the theory' does not affect agreement. 'Were,' 'have been,' and 'are' are plural.","skill":"Subject-verb agreement"},{"cat":"conventions","a":1,"q":"The city council approved funding for three new ______ a public library, a community garden, and a bicycle path. Which choice completes the text so that it conforms to the conventions of Standard English?","options":["projects,","projects:","projects;","projects"],"explanation":"A colon introduces a list following an independent clause. A comma here is too weak before a list of this kind; a semicolon and no punctuation are both incorrect for introducing the list.","skill":"Colons"},{"cat":"conventions","a":1,"q":"The painting that hangs in the entrance hall, a vivid landscape by a local ______ was donated to the school by a former student. Which choice completes the text so that it conforms to the conventions of Standard English?","options":["artist","artist,","artist;","artist:"],"explanation":"The appositive 'a vivid landscape by a local artist' must be closed with a comma to match the opening comma. Omitting it (A), or using a semicolon (C) or colon (D), disrupts the paired punctuation.","skill":"Supplementary elements"},{"cat":"conventions","a":2,"q":"Whenever the orchestra rehearses late into the evening, the conductor insists that every musician ______ fully focused. Which choice completes the text so that it conforms to the conventions of Standard English?","options":["remaining","remains","remain","to remain"],"explanation":"The subjunctive mood after 'insists that' requires the base form 'remain.' 'Remains' is indicative; 'remaining' and 'to remain' are nonfinite forms.","skill":"Verb form"},{"cat":"conventions","a":1,"q":"The two researchers shared the award equally, dividing the prize money between ______ Which choice completes the text so that it conforms to the conventions of Standard English?","options":["they.","them.","themselves.","their."],"explanation":"The object of the preposition 'between' requires the objective pronoun 'them.' 'They' is subjective; 'themselves' is reflexive and lacks a proper antecedent here; 'their' is possessive.","skill":"Pronoun case"},{"cat":"conventions","a":2,"q":"Having trained for months in difficult conditions, ______ felt ready to attempt the summit at dawn. Which choice completes the text so that it conforms to the conventions of Standard English?","options":["the gear was packed and the climbers","it was decided that the climbers","the climbers","the expedition's plan"],"explanation":"The introductory phrase 'Having trained for months' must modify the people who trained, so 'the climbers' must follow directly. The other options create dangling modifiers.","skill":"Modifier placement"},{"cat":"conventions","a":1,"q":"The report concluded that the company's profits had risen sharply ______ its workforce had also grown by nearly twenty percent. Which choice completes the text so that it conforms to the conventions of Standard English?","options":["sharply,","sharply, and that","sharply and","sharply; that"],"explanation":"Parallelism with 'that the company's profits had risen' requires a second 'that' clause joined by 'and,' giving 'and that.' A comma alone is a splice; 'and' without 'that' breaks parallelism; the semicolon with 'that' is ungrammatical.","skill":"Parallel structure"},{"cat":"conventions","a":1,"q":"The ancient bridge, ______ stone arches have survived centuries of floods, remains in use today. Which choice completes the text so that it conforms to the conventions of Standard English?","options":["who's","whose","whom","which"],"explanation":"The possessive relative pronoun 'whose' shows that the arches belong to the bridge. 'Who's' means 'who is'; 'whom' is objective; 'which' cannot be possessive here.","skill":"Pronoun case"},{"cat":"conventions","a":1,"q":"The chemistry students measured the temperature, recorded the data, and ______ their findings in detailed lab reports. Which choice completes the text so that it conforms to the conventions of Standard English?","options":["analyzing","analyzed","had analyzed","would analyze"],"explanation":"Parallel structure with 'measured' and 'recorded' requires the simple past 'analyzed.' 'Analyzing' is not finite; 'had analyzed' and 'would analyze' break the parallel verb series.","skill":"Parallel structure"},{"cat":"conventions","a":1,"q":"The festival, which had been postponed twice because of bad ______ finally took place under clear skies in late June. Which choice completes the text so that it conforms to the conventions of Standard English?","options":["weather","weather,","weather;","weather:"],"explanation":"The nonrestrictive clause 'which had been postponed...weather' must be closed with a comma to pair with the opening comma. Omitting it (A) or using a semicolon (C) or colon (D) is incorrect.","skill":"Supplementary elements"},{"cat":"conventions","a":0,"q":"Several of the antique ______ delicate gold trim made them especially valuable to collectors, were sold at auction. Which choice completes the text so that it conforms to the conventions of Standard English?","options":["plates, whose","plates whose","plates, who's","plates; whose"],"explanation":"A nonrestrictive clause introduced by the possessive 'whose' is set off with a comma. 'Plates whose' omits the comma; 'who's' means 'who is'; the semicolon wrongly separates the clause.","skill":"Pronoun case"},{"cat":"algebra","a":0,"q":"A drone delivery service charges a flat dispatch fee plus a rate per kilometer. A 4 km delivery costs $19 and a 9 km delivery costs $34. What is the cost, in dollars, of a 6 km delivery?","options":["$25","$22","$28","$24"],"explanation":"Rate = (34-19)/(9-4) = 15/5 = 3 per km. Fee = 19 - 3(4) = 7. Cost(6) = 7 + 3(6) = 25. Distractor $22 omits adding the fee correctly by using 19 + 3(1).","skill":"Linear models from two points"},{"cat":"algebra","a":0,"q":"If 5(2x - 3) = 7x + 9, what is the value of x?","options":["8","6","-8","2"],"explanation":"10x - 15 = 7x + 9, so 3x = 24, x = 8. Distractor 6 comes from forgetting to distribute the 5 across the -3.","skill":"Linear equations one variable"},{"cat":"algebra","a":0,"q":"A line passes through the points (-2, 7) and (4, -5). What is the slope of the line?","options":["-2","2","-1/2","-3"],"explanation":"Slope = (-5 - 7)/(4 - (-2)) = -12/6 = -2. Distractor -1/2 inverts the rise and run.","skill":"Slope of a line"},{"cat":"algebra","a":0,"q":"A printing shop binds booklets. The number of usable pages p left from a roll after binding b booklets is p = 480 - 16b. What does the number 16 represent?","options":["The pages used per booklet","The total pages on a roll","The number of booklets per roll","The pages left after one booklet"],"explanation":"The coefficient of b is the rate of pages consumed per booklet bound. 480 is the starting amount, not 16.","skill":"Interpreting linear models"},{"cat":"algebra","a":0,"q":"What value of k makes the equation 3(kx + 2) = 12x + 6 true for all values of x?","options":["4","2","6","12"],"explanation":"3kx + 6 = 12x + 6, so 3k = 12, k = 4. Distractor 2 comes from solving 3k = 6 by misreading the right side.","skill":"Equivalent linear expressions"},{"cat":"algebra","a":0,"q":"The solution to |2x - 5| = 11 consists of two values. What is their sum?","options":["5","11","8","-3"],"explanation":"2x - 5 = 11 gives x = 8; 2x - 5 = -11 gives x = -3. Sum = 8 + (-3) = 5. Distractor 11 mistakes the constant on the right for the sum.","skill":"Absolute value equations"},{"cat":"algebra","a":0,"q":"A system is given by 4x - 3y = 18 and 2x + y = 4. What is the value of y?","options":["-2","2","6","-1"],"explanation":"From the second equation y = 4 - 2x. Substitute: 4x - 3(4 - 2x) = 18, so 4x - 12 + 6x = 18, 10x = 30, x = 3, y = 4 - 2(3) = -2. Distractor 2 forgets the negative sign when computing y.","skill":"Systems by substitution"},{"cat":"algebra","a":0,"q":"A gym membership has a $40 sign-up fee and costs $25 per month. Which equation gives the total cost C, in dollars, after m months?","options":["C = 25m + 40","C = 40m + 25","C = 65m","C = 25m - 40"],"explanation":"Total = monthly rate times months plus one-time fee = 25m + 40. Distractor swaps which value is multiplied by m.","skill":"Building linear equations"},{"cat":"algebra","a":0,"q":"If 3x - 7 > 2x + 5, which of the following describes all solutions?","options":["x > 12","x < 12","x > -2","x > 2"],"explanation":"Subtract 2x: x - 7 > 5, so x > 12. Distractor x < 12 wrongly flips the inequality sign.","skill":"Linear inequalities"},{"cat":"algebra","a":0,"q":"For what value of c does the system 6x - 2y = 10 and 9x - 3y = c have infinitely many solutions?","options":["15","10","30","5"],"explanation":"The second equation must be a multiple of the first. Multiply the first by 1.5: 9x - 3y = 15, so c = 15. Distractor 10 just copies the first equation's constant.","skill":"Systems infinite solutions"},{"cat":"algebra","a":0,"q":"A linear function f satisfies f(2) = 9 and f(6) = 21. What is f(0)?","options":["3","6","0","9"],"explanation":"Slope = (21-9)/(6-2) = 3. f(0) = f(2) - 2(3) = 9 - 6 = 3. Distractor 6 subtracts only one slope step.","skill":"Linear functions"},{"cat":"algebra","a":0,"q":"The expression (8x + 12)/4 is equivalent to which of the following?","options":["2x + 3","2x + 12","8x + 3","2x + 4"],"explanation":"Divide each term by 4: 8x/4 + 12/4 = 2x + 3. Distractor 2x + 12 fails to divide the constant term.","skill":"Equivalent linear expressions"},{"cat":"algebra","a":0,"q":"A water tank holds 320 liters and drains at a steady 8 liters per minute. After how many minutes will the tank contain 120 liters?","options":["25","40","15","20"],"explanation":"320 - 8t = 120, so 8t = 200, t = 25. Distractor 40 solves 320 - 8t = 0 (the full drain time).","skill":"Linear equations in context"},{"cat":"algebra","a":0,"q":"Which point lies on the line 5x - 4y = 12?","options":["(4, 2)","(2, 4)","(0, 3)","(4, -2)"],"explanation":"Test (4,2): 5(4) - 4(2) = 20 - 8 = 12. True. Distractor (2,4) gives 10 - 16 = -6, not 12.","skill":"Linear equations two variables"},{"cat":"algebra","a":0,"q":"A phone plan costs $15 plus $0.06 per text. If the monthly bill was $33.60, how many texts were sent?","options":["310","560","250","186"],"explanation":"33.60 - 15 = 18.60; 18.60 / 0.06 = 310. Distractor 560 divides 33.60 by 0.06 without subtracting the base charge.","skill":"Linear equations in context"},{"cat":"algebra","a":0,"q":"If the lines y = 3x + 1 and y = -2x + 16 intersect, at what x-value do they meet?","options":["3","5","15","-3"],"explanation":"3x + 1 = -2x + 16, so 5x = 15, x = 3. Distractor 5 comes from solving x = 15/3 after a sign error.","skill":"Systems of equations"},{"cat":"algebra","a":0,"q":"A recipe needs flour and sugar in a 5:2 ratio by weight. If a baker uses 350 grams of flour, how many grams of sugar are needed?","options":["140","875","175","100"],"explanation":"Sugar = (2/5)(350) = 140 grams. Distractor 875 multiplies by 5/2 instead of 2/5.","skill":"Proportional linear relationships"},{"cat":"algebra","a":0,"q":"The equation 2(x - 4) - 3(x + 1) = -15 has what solution for x?","options":["4","-4","8","2"],"explanation":"2x - 8 - 3x - 3 = -15, so -x - 11 = -15, -x = -4, x = 4. Distractor -4 drops the sign when isolating x.","skill":"Linear equations one variable"},{"cat":"algebra","a":0,"q":"A salesperson earns a base salary plus commission. Her weekly pay P, in dollars, for selling n units is P = 12n + 480. If she earned $792 one week, how many units did she sell?","options":["26","66","36","24"],"explanation":"792 - 480 = 312; 312 / 12 = 26. Distractor 66 divides 792 by 12 without subtracting the base salary.","skill":"Interpreting linear models"},{"cat":"algebra","a":0,"q":"For which value of x is the equation |3x + 6| = 0 satisfied?","options":["-2","2","0","6"],"explanation":"An absolute value equals 0 only when the inside is 0: 3x + 6 = 0, so x = -2. Distractor 2 drops the negative sign.","skill":"Absolute value equations"},{"cat":"algebra","a":0,"q":"A system of equations is 7x + 2y = 31 and 3x - 2y = -1. What is the value of x?","options":["3","5","2","4"],"explanation":"Add the equations: 10x = 30, x = 3. Distractor 5 results from subtracting instead of adding to eliminate y.","skill":"Systems by elimination"},{"cat":"algebra","a":0,"q":"A car's value depreciates linearly. It was worth $24,000 when new and $18,000 after 2 years. What will it be worth after 5 years?","options":["$9,000","$12,000","$6,000","$15,000"],"explanation":"Loss = (24000-18000)/2 = 3000 per year. Value after 5 years = 24000 - 5(3000) = 9000. Distractor $12,000 uses only the value drop over the first window doubled.","skill":"Linear models in context"},{"cat":"algebra","a":0,"q":"Which inequality is represented by all points on or below the line through (0, 5) with slope -1?","options":["y ≤ -x + 5","y ≥ -x + 5","y ≤ x + 5","y < -x + 5"],"explanation":"The line is y = -x + 5; 'on or below' means y ≤ -x + 5. Distractor with ≥ describes the region above the line.","skill":"Graphs of inequalities"},{"cat":"algebra","a":0,"q":"If 4/(x) = 6/(x + 5), what is the value of x?","options":["10","6","5","12"],"explanation":"Cross-multiply: 4(x + 5) = 6x, so 4x + 20 = 6x, 2x = 20, x = 10. Distractor 6 comes from solving 4x = 6x + 5 with a sign slip.","skill":"Linear equations (proportions)"},{"cat":"algebra","a":0,"q":"A landscaper plants trees and shrubs. Each tree costs $45 and each shrub costs $20. If a job used 30 plants total costing $950, how many trees were planted?","options":["14","16","12","18"],"explanation":"Let t = trees: 45t + 20(30 - t) = 950, so 45t + 600 - 20t = 950, 25t = 350, t = 14. Distractor 16 mistakenly solves for shrubs.","skill":"Systems word problems"},{"cat":"algebra","a":0,"q":"The line 2x + 5y = 20 crosses the x-axis at which point?","options":["(10, 0)","(0, 4)","(4, 0)","(0, 10)"],"explanation":"At the x-axis y = 0: 2x = 20, x = 10, giving (10, 0). Distractor (0,4) is the y-intercept, not the x-intercept.","skill":"Linear equations two variables"},{"cat":"algebra","a":0,"q":"A pool is being filled. After 3 minutes it holds 84 gallons, and after 7 minutes it holds 156 gallons. How many gallons did it hold before filling began?","options":["30","42","18","48"],"explanation":"Rate = (156-84)/(7-3) = 72/4 = 18 per minute. Initial = 84 - 3(18) = 30. Distractor 42 incorrectly subtracts only one minute's worth.","skill":"Linear models from two points"},{"cat":"algebra","a":0,"q":"If 3x + 2y = 24 and y = 2x - 1, what is the value of x?","options":["26/7","4","3","22/7"],"explanation":"Substitute: 3x + 2(2x - 1) = 24, so 3x + 4x - 2 = 24, 7x = 26, x = 26/7. Distractor 4 wrongly drops the -2 term.","skill":"Systems by substitution"},{"cat":"algebra","a":0,"q":"A streaming service raised its monthly price by the same dollar amount each year. It was $9 in year 1 and $15 in year 4. Which expression gives the price in year n?","options":["7 + 2n","9 + 2n","6 + 3n","15 - 2n"],"explanation":"Increase = (15-9)/(4-1) = 2 per year. Price = 9 + 2(n-1) = 7 + 2n. Check year 1: 7+2=9. Distractor 9 + 2n gives $11 in year 1, which is wrong.","skill":"Building linear equations"},{"cat":"advanced","a":1,"q":"The function h is defined by h(x) = 3x^2 - 12x + 7. What is the x-coordinate of the vertex of the graph of h in the xy-plane?","options":["-2","2","4","7"],"explanation":"The vertex x-coordinate is -b/(2a) = -(-12)/(2*3) = 12/6 = 2. Choosing -2 comes from forgetting the sign on -b.","skill":"Quadratic vertex"},{"cat":"advanced","a":2,"q":"If (x - 5) is a factor of the polynomial p(x) = x^2 + kx - 30, what is the value of k?","options":["-6","-1","1","6"],"explanation":"If (x-5) is a factor then p(5)=0: 25 + 5k - 30 = 0, so 5k = 5 and k = 1. Choosing 6 comes from using the other root incorrectly.","skill":"Polynomial factors"},{"cat":"advanced","a":2,"q":"Which expression is equivalent to (2a^3 b^-2)^4 for positive a and b?","options":["8a^12 / b^8","16a^7 / b^6","16a^12 / b^8","2a^12 / b^8"],"explanation":"Raise each factor to the 4th: 2^4 = 16, (a^3)^4 = a^12, (b^-2)^4 = b^-8 = 1/b^8, giving 16a^12/b^8. Choosing 8a^12/b^8 misapplies 2^4 as 2*4.","skill":"Exponent rules"},{"cat":"advanced","a":2,"q":"For the equation x^2 - 6x + c = 0 to have exactly one real solution, what must be the value of c?","options":["3","6","9","12"],"explanation":"One real solution means the discriminant is 0: (-6)^2 - 4(1)(c) = 0, so 36 - 4c = 0 and c = 9. Choosing 6 comes from setting 36 = 6c.","skill":"Discriminant"},{"cat":"advanced","a":1,"q":"A culture starts with 240 bacteria and triples every 5 hours. Which function gives the number of bacteria after t hours?","options":["N(t) = 240(3)^(5t)","N(t) = 240(3)^(t/5)","N(t) = 240(5)^(t/3)","N(t) = 240 + 3(t/5)"],"explanation":"Tripling every 5 hours gives base 3 with exponent t/5, so N(t)=240(3)^(t/5). Choosing (3)^(5t) triples every 1/5 hour instead.","skill":"Exponential growth"},{"cat":"advanced","a":1,"q":"If f(x) = x^2 + 1 and g(x) = 2x - 3, what is f(g(2))?","options":["1","2","3","5"],"explanation":"g(2) = 2(2) - 3 = 1, then f(1) = 1^2 + 1 = 2. Choosing 5 computes g(f(2)) instead.","skill":"Function composition"},{"cat":"advanced","a":0,"q":"Which expression is equivalent to (x^2 - 9)/(x^2 + 7x + 12) for x not equal to -3 or -4?","options":["(x - 3)/(x + 4)","(x + 3)/(x + 4)","(x - 3)/(x - 4)","(x - 9)/(x + 12)"],"explanation":"Factor: (x-3)(x+3) over (x+3)(x+4); cancel (x+3) to get (x-3)/(x+4). Choosing (x+3)/(x+4) cancels the wrong factor.","skill":"Rational expressions"},{"cat":"advanced","a":3,"q":"The graph of y = a(x + 2)(x - 6) passes through the point (0, -24). What is the value of a?","options":["-2","-1","1","2"],"explanation":"Substitute (0,-24): -24 = a(2)(-6) = -12a, so a = 2. Choosing -2 drops a sign in -12a.","skill":"Quadratic from points"},{"cat":"advanced","a":0,"q":"Which of the following is equivalent to √(50x^5) for x greater than 0?","options":["5x^2 √(2x)","25x^2 √(2x)","5x √(10x)","10x^2 √(5x)"],"explanation":"√50 = 5√2 and √(x^5) = x^2 √x, so √(50x^5) = 5x^2 √(2x). Choosing 25x^2√(2x) squares the 5 incorrectly.","skill":"Radicals"},{"cat":"advanced","a":2,"q":"If 4^(2x) = 8^(x + 1), what is the value of x?","options":["1","2","3","4"],"explanation":"Write both with base 2: 2^(4x) = 2^(3x+3), so 4x = 3x + 3 and x = 3. Choosing 1 incorrectly sets 2x = x+1.","skill":"Exponential equations"},{"cat":"advanced","a":0,"q":"The expression (3x - 2)(x + 4) - (x^2 - 5) is equivalent to which of the following?","options":["2x^2 + 10x - 3","3x^2 + 10x - 13","2x^2 + 10x - 13","2x^2 + 14x - 3"],"explanation":"Expand: 3x^2 + 10x - 8, then subtract (x^2 - 5): 3x^2 + 10x - 8 - x^2 + 5 = 2x^2 + 10x - 3. Choosing the -13 option forgets to flip the sign of -5.","skill":"Polynomial operations"},{"cat":"advanced","a":2,"q":"A quantity decreases by 15% each year. If the initial amount is 800, which function models the amount A after y years?","options":["A(y) = 800(0.15)^y","A(y) = 800(1.15)^y","A(y) = 800(0.85)^y","A(y) = 800 - 0.15y"],"explanation":"A 15% decrease keeps 85% each year, so A(y)=800(0.85)^y. Choosing (0.15)^y uses the loss rate as the multiplier.","skill":"Exponential decay"},{"cat":"advanced","a":2,"q":"What is the sum of the solutions to the system y = x^2 - 2x and y = 3x - 4?","options":["1","3","5","6"],"explanation":"Set x^2 - 2x = 3x - 4, so x^2 - 5x + 4 = 0; solutions 1 and 4 sum to 5. Choosing 6 adds the wrong roots.","skill":"Nonlinear systems"},{"cat":"advanced","a":0,"q":"The function f is defined by f(x) = 2(x - 3)^2 - 8. What is the minimum value of f?","options":["-8","-3","2","3"],"explanation":"In vertex form 2(x-3)^2 - 8 with positive leading coefficient, the minimum value is -8 at x = 3. Choosing -3 confuses the vertex x-value with the minimum.","skill":"Quadratic minimum"},{"cat":"advanced","a":1,"q":"If 5/(x - 1) + 2 = 9/(x - 1), what is the value of x?","options":["1","3","4","6"],"explanation":"Subtract 5/(x-1) from both sides: 2 = 4/(x-1), so x - 1 = 2 and x = 3. Choosing 4 forgets to subtract the 5/(x-1) term first.","skill":"Rational equations"},{"cat":"advanced","a":0,"q":"Which of the following is a factor of 6x^2 + 11x - 10?","options":["3x - 2","2x - 5","2x + 5","3x + 5"],"explanation":"Factor: 6x^2 + 11x - 10 = (3x - 2)(2x + 5). So 3x - 2 is a factor. Choosing 2x - 5 has the wrong sign.","skill":"Factoring quadratics"},{"cat":"advanced","a":1,"q":"The graph of g(x) = x^2 is shifted 4 units right and 3 units down. Which equation represents the new graph?","options":["g(x) = (x + 4)^2 - 3","g(x) = (x - 4)^2 - 3","g(x) = (x - 4)^2 + 3","g(x) = (x - 3)^2 - 4"],"explanation":"A right shift of 4 gives (x - 4)^2 and a down shift of 3 subtracts 3: (x - 4)^2 - 3. Choosing (x + 4)^2 shifts left instead of right.","skill":"Transformations"},{"cat":"advanced","a":0,"q":"If the polynomial p(x) = x^3 - 4x^2 + x + 6 has a zero at x = 3, which factored form is correct?","options":["(x - 3)(x + 1)(x - 2)","(x - 3)(x - 1)(x + 2)","(x - 3)(x + 1)(x + 2)","(x + 3)(x - 1)(x - 2)"],"explanation":"Dividing by (x-3) gives x^2 - x - 2 = (x+1)(x-2), so p(x)=(x-3)(x+1)(x-2). Check zeros 3, -1, 2 satisfy p. Choosing (x-1)(x+2) has the wrong inner factors.","skill":"Polynomial zeros"},{"cat":"advanced","a":2,"q":"For positive x, the expression (x^(1/2) * x^(1/3)) / x^(1/6) is equivalent to which of the following?","options":["x^(1/3)","x^(1/2)","x^(2/3)","x"],"explanation":"Add and subtract exponents: 1/2 + 1/3 - 1/6 = 3/6 + 2/6 - 1/6 = 4/6 = 2/3, giving x^(2/3). Choosing x^(1/2) adds 1/2 and 1/3 to 1/2 only.","skill":"Rational exponents"},{"cat":"advanced","a":1,"q":"The quadratic f(x) = -x^2 + 8x - 12 models the height, in feet, of an object x seconds after launch. At what value of x is the height greatest?","options":["2","4","6","8"],"explanation":"Maximum occurs at x = -b/(2a) = -8/(2*-1) = 4 seconds. Choosing 8 uses b without dividing by 2a.","skill":"Quadratic maximum"},{"cat":"advanced","a":1,"q":"What are all real solutions to the equation x^4 - 13x^2 + 36 = 0?","options":["x = 2 and x = 3 only","x = -2, 2, -3, 3","x = 4 and x = 9","x = -4, 4, -9, 9"],"explanation":"Let u = x^2: u^2 - 13u + 36 = (u-4)(u-9)=0, so x^2 = 4 or 9, giving x = ±2, ±3. Choosing x = 4 and 9 forgets to take square roots.","skill":"Quadratic in form"},{"cat":"advanced","a":0,"q":"If f(x) = 5x - 2, what is f^-1(x), the inverse function?","options":["(x + 2)/5","(x - 2)/5","5x + 2","(2 - x)/5"],"explanation":"Solve y = 5x - 2 for x: x = (y + 2)/5, so f^-1(x) = (x + 2)/5. Choosing (x - 2)/5 subtracts instead of adds.","skill":"Inverse functions"},{"cat":"advanced","a":0,"q":"The value of an investment is modeled by V(t) = 1500(1.04)^t dollars after t years. What does the 1.04 represent?","options":["A 4% increase each year","A 14% increase each year","A 104% increase each year","A 0.04% increase each year"],"explanation":"A growth factor of 1.04 means the value grows by 4% per year. Choosing 104% misreads the factor as the percent increase itself.","skill":"Exponential models"},{"cat":"advanced","a":0,"q":"Which expression is equivalent to 1/(x + 2) - 1/(x + 5)?","options":["3 / ((x + 2)(x + 5))","-3 / ((x + 2)(x + 5))","7 / ((x + 2)(x + 5))","(2x + 7) / ((x + 2)(x + 5))"],"explanation":"Common denominator: [(x+5) - (x+2)] / ((x+2)(x+5)) = 3 / ((x+2)(x+5)). Choosing -3 flips the subtraction order.","skill":"Combining rationals"},{"cat":"advanced","a":3,"q":"The system y = x^2 + 2 and y = k has no real solutions. Which of the following could be the value of k?","options":["6","4","2","0"],"explanation":"Since x^2 + 2 is always at least 2, the line y = k misses the parabola only when k < 2; among the choices only k = 0 works. Choosing 2 gives one solution (tangent), not zero.","skill":"Nonlinear systems"},{"cat":"advanced","a":1,"q":"A ball's height in meters is h(t) = -5t^2 + 20t. For what positive value of t does the ball return to the ground (h = 0)?","options":["2","4","5","20"],"explanation":"Set -5t^2 + 20t = 0, factor -5t(t - 4) = 0, so t = 0 or t = 4; the positive value is 4. Choosing 2 gives the vertex time, not the landing time.","skill":"Quadratic roots"},{"cat":"advanced","a":0,"q":"Which of the following is equivalent to (x^2 - x - 12)/(x - 4) for x not equal to 4?","options":["x + 3","x - 3","x + 4","x - 12"],"explanation":"Factor numerator: (x - 4)(x + 3); cancel (x - 4) to get x + 3. Choosing x - 3 uses the wrong factor sign.","skill":"Rational simplification"},{"cat":"advanced","a":0,"q":"The function f is defined by f(x) = ax^2 + bx + c with a > 0. If the discriminant b^2 - 4ac is negative, how many times does the graph of f cross the x-axis?","options":["0","1","2","Cannot be determined"],"explanation":"A negative discriminant means no real roots, so the graph never crosses the x-axis (0 times). Choosing 2 ignores the sign of the discriminant.","skill":"Discriminant meaning"},{"cat":"data","a":1,"q":"A printing shop produces 14 booklets every 6 minutes when all machines run. At this rate, how many booklets does the shop produce in 45 minutes?","options":["98","105","112","120"],"explanation":"Rate = 14/6 booklets per minute. In 45 minutes: (14/6)(45) = 14*7.5 = 105. A common error of using 14/6 rounded to 2 per minute gives 90; multiplying 14 by 45/6=7.5 correctly gives 105. The distractor 112 comes from 14*8 (rounding 7.5 up).","skill":"rates"},{"cat":"data","a":1,"q":"A recipe uses flour and sugar in a ratio of 5 to 2 by weight. If a baker uses 350 grams of flour, how many grams of sugar are needed to keep the same ratio?","options":["120","140","175","700"],"explanation":"5 parts flour = 350 g, so 1 part = 70 g. Sugar = 2 parts = 140 g. The distractor 175 comes from incorrectly taking half of 350 (a 2-to-1 thought), and 700 reverses the ratio (multiplying instead of dividing).","skill":"ratios"},{"cat":"data","a":2,"q":"A car travels 234 kilometers using 18 liters of fuel. At this efficiency, how many liters are needed to travel 390 kilometers?","options":["26","28","30","32.5"],"explanation":"Efficiency = 234/18 = 13 km per liter. Liters for 390 km = 390/13 = 30. The distractor 26 comes from dividing 390 by 15 (a wrong efficiency), and 32.5 from using 12 km/L.","skill":"proportions"},{"cat":"data","a":2,"q":"A length is measured as 3.5 yards. Given that 1 yard equals 3 feet and 1 foot equals 12 inches, how many inches is this length?","options":["42","105","126","378"],"explanation":"3.5 yards * 3 = 10.5 feet; 10.5 * 12 = 126 inches. The distractor 42 stops at converting yards to feet only by 12 (3.5*12), and 105 multiplies 10.5 by 10.","skill":"unit conversion"},{"cat":"data","a":1,"q":"A water tank fills at a constant rate of 2.5 gallons every 20 seconds. How many minutes does it take to fill a 450-gallon tank?","options":["50","60","75","90"],"explanation":"Rate = 2.5/20 = 0.125 gallons per second. Time = 450/0.125 = 3600 seconds = 60 minutes. The distractor 75 comes from using 0.1 gal/s; 90 from dividing 450 by 5.","skill":"rates"},{"cat":"data","a":2,"q":"A jacket originally priced at 80 dollars is marked up by 25%, and later the new price is reduced by 20%. What is the final price?","options":["76 dollars","78 dollars","80 dollars","84 dollars"],"explanation":"After 25% markup: 80*1.25 = 100. After 20% reduction: 100*0.80 = 80. The increases and decreases cancel here. A common error assumes +25% then -20% equals +5%, giving 84.","skill":"percent change"},{"cat":"data","a":0,"q":"A population of 1,200 increases by 15% in one year, then decreases by 10% the next year. What is the population after two years?","options":["1,242","1,260","1,290","1,350"],"explanation":"After +15%: 1200*1.15 = 1380. After -10%: 1380*0.90 = 1242. The distractor 1260 comes from applying a net +5% (1200*1.05), ignoring that percents apply to different bases.","skill":"percent change"},{"cat":"data","a":1,"q":"In a survey, 240 people responded, and 18% said they prefer tea. How many of the respondents did NOT say they prefer tea?","options":["43","197","202","222"],"explanation":"18% prefer tea means 82% do not: 240*0.82 = 196.8, which rounds to 197 people. The distractor 43 is the number who prefer tea (240*0.18 = 43.2), answering the wrong question.","skill":"percentages"},{"cat":"data","a":2,"q":"A store's revenue rose from 45,000 dollars to 58,500 dollars over a year. What was the percent increase in revenue?","options":["13.5%","23.1%","30%","43%"],"explanation":"Increase = 58500 - 45000 = 13500. Percent = 13500/45000 = 0.30 = 30%. The distractor 23.1% wrongly divides 13500 by 58500 (the new value instead of the original).","skill":"percent change"},{"cat":"data","a":1,"q":"The seven daily high temperatures, in degrees, for a week were 68, 72, 75, 70, 68, 74, and 79. What is the mean of these temperatures?","options":["70","72","73","75"],"explanation":"Sum = 68+72+75+70+68+74+79 = 506. Mean = 506/7 = 72.28..., which rounds to 72. The distractor 70 is the mode/a middle-looking value, not the computed mean.","skill":"mean"},{"cat":"data","a":1,"q":"A data set consists of the values 4, 9, 9, 12, 15, 21, and 30. What is the median of this data set?","options":["9","12","13","15"],"explanation":"With 7 values in order, the median is the 4th value: 12. The distractor 13 is the mean (sum 100 divided by... actually 100/7), and 9 is the mode, neither of which is the median.","skill":"median"},{"cat":"data","a":0,"q":"A list of six numbers has a mean of 14. If five of the numbers are 10, 12, 15, 18, and 20, what is the sixth number?","options":["9","11","12","14"],"explanation":"Total must be 6*14 = 84. The five given sum to 75, so the sixth is 84 - 75 = 9. The distractor 14 wrongly assumes the missing value equals the mean.","skill":"mean"},{"cat":"data","a":2,"q":"For the values 23, 19, 35, 28, 41, and 19, what is the range?","options":["16","19","22","41"],"explanation":"Range = maximum minus minimum = 41 - 19 = 22. The distractor 19 is the minimum (and the mode), and 41 is just the maximum, not the range.","skill":"range"},{"cat":"data","a":1,"q":"A teacher records seven quiz scores: 88, 91, 76, 88, 95, 82, and 88. Which statement is true about these scores?","options":["The mean is greater than the mode","The median equals the mode","The mode is 91","The range is 88"],"explanation":"Ordered: 76,82,88,88,88,91,95. Median (4th value) = 88, and mode = 88, so they are equal. The mean is 608/7 = 86.86, which is less than the mode 88, so the first option is false.","skill":"mean median mode"},{"cat":"data","a":1,"q":"Two classes each took the same test. Class A scores were tightly grouped between 78 and 84, while Class B scores ranged widely from 55 to 99, with the same mean as Class A. Which statement about standard deviation is correct?","options":["Class A has a larger standard deviation","Class B has a larger standard deviation","Both have equal standard deviation","Standard deviation cannot be compared without the median"],"explanation":"Standard deviation measures spread from the mean. Class B's scores are spread far more widely than Class A's tightly clustered scores, so Class B has the larger standard deviation. Equal means do not imply equal spread.","skill":"standard deviation"},{"cat":"data","a":1,"q":"Data set X is {30, 30, 30, 30, 30} and data set Y is {10, 20, 30, 40, 50}. Both have a mean of 30. Which statement correctly compares their standard deviations?","options":["X has a greater standard deviation than Y","Y has a greater standard deviation than X","Both have a standard deviation of zero","Both have equal nonzero standard deviation"],"explanation":"Set X has identical values, so its standard deviation is 0. Set Y varies around the mean, giving a positive standard deviation. Therefore Y has the greater standard deviation. Equal means do not force equal spread.","skill":"standard deviation"},{"cat":"data","a":1,"q":"A spinner has 12 equal sections numbered 1 through 12. What is the probability that a single spin lands on a number that is a multiple of 3 or equal to 10?","options":["1/4","5/12","1/2","7/12"],"explanation":"Multiples of 3: 3,6,9,12 (four numbers). Adding 10 gives five favorable outcomes. Probability = 5/12. The distractor 1/4 counts only the four multiples of 3 and forgets 10.","skill":"probability"},{"cat":"data","a":1,"q":"A survey of 200 commuters recorded mode of travel and gender. Of 120 men, 45 take the bus and the rest drive. Of 80 women, 60 take the bus and the rest drive. If a randomly selected commuter takes the bus, what is the probability the commuter is a woman?","options":["3/7","4/7","3/8","60/200"],"explanation":"Total bus riders = 45 + 60 = 105. Of these, 60 are women, so P = 60/105 = 4/7. The distractor 60/200 = 3/10 wrongly divides by all commuters instead of only bus riders.","skill":"conditional probability"},{"cat":"data","a":0,"q":"In a group of 150 students, 90 play a sport and 70 are in a club; 40 do both. If a student selected at random is in a club, what is the probability that the student also plays a sport?","options":["4/7","4/9","40/150","4/15"],"explanation":"Conditional probability given club membership: of the 70 club members, 40 also play a sport, so P = 40/70 = 4/7. The distractor 40/150 divides by the whole group rather than only club members.","skill":"conditional probability"},{"cat":"data","a":0,"q":"A two-way table classifies 300 phones by brand (X or Y) and condition (new or refurbished). Brand X has 110 new and 40 refurbished. Brand Y has 90 new and 60 refurbished. Given that a phone is refurbished, what is the probability it is brand X?","options":["2/5","2/3","40/300","2/7"],"explanation":"Total refurbished = 40 + 60 = 100. Brand X refurbished = 40, so P = 40/100 = 2/5. The distractor 40/300 = 2/15 divides by all phones instead of only refurbished ones.","skill":"conditional probability"},{"cat":"data","a":1,"q":"A frequency table lists ages of 50 club members: 10 are aged 14, 15 are aged 15, 20 are aged 16, and 5 are aged 17. What is the median age of the members?","options":["15","15.5","16","16.5"],"explanation":"With 50 members, the median is the average of the 25th and 26th values. Ages 14 fill positions 1-10 and ages 15 fill positions 11-25, so the 25th value is 15 and the 26th value (first age 16) is 16. The median is (15+16)/2 = 15.5. The distractor 16 ignores that the 25th value is still 15.","skill":"table interpretation"},{"cat":"data","a":2,"q":"A table shows monthly sales (in units) for four products: P at 320, Q at 280, R at 450, and S at 150. If total sales were 1,200 units, what percent of total sales did product R account for?","options":["27.5%","30%","37.5%","45%"],"explanation":"R's share = 450/1200 = 0.375 = 37.5%. The distractor 30% comes from dividing 450 by 1500 (a wrong total), and 45% mistakes the raw 450 as a percent.","skill":"table interpretation"},{"cat":"data","a":1,"q":"A bar graph shows rainfall over four months: March 4 inches, April 6 inches, May 9 inches, and June 5 inches. By what percent did rainfall increase from April to May?","options":["33%","50%","60%","150%"],"explanation":"Increase = 9 - 6 = 3 inches over a base of 6: 3/6 = 0.50 = 50%. The distractor 33% wrongly divides 3 by 9 (the new value), and 150% mistakes the ratio 9/6.","skill":"graph interpretation"},{"cat":"data","a":2,"q":"A scatterplot of hours studied (x) versus test score (y) has a line of best fit y = 6x + 52. Based on this model, what is the predicted score for a student who studies 7 hours?","options":["88","90","94","98"],"explanation":"y = 6(7) + 52 = 42 + 52 = 94. The distractor 88 comes from forgetting the intercept partly (6*6+52), and 98 from using slope 7 mistakenly (7*7-ish miscalc).","skill":"line of best fit"},{"cat":"data","a":1,"q":"A line of best fit for a scatterplot of years since opening (x) and annual members (y) is y = 120x + 540. What does the slope 120 represent in this context?","options":["The number of members when the gym opened","The predicted increase in members each year","The total members after 120 years","The year the gym reached 540 members"],"explanation":"The slope is the change in y per one-unit change in x, so 120 is the predicted yearly increase in members. The intercept 540, not the slope, represents the starting membership.","skill":"line of best fit"},{"cat":"data","a":1,"q":"A scatterplot shows a strong negative linear association between a car's age (x, years) and its resale value (y, dollars). The line of best fit is y = -1,500x + 24,000. Approximately what is the predicted resale value of an 8-year-old car?","options":["10,000 dollars","12,000 dollars","13,500 dollars","16,500 dollars"],"explanation":"y = -1500(8) + 24000 = -12000 + 24000 = 12000 dollars. The distractor 10000 comes from using -1750 per year, and 16500 from subtracting only one 1500 increment.","skill":"line of best fit"},{"cat":"data","a":2,"q":"A researcher wants to estimate the average daily screen time of all students at a large university. Which sampling method would most likely produce an unbiased estimate?","options":["Surveying students leaving the computer lab","Surveying students who post on a gaming forum","Selecting students at random from the full enrollment list","Surveying members of the e-sports club"],"explanation":"A random selection from the entire enrollment list gives every student an equal chance and avoids favoring heavy screen users. The other methods oversample groups likely to have high screen time, biasing the estimate upward.","skill":"sampling"},{"cat":"data","a":1,"q":"A poll estimates that 52% of voters favor a measure, with a margin of error of 3 percentage points at a 95% confidence level. Which conclusion is most appropriate?","options":["Exactly 52% of all voters favor the measure","The true percentage is plausibly between 49% and 55%","More than 55% of all voters favor the measure","The true percentage is exactly 49% or 55%"],"explanation":"The margin of error gives a plausible interval of 52% plus or minus 3%, i.e., 49% to 55%. The point estimate 52% is not exact, and values outside the interval are not supported by the data.","skill":"margin of error"},{"cat":"data","a":1,"q":"Two surveys estimate the same population proportion. Survey A samples 400 people and Survey B samples 1,600 people, using the same random method. Which statement about the margin of error is correct?","options":["Survey A has a smaller margin of error","Survey B has a smaller margin of error","Both have the same margin of error","Margin of error does not depend on sample size"],"explanation":"Larger random samples reduce the margin of error, so Survey B with 1,600 people has the smaller margin of error. Margin of error decreases as sample size increases, all else equal.","skill":"margin of error"},{"cat":"geometry","a":1,"q":"A rectangle has a length of 14 cm and a width of 9 cm. What is the perimeter of the rectangle?","options":["23 cm","46 cm","63 cm","126 cm"],"explanation":"Perimeter = 2(length + width) = 2(14 + 9) = 2(23) = 46 cm. The distractor 23 forgets to double the sum; 126 is the area.","skill":"perimeter"},{"cat":"geometry","a":1,"q":"A circle has a radius of 7 inches. What is the circumference of the circle? (Use the exact value in terms of π.)","options":["7π inches","14π inches","28π inches","49π inches"],"explanation":"Circumference = 2πr = 2π(7) = 14π inches. The distractor 49π is the area (πr^2); 7π uses radius instead of diameter.","skill":"circumference"},{"cat":"geometry","a":0,"q":"In a triangle, two of the interior angles measure 58° and 47°. What is the measure of the third interior angle?","options":["75°","85°","95°","105°"],"explanation":"Angle sum of a triangle is 180°, so the third angle = 180 − 58 − 47 = 75°. The distractor 105° is the supplement of one combination, not the missing angle.","skill":"triangle angle sum"},{"cat":"geometry","a":1,"q":"A right triangle has legs of length 9 and 12. What is the length of the hypotenuse?","options":["13","15","18","21"],"explanation":"By the Pythagorean theorem, hypotenuse = √(9^2 + 12^2) = √(81 + 144) = √225 = 15. The distractor 21 incorrectly adds the legs (9 + 12).","skill":"Pythagorean theorem"},{"cat":"geometry","a":1,"q":"Two parallel lines are cut by a transversal. One of the angles formed measures 113°. What is the measure of its co-interior (same-side interior) angle?","options":["57°","67°","77°","113°"],"explanation":"Co-interior angles on the same side of a transversal are supplementary, so the angle = 180 − 113 = 67°. The distractor 113° wrongly treats them as equal (alternate angles).","skill":"parallel line angles"},{"cat":"geometry","a":3,"q":"A cube has an edge length of 5 m. What is the volume of the cube?","options":["15 m^3","25 m^3","75 m^3","125 m^3"],"explanation":"Volume of a cube = edge^3 = 5^3 = 125 m^3. The distractor 25 is the area of one face; 75 is the total surface area divided.","skill":"volume of solids"},{"cat":"geometry","a":1,"q":"In a 45-45-90 right triangle, each leg has length 6. What is the length of the hypotenuse?","options":["6","6√2","6√3","12"],"explanation":"In a 45-45-90 triangle the hypotenuse equals leg × √2 = 6√2. The distractor 6√3 confuses the ratio with a 30-60-90 triangle.","skill":"special right triangles"},{"cat":"geometry","a":0,"q":"An angle measures 135°. What is the equivalent measure in radians?","options":["3π/4","2π/3","5π/6","5π/4"],"explanation":"Multiply by π/180: 135 × π/180 = 135π/180 = 3π/4 radians. The distractor 5π/4 corresponds to 225°, an arithmetic slip.","skill":"degree to radian"},{"cat":"geometry","a":0,"q":"In right triangle ABC, the right angle is at C. The side opposite angle A has length 8 and the hypotenuse has length 17. What is sin(A)?","options":["8/17","15/17","8/15","17/8"],"explanation":"sin(A) = opposite/hypotenuse = 8/17. The distractor 15/17 is cos(A), since the adjacent leg is √(17^2 − 8^2) = 15.","skill":"right triangle trig"},{"cat":"geometry","a":2,"q":"A cylinder has a radius of 4 cm and a height of 10 cm. What is its volume? (Express in terms of π.)","options":["40π cm^3","80π cm^3","160π cm^3","400π cm^3"],"explanation":"Volume = πr^2h = π(4^2)(10) = π(16)(10) = 160π cm^3. The distractor 80π uses r instead of r^2 incorrectly (π·4·... ) / 40π drops a factor.","skill":"volume of cylinder"},{"cat":"geometry","a":1,"q":"A circle has a radius of 9. A sector of this circle has a central angle of 40°. What is the area of the sector? (Express in terms of π.)","options":["4π","9π","18π","81π"],"explanation":"Sector area = (central angle/360)·πr^2 = (40/360)·π(81) = (1/9)(81π) = 9π. The distractor 18π doubles by mistaking the fraction as 2/9.","skill":"sector area"},{"cat":"geometry","a":2,"q":"Triangle DEF is similar to triangle GHI. Side DE = 6 corresponds to side GH = 15. If side EF = 10, what is the length of the corresponding side HI?","options":["19","21","25","30"],"explanation":"The scale factor is 15/6 = 2.5, so HI = 10 × 2.5 = 25. The distractor 19 incorrectly adds the difference (10 + 9) instead of scaling.","skill":"similar triangles"},{"cat":"geometry","a":0,"q":"A circle in the xy-plane has equation (x − 3)^2 + (y + 5)^2 = 49. What are the coordinates of the center of the circle?","options":["(3, −5)","(−3, 5)","(3, 5)","(−3, −5)"],"explanation":"For (x − h)^2 + (y − k)^2 = r^2, the center is (h, k) = (3, −5). The distractor (−3, 5) flips both signs incorrectly.","skill":"equation of a circle"},{"cat":"geometry","a":2,"q":"Two angles are vertical angles. One of them is described by the expression (4x + 10)° and the other by (6x − 20)°. What is the value of x?","options":["5","10","15","20"],"explanation":"Vertical angles are equal: 4x + 10 = 6x − 20, so 30 = 2x and x = 15. The distractor 5 comes from setting the sum to 180° (supplementary) by mistake.","skill":"vertical angles"},{"cat":"geometry","a":1,"q":"A right circular cone has a radius of 6 and a height of 8. What is the volume of the cone? (Express in terms of π.)","options":["48π","96π","144π","288π"],"explanation":"Volume = (1/3)πr^2h = (1/3)π(36)(8) = (1/3)(288π) = 96π. The distractor 288π forgets the factor of 1/3.","skill":"volume of cone"},{"cat":"geometry","a":0,"q":"In right triangle PQR, angle Q is the right angle. If sin(P) = 3/5, what is cos(R)?","options":["3/5","4/5","5/3","5/4"],"explanation":"Angles P and R are complementary, so cos(R) = sin(P) = 3/5. The distractor 4/5 equals cos(P) = sin(R), the wrong complementary match.","skill":"complementary angle trig"},{"cat":"geometry","a":0,"q":"A circle has a radius of 12. An arc of the circle is intercepted by a central angle of 75°. What is the length of the arc? (Express in terms of π.)","options":["5π","10π","15π","18π"],"explanation":"Arc length = (central angle/360)·2πr = (75/360)·2π(12) = (75/360)(24π) = 5π. The distractor 10π doubles the fraction in error.","skill":"arc length"},{"cat":"geometry","a":2,"q":"A rectangular prism has dimensions 3 cm by 5 cm by 8 cm. What is the total surface area of the prism?","options":["79 cm^2","120 cm^2","158 cm^2","316 cm^2"],"explanation":"Surface area = 2(lw + lh + wh) = 2(15 + 24 + 40) = 2(79) = 158 cm^2. The distractor 79 is the sum before doubling; 120 is the volume.","skill":"surface area"},{"cat":"geometry","a":1,"q":"In a circle, an inscribed angle intercepts an arc whose central angle measures 96°. What is the measure of the inscribed angle?","options":["24°","48°","96°","192°"],"explanation":"An inscribed angle is half the central angle that subtends the same arc: 96/2 = 48°. The distractor 192° doubles instead of halves.","skill":"inscribed angles"},{"cat":"geometry","a":1,"q":"A square has a diagonal of length 10√2. What is the area of the square?","options":["50","100","141","200"],"explanation":"The side equals diagonal/√2 = 10√2/√2 = 10, so area = 10^2 = 100. The distractor 200 squares the diagonal directly without dividing by 2.","skill":"area of square"},{"cat":"geometry","a":1,"q":"Right triangle JKL has the right angle at K. The leg JK = 5 and the leg KL = 12. What is tan(J)?","options":["5/12","12/5","5/13","12/13"],"explanation":"tan(J) = opposite/adjacent = KL/JK = 12/5. The distractor 5/12 inverts the ratio (uses adjacent over opposite).","skill":"right triangle trig"},{"cat":"geometry","a":1,"q":"An angle measures 7π/6 radians. What is the equivalent measure in degrees?","options":["150°","210°","240°","330°"],"explanation":"Multiply by 180/π: (7π/6)(180/π) = 7(30) = 210°. The distractor 150° corresponds to 5π/6, a numerator slip.","skill":"radian to degree"},{"cat":"geometry","a":2,"q":"A sphere has a radius of 3. What is the surface area of the sphere? (Express in terms of π.)","options":["12π","27π","36π","108π"],"explanation":"Surface area of a sphere = 4πr^2 = 4π(9) = 36π. The distractor 12π uses 4πr instead of 4πr^2; 108π multiplies 4·27 using r^3.","skill":"surface area of sphere"},{"cat":"geometry","a":1,"q":"Two complementary angles have measures (2x + 5)° and (3x − 10)°. What is the value of x?","options":["17","19","35","39"],"explanation":"Complementary angles sum to 90°: (2x + 5) + (3x − 10) = 90, so 5x − 5 = 90, 5x = 95, x = 19. The distractor 35 wrongly uses a sum of 180° (supplementary).","skill":"complementary angles"},{"cat":"geometry","a":2,"q":"A trapezoid has parallel sides (bases) of length 8 and 14 and a height of 6. What is the area of the trapezoid?","options":["33","44","66","132"],"explanation":"Area = (1/2)(b1 + b2)(h) = (1/2)(8 + 14)(6) = (1/2)(22)(6) = 66. The distractor 132 forgets the factor of 1/2.","skill":"area of trapezoid"},{"cat":"geometry","a":1,"q":"A circle in the xy-plane passes through the point (10, 2) and has center (4, 2). What is the equation of the circle?","options":["(x − 4)^2 + (y − 2)^2 = 6","(x − 4)^2 + (y − 2)^2 = 36","(x + 4)^2 + (y + 2)^2 = 36","(x − 10)^2 + (y − 2)^2 = 36"],"explanation":"The radius is the distance from (4,2) to (10,2) = 6, so r^2 = 36 and the equation is (x − 4)^2 + (y − 2)^2 = 36. The distractor with =6 forgets to square the radius.","skill":"equation of a circle"},{"cat":"geometry","a":1,"q":"A right triangle has a hypotenuse of length 26 and one leg of length 24. A second right triangle is similar to the first with a scale factor of 1.5. What is the length of the shorter leg of the second triangle?","options":["10","15","16","20"],"explanation":"The missing leg of the first triangle is √(26^2 − 24^2) = √(676 − 576) = √100 = 10, the shorter leg. Scaled by 1.5: 10 × 1.5 = 15. The distractor 10 ignores the scale factor.","skill":"similar triangles"},{"cat":"geometry","a":2,"q":"A solid consists of a cylinder of radius 2 and height 9 topped by a cone of radius 2 and height 6. What is the total volume of the solid? (Express in terms of π.)","options":["36π","40π","44π","48π"],"explanation":"Cylinder volume = π(2^2)(9) = 36π; cone volume = (1/3)π(2^2)(6) = 8π; total = 36π + 8π = 44π. The distractor 36π omits the cone's volume.","skill":"composite volume"},{"cat":"geometry","a":1,"q":"In right triangle ABC, the right angle is at B. The legs are AB = 9 and BC = 9. A point D lies on AC such that BD is perpendicular to AC. What is the length of BD?","options":["4.5","4.5√2","9","9√2"],"explanation":"Triangle ABC is a 45-45-90 with legs 9, so AC = 9√2. BD is the altitude to the hypotenuse from the right angle; for an isosceles right triangle BD = (1/2)AC = (1/2)(9√2) = 4.5√2. The distractor 4.5 uses half a leg, not half the hypotenuse.","skill":"special right triangles"},{"cat":"information","a":0,"q":"The desert tortoise survives long droughts by storing water in a large bladder, which can hold a volume of liquid equal to nearly forty percent of the animal's body weight. During the dry season, the tortoise reabsorbs this stored water as needed, allowing it to go for more than a year without drinking. This reserve is so vital that biologists urge hikers never to handle a wild tortoise, because a frightened animal may empty its bladder and lose its only buffer against the heat.\n\nWhich choice best states the main idea of the text?","options":["The desert tortoise's stored water is essential to its survival, so disturbing the animal can be dangerous.","Hikers frequently encounter desert tortoises during the dry season.","The desert tortoise prefers to drink water rather than reabsorb it from its bladder.","Biologists have only recently learned how the desert tortoise stores water."],"explanation":"The text emphasizes that the stored water is vital and that frightening the tortoise causes it to lose this buffer, supporting choice A. Choice B introduces frequency of encounters not discussed; the text never claims hikers encounter tortoises often.","skill":"central idea"},{"cat":"information","a":1,"q":"In her short story, the narrator describes her grandmother's kitchen: \"Every jar bore a label in her cramped hand, every spoon hung from its own nail, and the flour bin was wiped clean each night before she allowed herself to sit.\" The narrator notes that as a child she found these habits exhausting to watch, yet as an adult she keeps her own pantry in the very same order.\n\nWhich choice best describes the function of the second sentence in the text?","options":["It questions whether the grandmother's habits were truly as strict as described.","It reveals that the narrator has come to adopt the orderly habits she once found tiring.","It explains why the grandmother first developed her careful routines.","It suggests that the narrator dislikes spending time in her own kitchen."],"explanation":"The second sentence contrasts the narrator's childhood reaction with her adult behavior, showing she now keeps the same order, supporting B. Choice C is unsupported because the text never explains the origin of the grandmother's routines.","skill":"text structure / function"},{"cat":"information","a":1,"q":"A team of marine ecologists studied how artificial reefs made from sunken ships affect local fish populations. They found that within three years, the sunken structures hosted nearly as many fish species as nearby natural reefs of similar size. However, the researchers cautioned that the artificial reefs attracted fish from surrounding areas rather than necessarily increasing the total number of fish in the region.\n\nWhich choice most logically completes the text?","options":["the artificial reefs had clearly reduced the number of fish living on natural reefs.","the high species count at the artificial reefs may not represent a true gain in the overall fish population.","natural reefs are no longer necessary for supporting diverse fish communities.","sunken ships are the most effective method available for breeding new fish species."],"explanation":"The caution that fish were attracted from surrounding areas rather than added suggests the high count may not reflect a real population gain, supporting B. Choice A overstates the finding; the text says fish may have been drawn away but does not state natural reef numbers clearly dropped.","skill":"inference"},{"cat":"information","a":1,"q":"Historians once assumed that the medieval trade routes across the Sahara carried mainly gold and salt. Recent analysis of merchant ledgers recovered from an oasis town, however, lists copper, glass beads, and books among the most frequently recorded goods, with gold appearing far less often than expected.\n\nWhich finding, if true, would most directly support the conclusion that the recovered ledgers give an incomplete picture of the trade?","options":["The ledgers were written in a script used widely across the region during the period.","Gold was typically recorded by separate officials in documents that have not survived.","Copper and glass beads were valued highly by buyers in distant markets.","The oasis town was located along one of the busiest routes in the network."],"explanation":"If gold was tracked in separate, now-lost documents, the surviving ledgers would naturally understate gold, making the picture incomplete, supporting B. Choice C explains why other goods were traded but does not address why the ledgers might misrepresent gold's role.","skill":"command of evidence (textual)"},{"cat":"information","a":0,"q":"A psychologist tested whether brief exposure to nature images could improve concentration. Participants completed a demanding attention task, took a short break viewing either photos of green landscapes or photos of city streets, and then repeated the task. Those who viewed the landscapes showed a measurable improvement in accuracy on the second round, while those who viewed city scenes did not.\n\nWhich choice most logically completes the text?","options":["the content of a restorative break, not merely its existence, may influence later performance.","city scenes are more distracting than green landscapes in every kind of task.","longer breaks always lead to greater improvements in concentration.","viewing photographs has no effect on performance of attention tasks."],"explanation":"Both groups took a break but only the landscape group improved, indicating that what is viewed during the break matters, supporting A. Choice D contradicts the result, since the landscape group did improve after viewing photos.","skill":"inference"},{"cat":"information","a":1,"q":"Text 1: Linguist Dara Okoye argues that languages with very large vocabularies allow speakers to express ideas with greater precision, reducing misunderstandings in technical fields.\n\nText 2: Linguist Marco Vella counters that speakers of languages with smaller core vocabularies routinely combine simple words into precise compounds, achieving the same clarity without a vast store of distinct terms.\n\nBased on the texts, how would Vella most likely respond to Okoye's argument?","options":["By agreeing that large vocabularies are necessary for precise technical communication.","By noting that precision can be achieved through word combination, not only through many distinct words.","By arguing that technical fields rarely require precise language at all.","By claiming that misunderstandings are equally common in all languages."],"explanation":"Vella's view is that combining simple words yields the same clarity, so he would emphasize combination over a large stock of words, supporting B. Choice A reverses Vella's position, which disputes the necessity of large vocabularies.","skill":"cross-text connections"},{"cat":"information","a":0,"q":"An engineer testing a new bicycle helmet design measured the force transmitted to a model head during simulated crashes. Three designs were compared. Design A transmitted an average of 180 units of force, Design B transmitted 145 units, and Design C transmitted 120 units; lower values indicate better protection. The engineer concluded that Design C offered the best protection of the three.\n\nWhich choice best uses data from the text to support the engineer's conclusion?","options":["Design C transmitted 120 units of force, the lowest of the three designs.","Design A transmitted 180 units of force, more than the other designs.","Design B transmitted 145 units, placing it between the other two designs.","All three designs transmitted fewer than 200 units of force."],"explanation":"Since lower force means better protection, Design C's lowest value of 120 directly supports the conclusion that it protects best, supporting A. Choice B describes only Design A and does not establish that C is best.","skill":"command of evidence (quantitative)"},{"cat":"information","a":1,"q":"The composer Hadley Reyes was known for revising her works obsessively, sometimes returning to a finished symphony years later to alter a single passage. Critics complained that this made her catalog difficult to publish, since no version could be called final. Reyes, however, viewed each performance as a living draft and insisted that a piece of music was never truly complete.\n\nIt can most reasonably be inferred from the text that Reyes believed","options":["her music should be performed exactly the same way every time.","the value of a composition lay in its capacity to keep changing.","critics were better judges of her work than performers were.","publishing her works was more important than perfecting them."],"explanation":"Viewing each performance as a living draft and insisting music is never complete implies Reyes valued ongoing change, supporting B. Choice A contradicts her practice of continual revision and her view of performances as drafts.","skill":"inference"},{"cat":"information","a":0,"q":"Researchers surveyed commuters in a large city to learn why ridership on a new express bus line was lower than projected. Among riders who had tried the line once but did not return, the most commonly cited reason was not travel time but the unpredictability of arrivals, which made it hard to plan connections.\n\nWhich choice most logically completes the text?","options":["improving the reliability of arrival times might do more to retain riders than reducing travel time would.","the express bus line travels faster than any other route in the city.","commuters generally prefer driving to using public transportation.","the survey failed to identify any clear reason for the low ridership."],"explanation":"Since unpredictable arrivals, not travel time, was the top complaint, addressing reliability would likely retain more riders, supporting A. Choice D contradicts the text, which clearly identifies unpredictability as the main reason.","skill":"inference"},{"cat":"information","a":0,"q":"In the novel, the merchant Sallow keeps a ledger of favors rather than money, recording each kindness he receives and each he gives. He treats the book as a moral account that must always balance, refusing to sleep until the day's entries are squared. When a stranger once saved his cart from a flood, Sallow spent a week anxiously searching for a way to repay a debt the stranger had already forgotten.\n\nWhich choice best describes the overall structure of the text?","options":["It presents a character's unusual principle and then illustrates that principle with a specific incident.","It compares two characters who hold opposing views about money.","It traces how a character gradually abandons a long-held belief.","It lists several unrelated habits of a minor character."],"explanation":"The text first describes Sallow's principle of balancing favors and then gives the flood incident as an example, supporting A. Choice C is wrong because Sallow never abandons his belief; the incident shows him acting on it.","skill":"text structure / function"},{"cat":"information","a":1,"q":"A botanist proposed that a certain alpine flower blooms earlier on south-facing slopes because those slopes receive more direct sunlight and warm sooner in spring. To test this, she recorded the first bloom date of the flower on slopes facing different directions across one mountain range.\n\nWhich finding, if true, would most strongly support the botanist's proposal?","options":["Flowers on north-facing slopes were larger and more numerous than those on south-facing slopes.","On south-facing slopes, the flower bloomed an average of two weeks earlier than on north-facing slopes.","Flowers bloomed at the same time on all slopes regardless of the direction they faced.","South-facing slopes had thinner soil than north-facing slopes across the range."],"explanation":"Earlier blooming on warmer south-facing slopes directly matches the proposal that more sunlight causes earlier blooming, supporting B. Choice C contradicts the proposal by showing no timing difference between slope directions.","skill":"command of evidence (textual)"},{"cat":"information","a":0,"q":"Archaeologists excavating a coastal settlement found fish bones from deep-water species in a layer dated to roughly three thousand years ago. Catching such fish would have required boats capable of traveling far from shore. The same layer also contained fragments of woven cordage strong enough to serve as fishing line.\n\nWhich choice most logically completes the text?","options":["the settlement's people likely possessed the seafaring technology needed to fish in deep water.","the deep-water fish bones must have washed ashore from a distant shipwreck.","the settlement was probably abandoned shortly after the layer formed.","woven cordage was used mainly for purposes other than fishing."],"explanation":"Deep-water fish bones plus strong cordage suitable for fishing line point to the people having the means to fish far offshore, supporting A. Choice B ignores the cordage evidence and offers an explanation the text does not support.","skill":"inference"},{"cat":"information","a":1,"q":"A nutrition study tracked two groups of office workers over eight weeks. One group kept a daily written food log; the other did not. At the study's end, members of the logging group reported being more aware of their snacking habits, and on average they consumed 15 percent fewer snacks per day than the non-logging group.\n\nWhich choice best uses data from the text to illustrate the effect of keeping a food log?","options":["Both groups reported greater awareness of their snacking habits by the end of the study.","The logging group consumed 15 percent fewer snacks per day than the non-logging group.","The study lasted eight weeks and involved office workers.","The non-logging group consumed more snacks at the start than the logging group did."],"explanation":"The 15 percent reduction in the logging group directly illustrates the log's effect on snacking, supporting B. Choice A misstates the text, which credits greater awareness only to the logging group.","skill":"command of evidence (quantitative)"},{"cat":"information","a":1,"q":"The poet Imre Bardos rarely titled his poems, instead numbering them in the order he wrote them. He claimed that titles tempted readers to decide what a poem meant before reading it, while bare numbers left the work open. After his death, an editor added descriptive titles to a new edition, and several scholars argued the change betrayed the poet's clear intentions.\n\nIt can most reasonably be inferred from the text that Bardos valued","options":["the chance to revise his poems after publication.","leaving readers free to interpret his poems without guidance from titles.","the opinions of editors over those of ordinary readers.","writing as many poems as possible in a short time."],"explanation":"Bardos avoided titles because they made readers decide meaning in advance, so he valued leaving interpretation open, supporting B. Choice C is unsupported; the scholars, not Bardos, are shown objecting to the editor's changes.","skill":"inference"},{"cat":"information","a":1,"q":"Economists examined whether posting calorie counts on menus changed what diners ordered at a chain of cafes. After the labels appeared, the average number of calories per order fell only slightly. However, sales of the cafes' lowest-calorie items rose sharply, suggesting that the labels influenced a particular group of customers more than others.\n\nWhich choice most logically completes the text?","options":["the labels had no measurable effect on any customer's choices.","the labels mainly affected customers already inclined toward low-calorie options.","most customers switched entirely to the highest-calorie items available.","calorie labels are required by law in every region studied."],"explanation":"A small overall change but a sharp rise in low-calorie sales suggests the labels swayed customers already leaning toward such items, supporting B. Choice A contradicts the sharp rise in low-calorie sales, which shows a measurable effect.","skill":"inference"},{"cat":"information","a":1,"q":"Text 1: Astronomer Lena Farr maintains that searching for life on distant planets should focus on worlds with liquid water, since every known organism depends on it.\n\nText 2: Astrobiologist Tomas Wren argues that limiting the search to water-based worlds risks overlooking life that might use other liquids, such as methane, as a medium for its chemistry.\n\nBased on the texts, Farr and Wren would most likely disagree about which of the following?","options":["Whether any organisms known on Earth depend on liquid water.","Whether the search for life should be limited to planets with liquid water.","Whether distant planets are worth studying at all.","Whether methane can exist in liquid form on other planets."],"explanation":"Farr favors focusing on water worlds while Wren warns against limiting the search that way, so they disagree about whether to restrict the search to water planets, supporting B. Choice A is something both accept, since Wren does not dispute that known life needs water.","skill":"cross-text connections"},{"cat":"information","a":1,"q":"A geologist studying an ancient lake bed observed that its sediment layers alternate between dark, organic-rich bands and pale, mineral-rich bands. She proposed that each pair of bands represents a single year, with the dark band forming in the wet season and the pale band in the dry season. Counting the pairs would then reveal how long the lake existed.\n\nWhich finding, if true, would most strengthen the geologist's proposal?","options":["The lake bed contains fossils of fish that lived only in deep water.","In modern lakes of the same type, dark and pale bands form in wet and dry seasons each year.","The pale bands are slightly thicker than the dark bands on average.","The lake bed lies near a mountain range that formed long after the lake dried up."],"explanation":"Showing that modern lakes form one dark and one pale band per year supports treating each pair as a single year, strengthening the proposal, supporting B. Choice C describes band thickness but does not address whether a pair equals one year.","skill":"command of evidence (textual)"},{"cat":"information","a":1,"q":"In the folktale, a weaver is offered a single wish by a river spirit. Rather than asking for gold or long life, she asks that her loom never tangle, so that her days will pass without frustration. Years later, when neighbors marvel at her steady contentment, she tells them the secret of happiness is not having more but spending one's hours unsnarled.\n\nWhich choice best states the main idea of the text?","options":["The weaver regrets not asking the river spirit for wealth.","The weaver finds contentment by choosing to remove a small daily frustration rather than seeking riches.","The river spirit rewards only those who ask for modest wishes.","The weaver's neighbors are jealous of her untangled loom."],"explanation":"The weaver chooses to end a daily frustration over wealth and credits her contentment to that choice, supporting B. Choice A contradicts the text, which shows her satisfied rather than regretful.","skill":"central idea"},{"cat":"information","a":0,"q":"A researcher studying urban birds found that mockingbirds living in noisy areas near highways sang at a higher pitch than those in quieter parks. She suggested that the higher pitch helps their songs carry over the low-frequency rumble of traffic, making the birds easier for mates to hear.\n\nWhich choice most logically completes the text?","options":["the birds in noisy areas may have adjusted their songs in response to the traffic noise around them.","mockingbirds are unable to survive in areas near highways.","low-pitched songs are always more attractive to mockingbird mates.","traffic noise has no effect on how birds communicate."],"explanation":"Higher-pitched songs in noisy areas that help cut through traffic rumble suggest the birds adjusted to the noise, supporting A. Choice D contradicts the researcher's suggestion that pitch changes are a response to traffic noise.","skill":"inference"},{"cat":"information","a":0,"q":"An education researcher compared two methods of teaching vocabulary. In one classroom, students memorized definitions from a list; in another, they encountered each new word in several short stories. On a test given a month later, students from the story-based classroom correctly recalled an average of 22 words, while those from the list-based classroom recalled an average of 14.\n\nWhich choice best uses data from the text to support the claim that the story-based method aided long-term recall?","options":["Story-based students recalled an average of 22 words, compared with 14 for list-based students.","Both classrooms studied the same number of new vocabulary words.","The test was given one month after the lessons ended.","List-based students recalled an average of 14 words on the delayed test."],"explanation":"The comparison of 22 to 14 words recalled a month later directly supports the claim that the story-based method aided long-term recall, supporting A. Choice D gives only one group's figure and omits the comparison needed to show an advantage.","skill":"command of evidence (quantitative)"},{"cat":"information","a":1,"q":"The philosopher Aurelia Stern argued that boredom is not merely an absence of stimulation but a signal that a person's current activity no longer matches their deeper interests. On this view, the discomfort of boredom serves a purpose: it nudges people to seek out pursuits that engage them more fully. Stern therefore treated chronic boredom as worth examining rather than simply escaping.\n\nIt can most reasonably be inferred from the text that Stern would most likely encourage a bored person to","options":["ignore the feeling until it passes on its own.","consider what their boredom might reveal about their interests.","seek out the most intense stimulation available.","accept that boredom has no meaning or value."],"explanation":"Since Stern saw boredom as a meaningful signal worth examining, she would encourage reflecting on what it reveals, supporting B. Choice D contradicts her view that boredom serves a purpose and is worth examining.","skill":"inference"},{"cat":"information","a":1,"q":"A conservation group reintroduced beavers to a stretch of river that had been straightened decades earlier for farming. Within five years, the beavers' dams had slowed the water, created small wetlands, and raised the water table in the surrounding fields. Farmers who had once opposed the project reported that their pastures stayed green later into the dry season than before.\n\nWhich choice best states the main idea of the text?","options":["Beavers are difficult to reintroduce to rivers altered by farming.","The reintroduced beavers reshaped the river in ways that ended up benefiting nearby farmland.","Farmers should always oppose conservation projects on their land.","Straightening rivers is the most effective way to support agriculture."],"explanation":"The beavers' changes raised the water table and kept pastures green, benefiting the farmland, supporting B. Choice C contradicts the text, which shows opposing farmers later reporting benefits.","skill":"central idea"},{"cat":"information","a":1,"q":"A historian studying a nineteenth-century mill town claimed that workers there enjoyed unusually strong community ties. As evidence, she pointed to surviving records showing that the town supported a library, several social clubs, and a mutual-aid fund to which most households contributed.\n\nWhich additional finding, if true, would most weaken the historian's claim?","options":["The mutual-aid fund was managed by a committee of elected residents.","Most households left the town within a year of arriving and rarely formed lasting bonds.","The library held a larger collection than libraries in neighboring towns.","The social clubs met in a hall built by the mill's owners."],"explanation":"High turnover with few lasting bonds undercuts the claim of strong community ties despite the institutions, weakening it, supporting B. Choice C concerns library size, which does not address whether residents had strong ties.","skill":"command of evidence (textual)"},{"cat":"information","a":1,"q":"In the story, a clockmaker named Vasco refuses to repair clocks that run too fast, accepting only those that run slow. He explains that a slow clock merely makes a person late, an error easily forgiven, while a fast clock makes a person wait, wasting hours that can never be recovered. His customers find the rule strange, but they bring him their slow clocks all the same.\n\nWhich choice best describes the function of the second sentence in the text?","options":["It reveals that Vasco's customers disagree with his reasoning.","It provides the reasoning behind Vasco's unusual policy.","It shows that Vasco is unable to repair fast clocks.","It explains how Vasco first learned the clockmaking trade."],"explanation":"The second sentence gives Vasco's explanation for why he prefers slow clocks, providing the reasoning behind his policy, supporting B. Choice C is wrong because the text shows Vasco refusing, not failing, to fix fast clocks.","skill":"text structure / function"},{"cat":"information","a":2,"q":"Materials scientists tested a new coating designed to keep solar panels free of dust, which can sharply reduce the amount of electricity panels produce. In a desert trial, coated panels retained 94 percent of their peak output after a month, while uncoated panels retained only 71 percent. The team concluded that the coating substantially reduced dust-related power loss.\n\nWhich choice best uses data from the text to support the team's conclusion?","options":["Uncoated panels retained 71 percent of their peak output after a month.","The trial was conducted in a desert over the course of one month.","Coated panels retained 94 percent of peak output, compared with 71 percent for uncoated panels.","Dust can reduce the electricity that solar panels produce."],"explanation":"Comparing 94 percent retention for coated panels with 71 percent for uncoated ones directly supports the conclusion that the coating reduced power loss, supporting C. Choice A gives only the uncoated figure and omits the comparison.","skill":"command of evidence (quantitative)"},{"cat":"information","a":1,"q":"Scientists have long debated why some species of fig trees produce fruit year-round rather than seasonally. One team observed that the animals that disperse fig seeds, such as certain bats and birds, remain in the forest throughout the year and depend on figs when other fruits are scarce. The team proposed that year-round fruiting and the constant presence of these animals reinforce each other.\n\nWhich choice most logically completes the text?","options":["the fig trees would produce more fruit if the dispersing animals left the forest.","the relationship between the fig trees and the animals may benefit both over time.","seasonal fruiting is more common among fig trees than year-round fruiting.","the dispersing animals prefer fruits other than figs in every season."],"explanation":"If year-round fruiting and the animals' constant presence reinforce each other, the relationship likely benefits both, supporting B. Choice D contradicts the text, which says the animals depend on figs when other fruits are scarce.","skill":"inference"},{"cat":"information","a":0,"q":"Text 1: Curator Niamh Doyle contends that museums should display artworks with minimal labeling, allowing visitors to form their own impressions before reading any explanation.\n\nText 2: Curator Felix Aldous responds that without context, many visitors miss the historical circumstances that give a work its meaning, leaving them with shallow first impressions that detailed labels could deepen.\n\nWhich choice best describes the relationship between the two texts?","options":["Text 2 challenges the approach recommended in Text 1 by stressing the value of context.","Text 2 provides specific examples that confirm the claim made in Text 1.","Text 2 restates the argument of Text 1 using different terms.","Text 2 agrees with Text 1 that labels distract from artworks."],"explanation":"Aldous argues that minimal labeling leaves shallow impressions and that context deepens understanding, challenging Doyle's approach, supporting A. Choice D is wrong because Aldous defends, rather than criticizes, the use of labels.","skill":"cross-text connections"},{"cat":"information","a":1,"q":"A team studying memory had volunteers learn a list of words and then either sleep for eight hours or stay awake for the same period before being tested. Those who slept recalled significantly more words than those who stayed awake. The researchers noted that during certain stages of sleep, the brain appears to replay and strengthen newly formed memories.\n\nWhich finding, if true, would most directly support the researchers' explanation for the sleep group's better recall?","options":["Volunteers who slept reported feeling more rested than those who stayed awake.","Brain recordings showed patterns linked to the learned words reappearing during sleep.","The sleep and awake groups learned the same list of words at the same time of day.","Volunteers who stayed awake performed other tasks during the waiting period."],"explanation":"Evidence that word-related brain patterns reappeared during sleep directly supports the idea that sleep replays and strengthens memories, supporting B. Choice A concerns feeling rested, which does not address the replay mechanism the researchers proposed.","skill":"command of evidence (textual)"},{"cat":"information","a":1,"q":"In her memoir, a former lighthouse keeper recalls the winters she spent alone on a rocky island. She writes that the isolation she had dreaded became, over time, a kind of companionship with the sea and the weather, and that returning to the mainland left her oddly restless among crowds. Only on the island, she explains, had she ever felt that her attention belonged entirely to her.\n\nIt can most reasonably be inferred from the text that the keeper came to view her isolation as","options":["a hardship she never managed to overcome.","an unexpected source of focus and belonging.","a temporary stage she was eager to leave behind.","proof that she preferred crowded places."],"explanation":"The keeper found companionship in isolation and felt her attention fully her own only on the island, so she came to see it as a source of focus and belonging, supporting B. Choice D contradicts her restlessness among mainland crowds.","skill":"inference"},{"cat":"information","a":2,"q":"A team surveyed residents of three neighborhoods about a proposed park. In the neighborhood closest to the planned site, 78 percent of residents supported the park; in a neighborhood about a mile away, 55 percent supported it; and in the farthest neighborhood, only 40 percent did. The researchers suggested that support for the park declined with distance from the proposed site.\n\nWhich choice best uses data from the text to support the researchers' suggestion?","options":["In the farthest neighborhood, 40 percent of residents supported the park.","A majority of residents in the closest neighborhood supported the park.","Support fell from 78 percent in the closest neighborhood to 40 percent in the farthest.","The survey covered three neighborhoods at different distances from the site."],"explanation":"Showing support dropping from 78 percent nearest to 40 percent farthest directly illustrates the decline with distance, supporting C. Choice A reports only the farthest neighborhood's figure and does not show a trend across distances.","skill":"command of evidence (quantitative)"},{"cat":"craft","a":0,"q":"The chef insisted that her signature broth could not be ______; even a slight change in the simmering time or the proportion of bones would yield a noticeably different flavor.\n\nWhich choice completes the text with the most logical and precise word?","options":["replicated","imagined","tolerated","discounted"],"explanation":"The chef claims the broth cannot be exactly reproduced because small changes alter the result, so \"replicated\" (copied precisely) fits. \"Imagined\" wrongly suggests the broth cannot be conceived of, which the context does not support.","skill":"Words in Context"},{"cat":"craft","a":1,"q":"As used in the passage, \"command\" most nearly means\n\nMargo's command of conversational Portuguese was impressive: after only a year abroad, she could follow rapid debates among native speakers and reply without hesitation.","options":["order","mastery","view","authority"],"explanation":"\"Command\" here describes Margo's skilled control of the language, so \"mastery\" fits. \"Order\" and \"authority\" treat command as a directive or power, which the sentence about language skill does not support.","skill":"Words in Context"},{"cat":"craft","a":2,"q":"The following text is from a short story about a clockmaker.\n\nOld Petrov never hurried. While apprentices rushed to finish a dozen repairs in a morning, he would spend hours on a single mechanism, turning each gear under his glass until he understood not merely whether it worked but why it had failed in the first place.\n\nWhich choice best describes the overall structure of the text?","options":["It introduces a general rule and then lists exceptions to it.","It presents two competing theories and endorses one.","It contrasts Petrov's careful method with the haste of others to highlight his thoroughness.","It traces a sequence of events leading to a surprising outcome."],"explanation":"The text sets the apprentices' rushing against Petrov's slow, deep attention, emphasizing his thoroughness through contrast. There is no rule with exceptions, competing theories, or surprising outcome.","skill":"Text Structure and Purpose"},{"cat":"craft","a":0,"q":"Despite the committee's reputation for ______, the new members were surprised by how quickly the group reached consensus, settling a contentious zoning question in a single afternoon.\n\nWhich choice completes the text with the most logical and precise word?","options":["discord","candor","prestige","secrecy"],"explanation":"\"Despite\" signals a contrast with quick consensus, so the committee was known for \"discord\" (disagreement). \"Secrecy\" introduces no contrast with reaching consensus quickly and is not supported.","skill":"Words in Context"},{"cat":"craft","a":1,"q":"The following text is from a researcher's report on urban birds.\n\nCity pigeons, it turns out, are not the indiscriminate scavengers we assume. In our study, individual birds returned again and again to particular vendors, ignoring identical food only meters away. Such loyalty suggests a capacity for preference that we rarely credit to them.\n\nWhich choice best states the main purpose of the text?","options":["To recommend new feeding practices for urban vendors","To challenge a common assumption by presenting an unexpected finding","To compare the diets of city pigeons and rural pigeons","To explain how pigeons navigate over long distances"],"explanation":"The text opens by rejecting a common belief and then offers a surprising observation supporting that rejection. It does not recommend practices, compare diets, or discuss navigation.","skill":"Text Structure and Purpose"},{"cat":"craft","a":2,"q":"Although critics dismissed her early canvases as merely ______, later scholars found in those same works a deliberate plainness that anticipated the minimalist movement by decades.\n\nWhich choice completes the text with the most logical and precise word?","options":["ornate","austere","derivative","luminous"],"explanation":"The contrast \"although ... later scholars found ... deliberate plainness ... anticipated\" implies critics saw the work as unoriginal, so \"derivative\" fits. \"Austere\" would not be a dismissal, since later scholars praise that very plainness.","skill":"Words in Context"},{"cat":"craft","a":1,"q":"As used in the text, \"weather\" most nearly means\n\nThe small bookshop had managed to weather two recessions and the arrival of a chain store across the street, largely because its owner refused to carry anything she had not personally read.","options":["forecast","endure","erode","celebrate"],"explanation":"To \"weather\" recessions and competition means to survive them, so \"endure\" fits. \"Erode\" reverses the meaning, suggesting the shop wore down rather than withstood the hardships.","skill":"Words in Context"},{"cat":"craft","a":1,"q":"Text 1\nMany educators argue that handwriting instruction should remain central in early grades. Forming letters by hand, they note, engages motor and visual systems together, and studies link this practice to stronger letter recognition and recall than typing produces.\n\nText 2\nClassroom hours are finite. Time spent drilling penmanship is time not spent on composition, coding, or analysis—skills that matter more in students' futures. If handwriting offers a modest cognitive boost, that benefit must be weighed against everything it crowds out.\n\nBased on the texts, how would the author of Text 2 most likely respond to the educators described in Text 1?","options":["By denying that handwriting has any cognitive benefits whatsoever","By acknowledging the benefits but questioning whether they justify the time required","By arguing that typing produces stronger letter recognition than handwriting","By proposing that handwriting be taught only in the latest grades"],"explanation":"Text 2 concedes a \"modest cognitive boost\" but insists it be \"weighed against everything it crowds out,\" matching choice B. It does not deny benefits outright or claim typing aids recognition.","skill":"Cross-Text Connections"},{"cat":"craft","a":1,"q":"The biographer's portrait of the inventor is notably ______: rather than smoothing over his subject's failures and cruelties, she presents them alongside his triumphs in equal detail.\n\nWhich choice completes the text with the most logical and precise word?","options":["flattering","evenhanded","tentative","nostalgic"],"explanation":"Presenting failures and triumphs \"in equal detail\" describes a balanced, \"evenhanded\" treatment. \"Flattering\" contradicts the inclusion of failures and cruelties.","skill":"Words in Context"},{"cat":"craft","a":0,"q":"The following text is from a novel. The narrator is describing her grandmother.\n\nGrandmother spoke of the war only obliquely, in fragments dropped between recipes and weather reports. A name here, a date there—never a whole story. We learned to listen for these slivers and to ask nothing, knowing that a direct question would close the door entirely.\n\nWhich choice best describes the function of the second sentence (\"A name here ... whole story\")?","options":["It offers an example that clarifies how the grandmother referred to the war.","It introduces a contrasting view held by the narrator.","It summarizes the grandmother's complete account of the war.","It explains why the family avoided discussing the weather."],"explanation":"The sentence illustrates the \"obliquely, in fragments\" claim by specifying what those fragments were—a name, a date. It does not contrast, summarize a full account, or concern the weather.","skill":"Text Structure and Purpose"},{"cat":"craft","a":1,"q":"As used in the text, \"qualify\" most nearly means\n\nThe scientist was careful to qualify her conclusion, noting that the pattern held only for samples collected in summer and might not extend to colder seasons.","options":["certify","limit","prepare","compete"],"explanation":"She narrows her conclusion by adding restrictions, so \"qualify\" means to \"limit.\" \"Certify\" would mean to confirm without restriction, the opposite of adding caveats.","skill":"Words in Context"},{"cat":"craft","a":1,"q":"Far from being ______, the new policy was the product of months of negotiation, with every clause traceable to a specific demand raised in committee.\n\nWhich choice completes the text with the most logical and precise word?","options":["deliberate","arbitrary","contested","binding"],"explanation":"\"Far from\" contrasts with a policy whose every clause is traceable to deliberate negotiation, so the policy was not \"arbitrary\" (random). \"Deliberate\" matches the policy rather than contrasting with it.","skill":"Words in Context"},{"cat":"craft","a":1,"q":"Text 1\nProponents of remote work point to gains in productivity. Freed from commutes and office interruptions, employees in several large studies completed more tasks per week and reported higher job satisfaction.\n\nText 2\nThe productivity numbers are real but incomplete. They measure individual output, not the slow erosion of mentorship and spontaneous collaboration. A junior employee may finish more tickets at home while learning far less than she would beside experienced colleagues.\n\nWhich choice best describes the relationship between the two texts?","options":["Text 2 rejects the data presented in Text 1 as fabricated.","Text 2 accepts Text 1's findings but argues they overlook an important dimension.","Text 2 provides additional evidence that confirms Text 1's conclusion.","Text 2 restates Text 1's argument in different terms."],"explanation":"Text 2 calls the numbers \"real but incomplete\" and adds the overlooked dimension of mentorship, matching choice B. It neither calls the data fabricated nor confirms or merely restates Text 1.","skill":"Cross-Text Connections"},{"cat":"craft","a":0,"q":"The diplomat's remarks were so ______ that reporters left the briefing unable to agree on whether an agreement had been reached or rejected.\n\nWhich choice completes the text with the most logical and precise word?","options":["equivocal","verbose","abrasive","scripted"],"explanation":"Remarks that leave reporters unable to agree on their meaning are \"equivocal\" (deliberately ambiguous). \"Verbose\" means wordy, which would not by itself create such uncertainty about meaning.","skill":"Words in Context"},{"cat":"craft","a":1,"q":"The following text is from an essay on architecture.\n\nWe tend to praise buildings for what they add to a skyline. But a good public library does something quieter: it subtracts. Inside its walls, the noise of the street falls away, the rush of the day slows, and a person is left, for an hour, with nothing demanded of her but attention.\n\nWhich choice best describes the function of the phrase \"it subtracts\" in the text?","options":["It corrects a factual error about how libraries are funded.","It reframes the library's value as removal rather than addition, against the usual emphasis.","It introduces a list of services that libraries provide to the public.","It signals a shift to discussing the library's exterior design."],"explanation":"\"It subtracts\" reverses the opening idea of buildings that \"add,\" recasting the library's worth as taking things away. It is not a factual correction, a service list, or about the exterior.","skill":"Text Structure and Purpose"},{"cat":"craft","a":2,"q":"As used in the text, \"register\" most nearly means\n\nA seismograph so sensitive that it could register the footsteps of a person walking across the laboratory was useless for studying distant earthquakes, since the background noise overwhelmed the faint signals.","options":["enroll","scold","detect","classify"],"explanation":"The instrument picks up tiny vibrations, so \"register\" means to \"detect.\" \"Classify\" suggests sorting into categories, which the sensing of footsteps does not describe.","skill":"Words in Context"},{"cat":"craft","a":1,"q":"The memoir avoids ______ entirely; the author never pauses to draw a moral or tell readers what to feel, trusting the bare events to speak for themselves.\n\nWhich choice completes the text with the most logical and precise word?","options":["sentiment","didacticism","ambiguity","chronology"],"explanation":"Refusing to \"draw a moral or tell readers what to feel\" is avoiding \"didacticism\" (the impulse to instruct). \"Sentiment\" concerns emotion, but the text targets the act of moralizing, not feeling itself.","skill":"Words in Context"},{"cat":"craft","a":0,"q":"The following text is from a science article about deep-sea exploration.\n\nFor decades, the deepest ocean trenches were assumed to be lifeless deserts, too cold and pressured for anything to survive. Then cameras lowered into the Mariana Trench captured small, translucent fish drifting calmly at depths once thought impossible. The deserts, it seemed, were inhabited after all.\n\nWhich choice best describes the overall structure of the text?","options":["It states a long-held belief and then presents evidence that overturns it.","It defines a scientific term and provides several examples.","It poses a question and answers it with a series of statistics.","It describes a process in chronological steps."],"explanation":"The text presents the old assumption of lifeless trenches, then the footage of fish that overturns it. There is no defined term, statistics, or step-by-step process.","skill":"Text Structure and Purpose"},{"cat":"craft","a":1,"q":"Critics had expected the sequel to merely ______ the original's success, but the director took unexpected risks, abandoning the formula that had made the first film popular.\n\nWhich choice completes the text with the most logical and precise word?","options":["surpass","exploit","undermine","predict"],"explanation":"\"Merely\" plus the contrast with \"unexpected risks\" implies critics expected the sequel to cash in on, or \"exploit,\" the original's success. \"Surpass\" would itself be ambitious, conflicting with \"merely.\"","skill":"Words in Context"},{"cat":"craft","a":1,"q":"Text 1\nThe restoration of wolves to the national park has been hailed as an ecological triumph. With wolves present, elk no longer linger in the valleys, willows have regrown along the streams, and songbird populations have rebounded.\n\nText 2\nIt is tempting to credit wolves with every change in the park. But the same decades saw shifts in rainfall, beaver activity, and human management. Untangling the wolves' true contribution from these tangled causes is far harder than the celebratory accounts suggest.\n\nBased on the texts, the author of Text 2 would most likely characterize the claims in Text 1 as","options":["entirely mistaken and unsupported by any evidence","overly simple in attributing complex changes to a single cause","too cautious in describing the wolves' effects","irrelevant to questions of park management"],"explanation":"Text 2 warns against crediting wolves \"with every change\" given other factors, so it sees Text 1 as oversimplifying a multi-cause situation. It does not call the claims entirely wrong, too cautious, or irrelevant.","skill":"Cross-Text Connections"},{"cat":"craft","a":1,"q":"As used in the text, \"arrest\" most nearly means\n\nThe sudden silence in the concert hall seemed to arrest time itself; not a program rustled, not a cough broke the stillness, until the conductor finally lowered his baton.","options":["capture","halt","accuse","decline"],"explanation":"The silence stops time, so \"arrest\" means to \"halt.\" \"Capture\" (to seize) and \"accuse\" do not match the sense of bringing motion to a stop.","skill":"Words in Context"},{"cat":"craft","a":1,"q":"The following text is from a review of a debut poetry collection.\n\nThe poems are uneven, and some images strain past their meaning. Yet even the weakest of them carries a restless energy, a sense of a writer unwilling to settle. One forgives the lapses, because they are the lapses of ambition, not of carelessness.\n\nWhich choice best describes the function of the last sentence in the text?","options":["It withdraws the praise offered earlier in the passage.","It explains why the reviewer excuses the collection's flaws.","It introduces a comparison to another poet's work.","It restates the opening claim without adding new information."],"explanation":"The final sentence accounts for the reviewer's forgiveness by attributing the flaws to ambition rather than carelessness. It does not withdraw praise, compare poets, or merely restate the opening.","skill":"Text Structure and Purpose"},{"cat":"craft","a":1,"q":"Because the treaty's language was intentionally ______, each side could return home claiming the document supported its own interpretation of the disputed border.\n\nWhich choice completes the text with the most logical and precise word?","options":["concise","elastic","archaic","redundant"],"explanation":"Language that lets each side claim support for opposing interpretations is \"elastic\" (stretchable in meaning). \"Concise\" implies precise brevity, which would resist conflicting readings.","skill":"Words in Context"},{"cat":"craft","a":1,"q":"As used in the text, \"economy\" most nearly means\n\nWhat struck readers about the author's late style was its economy: where she once spent paragraphs describing a room, she now conveyed it in a single, exact phrase.","options":["wealth","thrift","market","system"],"explanation":"Conveying much in few words reflects an \"economy\" of language, meaning \"thrift\" or sparingness. \"Market\" and \"system\" refer to economics, not concise expression.","skill":"Words in Context"},{"cat":"craft","a":1,"q":"The following text is from an article about a community garden.\n\nThe plot had sat vacant for years, a tangle of weeds behind a chain-link fence. No single person decided to change that. A neighbor cleared one corner; another brought soil; a third planted tomatoes. By summer, what no one had planned had somehow taken root.\n\nWhich choice best states the main idea of the text?","options":["The garden succeeded because of one neighbor's careful planning.","A shared space emerged from many small, uncoordinated contributions.","Vacant lots are difficult to convert into useful spaces.","Growing tomatoes requires soil brought from elsewhere."],"explanation":"The text stresses that \"no single person decided\" and that the garden arose from separate small acts, matching choice B. It explicitly denies a single planner and is not about difficulty or tomato cultivation.","skill":"Text Structure and Purpose"},{"cat":"craft","a":0,"q":"The scholar warned against reading the ancient text too ______, reminding students that a phrase obvious to its original audience might carry connotations entirely lost to modern readers.\n\nWhich choice completes the text with the most logical and precise word?","options":["literally","skeptically","reverently","frequently"],"explanation":"Warning that obvious phrases carry lost connotations cautions against taking words at face value, so reading too \"literally\" fits. \"Skeptically\" would mean doubting the text, not missing hidden connotations.","skill":"Words in Context"},{"cat":"craft","a":1,"q":"Text 1\nSome historians treat the printing press as the single engine of the Reformation. Without cheap pamphlets, they argue, reformist ideas could never have spread fast enough to outpace the authorities trying to suppress them.\n\nText 2\nPrint mattered, but ideas travel by many roads. Sermons, songs, and rumor carried reformist messages to the illiterate majority who could not read a pamphlet at all. To make the press the lone cause is to forget how most people actually encountered new ideas.\n\nBased on the texts, the author of Text 2 would most likely argue that the historians in Text 1","options":["underestimate how quickly pamphlets could be printed","overlook channels through which ideas reached people who could not read","deny that the printing press had any influence at all","exaggerate the authorities' ability to suppress new ideas"],"explanation":"Text 2 emphasizes sermons, songs, and rumor reaching the illiterate, faulting Text 1 for ignoring those non-print channels. It does not concern printing speed, deny print's influence, or focus on suppression.","skill":"Cross-Text Connections"},{"cat":"craft","a":2,"q":"As used in the text, \"temper\" most nearly means\n\nThe editor urged the columnist to temper his harshest accusations with at least some acknowledgment that the officials might have acted in good faith.","options":["mood","harden","moderate","forge"],"explanation":"Softening harsh accusations with acknowledgment means to \"moderate\" them. \"Harden\" reverses the sense, and \"mood\" is a noun that does not fit the verb slot.","skill":"Words in Context"},{"cat":"craft","a":0,"q":"The following text is from a nature writer's field notes.\n\nI had come to the marsh expecting spectacle—the great flocks I had read about, rising at once like smoke. What I found instead was patience: a single heron, motionless for an hour, teaching me that the marsh rewards those willing to wait rather than those hoping to be dazzled.\n\nWhich choice best describes the overall structure of the text?","options":["It sets up an expectation and then describes a different, more valuable discovery.","It lists the species a visitor is likely to encounter at a marsh.","It argues that marshes are more important than other habitats.","It recounts a single event in strict chronological order."],"explanation":"The writer expects spectacle but finds, and prizes, the lesson of patience instead, an expectation-versus-reality structure. It is not a species list, a habitat comparison, or a plain chronology.","skill":"Text Structure and Purpose"},{"cat":"craft","a":0,"q":"Reviewers praised the documentary's ______ approach: rather than guiding viewers toward a verdict, it laid out conflicting testimony and left the judgment to the audience.\n\nWhich choice completes the text with the most logical and precise word?","options":["impartial","exhaustive","sympathetic","provocative"],"explanation":"Presenting conflicting testimony without steering viewers toward a verdict describes an \"impartial\" approach. \"Exhaustive\" concerns thoroughness, not the refusal to take sides that the sentence highlights.","skill":"Words in Context"},{"cat":"expression","a":1,"q":"While researching a topic, a student has taken the following notes:\n- The axolotl is a type of salamander native to lakes near Mexico City.\n- Most salamanders lose their gills and leave the water as adults.\n- The axolotl keeps its feathery external gills and stays in the water for its entire life.\n- It can regrow lost limbs, parts of its heart, and even portions of its brain.\nThe student wants to emphasize a way the axolotl differs from most salamanders. Which choice most effectively uses the relevant information from the notes to accomplish this goal?","options":["The axolotl is a salamander that lives in lakes near Mexico City and can regrow many of its body parts.","Unlike most salamanders, which leave the water as adults, the axolotl keeps its gills and remains aquatic for its whole life.","The axolotl, a salamander, has feathery external gills that allow it to breathe underwater.","Salamanders are a diverse group, and the axolotl is one species found in Mexico."],"explanation":"The key contrasts the axolotl with most salamanders, directly meeting the goal of emphasizing a difference. The main distractor (A) lists facts about the axolotl but draws no comparison to other salamanders, so it fails the stated goal.","skill":"Synthesis: emphasize a difference"},{"cat":"expression","a":0,"q":"While researching a topic, a student has taken the following notes:\n- Beatrix Potter was a British author and illustrator born in 1866.\n- She wrote and illustrated 'The Tale of Peter Rabbit' in 1902.\n- She was also a skilled naturalist who studied fungi.\n- She used the money from her books to buy farmland in England's Lake District.\n- She left over 4,000 acres of land to the National Trust for conservation.\nThe student wants to introduce Beatrix Potter to an audience unfamiliar with her. Which choice most effectively uses the relevant information from the notes to accomplish this goal?","options":["Beatrix Potter, born in 1866, was a British author and illustrator best known for 'The Tale of Peter Rabbit.'","Beatrix Potter studied fungi and was considered a skilled naturalist during her lifetime.","Using money from her books, Beatrix Potter bought farmland in the Lake District.","Beatrix Potter left over 4,000 acres of land to the National Trust."],"explanation":"An introduction for an unfamiliar audience needs basic identifying information: who she was and what she is best known for. Choice A provides her name, era, role, and most famous work. The distractors begin with specialized details that assume the reader already knows who she is.","skill":"Synthesis: introduce to unfamiliar audience"},{"cat":"expression","a":1,"q":"The desert tortoise spends much of the hot summer underground in burrows it digs with its strong front legs. These burrows can be several feet deep and stay much cooler than the surface. ______ they shelter many other animals, including snakes, lizards, and small mammals seeking relief from the heat.\nWhich choice completes the text with the most logical transition?","options":["However,","In addition to protecting the tortoise,","For instance,","By contrast,"],"explanation":"The sentence adds a second function of the burrows beyond sheltering the tortoise, so an additive phrase signaling 'on top of protecting the tortoise' fits. 'However' and 'By contrast' wrongly signal opposition, and 'For instance' wrongly signals an example of the prior idea.","skill":"Transition: addition"},{"cat":"expression","a":2,"q":"While researching a topic, a student has taken the following notes:\n- Tardigrades, often called water bears, are microscopic animals.\n- They can survive being completely dried out for years.\n- They can endure temperatures near absolute zero and far above boiling.\n- Some have survived exposure to the vacuum of outer space.\n- Scientists study them to understand the limits of life.\nThe student wants to emphasize the tardigrade's ability to survive extreme conditions. Which choice most effectively uses the relevant information from the notes to accomplish this goal?","options":["Tardigrades are microscopic animals that scientists study in laboratories.","Tardigrades, also known as water bears, are sometimes found in damp moss.","Tardigrades can survive being dried out for years, exposed to extreme temperatures, and even left in the vacuum of space.","Tardigrades are commonly called water bears because of their plump appearance."],"explanation":"Choice C bundles the survival feats from the notes, directly emphasizing the tardigrade's endurance. The distractors mention the animal but omit any extreme conditions, failing the goal.","skill":"Synthesis: emphasize a quality"},{"cat":"expression","a":2,"q":"Honeybees communicate the location of food through a 'waggle dance,' moving in a figure-eight pattern on the honeycomb. The angle of the dance indicates the direction of the food relative to the sun. ______ the duration of the waggle indicates how far away the food is.\nWhich choice completes the text with the most logical transition?","options":["Nevertheless,","Meanwhile,","Similarly,","In contrast,"],"explanation":"Both sentences describe parallel features of the dance encoding information, so 'Similarly' signals the matching relationship. 'Nevertheless' and 'In contrast' wrongly imply opposition, and 'Meanwhile' implies simultaneous unrelated events.","skill":"Transition: similarity"},{"cat":"expression","a":1,"q":"While researching a topic, a student has taken the following notes:\n- The Eiffel Tower was completed in Paris in 1889.\n- It was built as the entrance arch for the 1889 World's Fair.\n- Many Parisian artists and citizens criticized its design at first.\n- The tower was originally meant to be torn down after 20 years.\n- It was saved because it proved useful as a radio transmission tower.\nThe student wants to explain why the Eiffel Tower was not demolished. Which choice most effectively uses the relevant information from the notes to accomplish this goal?","options":["The Eiffel Tower, completed in 1889, served as the entrance arch for that year's World's Fair.","Although it was originally meant to be torn down after 20 years, the Eiffel Tower was saved because it proved useful for radio transmission.","When it was first built, the Eiffel Tower was criticized by many Parisian artists and citizens.","The Eiffel Tower has become one of the most recognized landmarks in the world."],"explanation":"Choice B states both the demolition plan and the reason the tower survived, directly answering why it was not demolished. The distractors give background or reception but never explain its preservation.","skill":"Synthesis: explain a cause/reason"},{"cat":"expression","a":0,"q":"Many early mapmakers filled the unknown edges of their maps with drawings of sea monsters and imaginary creatures. These illustrations were not merely decorative. ______ they often marked regions that sailors considered dangerous or had never explored.\nWhich choice completes the text with the most logical transition?","options":["Instead,","Likewise,","For example,","Therefore,"],"explanation":"The second sentence corrects the dismissal 'not merely decorative' by offering the real purpose, so the contrastive 'Instead' fits. 'For example' and 'Likewise' imply continuation of the same idea, and 'Therefore' implies a conclusion drawn from the prior claim.","skill":"Transition: contrast/correction"},{"cat":"expression","a":1,"q":"For centuries, people believed that meteorites were ordinary earthly rocks struck by lightning. In 1794, the physicist Ernst Chladni argued that these stones actually fell from space. ______ his idea was widely ridiculed by scientists who could not accept that rocks could come from beyond Earth.\nWhich choice completes the text with the most logical transition?","options":["As a result,","At first,","Consequently,","In other words,"],"explanation":"'At first' signals an initial reaction that later changed, fitting the implied turn in the history of the idea. 'As a result' and 'Consequently' wrongly frame the ridicule as a logical outcome of the argument, and 'In other words' signals restatement.","skill":"Transition: sequence/time"},{"cat":"expression","a":3,"q":"While researching a topic, a student has taken the following notes:\n- Mary Anning was a fossil collector born in England in 1799.\n- She discovered the first complete ichthyosaur skeleton when she was about twelve.\n- She later found the first two plesiosaur skeletons ever identified.\n- As a woman, she was not allowed to join the Geological Society of London.\n- Her discoveries helped shape early ideas about prehistoric life.\nThe student wants to highlight an obstacle Anning faced in her career. Which choice most effectively uses the relevant information from the notes to accomplish this goal?","options":["Mary Anning discovered the first complete ichthyosaur skeleton at about age twelve.","Mary Anning's discoveries helped shape early ideas about prehistoric life.","Mary Anning found the first two plesiosaur skeletons ever identified.","Despite her major discoveries, Mary Anning was barred from the Geological Society of London because she was a woman."],"explanation":"Choice D names the obstacle, the gender-based exclusion from the scientific society, meeting the goal. The other choices describe her achievements but identify no obstacle.","skill":"Synthesis: highlight an obstacle"},{"cat":"expression","a":0,"q":"The blue whale is the largest animal known to have ever lived, weighing as much as 200 tons. ______ it feeds almost entirely on krill, tiny shrimp-like creatures that are no longer than a paperclip.\nWhich choice completes the text with the most logical transition?","options":["Yet","Thus","Likewise,","For this reason,"],"explanation":"The contrast between the largest animal and its tiny prey calls for 'Yet.' 'Thus' and 'For this reason' wrongly imply the diet results from the whale's size, and 'Likewise' implies similarity rather than contrast.","skill":"Transition: contrast"},{"cat":"expression","a":0,"q":"Vincent van Gogh sold very few paintings during his lifetime and struggled financially for years. ______ his works now sell for tens of millions of dollars and hang in the world's most famous museums.\nWhich choice completes the text with the most logical transition?","options":["Today,","As a result,","For instance,","Indeed,"],"explanation":"'Today' marks the time shift from his unsuccessful lifetime to his present fame, the central contrast. 'As a result' wrongly implies the fame caused by his earlier struggles, 'For instance' implies an example, and 'Indeed' implies emphatic agreement.","skill":"Transition: time contrast"},{"cat":"expression","a":1,"q":"While researching a topic, a student has taken the following notes:\n- The Great Pacific Garbage Patch is a collection of floating trash in the ocean.\n- It is located between California and Hawaii.\n- It is roughly twice the size of the state of Texas.\n- Most of the debris is tiny pieces of broken-down plastic.\n- It is not a solid island that can be walked on, as some people imagine.\nThe student wants to correct a common misconception about the garbage patch. Which choice most effectively uses the relevant information from the notes to accomplish this goal?","options":["The Great Pacific Garbage Patch lies between California and Hawaii.","Although some imagine it as a solid island, the Great Pacific Garbage Patch is mostly tiny pieces of broken-down plastic.","The Great Pacific Garbage Patch is roughly twice the size of Texas.","The Great Pacific Garbage Patch is a collection of floating trash in the ocean."],"explanation":"Choice B states the misconception (a solid island) and corrects it, meeting the goal. The other choices give accurate facts but do not address or correct the misconception.","skill":"Synthesis: correct a misconception"},{"cat":"expression","a":2,"q":"Octopuses can change the color and texture of their skin almost instantly to blend into their surroundings. This ability helps them hide from predators. ______ it allows them to ambush prey by remaining unseen until the moment they strike.\nWhich choice completes the text with the most logical transition?","options":["Nevertheless,","However,","Moreover,","Otherwise,"],"explanation":"The second sentence adds a second benefit of camouflage, so the additive 'Moreover' fits. 'Nevertheless' and 'However' signal contrast, and 'Otherwise' signals an alternative consequence.","skill":"Transition: addition"},{"cat":"expression","a":2,"q":"While researching a topic, a student has taken the following notes:\n- Katherine Johnson was a mathematician who worked at NASA.\n- She calculated trajectories for early American spaceflights.\n- Her calculations were used for John Glenn's 1962 orbital mission.\n- Glenn reportedly asked that she personally verify the computer's numbers before he flew.\n- She received the Presidential Medal of Freedom in 2015.\nThe student wants to emphasize the trust placed in Johnson's calculations. Which choice most effectively uses the relevant information from the notes to accomplish this goal?","options":["Katherine Johnson was a mathematician who worked at NASA for many years.","Katherine Johnson received the Presidential Medal of Freedom in 2015.","Before his 1962 orbital flight, John Glenn reportedly asked that Katherine Johnson personally verify the computer's calculations.","Katherine Johnson calculated trajectories for early American spaceflights."],"explanation":"Choice C shows an astronaut trusting Johnson over the computer, directly emphasizing the trust in her work. The other choices state her role or honors without conveying that trust.","skill":"Synthesis: emphasize a quality"},{"cat":"expression","a":1,"q":"Bamboo is one of the fastest-growing plants on Earth, with some species growing nearly a meter in a single day. It is also remarkably strong, with a tensile strength rivaling that of steel. ______ builders in many regions use bamboo as scaffolding and structural support.\nWhich choice completes the text with the most logical transition?","options":["Nonetheless,","For these reasons,","In contrast,","Earlier,"],"explanation":"The builders' use of bamboo follows from its speed of growth and strength, so 'For these reasons' signals the causal conclusion. 'Nonetheless' and 'In contrast' signal opposition, and 'Earlier' signals time sequence.","skill":"Transition: cause/conclusion"},{"cat":"expression","a":1,"q":"While researching a topic, a student has taken the following notes:\n- The platypus is a mammal native to Australia.\n- Unlike most mammals, it lays eggs instead of giving birth to live young.\n- It has a bill and webbed feet like a duck.\n- Male platypuses have venomous spurs on their hind legs.\nThe student wants to introduce the platypus to readers who have never heard of it. Which choice most effectively uses the relevant information from the notes to accomplish this goal?","options":["Male platypuses have venomous spurs on their hind legs.","The platypus, a mammal native to Australia, is unusual because it lays eggs and has a duck-like bill.","Unlike most mammals, the platypus lays eggs instead of giving live birth.","The platypus has webbed feet that help it swim."],"explanation":"Choice B identifies what the animal is, where it lives, and its most striking features, suiting an introduction. The distractors begin with a single specialized detail and assume the reader already knows the animal.","skill":"Synthesis: introduce to unfamiliar audience"},{"cat":"expression","a":2,"q":"Most volcanoes form at the boundaries where Earth's tectonic plates meet. The Hawaiian Islands, however, sit in the middle of a single plate, far from any boundary. ______ scientists explain their volcanoes as the product of a 'hot spot,' a plume of hot material rising from deep within the Earth.\nWhich choice completes the text with the most logical transition?","options":["For example,","Similarly,","To explain this puzzle,","On the other hand,"],"explanation":"The hot-spot theory resolves the apparent contradiction of mid-plate volcanoes, so a phrase signaling explanation of the puzzle fits. 'For example' and 'Similarly' wrongly signal continuation, and 'On the other hand' signals a fresh contrast rather than a resolution.","skill":"Transition: explanation/resolution"},{"cat":"expression","a":2,"q":"While researching a topic, a student has taken the following notes:\n- Jane Goodall began studying wild chimpanzees in Tanzania in 1960.\n- She observed chimpanzees making and using tools to catch termites.\n- Before this, scientists believed only humans made tools.\n- Her discovery forced a redefinition of what separates humans from animals.\nThe student wants to explain the significance of Goodall's observation. Which choice most effectively uses the relevant information from the notes to accomplish this goal?","options":["Jane Goodall began studying wild chimpanzees in Tanzania in 1960.","Jane Goodall observed chimpanzees in their natural habitat for many years.","By showing that chimpanzees make tools, Goodall overturned the long-held belief that only humans do, forcing scientists to rethink what sets humans apart.","Jane Goodall watched chimpanzees catch termites using thin sticks."],"explanation":"Choice C connects the observation to its impact on scientific belief, explaining why it mattered. Choice D describes the same behavior but stops short of stating its significance.","skill":"Synthesis: explain significance"},{"cat":"expression","a":1,"q":"Solar panels generate the most electricity on clear, sunny days. On cloudy days, their output drops significantly, and at night they produce none at all. ______ many solar systems are paired with batteries that store excess energy for later use.\nWhich choice completes the text with the most logical transition?","options":["Nevertheless,","To address this limitation,","Similarly,","For example,"],"explanation":"Batteries are a response to the problem of inconsistent solar output, so a phrase signaling a solution to the limitation fits. 'Nevertheless' and 'Similarly' miss the problem-solution link, and 'For example' wrongly signals an instance of the prior idea.","skill":"Transition: problem-solution"},{"cat":"expression","a":2,"q":"While researching a topic, a student has taken the following notes:\n- The Dewey Decimal System organizes library books by subject.\n- It was created by Melvil Dewey in 1876.\n- It assigns each book a number based on its topic.\n- It divides knowledge into ten main classes, such as science and history.\n- It is used in libraries around the world.\nThe student wants to explain how the system works to someone unfamiliar with it. Which choice most effectively uses the relevant information from the notes to accomplish this goal?","options":["The Dewey Decimal System was created by Melvil Dewey in 1876.","The Dewey Decimal System is used in libraries around the world.","The Dewey Decimal System organizes books by assigning each one a number based on its subject, dividing knowledge into ten main classes.","Melvil Dewey was an influential figure in the history of libraries."],"explanation":"Choice C explains the system's mechanism, assigning subject-based numbers within ten classes, meeting the explanatory goal. The other choices give history or scope but not how it works.","skill":"Synthesis: explain a process"},{"cat":"expression","a":1,"q":"Penguins are birds, but they cannot fly through the air like most other birds. Their wings have evolved into stiff, paddle-like flippers. ______ these flippers make penguins powerful and agile swimmers, propelling them through water at impressive speeds.\nWhich choice completes the text with the most logical transition?","options":["However,","Instead,","In conclusion,","Regardless,"],"explanation":"The flippers replace the lost function of flight with swimming, so 'Instead' signals the substitution. 'However' alone signals only contrast without the replacement sense, 'In conclusion' signals a summary, and 'Regardless' dismisses the prior point.","skill":"Transition: contrast/substitution"},{"cat":"expression","a":1,"q":"While researching a topic, a student has taken the following notes:\n- Fireflies and glowworms both produce light, a process called bioluminescence.\n- Adult fireflies are flying beetles that flash light to find mates.\n- Glowworms are usually the larvae or wingless females of certain beetles.\n- Glowworms glow steadily rather than flashing.\nThe student wants to emphasize a difference between fireflies and glowworms. Which choice most effectively uses the relevant information from the notes to accomplish this goal?","options":["Fireflies and glowworms both produce light through bioluminescence.","While adult fireflies are flying beetles that flash, glowworms typically cannot fly and glow steadily.","Glowworms are usually the larvae or wingless females of certain beetles.","Both fireflies and glowworms are types of beetles that can produce light."],"explanation":"Choice B contrasts the two on flight and light pattern, meeting the goal of emphasizing a difference. Choices A and D emphasize similarity, and C describes only glowworms.","skill":"Synthesis: emphasize a difference"},{"cat":"expression","a":2,"q":"The ancient Roman concrete used in structures like the Pantheon has survived for nearly two thousand years. Modern concrete, by comparison, often begins to crack and crumble within a few decades. ______ researchers have recently begun studying the chemistry of Roman concrete in hopes of building more durable structures.\nWhich choice completes the text with the most logical transition?","options":["For instance,","Even so,","Consequently,","Previously,"],"explanation":"The research follows from the surprising durability gap, so the causal 'Consequently' fits. 'For instance' wrongly signals an example, 'Even so' signals concession, and 'Previously' signals an earlier time, contradicting 'recently.'","skill":"Transition: cause/result"},{"cat":"expression","a":2,"q":"While researching a topic, a student has taken the following notes:\n- Wind turbines convert the energy of moving air into electricity.\n- A single large turbine can power hundreds of homes.\n- Wind farms can be built on land or offshore in the ocean.\n- Offshore winds are usually stronger and more consistent than winds on land.\nThe student wants to explain an advantage of offshore wind farms over land-based ones. Which choice most effectively uses the relevant information from the notes to accomplish this goal?","options":["Wind turbines convert the energy of moving air into electricity.","A single large wind turbine can power hundreds of homes.","Offshore wind farms benefit from winds that are usually stronger and more consistent than those on land.","Wind farms can be built either on land or offshore in the ocean."],"explanation":"Choice C names a specific advantage of offshore farms, the stronger and steadier winds, meeting the goal. The other choices give general facts without comparing offshore to land-based farms.","skill":"Synthesis: explain an advantage"},{"cat":"expression","a":1,"q":"When the printing press was introduced in Europe in the fifteenth century, some scholars worried that the easy availability of books would make people lazy thinkers. Centuries later, similar fears greeted the arrival of the internet. ______ each new technology for sharing information has prompted concerns that it would weaken the human mind.\nWhich choice completes the text with the most logical transition?","options":["Surprisingly,","In short,","By contrast,","Nonetheless,"],"explanation":"The final sentence summarizes the pattern shown by the two examples, so 'In short' signals the generalization. 'By contrast' and 'Nonetheless' signal opposition, and 'Surprisingly' implies the pattern is unexpected, which the examples do not support.","skill":"Transition: summary/generalization"},{"cat":"expression","a":1,"q":"While researching a topic, a student has taken the following notes:\n- The Sahara Desert was not always a desert.\n- Between about 11,000 and 5,000 years ago, it was green and full of lakes.\n- Rock paintings from the region show people swimming and herding cattle.\n- A shift in Earth's orbit gradually changed the climate, drying the land.\nThe student wants to present evidence that the Sahara was once green. Which choice most effectively uses the relevant information from the notes to accomplish this goal?","options":["A shift in Earth's orbit gradually dried out the Sahara region.","Rock paintings found in the Sahara depict people swimming and herding cattle, evidence that the region was once green.","The Sahara Desert was not always the dry place it is today.","Between about 11,000 and 5,000 years ago, the climate of the Sahara began to change."],"explanation":"Choice B presents concrete evidence, the rock paintings, supporting the claim that the Sahara was green. The other choices assert or explain the change but do not supply supporting evidence.","skill":"Synthesis: present evidence"},{"cat":"expression","a":1,"q":"Astronomers once classified Pluto as the ninth planet of our solar system. As telescopes improved, however, they discovered many similar icy bodies beyond Neptune, some nearly Pluto's size. ______ in 2006 they created the new category of 'dwarf planet' and reclassified Pluto into it.\nWhich choice completes the text with the most logical transition?","options":["Nevertheless,","In response,","For example,","Likewise,"],"explanation":"Creating the new category was a reaction to the new discoveries, so 'In response' fits. 'Nevertheless' signals concession, 'For example' signals an instance, and 'Likewise' signals similarity, none of which captures the cause-and-reaction link.","skill":"Transition: response/result"},{"cat":"expression","a":2,"q":"While researching a topic, a student has taken the following notes:\n- Sequoia trees are among the largest living things on Earth.\n- Their bark can be more than a foot thick.\n- The thick bark contains tannins that resist fire and insects.\n- Low-intensity fires actually help sequoias by clearing competing plants.\n- Sequoia cones often release their seeds only after exposure to fire's heat.\nThe student wants to emphasize how sequoias depend on fire. Which choice most effectively uses the relevant information from the notes to accomplish this goal?","options":["Sequoia trees are among the largest living things on Earth.","The thick bark of a sequoia can be more than a foot thick.","Sequoias depend on fire: low-intensity blazes clear competing plants, and the heat prompts their cones to release seeds.","Sequoia bark contains tannins that help resist insects."],"explanation":"Choice C ties together two ways sequoias rely on fire, directly emphasizing that dependence. The other choices describe size or bark without showing the trees' reliance on fire.","skill":"Synthesis: emphasize a relationship"},{"cat":"conventions","a":0,"q":"The ceramicist shapes each bowl by hand, and then she ______ it in a kiln heated to over a thousand degrees. Which choice completes the text so that it conforms to the conventions of Standard English?","options":["fires","firing","to fire","having fired"],"explanation":"The clause after 'and then' needs a finite main verb to pair with the subject 'she'; 'fires' supplies it. The participle 'firing' and the infinitive 'to fire' cannot serve as the verb of an independent clause.","skill":"verb form"},{"cat":"conventions","a":1,"q":"A colony of leaf-cutter ants ______ fungus underground, feeding it the plant matter the workers harvest from the forest above. Which choice completes the text so that it conforms to the conventions of Standard English?","options":["cultivate","cultivates","are cultivating","have cultivated"],"explanation":"The singular collective subject 'A colony' takes a singular verb, 'cultivates.' The plural forms 'cultivate,' 'are cultivating,' and 'have cultivated' disagree with the singular subject.","skill":"subject-verb agreement"},{"cat":"conventions","a":1,"q":"Marie Tharp, the geologist who mapped the ocean floor, helped confirm the theory of continental ______ her detailed charts revealed a great rift running down the Atlantic. Which choice completes the text so that it conforms to the conventions of Standard English?","options":["drift,","drift;","drift","drift but"],"explanation":"Two independent clauses must be joined by a semicolon (or a comma plus a conjunction). A comma alone creates a comma splice, no punctuation creates a run-on, and 'but' wrongly signals contrast without a needed comma.","skill":"sentence boundaries"},{"cat":"conventions","a":1,"q":"Because the bridge had been closed for repairs, commuters who normally drove across ______ to take a longer route through the valley. Which choice completes the text so that it conforms to the conventions of Standard English?","options":["was forced","were forced","is forced","forcing"],"explanation":"The plural subject 'commuters' requires the plural verb 'were forced.' The singular verbs disagree, and 'forcing' leaves the main clause without a finite verb.","skill":"subject-verb agreement"},{"cat":"conventions","a":1,"q":"The astronomer explained that the comet, which had not been visible from Earth for nearly seventy ______ would not return again within any living person's lifetime. Which choice completes the text so that it conforms to the conventions of Standard English?","options":["years","years,","years;","years:"],"explanation":"The nonrestrictive clause 'which had not been visible... years' must be closed with a comma to match the comma that opens it. A semicolon or colon cannot pair with the opening comma, and omitting punctuation breaks the pair.","skill":"nonrestrictive element"},{"cat":"conventions","a":2,"q":"Every one of the volunteers who restored the wetland ______ proud of the heron that has since returned to nest there. Which choice completes the text so that it conforms to the conventions of Standard English?","options":["are","were","is","have been"],"explanation":"The subject is the singular 'Every one,' not the plural 'volunteers' in the modifying phrase, so the singular verb 'is' is required. The plural verbs incorrectly agree with the nearest noun.","skill":"subject-verb agreement"},{"cat":"conventions","a":0,"q":"The chef garnished the plate with microgreens, a drizzle of olive oil, and ______ Which choice completes the text so that it conforms to the conventions of Standard English?","options":["a few flakes of sea salt.","a few flakes of sea salt;","a few, flakes of sea salt.","a few flakes, of sea salt."],"explanation":"The final item of a list simply ends with a period. The semicolon is wrong for a simple list, and the commas inserted inside the phrase incorrectly separate words that belong together.","skill":"punctuation: lists"},{"cat":"conventions","a":0,"q":"Although the early printing press could produce books far faster than scribes ______ many readers still preferred handwritten manuscripts for their beauty. Which choice completes the text so that it conforms to the conventions of Standard English?","options":["could,","could","could;","could:"],"explanation":"A comma is needed after the introductory dependent clause beginning with 'Although.' Omitting the comma runs the clauses together, and a semicolon or colon cannot separate a dependent clause from its main clause.","skill":"punctuation: intro clause"},{"cat":"conventions","a":1,"q":"The architect's most famous building, a spiraling museum in the heart of the ______ draws visitors who come as much for the structure as for the art inside. Which choice completes the text so that it conforms to the conventions of Standard English?","options":["city","city,","city;","city:"],"explanation":"The appositive phrase 'a spiraling museum... city' is nonrestrictive and must be closed with a comma to match its opening comma before the main verb 'draws.' The other marks cannot pair with the opening comma.","skill":"nonrestrictive appositive"},{"cat":"conventions","a":2,"q":"Neither the director nor the producers ______ willing to reveal how the film's startling final scene was made. Which choice completes the text so that it conforms to the conventions of Standard English?","options":["was","is","were","has been"],"explanation":"In 'neither...nor' constructions, the verb agrees with the nearer subject, here the plural 'producers,' so 'were' is correct. The singular verbs disagree with that nearer plural noun.","skill":"subject-verb agreement"},{"cat":"conventions","a":1,"q":"The hikers reached the summit just before dawn, ______ the valley below still wrapped in a soft gray mist. Which choice completes the text so that it conforms to the conventions of Standard English?","options":["they found","finding","and they found","found"],"explanation":"A participial phrase 'finding the valley...' correctly modifies the main clause without creating a new independent clause. 'They found' and 'found' would create a comma splice or a faulty second predicate; only the participle works after the comma.","skill":"sentence boundaries"},{"cat":"conventions","a":1,"q":"After studying the rings of the ancient ______ the botanist could estimate not only its age but also the climate it had endured. Which choice completes the text so that it conforms to the conventions of Standard English?","options":["tree;","tree,","tree","tree:"],"explanation":"A comma must follow the introductory prepositional phrase 'After studying...tree' before the main clause. A semicolon or colon is incorrect because what precedes is not an independent clause, and omitting punctuation is awkward.","skill":"punctuation: intro phrase"},{"cat":"conventions","a":0,"q":"The committee praised the report for ______ thoroughness, noting that it addressed every concern the residents had raised. Which choice completes the text so that it conforms to the conventions of Standard English?","options":["its","it's","their","its'"],"explanation":"The possessive pronoun 'its' correctly shows the report's thoroughness. 'It's' means 'it is,' 'their' is plural and disagrees with the singular 'report,' and 'its'' is not a word.","skill":"possessive pronoun"},{"cat":"conventions","a":1,"q":"Restored to its original colors after decades of careful ______ the mural now glows with the vivid blues and golds the artist first intended. Which choice completes the text so that it conforms to the conventions of Standard English?","options":["work","work,","work;","work:"],"explanation":"The introductory participial phrase 'Restored...work' must be set off by a comma before the subject 'the mural.' A semicolon or colon cannot separate this modifier from the clause it modifies.","skill":"modifier placement"},{"cat":"conventions","a":1,"q":"The two researchers shared the award equally, but the breakthrough had originally come from ______ alone. Which choice completes the text so that it conforms to the conventions of Standard English?","options":["she","her","hers","herself's"],"explanation":"As the object of the preposition 'from,' the objective pronoun 'her' is required. The subjective 'she,' the possessive 'hers,' and the nonexistent 'herself's' are all incorrect.","skill":"pronoun case"},{"cat":"conventions","a":2,"q":"The orchestra's new conductor brought an unusual ______ rather than rehearsing each movement in order, he began with the loudest passages first. Which choice completes the text so that it conforms to the conventions of Standard English?","options":["approach,","approach;","approach:","approach"],"explanation":"A colon properly introduces the explanation of the 'unusual approach' that follows, and the first clause is independent. A comma would create a splice, a semicolon is wrong before an elaboration, and no punctuation creates a run-on.","skill":"punctuation: colon"},{"cat":"conventions","a":0,"q":"By the time the relief supplies finally arrived, the stranded villagers ______ without fresh water for nearly three days. Which choice completes the text so that it conforms to the conventions of Standard English?","options":["had gone","have gone","go","are going"],"explanation":"The past perfect 'had gone' correctly shows an action completed before the past arrival of supplies. The present and present-perfect forms do not fit the established past time frame.","skill":"verb tense"},{"cat":"conventions","a":2,"q":"The documentary follows three ______ a marine biologist, a retired fisherman, and a teenage activist as they work to protect a single stretch of coast. Which choice completes the text so that it conforms to the conventions of Standard English?","options":["people","people,","people:","people;"],"explanation":"A colon correctly introduces the list naming the three people, and the clause before it is complete. A comma alone cannot introduce this appositive list cleanly here, and a semicolon is wrong before a list.","skill":"punctuation: colon"},{"cat":"conventions","a":1,"q":"Carved more than two thousand years ago, the stone figures still stand in rows, ______ silent guardians over the buried tombs. Which choice completes the text so that it conforms to the conventions of Standard English?","options":["they keep watch as","keeping watch as","watch as","and keeping watch as"],"explanation":"The participial phrase 'keeping watch as...' attaches smoothly to the main clause. 'They keep watch' would create a comma splice, and the other options leave the sentence ungrammatical.","skill":"sentence boundaries"},{"cat":"conventions","a":1,"q":"The engineer wanted to test whether the new alloy could withstand extreme cold, intense heat, and ______ Which choice completes the text so that it conforms to the conventions of Standard English?","options":["being put under sudden pressure.","sudden pressure.","when pressure was sudden.","to undergo sudden pressure."],"explanation":"Parallel structure requires the third item to match the noun phrases 'extreme cold' and 'intense heat,' so 'sudden pressure' is correct. The other options break the parallel pattern with a gerund, a clause, or an infinitive.","skill":"parallel structure"},{"cat":"conventions","a":0,"q":"The museum's curator, along with several visiting ______ believes that the painting was completed by an apprentice, not by the master himself. Which choice completes the text so that it conforms to the conventions of Standard English?","options":["scholars,","scholars","scholars;","scholar's"],"explanation":"The phrase 'along with several visiting scholars' is a nonrestrictive interrupter and must be closed with a comma to match its opening comma. The possessive 'scholar's' is also wrong because no possession is intended.","skill":"supplementary element"},{"cat":"conventions","a":0,"q":"The startup's founders insisted that their success was due less to luck ______ to years of patient, unglamorous work. Which choice completes the text so that it conforms to the conventions of Standard English?","options":["than","then","than was","as"],"explanation":"The comparative construction 'less to luck... than to' requires 'than.' 'Then' indicates time, 'than was' is ungrammatical here, and 'as' does not complete the 'less...than' pairing.","skill":"idiom/word choice"},{"cat":"conventions","a":2,"q":"When the storm knocked out power across the ______ neighbors gathered candles, shared food, and checked on the elderly residents down the street. Which choice completes the text so that it conforms to the conventions of Standard English?","options":["county;","county:","county,","county"],"explanation":"A comma is needed after the introductory dependent clause 'When the storm... county.' A semicolon or colon cannot join a dependent clause to the main clause, and omitting punctuation runs them together.","skill":"punctuation: intro clause"},{"cat":"conventions","a":1,"q":"Long admired for their intricate ______ the weavings of the region have recently drawn the attention of textile historians worldwide. Which choice completes the text so that it conforms to the conventions of Standard English?","options":["patterns","patterns,","patterns;","patterns:"],"explanation":"The introductory modifier 'Long admired...patterns' must be followed by a comma before the subject 'the weavings.' Without the comma the modifier runs into the clause, and the other marks are incorrect.","skill":"modifier placement"},{"cat":"conventions","a":2,"q":"The professor reminded the class that each scientist ______ responsible for documenting the methods so that other labs could reproduce the results. Which choice completes the text so that it conforms to the conventions of Standard English?","options":["are","were","is","have been"],"explanation":"The subject 'each scientist' is singular and requires the singular verb 'is.' The plural verbs do not agree with the singular 'each.'","skill":"subject-verb agreement"},{"cat":"conventions","a":0,"q":"The diver described the ______ ecosystem in vivid detail: schools of silver fish, swaying coral, and shafts of light slicing through the blue. Which choice completes the text so that it conforms to the conventions of Standard English?","options":["reef's","reefs","reefs'","reef"],"explanation":"The singular possessive 'reef's' correctly shows that the ecosystem belongs to one reef. 'Reefs' is a plural, 'reefs'' is a plural possessive, and 'reef' fails to show possession.","skill":"possessive apostrophe"},{"cat":"conventions","a":1,"q":"Having rehearsed the speech for ______ the candidate delivered it without once glancing at her notes. Which choice completes the text so that it conforms to the conventions of Standard English?","options":["weeks","weeks,","weeks;","weeks:"],"explanation":"The introductory participial phrase 'Having rehearsed...weeks' must be set off with a comma before the subject 'the candidate.' A semicolon or colon cannot follow this modifying phrase.","skill":"modifier placement"},{"cat":"conventions","a":1,"q":"The librarian recommended three classic novels to the book ______ each of which explores how memory shapes our sense of identity. Which choice completes the text so that it conforms to the conventions of Standard English?","options":["club;","club,","club","club:"],"explanation":"The relative clause 'each of which... identity' is nonrestrictive and is properly attached with a comma. A semicolon would wrongly require an independent clause after it, no punctuation creates a run-on, and a colon does not fit before this relative clause.","skill":"nonrestrictive element"}]};
